/**
 * Achievement System for Multi-Game Platform
 * Supports per-game achievements with unlock tracking and rewards
 * 
 * Collections:
 * - achievements: Stores achievement definitions (system-owned)
 * - achievement_progress: Stores player progress per game
 */

var ACHIEVEMENT_COLLECTION = "achievements";
var ACHIEVEMENT_PROGRESS_COLLECTION = "achievement_progress";

/**
 * RPC: achievements_get_all
 * Get all achievements for a game with player progress
 */
var rpcAchievementsGetAll = function(ctx, logger, nk, payload) {
    try {
        var data = JSON.parse(payload || '{}');
        
        if (!data.game_id) {
            throw Error("game_id is required");
        }
        
        var userId = ctx.userId;
        var gameId = data.game_id;
        
        logger.info("[Achievements] Getting all achievements for game: " + gameId);
        
        // Get achievement definitions
        var definitionsKey = "definitions_" + gameId;
        var definitions = [];
        
        try {
            var defRecords = nk.storageRead([{
                collection: ACHIEVEMENT_COLLECTION,
                key: definitionsKey,
                userId: "00000000-0000-0000-0000-000000000000"
            }]);
            
            if (defRecords && defRecords.length > 0 && defRecords[0].value) {
                definitions = defRecords[0].value.achievements || [];
            }
        } catch (err) {
            logger.warn("[Achievements] No definitions found for game: " + gameId);
        }
        
        // Get player progress
        var progressKey = "progress_" + userId + "_" + gameId;
        var progress = {};
        
        try {
            var progRecords = nk.storageRead([{
                collection: ACHIEVEMENT_PROGRESS_COLLECTION,
                key: progressKey,
                userId: userId
            }]);
            
            if (progRecords && progRecords.length > 0 && progRecords[0].value) {
                progress = progRecords[0].value;
            }
        } catch (err) {
            logger.debug("[Achievements] No progress found for user: " + userId);
        }
        
        // Merge definitions with progress
        var achievements = [];
        for (var i = 0; i < definitions.length; i++) {
            var def = definitions[i];
            var prog = progress[def.achievement_id] || {
                progress: 0,
                unlocked: false,
                unlock_date: null
            };
            
            // Hide secret achievements if not unlocked
            if (def.hidden && !prog.unlocked) {
                achievements.push({
                    achievement_id: def.achievement_id,
                    title: "???",
                    description: "Hidden achievement",
                    icon_url: "mystery_icon.png",
                    rarity: def.rarity,
                    category: def.category,
                    progress: 0,
                    target: def.target,
                    unlocked: false,
                    hidden: true,
                    points: def.points
                });
            } else {
                achievements.push({
                    achievement_id: def.achievement_id,
                    title: def.title,
                    description: def.description,
                    icon_url: def.icon_url,
                    rarity: def.rarity,
                    category: def.category,
                    type: def.type,
                    progress: prog.progress,
                    target: def.target,
                    unlocked: prog.unlocked,
                    unlock_date: prog.unlock_date,
                    rewards: def.rewards,
                    hidden: def.hidden || false,
                    points: def.points
                });
            }
        }
        
        // Calculate total achievement points
        var totalPoints = 0;
        var unlockedPoints = 0;
        
        for (var j = 0; j < achievements.length; j++) {
            totalPoints += achievements[j].points || 0;
            if (achievements[j].unlocked) {
                unlockedPoints += achievements[j].points || 0;
            }
        }
        
        return JSON.stringify({
            success: true,
            achievements: achievements,
            stats: {
                total_achievements: achievements.length,
                unlocked: achievements.filter(function(a) { return a.unlocked; }).length,
                total_points: totalPoints,
                unlocked_points: unlockedPoints,
                completion_percentage: achievements.length > 0 
                    ? Math.round((achievements.filter(function(a) { return a.unlocked; }).length / achievements.length) * 100)
                    : 0
            }
        });
        
    } catch (err) {
        logger.error("[Achievements] Get all error: " + err.message);
        return JSON.stringify({
            success: false,
            error: err.message
        });
    }
};

/**
 * RPC: achievements_update_progress
 * Update progress towards an achievement
 */
var rpcAchievementsUpdateProgress = function(ctx, logger, nk, payload) {
    try {
        var data = JSON.parse(payload || '{}');
        
        if (!data.game_id || !data.achievement_id || data.progress === undefined) {
            throw Error("game_id, achievement_id, and progress are required");
        }
        
        var userId = ctx.userId;
        var gameId = data.game_id;
        var achievementId = data.achievement_id;
        var newProgress = data.progress;
        var increment = data.increment || false;
        
        logger.info("[Achievements] Updating progress for " + achievementId + ": " + newProgress);
        
        // Get achievement definition
        var definitionsKey = "definitions_" + gameId;
        var achievement = null;
        
        var defRecords = nk.storageRead([{
            collection: ACHIEVEMENT_COLLECTION,
            key: definitionsKey,
            userId: "00000000-0000-0000-0000-000000000000"
        }]);
        
        if (defRecords && defRecords.length > 0 && defRecords[0].value) {
            var definitions = defRecords[0].value.achievements || [];
            for (var i = 0; i < definitions.length; i++) {
                if (definitions[i].achievement_id === achievementId) {
                    achievement = definitions[i];
                    break;
                }
            }
        }
        
        if (!achievement) {
            throw Error("Achievement not found: " + achievementId);
        }
        
        // Get or create progress record
        var progressKey = "progress_" + userId + "_" + gameId;
        var progressData = {};
        
        try {
            var progRecords = nk.storageRead([{
                collection: ACHIEVEMENT_PROGRESS_COLLECTION,
                key: progressKey,
                userId: userId
            }]);
            
            if (progRecords && progRecords.length > 0 && progRecords[0].value) {
                progressData = progRecords[0].value;
            }
        } catch (err) {
            logger.debug("[Achievements] Creating new progress record");
        }
        
        // Initialize achievement progress if doesn't exist
        if (!progressData[achievementId]) {
            progressData[achievementId] = {
                progress: 0,
                unlocked: false,
                unlock_date: null
            };
        }
        
        var achievementProgress = progressData[achievementId];
        
        // Don't update if already unlocked
        if (achievementProgress.unlocked) {
            return JSON.stringify({
                success: true,
                achievement: {
                    achievement_id: achievementId,
                    progress: achievementProgress.progress,
                    target: achievement.target,
                    unlocked: true,
                    already_unlocked: true
                }
            });
        }
        
        // Update progress
        if (increment) {
            achievementProgress.progress += newProgress;
        } else {
            achievementProgress.progress = newProgress;
        }
        
        // Check if unlocked
        var justUnlocked = false;
        if (achievementProgress.progress >= achievement.target) {
            achievementProgress.unlocked = true;
            achievementProgress.unlock_date = new Date().toISOString();
            justUnlocked = true;
            
            logger.info("[Achievements] Achievement unlocked: " + achievementId);
        }
        
        // Save progress
        progressData[achievementId] = achievementProgress;
        
        nk.storageWrite([{
            collection: ACHIEVEMENT_PROGRESS_COLLECTION,
            key: progressKey,
            userId: userId,
            value: progressData,
            permissionRead: 1,
            permissionWrite: 0
        }]);
        
        // Grant rewards if unlocked
        var rewardsGranted = null;
        if (justUnlocked && achievement.rewards) {
            rewardsGranted = grantAchievementRewards(nk, logger, userId, gameId, achievement.rewards);
        }
        
        return JSON.stringify({
            success: true,
            achievement: {
                achievement_id: achievementId,
                progress: achievementProgress.progress,
                target: achievement.target,
                unlocked: achievementProgress.unlocked,
                just_unlocked: justUnlocked,
                unlock_date: achievementProgress.unlock_date
            },
            rewards_granted: rewardsGranted
        });
        
    } catch (err) {
        logger.error("[Achievements] Update progress error: " + err.message);
        return JSON.stringify({
            success: false,
            error: err.message
        });
    }
};

/**
 * Helper: Grant achievement rewards
 */
var grantAchievementRewards = function(nk, logger, userId, gameId, rewards) {
    var granted = {
        coins: 0,
        xp: 0,
        items: [],
        badge: null,
        title: null
    };
    
    try {
        // Grant coins
        if (rewards.coins && rewards.coins > 0) {
            var walletKey = "wallet_" + userId + "_" + gameId;
            var wallet = { balance: 0 };
            
            try {
                var walletRecords = nk.storageRead([{
                    collection: gameId + "_wallets",
                    key: walletKey,
                    userId: userId
                }]);
                
                if (walletRecords && walletRecords.length > 0 && walletRecords[0].value) {
                    wallet = walletRecords[0].value;
                }
            } catch (err) {
                logger.debug("[Achievements] Creating new wallet");
            }
            
            wallet.balance = (wallet.balance || 0) + rewards.coins;
            wallet.updated_at = new Date().toISOString();
            
            nk.storageWrite([{
                collection: gameId + "_wallets",
                key: walletKey,
                userId: userId,
                value: wallet,
                permissionRead: 1,
                permissionWrite: 0
            }]);
            
            granted.coins = rewards.coins;
        }
        
        // Grant items (simplified - integrate with inventory system)
        if (rewards.items && rewards.items.length > 0) {
            granted.items = rewards.items;
            logger.info("[Achievements] Items granted: " + rewards.items.join(", "));
        }
        
        // Grant badge/title
        if (rewards.badge) {
            granted.badge = rewards.badge;
        }
        
        if (rewards.title) {
            granted.title = rewards.title;
        }
        
        return granted;
        
    } catch (err) {
        logger.error("[Achievements] Reward grant error: " + err.message);
        return granted;
    }
};

/**
 * RPC: achievements_create_definition (Admin only)
 * Create a new achievement definition
 */
var rpcAchievementsCreateDefinition = function(ctx, logger, nk, payload) {
    try {
        if (typeof RpcHelpers !== 'undefined' && RpcHelpers && RpcHelpers.requireAdmin) {
            RpcHelpers.requireAdmin(ctx, nk);
        } else {
            if (ctx.userId) {
                var _accts = nk.accountsGetId([ctx.userId]);
                var _isAdmin = false;
                if (_accts && _accts.length > 0) {
                    var _meta = _accts[0].user.metadata;
                    if (_meta && _meta.admin === true) _isAdmin = true;
                }
                if (!_isAdmin) throw Error("Admin access required");
            }
        }

        var data = JSON.parse(payload || '{}');
        
        if (!data.game_id || !data.achievement_id || !data.title) {
            throw Error("game_id, achievement_id, and title are required");
        }
        
        var gameId = data.game_id;
        var definitionsKey = "definitions_" + gameId;
        
        // Get existing definitions
        var definitions = { achievements: [] };
        
        try {
            var records = nk.storageRead([{
                collection: ACHIEVEMENT_COLLECTION,
                key: definitionsKey,
                userId: "00000000-0000-0000-0000-000000000000"
            }]);
            
            if (records && records.length > 0 && records[0].value) {
                definitions = records[0].value;
            }
        } catch (err) {
            logger.debug("[Achievements] Creating new definitions collection");
        }
        
        // Check if achievement already exists
        for (var i = 0; i < definitions.achievements.length; i++) {
            if (definitions.achievements[i].achievement_id === data.achievement_id) {
                throw Error("Achievement already exists: " + data.achievement_id);
            }
        }
        
        // Create achievement definition
        var achievement = {
            achievement_id: data.achievement_id,
            game_id: gameId,
            title: data.title,
            description: data.description || "",
            icon_url: data.icon_url || "default_icon.png",
            rarity: data.rarity || "common",
            category: data.category || "general",
            type: data.type || "simple",
            target: data.target || 1,
            rewards: data.rewards || { coins: 100, xp: 50 },
            created_at: new Date().toISOString(),
            updated_at: new Date().toISOString(),
            hidden: data.hidden || false,
            points: data.points || 10
        };
        
        definitions.achievements.push(achievement);
        
        // Save definitions
        nk.storageWrite([{
            collection: ACHIEVEMENT_COLLECTION,
            key: definitionsKey,
            userId: "00000000-0000-0000-0000-000000000000",
            value: definitions,
            permissionRead: 2,
            permissionWrite: 0
        }]);
        
        logger.info("[Achievements] Created definition: " + data.achievement_id);
        
        return JSON.stringify({
            success: true,
            achievement: achievement
        });
        
    } catch (err) {
        logger.error("[Achievements] Create definition error: " + err.message);
        return JSON.stringify({
            success: false,
            error: err.message
        });
    }
};

/**
 * RPC: achievements_bulk_create (Admin only)
 * Create multiple achievement definitions at once
 */
var rpcAchievementsBulkCreate = function(ctx, logger, nk, payload) {
    try {
        if (typeof RpcHelpers !== 'undefined' && RpcHelpers && RpcHelpers.requireAdmin) {
            RpcHelpers.requireAdmin(ctx, nk);
        } else {
            if (ctx.userId) {
                var _accts = nk.accountsGetId([ctx.userId]);
                var _isAdmin = false;
                if (_accts && _accts.length > 0) {
                    var _meta = _accts[0].user.metadata;
                    if (_meta && _meta.admin === true) _isAdmin = true;
                }
                if (!_isAdmin) throw Error("Admin access required");
            }
        }

        var data = JSON.parse(payload || '{}');
        
        if (!data.game_id || !data.achievements || !Array.isArray(data.achievements)) {
            throw Error("game_id and achievements array are required");
        }
        
        var gameId = data.game_id;
        var achievementsToCreate = data.achievements;
        var definitionsKey = "definitions_" + gameId;
        
        // Get existing definitions
        var definitions = { achievements: [] };
        
        try {
            var records = nk.storageRead([{
                collection: ACHIEVEMENT_COLLECTION,
                key: definitionsKey,
                userId: "00000000-0000-0000-0000-000000000000"
            }]);
            
            if (records && records.length > 0 && records[0].value) {
                definitions = records[0].value;
            }
        } catch (err) {
            logger.debug("[Achievements] Creating new definitions collection");
        }
        
        var created = [];
        var errors = [];
        
        for (var i = 0; i < achievementsToCreate.length; i++) {
            var achData = achievementsToCreate[i];
            
            try {
                if (!achData.achievement_id || !achData.title) {
                    throw Error("achievement_id and title are required");
                }
                
                // Check if already exists
                var exists = false;
                for (var j = 0; j < definitions.achievements.length; j++) {
                    if (definitions.achievements[j].achievement_id === achData.achievement_id) {
                        exists = true;
                        break;
                    }
                }
                
                if (exists) {
                    throw Error("Achievement already exists: " + achData.achievement_id);
                }
                
                var achievement = {
                    achievement_id: achData.achievement_id,
                    game_id: gameId,
                    title: achData.title,
                    description: achData.description || "",
                    icon_url: achData.icon_url || "default_icon.png",
                    rarity: achData.rarity || "common",
                    category: achData.category || "general",
                    type: achData.type || "simple",
                    target: achData.target || 1,
                    rewards: achData.rewards || { coins: 100, xp: 50 },
                    created_at: new Date().toISOString(),
                    updated_at: new Date().toISOString(),
                    hidden: achData.hidden || false,
                    points: achData.points || 10
                };
                
                definitions.achievements.push(achievement);
                created.push(achievement.achievement_id);
                
            } catch (err) {
                errors.push({
                    achievement_id: achData.achievement_id,
                    error: err.message
                });
            }
        }
        
        // Save definitions if any were created
        if (created.length > 0) {
            nk.storageWrite([{
                collection: ACHIEVEMENT_COLLECTION,
                key: definitionsKey,
                userId: "00000000-0000-0000-0000-000000000000",
                value: definitions,
                permissionRead: 2,
                permissionWrite: 0
            }]);
        }
        
        logger.info("[Achievements] Bulk create completed: " + created.length + " created, " + errors.length + " errors");
        
        return JSON.stringify({
            success: true,
            created: created,
            total_created: created.length,
            errors: errors,
            total_errors: errors.length
        });
        
    } catch (err) {
        logger.error("[Achievements] Bulk create error: " + err.message);
        return JSON.stringify({
            success: false,
            error: err.message
        });
    }
};


// --- Module: ai_player\ai_player.js ---
// ai_player.js - Player-Facing AI Features powered by LLM
// Supports: Claude (Anthropic), OpenAI (GPT), xAI (Grok)
// RPCs: ai_coach_advice, ai_match_recap, ai_player_journey, ai_rival_taunt,
//       ai_trivia_generate, ai_daily_briefing, ai_group_hype

// ============================================================================
// LLM CLIENT INFRASTRUCTURE
// ============================================================================

var LLM_PROVIDERS = {
    claude: {
        url: 'https://api.anthropic.com/v1/messages',
        model: 'claude-sonnet-4-20250514',
        envKey: 'ANTHROPIC_API_KEY'
    },
    openai: {
        url: 'https://api.openai.com/v1/chat/completions',
        model: 'gpt-4o-mini',
        envKey: 'OPENAI_API_KEY'
    },
    xai: {
        url: 'https://api.x.ai/v1/chat/completions',
        model: 'grok-3-mini',
        envKey: 'XAI_API_KEY'
    }
};

function getActiveProvider(ctx) {
    var preferred = (ctx.env && ctx.env['LLM_PROVIDER']) || 'claude';
    var provider = LLM_PROVIDERS[preferred];
    if (!provider) provider = LLM_PROVIDERS.claude;

    var apiKey = ctx.env ? ctx.env[provider.envKey] : null;
    if (!apiKey) {
        for (var name in LLM_PROVIDERS) {
            var p = LLM_PROVIDERS[name];
            var k = ctx.env ? ctx.env[p.envKey] : null;
            if (k) return { name: name, config: p, apiKey: k };
        }
        return null;
    }
    return { name: preferred, config: provider, apiKey: apiKey };
}

function callLLM(nk, logger, ctx, systemPrompt, userMessage, maxTokens) {
    var provider = getActiveProvider(ctx);
    if (!provider) {
        return { success: false, error: 'No LLM API key configured. Set ANTHROPIC_API_KEY, OPENAI_API_KEY, or XAI_API_KEY.' };
    }

    maxTokens = maxTokens || 500;

    try {
        var response;
        if (provider.name === 'claude') {
            response = nk.httpRequest(provider.config.url, 'post', {
                'Content-Type': 'application/json',
                'x-api-key': provider.apiKey,
                'anthropic-version': '2023-06-01'
            }, JSON.stringify({
                model: provider.config.model,
                max_tokens: maxTokens,
                system: systemPrompt,
                messages: [{ role: 'user', content: userMessage }]
            }));
        } else {
            response = nk.httpRequest(provider.config.url, 'post', {
                'Content-Type': 'application/json',
                'Authorization': 'Bearer ' + provider.apiKey
            }, JSON.stringify({
                model: provider.config.model,
                max_tokens: maxTokens,
                messages: [
                    { role: 'system', content: systemPrompt },
                    { role: 'user', content: userMessage }
                ]
            }));
        }

        if (response.code !== 200) {
            logger.error('[AI] LLM API returned ' + response.code + ': ' + response.body);
            return { success: false, error: 'LLM API error: ' + response.code };
        }

        var parsed = JSON.parse(response.body);
        var text = '';

        if (provider.name === 'claude') {
            text = parsed.content && parsed.content[0] ? parsed.content[0].text : '';
        } else {
            text = parsed.choices && parsed.choices[0] ? parsed.choices[0].message.content : '';
        }

        return { success: true, text: text, provider: provider.name, model: provider.config.model };

    } catch (err) {
        logger.error('[AI] LLM call failed: ' + err.message);
        return { success: false, error: 'LLM call failed: ' + err.message };
    }
}

// ============================================================================
// DATA GATHERING HELPERS
// ============================================================================

function gatherPlayerContext(nk, logger, userId, gameId) {
    var context = { userId: userId, gameId: gameId };

    try {
        var accounts = nk.accountGetId(userId);
        if (accounts) {
            context.username = accounts.user.username || 'Player';
            context.displayName = accounts.user.displayName || context.username;
            context.createTime = accounts.user.createTime;
        }
    } catch (e) { context.username = 'Player'; }

    try {
        var wallet = nk.walletLedgerList(userId, 10);
        if (wallet && wallet.items) {
            context.recentTransactions = wallet.items.length;
        }
    } catch (e) { /* no wallet data */ }

    try {
        var streakKey = gameId + '_user_daily_streak_' + userId;
        var streakRecords = nk.storageRead([{ collection: 'daily_streaks', key: streakKey, userId: userId }]);
        if (streakRecords && streakRecords.length > 0) {
            context.streak = streakRecords[0].value;
        }
    } catch (e) { /* no streak */ }

    try {
        var altKey = 'user_daily_streak_' + userId + '_' + gameId;
        if (!context.streak) {
            var altRecords = nk.storageRead([{ collection: 'daily_streaks', key: altKey, userId: userId }]);
            if (altRecords && altRecords.length > 0) context.streak = altRecords[0].value;
        }
    } catch (e) { /* no streak */ }

    try {
        var quizRecords = nk.storageList(userId, 'quiz_results', 10, '');
        var items = quizRecords;
        if (typeof quizRecords === 'object' && quizRecords.objects) items = quizRecords.objects;
        if (items && items.length > 0) {
            var scores = [];
            for (var i = 0; i < items.length; i++) {
                if (items[i].value) scores.push(items[i].value);
            }
            context.recentQuizzes = scores;
        }
    } catch (e) { /* no quiz data */ }

    try {
        var achieveRecords = nk.storageList(userId, 'achievements', 10, '');
        var aItems = achieveRecords;
        if (typeof achieveRecords === 'object' && achieveRecords.objects) aItems = achieveRecords.objects;
        if (aItems && aItems.length > 0) {
            context.achievements = [];
            for (var a = 0; a < aItems.length; a++) {
                if (aItems[a].value && aItems[a].value.name) {
                    context.achievements.push(aItems[a].value.name);
                }
            }
        }
    } catch (e) { /* no achievements */ }

    try {
        var metaRecords = nk.storageRead([{
            collection: 'player_metadata',
            key: 'user_identity',
            userId: userId
        }]);
        if (metaRecords && metaRecords.length > 0 && metaRecords[0].value) {
            var meta = metaRecords[0].value;
            context.totalSessions = meta.totalSessions || 0;
            context.level = meta.level || 1;
            context.favoriteCategory = meta.favoriteCategory || null;
        }
    } catch (e) { /* no metadata */ }

    return context;
}

function gatherRivalContext(nk, logger, userId, rivalId) {
    var context = { userId: userId, rivalId: rivalId };

    try {
        var userAccount = nk.accountGetId(userId);
        context.username = userAccount.user.username || 'Player';
    } catch (e) { context.username = 'Player'; }

    try {
        var rivalAccount = nk.accountGetId(rivalId);
        context.rivalUsername = rivalAccount.user.username || 'Rival';
    } catch (e) { context.rivalUsername = 'Rival'; }

    return context;
}

// ============================================================================
// RPC: ai_coach_advice
// ============================================================================

function rpcAiCoachAdvice(ctx, logger, nk, payload) {
    logger.info('[AI] ai_coach_advice called');
    try {
        if (!ctx.userId) return JSON.stringify({ success: false, error: 'Authentication required' });

        var data = JSON.parse(payload || '{}');
        var gameId = data.game_id || 'default';
        var topic = data.topic || 'general';

        var context = gatherPlayerContext(nk, logger, ctx.userId, gameId);

        var systemPrompt = 'You are a fun, encouraging game coach inside a mobile game. ' +
            'You have access to the player\'s actual game data. Give short, actionable advice (2-3 sentences max). ' +
            'Be specific to their data. Use a casual, energetic tone with occasional emojis. ' +
            'Never be condescending. If they\'re doing great, hype them up. If struggling, give one concrete tip.';

        var userMsg = 'Player: ' + context.username + '\n' +
            'Game: ' + gameId + '\n' +
            'Topic: ' + topic + '\n' +
            'Current streak: ' + (context.streak ? context.streak.currentStreak + ' days' : 'none yet') + '\n' +
            'Total sessions: ' + (context.totalSessions || 'unknown') + '\n' +
            'Level: ' + (context.level || 1) + '\n' +
            'Recent quizzes: ' + (context.recentQuizzes ? context.recentQuizzes.length + ' played' : 'none') + '\n' +
            'Achievements: ' + (context.achievements ? context.achievements.join(', ') : 'none yet') + '\n' +
            'Favorite category: ' + (context.favoriteCategory || 'not set') + '\n' +
            '\nGive coaching advice for this player.';

        var result = callLLM(nk, logger, ctx, systemPrompt, userMsg, 300);

        if (!result.success) return JSON.stringify(result);

        nk.storageWrite([{
            collection: 'ai_interactions',
            key: 'coach_' + ctx.userId + '_' + Date.now(),
            userId: ctx.userId,
            value: { type: 'coach', topic: topic, response_length: result.text.length, provider: result.provider, timestamp: new Date().toISOString() },
            permissionRead: 1, permissionWrite: 0
        }]);

        return JSON.stringify({
            success: true,
            advice: result.text,
            topic: topic,
            provider: result.provider,
            player_context: {
                streak: context.streak ? context.streak.currentStreak : 0,
                level: context.level || 1,
                sessions: context.totalSessions || 0
            }
        });

    } catch (err) {
        logger.error('[AI] ai_coach_advice error: ' + err.message);
        logRpcError(nk, logger, 'ai_coach_advice', err.message, ctx.userId, null);
        return JSON.stringify({ success: false, error: err.message });
    }
}

// ============================================================================
// RPC: ai_match_recap
// ============================================================================

function rpcAiMatchRecap(ctx, logger, nk, payload) {
    logger.info('[AI] ai_match_recap called');
    try {
        if (!ctx.userId) return JSON.stringify({ success: false, error: 'Authentication required' });

        var data = JSON.parse(payload || '{}');
        var gameId = data.game_id || 'default';
        var matchData = data.match_data || {};

        var context = gatherPlayerContext(nk, logger, ctx.userId, gameId);

        var systemPrompt = 'You are a sports-style commentator generating exciting post-match recaps for a mobile game. ' +
            'Write like a highlight reel narrator — dramatic, fun, personal. 3-4 sentences max. ' +
            'Reference specific stats from the match. Make the player feel like the main character. ' +
            'Use their name. Add flair.';

        var userMsg = 'Player: ' + context.username + '\n' +
            'Match data: ' + JSON.stringify(matchData) + '\n' +
            'Player streak: ' + (context.streak ? context.streak.currentStreak + ' days' : 'fresh start') + '\n' +
            'Player level: ' + (context.level || 1) + '\n' +
            '\nGenerate an exciting match recap.';

        var result = callLLM(nk, logger, ctx, systemPrompt, userMsg, 400);

        if (!result.success) return JSON.stringify(result);

        nk.storageWrite([{
            collection: 'ai_interactions',
            key: 'recap_' + ctx.userId + '_' + Date.now(),
            userId: ctx.userId,
            value: { type: 'recap', game_id: gameId, provider: result.provider, timestamp: new Date().toISOString() },
            permissionRead: 1, permissionWrite: 0
        }]);

        return JSON.stringify({
            success: true,
            recap: result.text,
            provider: result.provider,
            match_data: matchData
        });

    } catch (err) {
        logger.error('[AI] ai_match_recap error: ' + err.message);
        logRpcError(nk, logger, 'ai_match_recap', err.message, ctx.userId, null);
        return JSON.stringify({ success: false, error: err.message });
    }
}

// ============================================================================
// RPC: ai_player_journey
// ============================================================================

function rpcAiPlayerJourney(ctx, logger, nk, payload) {
    logger.info('[AI] ai_player_journey called');
    try {
        if (!ctx.userId) return JSON.stringify({ success: false, error: 'Authentication required' });

        var data = JSON.parse(payload || '{}');
        var gameId = data.game_id || 'default';

        var context = gatherPlayerContext(nk, logger, ctx.userId, gameId);

        var systemPrompt = 'You are a master storyteller narrating a player\'s gaming journey as an epic tale. ' +
            'Turn their stats and achievements into a dramatic narrative — like the opening crawl of a movie about THEM. ' +
            'Reference real data (their streak, level, achievements, time played). ' +
            'Make it personal, emotional, and make them feel their journey matters. 4-5 sentences. ' +
            'Write in second person ("You"). End with something forward-looking.';

        var daysSinceJoin = 'unknown';
        if (context.createTime) {
            var joinDate = new Date(context.createTime);
            var now = new Date();
            daysSinceJoin = Math.floor((now - joinDate) / (1000 * 60 * 60 * 24));
        }

        var userMsg = 'Player: ' + context.username + '\n' +
            'Days since joining: ' + daysSinceJoin + '\n' +
            'Current streak: ' + (context.streak ? context.streak.currentStreak + ' days' : '0') + '\n' +
            'Total claims: ' + (context.streak ? context.streak.totalClaims : 0) + '\n' +
            'Level: ' + (context.level || 1) + '\n' +
            'Total sessions: ' + (context.totalSessions || 0) + '\n' +
            'Achievements: ' + (context.achievements ? context.achievements.join(', ') : 'none yet') + '\n' +
            'Recent quizzes: ' + (context.recentQuizzes ? context.recentQuizzes.length : 0) + '\n' +
            'Favorite category: ' + (context.favoriteCategory || 'exploring everything') + '\n' +
            '\nNarrate their epic journey.';

        var result = callLLM(nk, logger, ctx, systemPrompt, userMsg, 500);

        if (!result.success) return JSON.stringify(result);

        nk.storageWrite([{
            collection: 'ai_interactions',
            key: 'journey_' + ctx.userId + '_' + Date.now(),
            userId: ctx.userId,
            value: { type: 'journey', game_id: gameId, provider: result.provider, timestamp: new Date().toISOString() },
            permissionRead: 1, permissionWrite: 0
        }]);

        return JSON.stringify({
            success: true,
            journey: result.text,
            provider: result.provider,
            stats: {
                days_since_join: daysSinceJoin,
                streak: context.streak ? context.streak.currentStreak : 0,
                level: context.level || 1,
                achievements_count: context.achievements ? context.achievements.length : 0
            }
        });

    } catch (err) {
        logger.error('[AI] ai_player_journey error: ' + err.message);
        logRpcError(nk, logger, 'ai_player_journey', err.message, ctx.userId, null);
        return JSON.stringify({ success: false, error: err.message });
    }
}

