var CHAR_STORAGE_COLLECTION = 'player_data';

// ─── HELPERS ────────────────────────────────────────────────────────────────

function charStorageKey(userId, gameId) {
    return 'characters_' + userId + '_' + gameId;
}

function readCharacterData(nk, logger, userId, gameId) {
    try {
        var records = nk.storageRead([{
            collection: CHAR_STORAGE_COLLECTION,
            key: charStorageKey(userId, gameId),
            userId: userId
        }]);
        if (records && records.length > 0 && records[0].value) {
            return records[0].value;
        }
    } catch (err) {
        logger.warn('[Characters] Storage read failed: ' + err.message);
    }
    return null;
}

function writeCharacterData(nk, logger, userId, gameId, data) {
    try {
        nk.storageWrite([{
            collection: CHAR_STORAGE_COLLECTION,
            key: charStorageKey(userId, gameId),
            userId: userId,
            value: data,
            permissionRead: 1,
            permissionWrite: 0
        }]);
        return true;
    } catch (err) {
        logger.error('[Characters] Storage write failed: ' + err.message);
        return false;
    }
}

function initCharacterData(userId) {
    var now = new Date().toISOString();
    return {
        activeCharacter: 'quizzy',
        unlockedCharacters: {
            quizzy: { unlockedAt: now },
            autocurio: { unlockedAt: now }
        },
        totalXpFromUnlocks: 0,
        createdAt: now,
        updatedAt: now
    };
}

function charErrorResponse(msg) {
    return JSON.stringify({ success: false, error: msg });
}

function charValidatePayload(payload) {
    if (!payload || payload === '') return {};
    try {
        return JSON.parse(payload);
    } catch (err) {
        return null;
    }
}

// ─── RPC: character_get_state ───────────────────────────────────────────────

function rpcCharacterGetState(ctx, logger, nk, payload) {
    if (!ctx.userId) return charErrorResponse('User not authenticated');

    var data = charValidatePayload(payload);
    if (data === null) return charErrorResponse('Invalid JSON payload');

    var gameId = data.gameId || 'quizverse';
    var charData = readCharacterData(nk, logger, ctx.userId, gameId);

    if (!charData) {
        charData = initCharacterData(ctx.userId);
        writeCharacterData(nk, logger, ctx.userId, gameId, charData);
    }

    // Auto-migrate: grant default characters to existing players
    var dirty = false;
    for (var defId in CHARACTER_DEFS) {
        if (CHARACTER_DEFS[defId].unlockCondition === 'default') {
            if (!charData.unlockedCharacters[defId]) {
                charData.unlockedCharacters[defId] = { unlockedAt: new Date().toISOString() };
                dirty = true;
            }
        }
    }
    if (dirty) {
        charData.updatedAt = new Date().toISOString();
        writeCharacterData(nk, logger, ctx.userId, gameId, charData);
    }

    // Build characters array with unlock status
    var characters = [];
    for (var charId in CHARACTER_DEFS) {
        var def = CHARACTER_DEFS[charId];
        var isUnlocked = charData.unlockedCharacters && charData.unlockedCharacters[charId];

        characters.push({
            id: def.id,
            name: def.name,
            description: def.description,
            rarity: def.rarity,
            xpBonus: def.xpBonus,
            unlocked: !!isUnlocked,
            unlockedAt: isUnlocked ? charData.unlockedCharacters[charId].unlockedAt : null,
            unlockCondition: isUnlocked ? null : def.unlockCondition,
            introVideoPath: def.introVideoPath
        });
    }

    return JSON.stringify({
        success: true,
        userId: ctx.userId,
        gameId: gameId,
        activeCharacter: charData.activeCharacter,
        characters: characters,
        totalUnlocked: Object.keys(charData.unlockedCharacters || {}).length,
        totalCharacters: Object.keys(CHARACTER_DEFS).length,
        totalXpFromUnlocks: charData.totalXpFromUnlocks || 0,
        timestamp: new Date().toISOString()
    });
}

// ─── RPC: character_unlock ──────────────────────────────────────────────────

function rpcCharacterUnlock(ctx, logger, nk, payload) {
    if (!ctx.userId) return charErrorResponse('User not authenticated');

    var data = charValidatePayload(payload);
    if (data === null) return charErrorResponse('Invalid JSON payload');

    var gameId = data.gameId || 'quizverse';
    var characterId = data.characterId;

    if (!characterId) return charErrorResponse('Missing required field: characterId');

    var def = CHARACTER_DEFS[characterId];
    if (!def) return charErrorResponse('Character not found: ' + characterId);

    var charData = readCharacterData(nk, logger, ctx.userId, gameId);
    if (!charData) {
        charData = initCharacterData(ctx.userId);
    }

    // Check if already unlocked
    if (charData.unlockedCharacters && charData.unlockedCharacters[characterId]) {
        return JSON.stringify({
            success: false,
            error: 'already_unlocked',
            characterId: characterId,
            unlockedAt: charData.unlockedCharacters[characterId].unlockedAt
        });
    }

    // NOTE: Unlock condition validation should be done client-side or via a separate check.
    // The server trusts that the client has verified the condition (badges, league tier, streak).
    // For critical conditions, add server-side validation here by reading badge/league/streak storage.

    var now = new Date().toISOString();
    var xpAwarded = def.xpRewardOnUnlock || 0;

    // Unlock character
    if (!charData.unlockedCharacters) charData.unlockedCharacters = {};
    charData.unlockedCharacters[characterId] = { unlockedAt: now };
    charData.totalXpFromUnlocks = (charData.totalXpFromUnlocks || 0) + xpAwarded;
    charData.updatedAt = now;

    // Rule#7: Award XP ONLY, never currency
    // XP is tracked in metadata, not wallet
    if (xpAwarded > 0) {
        try {
            // Update player metadata with XP
            var account = nk.accountGetId(ctx.userId);
            if (account) {
                var metadata = {};
                try {
                    metadata = JSON.parse(account.user.metadata || '{}');
                } catch (e) { metadata = {}; }

                metadata.totalXp = (metadata.totalXp || 0) + xpAwarded;
                metadata.lastXpSource = 'character_unlock_' + characterId;
                metadata.lastXpAt = now;

                nk.accountUpdateId(ctx.userId, null, null, null, null, null, null, null, JSON.stringify(metadata));
            }
        } catch (xpErr) {
            logger.warn('[Characters] XP update failed for ' + ctx.userId + ': ' + xpErr.message);
            // Non-critical — character is still unlocked
        }
    }

    if (!writeCharacterData(nk, logger, ctx.userId, gameId, charData)) {
        return charErrorResponse('Failed to save character data');
    }

    logger.info('[Characters] ' + characterId + ' unlocked for ' + ctx.userId + ' (+' + xpAwarded + ' XP)');

    return JSON.stringify({
        success: true,
        characterId: characterId,
        name: def.name,
        rarity: def.rarity,
        xpBonus: def.xpBonus,
        xpAwarded: xpAwarded,
        introVideoPath: def.introVideoPath,
        totalUnlocked: Object.keys(charData.unlockedCharacters).length,
        totalCharacters: Object.keys(CHARACTER_DEFS).length,
        timestamp: now
    });
}

// ─── RPC: character_set_active ──────────────────────────────────────────────

function rpcCharacterSetActive(ctx, logger, nk, payload) {
    if (!ctx.userId) return charErrorResponse('User not authenticated');

    var data = charValidatePayload(payload);
    if (data === null) return charErrorResponse('Invalid JSON payload');

    var gameId = data.gameId || 'quizverse';
    var characterId = data.characterId;

    if (!characterId) return charErrorResponse('Missing required field: characterId');

    var def = CHARACTER_DEFS[characterId];
    if (!def) return charErrorResponse('Character not found: ' + characterId);

    var charData = readCharacterData(nk, logger, ctx.userId, gameId);
    if (!charData) {
        charData = initCharacterData(ctx.userId);
    }

    // Must be unlocked
    if (!charData.unlockedCharacters || !charData.unlockedCharacters[characterId]) {
        return charErrorResponse('Character not unlocked: ' + characterId);
    }

    // Already active?
    if (charData.activeCharacter === characterId) {
        return JSON.stringify({
            success: true,
            activeCharacter: characterId,
            alreadyActive: true
        });
    }

    var previousCharacter = charData.activeCharacter;
    charData.activeCharacter = characterId;
    charData.updatedAt = new Date().toISOString();

    if (!writeCharacterData(nk, logger, ctx.userId, gameId, charData)) {
        return charErrorResponse('Failed to save character data');
    }

    // Also update player metadata for quick access
    try {
        var account = nk.accountGetId(ctx.userId);
        if (account) {
            var metadata = {};
            try {
                metadata = JSON.parse(account.user.metadata || '{}');
            } catch (e) { metadata = {}; }
            metadata.activeCharacter = characterId;
            metadata.activeCharacterXpBonus = def.xpBonus;
            nk.accountUpdateId(ctx.userId, null, null, null, null, null, null, null, JSON.stringify(metadata));
        }
    } catch (metaErr) {
        logger.warn('[Characters] Metadata update failed: ' + metaErr.message);
    }

    logger.info('[Characters] ' + ctx.userId + ' switched character: ' + previousCharacter + ' → ' + characterId);

    return JSON.stringify({
        success: true,
        activeCharacter: characterId,
        previousCharacter: previousCharacter,
        xpBonus: def.xpBonus,
        timestamp: new Date().toISOString()
    });
}


// --- Module: chat_moderation\chat_moderation.js ---
// chat_moderation.js - Chat Moderation Pipeline
// Storage collection: chat_reports, chat_filter_config
// RPCs: chat_report_message, chat_moderation_review, chat_moderation_stats

var PROFANITY_WORDS = [
    "fuck", "shit", "ass", "bitch", "dick", "cunt", "damn", "bastard",
    "nigger", "nigga", "faggot", "retard", "whore", "slut",
    "kill yourself", "kys", "die", "rape"
];

var SPAM_PATTERNS = [
    /(.)\1{5,}/,
    /https?:\/\/[^\s]+/,
    /\b(free|cheap|buy now|click here|subscribe)\b/i
];

var MODERATION_CONFIG = {
    max_reports_before_auto_mute: 5,
    report_cooldown_seconds: 60,
    auto_filter_enabled: true,
    max_message_length: 1000
};

/**
 * Check a message against the profanity word list.
 * Returns { flagged: bool, matched_words: string[], severity: string }
 */
function checkProfanity(text) {
    var lower = text.toLowerCase();
    var matched = [];

    for (var i = 0; i < PROFANITY_WORDS.length; i++) {
        if (lower.indexOf(PROFANITY_WORDS[i]) !== -1) {
            matched.push(PROFANITY_WORDS[i]);
        }
    }

    var severity = 'clean';
    if (matched.length > 0) severity = 'mild';
    if (matched.length >= 3) severity = 'severe';

    for (var j = 0; j < matched.length; j++) {
        var w = matched[j];
        if (w === 'nigger' || w === 'nigga' || w === 'faggot' || w === 'kill yourself' || w === 'kys' || w === 'rape') {
            severity = 'severe';
            break;
        }
    }

    return { flagged: matched.length > 0, matched_words: matched, severity: severity };
}

/**
 * Check a message for spam patterns.
 */
function checkSpam(text) {
    var flags = [];
    for (var i = 0; i < SPAM_PATTERNS.length; i++) {
        if (SPAM_PATTERNS[i].test(text)) {
            flags.push('spam_pattern_' + i);
        }
    }
    if (text.length > MODERATION_CONFIG.max_message_length) {
        flags.push('message_too_long');
    }
    return { flagged: flags.length > 0, flags: flags };
}

/**
 * Filter a message by replacing profanity with asterisks.
 * Returns the filtered text.
 */
function filterMessage(text) {
    var filtered = text;
    for (var i = 0; i < PROFANITY_WORDS.length; i++) {
        var word = PROFANITY_WORDS[i];
        var replacement = '';
        for (var c = 0; c < word.length; c++) replacement += '*';
        var regex = new RegExp(word.replace(/[.*+?^${}()|[\]\\]/g, '\\$&'), 'gi');
        filtered = filtered.replace(regex, replacement);
    }
    return filtered;
}

/**
 * RPC: chat_report_message
 * Report a chat message as inappropriate.
 */
function rpcChatReportMessage(ctx, logger, nk, payload) {
    logger.info('[Moderation] chat_report_message called');

    try {
        if (!ctx.userId) {
            return JSON.stringify({ success: false, error: 'Authentication required' });
        }

        var data = JSON.parse(payload || '{}');

        if (!data.message_id || !data.reason) {
            return JSON.stringify({
                success: false,
                error: 'message_id and reason are required'
            });
        }

        var reporterId = ctx.userId;
        var messageId = data.message_id;
        var reason = data.reason;
        var channelType = data.channel_type || 'unknown';
        var channelId = data.channel_id || '';
        var reportedUserId = data.reported_user_id || '';
        var messageContent = data.message_content || '';
        var additionalInfo = data.additional_info || '';

        // Check reporter hasn't spammed reports (cooldown)
        var recentReports = nk.storageList(reporterId, 'chat_reports_by_reporter', 10, '');
        var allRecent = recentReports;
        if (typeof recentReports === 'object' && recentReports.objects) {
            allRecent = recentReports.objects;
        }
        var nowMs = Date.now();
        if (allRecent && allRecent.length > 0) {
            var lastReport = allRecent[allRecent.length - 1];
            if (lastReport && lastReport.value && lastReport.value.created_at_unix) {
                var elapsed = (nowMs - lastReport.value.created_at_unix) / 1000;
                if (elapsed < MODERATION_CONFIG.report_cooldown_seconds) {
                    return JSON.stringify({
                        success: false,
                        error: 'Report cooldown active. Wait ' + Math.ceil(MODERATION_CONFIG.report_cooldown_seconds - elapsed) + 's.'
                    });
                }
            }
        }

        // Run automated checks on the reported content
        var profanityCheck = messageContent ? checkProfanity(messageContent) : { flagged: false, matched_words: [], severity: 'unknown' };
        var spamCheck = messageContent ? checkSpam(messageContent) : { flagged: false, flags: [] };

        var reportId = 'report_' + reporterId.slice(0, 8) + '_' + nowMs;
        var reportData = {
            report_id: reportId,
            message_id: messageId,
            channel_type: channelType,
            channel_id: channelId,
            reporter_id: reporterId,
            reporter_username: ctx.username || 'Unknown',
            reported_user_id: reportedUserId,
            message_content: messageContent,
            reason: reason,
            additional_info: additionalInfo,
            auto_analysis: {
                profanity: profanityCheck,
                spam: spamCheck
            },
            status: 'pending',
            created_at: new Date().toISOString(),
            created_at_unix: nowMs,
            reviewed_at: null,
            reviewed_by: null,
            action_taken: null
        };

        // Auto-escalate severe content
        if (profanityCheck.severity === 'severe') {
            reportData.status = 'auto_flagged_severe';
        }

        // Write to system-owned reports collection
        nk.storageWrite([{
            collection: 'chat_reports',
            key: reportId,
            userId: '00000000-0000-0000-0000-000000000000',
            value: reportData,
            permissionRead: 1,
            permissionWrite: 0
        }]);

        // Track per-reporter (for cooldown / abuse detection)
        nk.storageWrite([{
            collection: 'chat_reports_by_reporter',
            key: reportId,
            userId: reporterId,
            value: { report_id: reportId, created_at_unix: nowMs },
            permissionRead: 1,
            permissionWrite: 0
        }]);

        // Count total reports against the reported user
        if (reportedUserId) {
            var userReportCountKey = 'report_count_' + reportedUserId;
            var existing = null;
            try {
                var countRecords = nk.storageRead([{
                    collection: 'chat_moderation_user_stats',
                    key: userReportCountKey,
                    userId: '00000000-0000-0000-0000-000000000000'
                }]);
                if (countRecords && countRecords.length > 0) {
                    existing = countRecords[0].value;
                }
            } catch (e) { /* first report */ }

            var totalReports = (existing ? existing.total_reports : 0) + 1;
            var autoMuted = existing ? existing.auto_muted : false;

            if (totalReports >= MODERATION_CONFIG.max_reports_before_auto_mute && !autoMuted) {
                autoMuted = true;
                reportData.action_taken = 'auto_muted';
                logger.warn('[Moderation] Auto-muted user ' + reportedUserId + ' after ' + totalReports + ' reports');
            }

            nk.storageWrite([{
                collection: 'chat_moderation_user_stats',
                key: userReportCountKey,
                userId: '00000000-0000-0000-0000-000000000000',
                value: {
                    user_id: reportedUserId,
                    total_reports: totalReports,
                    auto_muted: autoMuted,
                    last_report_at: new Date().toISOString()
                },
                permissionRead: 1,
                permissionWrite: 0
            }]);
        }

        logger.info('[Moderation] Report created: ' + reportId);

        return JSON.stringify({
            success: true,
            report_id: reportId,
            auto_analysis: reportData.auto_analysis,
            status: reportData.status,
            action_taken: reportData.action_taken
        });

    } catch (err) {
        logger.error('[Moderation] chat_report_message error: ' + err.message);
        logRpcError(nk, logger, 'chat_report_message', err.message, ctx.userId, null);
        return JSON.stringify({ success: false, error: err.message });
    }
}

/**
 * RPC: chat_moderation_review
 * Admin-only: Review pending reports and take action.
 */
function rpcChatModerationReview(ctx, logger, nk, payload) {
    logger.info('[Moderation] chat_moderation_review called');

    try {
        var data = JSON.parse(payload || '{}');
        var action = data.action || 'list';

        if (action === 'list') {
            var limit = parseInt(data.limit, 10) || 50;
            var statusFilter = data.status || 'pending';
            var cursor = data.cursor || '';

            var records = nk.storageList('00000000-0000-0000-0000-000000000000', 'chat_reports', limit, cursor);
            var reports = [];
            var nextCursor = '';

            var allRecords = records;
            if (typeof records === 'object' && records.objects) {
                nextCursor = records.cursor || '';
                allRecords = records.objects;
            }

            for (var i = 0; i < allRecords.length; i++) {
                var r = allRecords[i].value;
                if (r && (statusFilter === 'all' || r.status === statusFilter || r.status === 'auto_flagged_severe')) {
                    reports.push(r);
                }
            }

            return JSON.stringify({
                success: true,
                reports: reports,
                count: reports.length,
                cursor: nextCursor
            });
        }

        if (action === 'resolve') {
            if (!data.report_id || !data.resolution) {
                return JSON.stringify({
                    success: false,
                    error: 'report_id and resolution are required for resolve action'
                });
            }

            var reportRecords = nk.storageRead([{
                collection: 'chat_reports',
                key: data.report_id,
                userId: '00000000-0000-0000-0000-000000000000'
            }]);

            if (!reportRecords || reportRecords.length === 0) {
                return JSON.stringify({ success: false, error: 'Report not found' });
            }

            var report = reportRecords[0].value;
            report.status = 'resolved';
            report.reviewed_at = new Date().toISOString();
            report.reviewed_by = ctx.userId || 'admin';
            report.action_taken = data.resolution;
            report.resolution_notes = data.notes || '';

            nk.storageWrite([{
                collection: 'chat_reports',
                key: data.report_id,
                userId: '00000000-0000-0000-0000-000000000000',
                value: report,
                permissionRead: 1,
                permissionWrite: 0
            }]);

            // Execute action if needed
            if (data.resolution === 'ban' && report.reported_user_id) {
                try {
                    nk.usersBanId([report.reported_user_id]);
                    logger.warn('[Moderation] Banned user: ' + report.reported_user_id);
                } catch (banErr) {
                    logger.error('[Moderation] Ban failed: ' + banErr.message);
                }
            }

            return JSON.stringify({
                success: true,
                report_id: data.report_id,
                new_status: 'resolved',
                action_taken: data.resolution
            });
        }

        return JSON.stringify({ success: false, error: 'Unknown action. Use "list" or "resolve".' });

    } catch (err) {
        logger.error('[Moderation] chat_moderation_review error: ' + err.message);
        logRpcError(nk, logger, 'chat_moderation_review', err.message, ctx.userId, null);
        return JSON.stringify({ success: false, error: err.message });
    }
}

/**
 * RPC: chat_moderation_stats
 * Returns moderation statistics: total reports, pending, resolved, top reported users, etc.
 */
function rpcChatModerationStats(ctx, logger, nk, payload) {
    logger.info('[Moderation] chat_moderation_stats called');

    try {
        var records = nk.storageList('00000000-0000-0000-0000-000000000000', 'chat_reports', 100, '');
        var allRecords = records;
        if (typeof records === 'object' && records.objects) {
            allRecords = records.objects;
        }

        var stats = {
            total_reports: 0,
            pending: 0,
            auto_flagged_severe: 0,
            resolved: 0,
            by_reason: {},
            by_channel_type: {},
            top_reported_users: {},
            profanity_detections: 0,
            spam_detections: 0
        };

        for (var i = 0; i < allRecords.length; i++) {
            var r = allRecords[i].value;
            if (!r) continue;

            stats.total_reports++;
            if (r.status === 'pending') stats.pending++;
            else if (r.status === 'auto_flagged_severe') stats.auto_flagged_severe++;
            else if (r.status === 'resolved') stats.resolved++;

            if (r.reason) {
                stats.by_reason[r.reason] = (stats.by_reason[r.reason] || 0) + 1;
            }
            if (r.channel_type) {
                stats.by_channel_type[r.channel_type] = (stats.by_channel_type[r.channel_type] || 0) + 1;
            }
            if (r.reported_user_id) {
                stats.top_reported_users[r.reported_user_id] = (stats.top_reported_users[r.reported_user_id] || 0) + 1;
            }
            if (r.auto_analysis) {
                if (r.auto_analysis.profanity && r.auto_analysis.profanity.flagged) stats.profanity_detections++;
                if (r.auto_analysis.spam && r.auto_analysis.spam.flagged) stats.spam_detections++;
            }
        }

        // Sort top reported users
        var sortedUsers = [];
        for (var uid in stats.top_reported_users) {
            sortedUsers.push({ user_id: uid, reports: stats.top_reported_users[uid] });
        }
        sortedUsers.sort(function(a, b) { return b.reports - a.reports; });
        stats.top_reported_users = sortedUsers.slice(0, 10);

        return JSON.stringify({
            success: true,
            stats: stats
        });

    } catch (err) {
        logger.error('[Moderation] chat_moderation_stats error: ' + err.message);
        logRpcError(nk, logger, 'chat_moderation_stats', err.message, ctx.userId, null);
        return JSON.stringify({ success: false, error: err.message });
    }
}

/**
 * RPC: chat_filter_message
 * Check a message against the word filter before sending.
 * Returns filtered text and flags. Can be called inline by clients before posting.
 */
function rpcChatFilterMessage(ctx, logger, nk, payload) {
    logger.info('[Moderation] chat_filter_message called');

    try {
        var data = JSON.parse(payload || '{}');

        if (!data.message) {
            return JSON.stringify({ success: false, error: 'message is required' });
        }

        var profanityResult = checkProfanity(data.message);
        var spamResult = checkSpam(data.message);
        var filteredText = filterMessage(data.message);

        var allowed = true;
        if (profanityResult.severity === 'severe') allowed = false;
        if (spamResult.flags.length > 2) allowed = false;

        return JSON.stringify({
            success: true,
            original: data.message,
            filtered: filteredText,
            allowed: allowed,
            profanity: profanityResult,
            spam: spamResult
        });

    } catch (err) {
        logger.error('[Moderation] chat_filter_message error: ' + err.message);
        return JSON.stringify({ success: false, error: err.message });
    }
}


// --- Module: copilot\cognito_wallet_mapper.js ---
// cognito_wallet_mapper.js - Core RPC functions for Cognito ↔ Wallet mapping

/**
 * RPC: get_user_wallet
 * Retrieves or creates a wallet for a Cognito user
 * 
 * @param {object} ctx - Nakama context
 * @param {object} logger - Nakama logger
 * @param {object} nk - Nakama runtime
 * @param {string} payload - JSON string with { "token": "<cognito_jwt>" }
 * @returns {string} JSON response with wallet info
 */
function getUserWallet(ctx, logger, nk, payload) {
    try {
        WalletUtils.logWalletOperation(logger, 'get_user_wallet', { payload: payload });
        
        // Parse input
        var input = {};
        if (payload) {
            try {
                input = JSON.parse(payload);
            } catch (err) {
                return JSON.stringify({
                    success: false,
                    error: 'Invalid JSON payload'
                });
            }
        }
        
        var token = input.token;
        
        // If no token provided, try to use ctx.userId (for authenticated Nakama users)
        var userId;
        var username;
        
        if (token) {
            // Validate JWT structure
            if (!WalletUtils.validateJWTStructure(token)) {
                return JSON.stringify({
                    success: false,
                    error: 'Invalid JWT token format'
                });
            }
            
            // Extract user info from Cognito JWT
            var userInfo = WalletUtils.extractUserInfo(token);
            userId = userInfo.sub;
            username = userInfo.username;
            
            WalletUtils.logWalletOperation(logger, 'extracted_user_info', {
                userId: userId,
                username: username
            });
        } else if (ctx.userId) {
            // Fallback to Nakama context user
            userId = ctx.userId;
            username = ctx.username || userId;
            
            WalletUtils.logWalletOperation(logger, 'using_context_user', {
                userId: userId,
                username: username
            });
        } else {
            return JSON.stringify({
                success: false,
                error: 'No token provided and no authenticated user in context'
            });
        }
        
        // Query wallet registry
        var wallet = WalletRegistry.getWalletByUserId(nk, logger, userId);
        
        // Create wallet if not found
        if (!wallet) {
            wallet = WalletRegistry.createWalletRecord(nk, logger, userId, username);
            WalletUtils.logWalletOperation(logger, 'wallet_created', {
                walletId: wallet.walletId
            });
        } else {
            WalletUtils.logWalletOperation(logger, 'wallet_found', {
                walletId: wallet.walletId,
                gamesLinked: wallet.gamesLinked
            });
        }
        
        // Return wallet info
        return JSON.stringify({
            success: true,
            walletId: wallet.walletId,
            userId: wallet.userId,
            status: wallet.status,
            gamesLinked: wallet.gamesLinked || [],
            createdAt: wallet.createdAt
        });
        
    } catch (err) {
        return JSON.stringify(WalletUtils.handleWalletError(logger, 'get_user_wallet', err));
    }
}

/**
 * RPC: link_wallet_to_game
 * Links a wallet to a specific game
 * 
 * @param {object} ctx - Nakama context
 * @param {object} logger - Nakama logger
 * @param {object} nk - Nakama runtime
 * @param {string} payload - JSON string with { "token": "<cognito_jwt>", "gameId": "<game_id>" }
 * @returns {string} JSON response with updated wallet info
 */
function linkWalletToGame(ctx, logger, nk, payload) {
    try {
        WalletUtils.logWalletOperation(logger, 'link_wallet_to_game', { payload: payload });
        
        // Parse input
        var input = {};
        if (payload) {
            try {
                input = JSON.parse(payload);
            } catch (err) {
                return JSON.stringify({
                    success: false,
                    error: 'Invalid JSON payload'
                });
            }
        }
        
        var token = input.token;
        var gameId = input.gameId;
        
        if (!gameId) {
            return JSON.stringify({
                success: false,
                error: 'gameId is required'
            });
        }
        
        // Get user ID from token or context
        var userId;
        var username;
        
        if (token) {
            if (!WalletUtils.validateJWTStructure(token)) {
                return JSON.stringify({
                    success: false,
                    error: 'Invalid JWT token format'
                });
            }
            
            var userInfo = WalletUtils.extractUserInfo(token);
            userId = userInfo.sub;
            username = userInfo.username;
        } else if (ctx.userId) {
            userId = ctx.userId;
            username = ctx.username || userId;
        } else {
            return JSON.stringify({
                success: false,
                error: 'No token provided and no authenticated user in context'
            });
        }
        
        // Ensure wallet exists
        var wallet = WalletRegistry.getWalletByUserId(nk, logger, userId);
        if (!wallet) {
            wallet = WalletRegistry.createWalletRecord(nk, logger, userId, username);
        }
        
        // Link game to wallet
        wallet = WalletRegistry.updateWalletGames(nk, logger, wallet.walletId, gameId);
        
        WalletUtils.logWalletOperation(logger, 'game_linked', {
            walletId: wallet.walletId,
            gameId: gameId,
            totalGames: wallet.gamesLinked.length
        });
        
        return JSON.stringify({
            success: true,
            walletId: wallet.walletId,
            gameId: gameId,
            gamesLinked: wallet.gamesLinked,
            message: 'Game successfully linked to wallet'
        });
        
    } catch (err) {
        return JSON.stringify(WalletUtils.handleWalletError(logger, 'link_wallet_to_game', err));
    }
}

/**
 * RPC: get_wallet_registry
 * Returns all wallets in the registry (admin function)
 * 
 * @param {object} ctx - Nakama context
 * @param {object} logger - Nakama logger
 * @param {object} nk - Nakama runtime
 * @param {string} payload - JSON string with optional { "limit": 100 }
 * @returns {string} JSON response with wallet array
 */
function getWalletRegistry(ctx, logger, nk, payload) {
    try {
        WalletUtils.logWalletOperation(logger, 'get_wallet_registry', { userId: ctx.userId });
        
        // Parse input
        var input = {};
        if (payload) {
            try {
                input = JSON.parse(payload);
            } catch (err) {
                // Ignore parse errors for optional payload
            }
        }
        
        var limit = input.limit || 100;
        
        // Get all wallets
        var wallets = WalletRegistry.getAllWallets(nk, logger, limit);
        
        return JSON.stringify({
            success: true,
            wallets: wallets,
            count: wallets.length
        });
        
    } catch (err) {
        return JSON.stringify(WalletUtils.handleWalletError(logger, 'get_wallet_registry', err));
    }
}


// --- Module: copilot\leaderboard_aggregate.js ---
// leaderboard_aggregate.js - Aggregate scores across all game leaderboards
// ES5 compatible for Nakama goja runtime

function rpcSubmitScoreWithAggregate(ctx, logger, nk, payload) {
    try {
        if (!ctx.userId) {
            return copilotHandleError(ctx, null, "Authentication required");
        }

        var data;
        try {
            data = JSON.parse(payload);
        } catch (err) {
            return copilotHandleError(ctx, err, "Invalid JSON payload");
        }

        var validation = copilotValidatePayload(data, ['gameId', 'score']);
        if (!validation.valid) {
            return copilotHandleError(ctx, null, "Missing required fields: " + validation.missing.join(', '));
        }

        var gameId = data.gameId;
        var individualScore = parseInt(data.score);

        if (isNaN(individualScore)) {
            return copilotHandleError(ctx, null, "Score must be a valid number");
        }

        var userId = ctx.userId;
        var username = ctx.username || userId;
        var submittedAt = new Date().toISOString();

        copilotLogInfo(logger, "Processing aggregate score for user " + username + " in game " + gameId);

        var gameLeaderboardId = "leaderboard_" + gameId;
        var metadata = {
            source: "submit_score_with_aggregate",
            gameId: gameId,
            submittedAt: submittedAt
        };

        try {
            nk.leaderboardRecordWrite(gameLeaderboardId, userId, username, individualScore, 0, metadata);
            copilotLogInfo(logger, "Individual score written to game leaderboard: " + gameLeaderboardId);
        } catch (err) {
            copilotLogError(logger, "Failed to write individual score: " + err.message);
            return copilotHandleError(ctx, err, "Failed to write score to game leaderboard");
        }

        var registry = copilotReadRegistry(nk, logger);
        var gameLeaderboards = [];

        for (var i = 0; i < registry.length; i++) {
            if (registry[i].scope === "game" && registry[i].leaderboardId) {
                gameLeaderboards.push(registry[i].leaderboardId);
            }
        }

        copilotLogInfo(logger, "Found " + gameLeaderboards.length + " game leaderboards in registry");

        var aggregateScore = 0;
        var processedBoards = 0;

        for (var j = 0; j < gameLeaderboards.length; j++) {
            var lbId = gameLeaderboards[j];
            try {
                var records = nk.leaderboardRecordsList(lbId, [userId], 1, null, 0);
                if (records && records.records && records.records.length > 0) {
                    var userScore = records.records[0].score;
                    aggregateScore += userScore;
                    processedBoards++;
                }
            } catch (err) {
                copilotLogInfo(logger, "Skipping leaderboard " + lbId + ": " + err.message);
            }
        }

        copilotLogInfo(logger, "Calculated aggregate score: " + aggregateScore + " from " + processedBoards + " leaderboards");

        var globalLeaderboardId = "leaderboard_global";
        var globalMetadata = {
            source: "submit_score_with_aggregate",
            aggregateScore: aggregateScore,
            individualScore: individualScore,
            gameId: gameId,
            submittedAt: submittedAt
        };

        try {
            nk.leaderboardRecordWrite(globalLeaderboardId, userId, username, aggregateScore, 0, globalMetadata);
            copilotLogInfo(logger, "Aggregate score written to global leaderboard");
        } catch (err) {
            copilotLogError(logger, "Failed to write aggregate score: " + err.message);
            return copilotHandleError(ctx, err, "Failed to write aggregate score to global leaderboard");
        }

        return JSON.stringify({
            success: true,
            gameId: gameId,
            individualScore: individualScore,
            aggregateScore: aggregateScore,
            leaderboardsProcessed: processedBoards
        });

    } catch (err) {
        copilotLogError(logger, "Unexpected error in rpcSubmitScoreWithAggregate: " + err.message);
        return copilotHandleError(ctx, err, "An error occurred while processing your request");
    }
}


// --- Module: copilot\leaderboard_friends.js ---
// leaderboard_friends.js - Friend-specific leaderboard features
// ES5 compatible for Nakama goja runtime

function rpcCreateAllLeaderboardsWithFriends(ctx, logger, nk, payload) {
    try {
        if (!ctx.userId) {
            return copilotHandleError(ctx, null, "Authentication required");
        }

        copilotLogInfo(logger, "Creating friend leaderboards");

        var sort = "desc";
        var operator = "best";
        var resetSchedule = "0 0 * * 0";
        var created = [];
        var skipped = [];

        var globalFriendsId = "leaderboard_friends_global";
        try {
            nk.leaderboardCreate(
                globalFriendsId, true, sort, operator, resetSchedule,
                { scope: "friends_global", desc: "Global Friends Leaderboard" },
                true  // enableRanks (QV_Bug_A8)
            );
            created.push(globalFriendsId);
        } catch (err) {
            skipped.push(globalFriendsId);
        }

        var registry = copilotReadRegistry(nk, logger);

        for (var i = 0; i < registry.length; i++) {
            var record = registry[i];
            if (record.scope === "game" && record.gameId) {
                var friendsLeaderboardId = "leaderboard_friends_" + record.gameId;
                try {
                    nk.leaderboardCreate(
                        friendsLeaderboardId, true, sort, operator, resetSchedule,
                        { scope: "friends_game", gameId: record.gameId },
                        true  // enableRanks (QV_Bug_A8)
                    );
                    created.push(friendsLeaderboardId);
                } catch (err) {
                    skipped.push(friendsLeaderboardId);
                }
            }
        }

        return JSON.stringify({
            success: true,
            created: created,
            skipped: skipped,
            totalProcessed: registry.length
        });

    } catch (err) {
        copilotLogError(logger, "Error in rpcCreateAllLeaderboardsWithFriends: " + err.message);
        return copilotHandleError(ctx, err, "An error occurred while creating friend leaderboards");
    }
}

function rpcSubmitScoreWithFriendsSync(ctx, logger, nk, payload) {
    try {
        if (!ctx.userId) {
            return copilotHandleError(ctx, null, "Authentication required");
        }

        var data;
        try {
            data = JSON.parse(payload);
        } catch (err) {
            return copilotHandleError(ctx, err, "Invalid JSON payload");
        }

        var validation = copilotValidatePayload(data, ['gameId', 'score']);
        if (!validation.valid) {
            return copilotHandleError(ctx, null, "Missing required fields: " + validation.missing.join(', '));
        }

        var gameId = data.gameId;
        var score = parseInt(data.score);

        if (isNaN(score)) {
            return copilotHandleError(ctx, null, "Score must be a valid number");
        }

        var userId = ctx.userId;
        var username = ctx.username || userId;
        var submittedAt = new Date().toISOString();
        var metadata = { source: "submit_score_with_friends_sync", gameId: gameId, submittedAt: submittedAt };

        var gameLeaderboardId = "leaderboard_" + gameId;
        var globalLeaderboardId = "leaderboard_global";
        var friendsGameLeaderboardId = "leaderboard_friends_" + gameId;
        var friendsGlobalLeaderboardId = "leaderboard_friends_global";

        var results = { regular: { game: false, global: false }, friends: { game: false, global: false } };

        try { nk.leaderboardRecordWrite(gameLeaderboardId, userId, username, score, 0, metadata); results.regular.game = true; } catch (err) { copilotLogError(logger, "Failed game LB: " + err.message); }
        try { nk.leaderboardRecordWrite(globalLeaderboardId, userId, username, score, 0, metadata); results.regular.global = true; } catch (err) { copilotLogError(logger, "Failed global LB: " + err.message); }
        try { nk.leaderboardRecordWrite(friendsGameLeaderboardId, userId, username, score, 0, metadata); results.friends.game = true; } catch (err) { copilotLogError(logger, "Failed friends game LB: " + err.message); }
        try { nk.leaderboardRecordWrite(friendsGlobalLeaderboardId, userId, username, score, 0, metadata); results.friends.global = true; } catch (err) { copilotLogError(logger, "Failed friends global LB: " + err.message); }

        return JSON.stringify({ success: true, gameId: gameId, score: score, results: results, submittedAt: submittedAt });

    } catch (err) {
        copilotLogError(logger, "Error in rpcSubmitScoreWithFriendsSync: " + err.message);
        return copilotHandleError(ctx, err, "An error occurred while submitting score");
    }
}

function rpcGetFriendLeaderboard(ctx, logger, nk, payload) {
    try {
        if (!ctx.userId) {
            return copilotHandleError(ctx, null, "Authentication required");
        }

        var data;
        try {
            data = JSON.parse(payload);
        } catch (err) {
            return copilotHandleError(ctx, err, "Invalid JSON payload");
        }

        var validation = copilotValidatePayload(data, ['leaderboardId']);
        if (!validation.valid) {
            return copilotHandleError(ctx, null, "Missing required field: leaderboardId");
        }

        var leaderboardId = data.leaderboardId;
        var limit = data.limit || 100;
        var userId = ctx.userId;

        var friends = [];
        try {
            var friendsList = nk.friendsList(userId, limit, null, null);
            if (friendsList && friendsList.friends) {
                for (var i = 0; i < friendsList.friends.length; i++) {
                    var friend = friendsList.friends[i];
                    if (friend.user && friend.user.id) {
                        friends.push(friend.user.id);
                    }
                }
            }
        } catch (err) {
            copilotLogError(logger, "Failed to get friends list: " + err.message);
            return copilotHandleError(ctx, err, "Failed to retrieve friends list");
        }

        friends.push(userId);

        var records = [];
        try {
            var leaderboardRecords = nk.leaderboardRecordsList(leaderboardId, friends, limit, null, 0);
            if (leaderboardRecords && leaderboardRecords.records) {
                records = leaderboardRecords.records;
            }
        } catch (err) {
            copilotLogError(logger, "Failed to query leaderboard: " + err.message);
            return copilotHandleError(ctx, err, "Failed to retrieve leaderboard records");
        }

        return JSON.stringify({
            success: true,
            leaderboardId: leaderboardId,
            records: records,
            totalFriends: friends.length - 1
        });

    } catch (err) {
        copilotLogError(logger, "Error in rpcGetFriendLeaderboard: " + err.message);
        return copilotHandleError(ctx, err, "An error occurred while retrieving friend leaderboard");
    }
}


