/**
 * Get the full 30-day calendar config for a game, falling back to default.
 */
function getCalendarConfig(gameId) {
    return CALENDAR_REWARD_CONFIGS[gameId] || CALENDAR_REWARD_CONFIGS["default"];
}

/**
 * RPC: daily_reward_get_calendar
 * Returns the full 30-day reward calendar with claimed/unclaimed status per day.
 */
function rpcDailyRewardGetCalendar(ctx, logger, nk, payload) {
    logger.info('[DailyRewardCalendar] daily_reward_get_calendar called');

    try {
        if (!ctx.userId) {
            return JSON.stringify({ success: false, error: 'Authentication required' });
        }

        var data = JSON.parse(payload || '{}');
        var gameId = data.game_id || data.gameId || 'default';
        var userId = ctx.userId;

        // Get the player's current streak data from the daily_streaks collection
        var streakData = null;
        try {
            var streakKey = gameId + '_user_daily_streak_' + userId;
            var records = nk.storageRead([{
                collection: 'daily_streaks',
                key: streakKey,
                userId: userId
            }]);
            if (records && records.length > 0) {
                streakData = records[0].value;
            }
        } catch (e) {
            logger.warn('[DailyRewardCalendar] Could not read streak data: ' + e.message);
        }

        // Also try the alternate key pattern
        if (!streakData) {
            try {
                var altKey = 'user_daily_streak_' + userId + '_' + gameId;
                var altRecords = nk.storageRead([{
                    collection: 'daily_streaks',
                    key: altKey,
                    userId: userId
                }]);
                if (altRecords && altRecords.length > 0) {
                    streakData = altRecords[0].value;
                }
            } catch (e) { /* no streak yet */ }
        }

        var currentStreak = streakData ? (streakData.currentStreak || 0) : 0;
        var lastClaimTimestamp = streakData ? (streakData.lastClaimTimestamp || 0) : 0;
        var totalClaims = streakData ? (streakData.totalClaims || 0) : 0;

        // Check if they can claim today
        var canClaimToday = true;
        if (lastClaimTimestamp > 0) {
            var lastClaimDate = new Date(lastClaimTimestamp * 1000);
            var today = new Date();
            lastClaimDate.setHours(0, 0, 0, 0);
            today.setHours(0, 0, 0, 0);
            if (lastClaimDate.getTime() === today.getTime()) {
                canClaimToday = false;
            }
            // Check streak break (>48h)
            var nowUnix = Math.floor(Date.now() / 1000);
            if ((nowUnix - lastClaimTimestamp) > 48 * 3600) {
                currentStreak = 0;
            }
        }

        // Build 30-day calendar
        var config = getCalendarConfig(gameId);
        var calendar = [];
        var totalTokens = 0;
        var totalXp = 0;

        for (var day = 1; day <= 30; day++) {
            var dayConfig = null;
            for (var c = 0; c < config.length; c++) {
                if (config[c].day === day) {
                    dayConfig = config[c];
                    break;
                }
            }

            if (!dayConfig) {
                // Fallback: cycle week 1 rewards with scaling
                var weekDay = ((day - 1) % 7);
                dayConfig = config[weekDay] || config[0];
                var weekNum = Math.floor((day - 1) / 7) + 1;
                dayConfig = {
                    day: day,
                    xp: Math.round(dayConfig.xp * (1 + (weekNum - 1) * 0.15)),
                    tokens: Math.round(dayConfig.tokens * (1 + (weekNum - 1) * 0.15)),
                    name: dayConfig.name,
                    tier: dayConfig.tier,
                    icon: dayConfig.icon
                };
            }

            totalTokens += dayConfig.tokens || 0;
            totalXp += dayConfig.xp || 0;

            var status = 'locked';
            if (day <= currentStreak) {
                status = 'claimed';
            } else if (day === currentStreak + 1 && canClaimToday) {
                status = 'available';
            } else if (day === currentStreak + 1 && !canClaimToday) {
                status = 'claimed_today';
            }

            calendar.push({
                day: day,
                name: dayConfig.name,
                tier: dayConfig.tier || 'common',
                icon: dayConfig.icon || 'coin_stack',
                rewards: {
                    xp: dayConfig.xp || 0,
                    tokens: dayConfig.tokens || 0,
                    multiplier: dayConfig.multiplier || null,
                    bonus: dayConfig.bonus || null
                },
                status: status
            });
        }

        // Milestones summary
        var milestones = [];
        for (var m = 0; m < config.length; m++) {
            if (config[m].tier === 'rare' || config[m].tier === 'epic' || config[m].tier === 'legendary') {
                milestones.push({
                    day: config[m].day,
                    name: config[m].name,
                    tier: config[m].tier,
                    reached: config[m].day <= currentStreak
                });
            }
        }

        return JSON.stringify({
            success: true,
            user_id: userId,
            game_id: gameId,
            current_streak: currentStreak,
            total_claims: totalClaims,
            can_claim_today: canClaimToday,
            calendar: calendar,
            milestones: milestones,
            totals: {
                total_tokens_30_days: totalTokens,
                total_xp_30_days: totalXp,
                claimed_tokens: 0,
                claimed_xp: 0
            },
            streak_status: currentStreak === 0 ? 'new' : (canClaimToday ? 'active' : 'claimed_today'),
            next_milestone: null
        });

    } catch (err) {
        logger.error('[DailyRewardCalendar] Error: ' + err.message);
        logRpcError(nk, logger, 'daily_reward_get_calendar', err.message, ctx.userId, null);
        return JSON.stringify({ success: false, error: err.message });
    }
}


// --- Module: event_pipeline\event_pipeline.js ---
// event_pipeline.js - Unified event ingestion and reward-pending checks
// Compatible with Nakama JavaScript runtime (no ES modules)

var SYSTEM_USER_ID = "00000000-0000-0000-0000-000000000000";

// ---------------------------------------------------------------------------
// Helpers
// ---------------------------------------------------------------------------

function generateUUID() {
    var d = new Date().getTime();
    var d2 = (typeof performance !== 'undefined' && performance.now && (performance.now() * 1000)) || 0;
    return 'xxxxxxxx-xxxx-4xxx-yxxx-xxxxxxxxxxxx'.replace(/[xy]/g, function (c) {
        var r = Math.random() * 16;
        if (d > 0) {
            r = (d + r) % 16 | 0;
            d = Math.floor(d / 16);
        } else {
            r = (d2 + r) % 16 | 0;
            d2 = Math.floor(d2 / 16);
        }
        return (c === 'x' ? r : (r & 0x3 | 0x8)).toString(16);
    });
}

function safeRead(nk, collection, key, userId) {
    try {
        var recs = nk.storageRead([{ collection: collection, key: key, userId: userId }]);
        if (recs && recs.length > 0) return recs[0].value;
    } catch (_) { /* swallow */ }
    return null;
}

function safeWrite(nk, collection, key, userId, value) {
    nk.storageWrite([{
        collection: collection,
        key: key,
        userId: userId,
        value: value,
        permissionRead: 1,
        permissionWrite: 0
    }]);
}

function nowISO() {
    return new Date().toISOString();
}

// ---------------------------------------------------------------------------
// Fan-out helpers – each returns { success, data?, error? }
// ---------------------------------------------------------------------------

function fanOutLogEvent(nk, logger, userId, eventType, eventData, deviceId, gameId) {
    var logEntry = {
        event_type: eventType,
        event_data: eventData,
        device_id: deviceId,
        game_id: gameId,
        timestamp: nowISO()
    };
    safeWrite(nk, "event_pipeline_log", eventType + ":" + generateUUID(), userId, logEntry);
    return { success: true };
}

function fanOutGrantXP(nk, logger, userId, xpAmount, source) {
    if (xpAmount <= 0) return { success: true, xp: 0 };
    var xpInt = Math.floor(xpAmount);
    try {
        nk.walletUpdate(userId, { coins: 0, gems: 0, xp: xpInt }, { source: source }, true);
        return { success: true, xp: xpInt };
    } catch (err) {
        logger.warn("[event_pipeline] XP grant failed: " + err.message);
        return { success: false, error: err.message };
    }
}

function fanOutMasteryXP(nk, logger, userId, category, xpAmount, gameId) {
    if (!category) return { success: true, skipped: true };
    var key = "mastery:" + gameId + ":" + category;
    var existing = safeRead(nk, "mastery_xp", key, userId);
    var record = existing || { category: category, game_id: gameId, total_xp: 0, level: 1 };
    record.total_xp += Math.floor(xpAmount);
    record.level = Math.floor(record.total_xp / 1000) + 1;
    record.updated_at = nowISO();
    safeWrite(nk, "mastery_xp", key, userId, record);
    return { success: true, total_xp: record.total_xp, level: record.level };
}

function fanOutAchievements(nk, logger, userId, eventType, eventData, gameId) {
    var key = "progress:" + gameId;
    var progress = safeRead(nk, "achievements_progress", key, userId) || { events: {} };
    var count = (progress.events[eventType] || 0) + 1;
    progress.events[eventType] = count;
    progress.updated_at = nowISO();
    safeWrite(nk, "achievements_progress", key, userId, progress);
    return { success: true, event_count: count };
}

function fanOutSeasonPass(nk, logger, userId, xpAmount, gameId) {
    var key = "season_pass:" + gameId;
    var sp = safeRead(nk, "season_pass", key, userId) || { xp: 0, level: 0, claimed_levels: [] };
    sp.xp += Math.floor(xpAmount);
    sp.level = Math.floor(sp.xp / 500);
    sp.updated_at = nowISO();
    safeWrite(nk, "season_pass", key, userId, sp);
    return { success: true, xp: sp.xp, level: sp.level };
}

function fanOutWeeklyGoals(nk, logger, userId, eventType, eventData, gameId) {
    var now = new Date();
    var weekKey = "weekly:" + gameId + ":" + now.getFullYear() + "W" + Math.ceil((now.getDate() + now.getDay()) / 7);
    var goals = safeRead(nk, "weekly_goals", weekKey, userId) || { tasks: {}, completed: false };
    var count = (goals.tasks[eventType] || 0) + 1;
    goals.tasks[eventType] = count;
    goals.updated_at = nowISO();
    safeWrite(nk, "weekly_goals", weekKey, userId, goals);
    return { success: true, tasks: goals.tasks };
}

function fanOutDailyMissions(nk, logger, userId, eventType, eventData, gameId) {
    var today = nowISO().substring(0, 10);
    var key = "daily_mission:" + gameId + ":" + today;
    var missions = safeRead(nk, "daily_missions", key, userId) || { tasks: {}, completed: false, claimed: false };
    var count = (missions.tasks[eventType] || 0) + 1;
    missions.tasks[eventType] = count;
    missions.updated_at = nowISO();
    safeWrite(nk, "daily_missions", key, userId, missions);
    return { success: true, tasks: missions.tasks };
}

function fanOutDailyStreak(nk, logger, userId, gameId) {
    var today = nowISO().substring(0, 10);
    var key = "daily_streak:" + gameId;
    var streak = safeRead(nk, "daily_streaks", key, userId) || { current: 0, longest: 0, last_login: "", claimed: false };
    if (streak.last_login === today) return { success: true, already_logged: true, current: streak.current };
    var yesterday = new Date(Date.now() - 86400000).toISOString().substring(0, 10);
    streak.current = (streak.last_login === yesterday) ? streak.current + 1 : 1;
    if (streak.current > streak.longest) streak.longest = streak.current;
    streak.last_login = today;
    streak.claimed = false;
    streak.updated_at = nowISO();
    safeWrite(nk, "daily_streaks", key, userId, streak);
    return { success: true, current: streak.current, longest: streak.longest };
}

function fanOutAnalytics(nk, logger, userId, eventType, eventData, gameId) {
    var entry = {
        user_id: userId,
        game_id: gameId,
        event_type: eventType,
        event_data: eventData,
        timestamp: nowISO()
    };
    safeWrite(nk, "analytics_events", eventType + ":" + generateUUID(), userId, entry);
    return { success: true };
}

// ---------------------------------------------------------------------------
// RPC 1 – rpcPlayerEventSubmit
// ---------------------------------------------------------------------------

/**
 * Mega-RPC: ingests a player event and fans out to every subsystem.
 * Payload: { device_id, game_id, event_type, event_data }
 */
function rpcPlayerEventSubmit(ctx, logger, nk, payload) {
    logger.info("[event_pipeline] rpcPlayerEventSubmit called");

    try {
        var data = JSON.parse(payload || '{}');

        if (!data.event_type) {
            return JSON.stringify({ success: false, error: "event_type is required" });
        }

        var userId = ctx.userId || SYSTEM_USER_ID;
        var deviceId = data.device_id || "";
        var gameId = data.game_id || "";
        var eventType = data.event_type;
        var eventData = data.event_data || {};
        var rewards = [];
        var fanOutResults = {};
        var xpEarned = 0;

        // ----- Event-specific logic -----

        if (eventType === "quiz_complete") {
            var score = Number(eventData.score) || 0;
            xpEarned = Math.floor(score * 0.1);
            try {
                fanOutResults.xp_grant = fanOutGrantXP(nk, logger, userId, xpEarned, "quiz_complete");
            } catch (e) { fanOutResults.xp_grant = { success: false, error: e.message }; }

            try {
                fanOutResults.mastery = fanOutMasteryXP(nk, logger, userId, eventData.category, xpEarned, gameId);
            } catch (e) { fanOutResults.mastery = { success: false, error: e.message }; }

            try {
                fanOutResults.analytics = fanOutAnalytics(nk, logger, userId, eventType, eventData, gameId);
            } catch (e) { fanOutResults.analytics = { success: false, error: e.message }; }

            if (xpEarned > 0) rewards.push({ type: "xp", amount: xpEarned, source: "quiz_complete" });

        } else if (eventType === "match_complete") {
            var survivalTime = Number(eventData.survival_time) || 0;
            xpEarned = Math.floor(survivalTime * 0.5);
            try {
                fanOutResults.xp_grant = fanOutGrantXP(nk, logger, userId, xpEarned, "match_complete");
            } catch (e) { fanOutResults.xp_grant = { success: false, error: e.message }; }

            try {
                fanOutResults.analytics = fanOutAnalytics(nk, logger, userId, eventType, eventData, gameId);
            } catch (e) { fanOutResults.analytics = { success: false, error: e.message }; }

            if (xpEarned > 0) rewards.push({ type: "xp", amount: xpEarned, source: "match_complete" });

        } else if (eventType === "login") {
            try {
                fanOutResults.daily_streak = fanOutDailyStreak(nk, logger, userId, gameId);
            } catch (e) { fanOutResults.daily_streak = { success: false, error: e.message }; }

            try {
                fanOutResults.analytics = fanOutAnalytics(nk, logger, userId, eventType, eventData, gameId);
            } catch (e) { fanOutResults.analytics = { success: false, error: e.message }; }

        } else {
            // purchase, friend_added, multiplayer_win, etc.
            try {
                fanOutResults.analytics = fanOutAnalytics(nk, logger, userId, eventType, eventData, gameId);
            } catch (e) { fanOutResults.analytics = { success: false, error: e.message }; }
        }

        // ----- Common fan-out for ALL events -----

        try {
            fanOutResults.event_log = fanOutLogEvent(nk, logger, userId, eventType, eventData, deviceId, gameId);
        } catch (e) { fanOutResults.event_log = { success: false, error: e.message }; }

        try {
            fanOutResults.achievements = fanOutAchievements(nk, logger, userId, eventType, eventData, gameId);
        } catch (e) { fanOutResults.achievements = { success: false, error: e.message }; }

        try {
            fanOutResults.season_pass = fanOutSeasonPass(nk, logger, userId, xpEarned > 0 ? xpEarned : 10, gameId);
        } catch (e) { fanOutResults.season_pass = { success: false, error: e.message }; }

        try {
            fanOutResults.weekly_goals = fanOutWeeklyGoals(nk, logger, userId, eventType, eventData, gameId);
        } catch (e) { fanOutResults.weekly_goals = { success: false, error: e.message }; }

        try {
            fanOutResults.daily_missions = fanOutDailyMissions(nk, logger, userId, eventType, eventData, gameId);
        } catch (e) { fanOutResults.daily_missions = { success: false, error: e.message }; }

        return JSON.stringify({
            success: true,
            event_type: eventType,
            fan_out_results: fanOutResults,
            rewards_earned: rewards
        });

    } catch (err) {
        logger.error("[event_pipeline] rpcPlayerEventSubmit error: " + err.message);
        return JSON.stringify({ success: false, error: err.message });
    }
}

// ---------------------------------------------------------------------------
// RPC 2 – rpcRewardsPending
// ---------------------------------------------------------------------------

/**
 * Scans every reward sub-system for unclaimed rewards.
 * Payload: { device_id, game_id }
 */
function rpcRewardsPending(ctx, logger, nk, payload) {
    logger.info("[event_pipeline] rpcRewardsPending called");

    try {
        var data = JSON.parse(payload || '{}');
        var userId = ctx.userId || SYSTEM_USER_ID;
        var gameId = data.game_id || "";
        var unclaimed = [];
        var totalCoins = 0;
        var totalGems = 0;
        var totalXP = 0;

        // 1. Daily streak reward
        try {
            var streakKey = "daily_streak:" + gameId;
            var streak = safeRead(nk, "daily_streaks", streakKey, userId);
            if (streak && !streak.claimed && streak.current > 0) {
                var streakCoins = streak.current * 50;
                unclaimed.push({
                    source: "daily_streak",
                    description: "Day " + streak.current + " streak reward",
                    reward: { coins: streakCoins, gems: 0, xp: 0 }
                });
                totalCoins += streakCoins;
            }
        } catch (e) {
            logger.warn("[event_pipeline] streak check failed: " + e.message);
        }

        // 2. Daily missions
        try {
            var today = nowISO().substring(0, 10);
            var missionKey = "daily_mission:" + gameId + ":" + today;
            var missions = safeRead(nk, "daily_missions", missionKey, userId);
            if (missions && missions.completed && !missions.claimed) {
                unclaimed.push({
                    source: "daily_missions",
                    description: "Daily missions complete",
                    reward: { coins: 100, gems: 5, xp: 50 }
                });
                totalCoins += 100;
                totalGems += 5;
                totalXP += 50;
            }
        } catch (e) {
            logger.warn("[event_pipeline] daily missions check failed: " + e.message);
        }

        // 3. Weekly goals
        try {
            var now = new Date();
            var weekKey = "weekly:" + gameId + ":" + now.getFullYear() + "W" + Math.ceil((now.getDate() + now.getDay()) / 7);
            var goals = safeRead(nk, "weekly_goals", weekKey, userId);
            if (goals && goals.completed && !goals.claimed) {
                unclaimed.push({
                    source: "weekly_goals",
                    description: "Weekly goals complete",
                    reward: { coins: 500, gems: 20, xp: 200 }
                });
                totalCoins += 500;
                totalGems += 20;
                totalXP += 200;
            }
        } catch (e) {
            logger.warn("[event_pipeline] weekly goals check failed: " + e.message);
        }

        // 4. Season pass – unclaimed levels
        try {
            var spKey = "season_pass:" + gameId;
            var sp = safeRead(nk, "season_pass", spKey, userId);
            if (sp && sp.level > 0) {
                var claimed = sp.claimed_levels || [];
                for (var lvl = 1; lvl <= sp.level; lvl++) {
                    if (claimed.indexOf(lvl) === -1) {
                        var lvlCoins = lvl * 100;
                        var lvlGems = lvl * 5;
                        unclaimed.push({
                            source: "season_pass",
                            description: "Season pass level " + lvl,
                            reward: { coins: lvlCoins, gems: lvlGems, xp: 0 }
                        });
                        totalCoins += lvlCoins;
                        totalGems += lvlGems;
                    }
                }
            }
        } catch (e) {
            logger.warn("[event_pipeline] season pass check failed: " + e.message);
        }

        // 5. Monthly milestones
        try {
            var monthKey = "milestone:" + gameId + ":" + nowISO().substring(0, 7);
            var milestones = safeRead(nk, "monthly_milestones", monthKey, userId);
            if (milestones && milestones.completed && !milestones.claimed) {
                unclaimed.push({
                    source: "monthly_milestones",
                    description: "Monthly milestone complete",
                    reward: { coins: 1000, gems: 50, xp: 500 }
                });
                totalCoins += 1000;
                totalGems += 50;
                totalXP += 500;
            }
        } catch (e) {
            logger.warn("[event_pipeline] monthly milestones check failed: " + e.message);
        }

        return JSON.stringify({
            success: true,
            unclaimed: unclaimed,
            total_value: { coins: totalCoins, gems: totalGems, xp: totalXP }
        });

    } catch (err) {
        logger.error("[event_pipeline] rpcRewardsPending error: " + err.message);
        return JSON.stringify({ success: false, error: err.message });
    }
}


// --- Module: external_analytics\external_analytics.js ---
/**
 * External Analytics Integration Module
 * Fetches analytics data from Appodeal, Apple App Store Connect, and Unity.
 *
 * RPCs:
 *   - analytics_appodeal           : Fetch ad stats from Appodeal Reporting API (live)
 *   - analytics_apple_appstore     : Read cached App Store Connect data from storage
 *   - analytics_unity              : Read cached Unity Analytics data
 *   - unity_analytics_import       : Import Unity Analytics data from external export
 *   - apple_appstore_import        : Import Apple App Store data from external fetcher
 *
 * QuizVerse App Keys (Appodeal):
 *   Android: 7a1ba193e83636aea003883115a8e95a34308e9eb77ade1e
 *   iOS:     515538dba6c331557f2822d821f99230ddbe539f75e90b88
 *
 * Unity Project ID: 3a1d54d0-7210-4cbc-9def-e741210d9f21
 *
 * Environment variables (docker-compose):
 *   APPODEAL_API_KEY, APPODEAL_USER_ID, APPODEAL_QUIZVERSE_APP_KEY,
 *   APPLE_KEY_ID, APPLE_ISSUER_ID, APPLE_PRIVATE_KEY, APPLE_QUIZVERSE_BUNDLE_ID,
 *   UNITY_QUIZVERSE_PROJECT_ID
 */

var EXTERNAL_ANALYTICS_COLLECTION = "external_analytics";
var SYSTEM_USER_ID = "00000000-0000-0000-0000-000000000000";

// QuizVerse Appodeal app keys (both platforms)
var QUIZVERSE_APPODEAL_KEYS = {
    android: "7a1ba193e83636aea003883115a8e95a34308e9eb77ade1e",
    ios: "515538dba6c331557f2822d821f99230ddbe539f75e90b88"
};

// ─── Helpers ──────────────────────────────────────────────

function externalDateRange(payload) {
    var data = {};
    try { data = JSON.parse(payload || '{}'); } catch (e) { /* ignore */ }
    var now = new Date();
    var days = parseInt(data.days, 10) || 7;
    var to = now.toISOString().slice(0, 10);
    var from = new Date(now.getTime() - days * 86400000).toISOString().slice(0, 10);
    if (data.date_from) { from = data.date_from; }
    if (data.date_to) { to = data.date_to; }
    return { from: from, to: to, days: days, raw: data };
}

function storageRead(nk, collection, key) {
    var objects = nk.storageRead([{
        collection: collection,
        key: key,
        userId: SYSTEM_USER_ID
    }]);
    if (objects && objects.length > 0) {
        return objects[0].value;
    }
    return null;
}

function storageWrite(nk, collection, key, value) {
    nk.storageWrite([{
        collection: collection,
        key: key,
        userId: SYSTEM_USER_ID,
        value: value,
        permissionRead: 1,
        permissionWrite: 0
    }]);
}

// ─── Appodeal ─────────────────────────────────────────────

/**
 * Helper: Submit a single Appodeal stats request and poll for results.
 * Returns the data array or null on failure.
 */
function appodealFetchStats(nk, logger, apiKey, userId, dateFrom, dateTo, appKeys, detalisation) {
    // Build URL
    var url = "https://api-services.appodeal.com/api/v2/stats_api" +
        "?api_key=" + apiKey +
        "&user_id=" + userId +
        "&date_from=" + dateFrom +
        "&date_to=" + dateTo;

    // Add detalisation params
    for (var d = 0; d < detalisation.length; d++) {
        url += "&detalisation%5B%5D=" + detalisation[d];
    }

    // Add app key filters
    for (var a = 0; a < appKeys.length; a++) {
        url += "&app%5B%5D=" + appKeys[a];
    }

    logger.info("[Appodeal] Submitting: " + dateFrom + " to " + dateTo + " apps=" + appKeys.length);
    var submitResp = nk.httpRequest(url, "get", {}, "");
    var submitBody = {};
    try { submitBody = JSON.parse(submitResp.body); } catch (e) {
        logger.error("[Appodeal] Parse error: " + e.message);
        return null;
    }

    // Error check
    if (submitBody.code && submitBody.code !== 0) {
        logger.error("[Appodeal] API error: " + submitBody.message);
        return null;
    }

    // Direct data (fast query)
    if (submitBody.data) {
        return submitBody.data;
    }

    // Async: poll task_id
    if (submitBody.task_id) {
        var taskId = submitBody.task_id;
        var maxAttempts = 15;
        var taskReady = false;

        for (var attempt = 0; attempt < maxAttempts; attempt++) {
            var checkUrl = "https://api-services.appodeal.com/api/v2/check_status" +
                "?api_key=" + apiKey +
                "&user_id=" + userId +
                "&task_id=" + taskId;
            var checkResp = nk.httpRequest(checkUrl, "get", {}, "");
            var checkBody = {};
            try { checkBody = JSON.parse(checkResp.body); } catch (e) { continue; }

            // task_status "1" = ready
            if (checkBody.task_status === "1" || checkBody.task_status === 1) {
                taskReady = true;
                break;
            }
        }

        if (!taskReady) {
            logger.warn("[Appodeal] Task " + taskId + " not ready after " + maxAttempts + " polls");
            return null;
        }

        // Fetch results
        var resultUrl = "https://api-services.appodeal.com/api/v2/output_result" +
            "?api_key=" + apiKey +
            "&user_id=" + userId +
            "&task_id=" + taskId;
        var resultResp = nk.httpRequest(resultUrl, "get", {}, "");
        var resultBody = {};
        try { resultBody = JSON.parse(resultResp.body); } catch (e) {
            logger.error("[Appodeal] Result parse error: " + e.message);
            return null;
        }

        if (resultBody.code === 0 && resultBody.data) {
            return resultBody.data;
        }
        return resultBody.data || null;
    }

    return null;
}

/**
 * RPC: analytics_appodeal
 * Fetches QuizVerse ad revenue stats from Appodeal Reporting API.
 * Fetches BOTH Android and iOS data.
 *
 * Payload: { days?: number, date_from?: string, date_to?: string, platform?: "all"|"android"|"ios" }
 *
 * Response fields per row:
 *   date, app_key, app_name, package_name, platform, 
 *   requests, fills, impressions, fillrate, clicks, ctr, views, revenue, ecpm
 */
function rpcAnalyticsAppodeal(ctx, logger, nk, payload) {
    try {
        var apiKey = ctx.env['APPODEAL_API_KEY'] || '';
        var userId = ctx.env['APPODEAL_USER_ID'] || '';
        if (!apiKey || !userId) {
            return JSON.stringify({
                success: false,
                error: "Appodeal credentials not configured. Set APPODEAL_API_KEY and APPODEAL_USER_ID in .env file.",
                setup: {
                    step1: "Open https://www.appodeal.com/profile/api_credentials",
                    step2: "Copy API Key and User ID",
                    step3: "Set in .env: APPODEAL_API_KEY=xxx, APPODEAL_USER_ID=xxx"
                }
            });
        }

        var range = externalDateRange(payload);
        var platform = range.raw.platform || "all";

        // Determine which app keys to fetch
        var appKeys = [];
        if (platform === "android") {
            appKeys.push(QUIZVERSE_APPODEAL_KEYS.android);
        } else if (platform === "ios") {
            appKeys.push(QUIZVERSE_APPODEAL_KEYS.ios);
        } else {
            // Fetch both platforms
            appKeys.push(QUIZVERSE_APPODEAL_KEYS.android);
            appKeys.push(QUIZVERSE_APPODEAL_KEYS.ios);
        }

        // Allow explicit app_key from payload to override (for custom queries)
        var customKey = range.raw.app_key || '';
        if (customKey) {
            appKeys = [customKey];
        }

        // Fetch with date + app detalisation (per day, per app)
        var data = appodealFetchStats(nk, logger, apiKey, userId, range.from, range.to, appKeys, ["date", "app"]);

        if (!data) {
            // Try reading from cache
            var cached = storageRead(nk, EXTERNAL_ANALYTICS_COLLECTION, "appodeal_latest");
            if (cached) {
                return JSON.stringify({
                    success: true,
                    source: "appodeal",
                    from_cache: true,
                    fetched_at: cached.fetched_at || "unknown",
                    data: cached.results || cached
                });
            }
            return JSON.stringify({
                success: false,
                error: "Appodeal task still processing or no data. Try again in a few seconds.",
                hint: "If this persists, check Appodeal credentials and API status."
            });
        }

        // Calculate aggregated totals
        var totalRevenue = 0, totalImpressions = 0, totalClicks = 0, totalRequests = 0;
        var androidRevenue = 0, iosRevenue = 0;
        for (var i = 0; i < data.length; i++) {
            var row = data[i];
            totalRevenue += parseFloat(row.revenue || 0);
            totalImpressions += parseInt(row.impressions || 0, 10);
            totalClicks += parseInt(row.clicks || 0, 10);
            totalRequests += parseInt(row.requests || 0, 10);
            if (row.platform === "Google") { androidRevenue += parseFloat(row.revenue || 0); }
            if (row.platform === "Apple") { iosRevenue += parseFloat(row.revenue || 0); }
        }

        var result = {
            success: true,
            source: "appodeal",
            from_cache: false,
            date_from: range.from,
            date_to: range.to,
            summary: {
                total_revenue: parseFloat(totalRevenue.toFixed(4)),
                android_revenue: parseFloat(androidRevenue.toFixed(4)),
                ios_revenue: parseFloat(iosRevenue.toFixed(4)),
                total_impressions: totalImpressions,
                total_clicks: totalClicks,
                total_requests: totalRequests,
                avg_ecpm: totalImpressions > 0 ? parseFloat((totalRevenue / totalImpressions * 1000).toFixed(2)) : 0,
                avg_fillrate: totalRequests > 0 ? parseFloat((totalImpressions / totalRequests * 100).toFixed(1)) : 0
            },
            data: data
        };

        // Cache the results
        storageWrite(nk, EXTERNAL_ANALYTICS_COLLECTION, "appodeal_latest", {
            fetched_at: new Date().toISOString(),
            date_from: range.from,
            date_to: range.to,
            results: data,
            summary: result.summary
        });
        storageWrite(nk, EXTERNAL_ANALYTICS_COLLECTION, "appodeal_" + range.from + "_" + range.to, {
            fetched_at: new Date().toISOString(),
            results: data
        });

        return JSON.stringify(result);

    } catch (err) {
        logger.error("[ExternalAnalytics] Appodeal error: " + err.message);
        return JSON.stringify({ success: false, error: err.message });
    }
}

// ─── Apple App Store Connect ──────────────────────────────

/**
 * RPC: analytics_apple_appstore
 * Reads cached App Store Connect data from Nakama storage.
 * Data is populated by:
 *   1. External script: node scripts/apple_data_fetcher.js
 *   2. Import RPC: apple_appstore_import
 *
 * Note: App Store Connect API requires ES256 JWT signing,
 * which is not available in Nakama's Goja JS runtime.
 *
 * Payload: { days?: number, date_from?: string, date_to?: string, metric?: string }
 */
function rpcAnalyticsAppleAppstore(ctx, logger, nk, payload) {
    try {
        var range = externalDateRange(payload);
        var metric = range.raw.metric || "all";
        var bundleId = ctx.env['APPLE_QUIZVERSE_BUNDLE_ID'] || 'com.intelliversex.quizverse';

        // Read cached data written by external fetcher or import RPC
        var cached = storageRead(nk, EXTERNAL_ANALYTICS_COLLECTION, "apple_quizverse_latest");
        if (!cached) {
            cached = storageRead(nk, EXTERNAL_ANALYTICS_COLLECTION, "apple_latest");
        }

        if (!cached) {
            // Check if Apple credentials are configured
            var hasCredentials = ctx.env['APPLE_KEY_ID'] && ctx.env['APPLE_ISSUER_ID'] && ctx.env['APPLE_PRIVATE_KEY'];
            return JSON.stringify({
                success: false,
                error: "No Apple App Store data cached.",
                credentials_configured: !!hasCredentials,
                bundle_id: bundleId,
                how_to_populate: {
                    option1: "Run: cd scripts && node apple_data_fetcher.js",
                    option2: "Call RPC: apple_appstore_import with {data: {...}}",
                    option3: "Export from App Store Connect → Analytics → Download"
                }
            });
        }

        // Filter by metric if requested
        if (metric !== "all" && cached.metrics) {
            var filtered = {};
            filtered[metric] = cached.metrics[metric];
            return JSON.stringify({
                success: true,
                source: "apple_appstore",
                bundle_id: bundleId,
                fetched_at: cached.fetched_at || "unknown",
                data: filtered
            });
        }

        return JSON.stringify({
            success: true,
            source: "apple_appstore",
            bundle_id: bundleId,
            fetched_at: cached.fetched_at || "unknown",
            data: cached
        });

    } catch (err) {
        logger.error("[ExternalAnalytics] Apple error: " + err.message);
        return JSON.stringify({ success: false, error: err.message });
    }
}

/**
 * RPC: apple_appstore_import
 * Import Apple App Store data (from apple_data_fetcher.js or manual export).
 * Payload: { data: {...}, source?: string }
 */
function rpcAppleImport(ctx, logger, nk, payload) {
    try {
        var input = {};
        try { input = JSON.parse(payload || '{}'); } catch (e) {
            return JSON.stringify({ success: false, error: "Invalid JSON payload" });
        }

        if (!input.data) {
            return JSON.stringify({ success: false, error: "Missing 'data' field in payload" });
        }

        var cacheData = {
            fetched_at: new Date().toISOString(),
            source: input.source || "manual_import",
            metrics: input.data.metrics || input.data,
            apps: input.data.apps || []
        };

        storageWrite(nk, EXTERNAL_ANALYTICS_COLLECTION, "apple_quizverse_latest", cacheData);
        storageWrite(nk, EXTERNAL_ANALYTICS_COLLECTION, "apple_latest", cacheData);

        logger.info("[ExternalAnalytics] Apple data imported successfully");
        return JSON.stringify({ success: true, message: "Apple App Store data imported" });

    } catch (err) {
        logger.error("[ExternalAnalytics] Apple import error: " + err.message);
        return JSON.stringify({ success: false, error: err.message });
    }
}

// ─── Unity Gaming Services ───────────────────────────────

/**
 * RPC: analytics_unity
 * Reads Unity Analytics data from cache.
 * 
 * NOTE: Unity Analytics REST API is for SUBMITTING events only, not reading.
 * To populate data, use unity_analytics_import RPC or external script.
 * 
 * Project ID: 3a1d54d0-7210-4cbc-9def-e741210d9f21 (QuizVerse)
 * 
 * Payload: { days?: number }
 */
function rpcAnalyticsUnity(ctx, logger, nk, payload) {
    try {
        var range = externalDateRange(payload);
        var projectId = ctx.env['UNITY_QUIZVERSE_PROJECT_ID'] || '3a1d54d0-7210-4cbc-9def-e741210d9f21';
        
        // Read cached data (populated by external script or unity_analytics_import RPC)
        var cached = storageRead(nk, EXTERNAL_ANALYTICS_COLLECTION, "unity_quizverse_latest");
        if (!cached) {
            cached = storageRead(nk, EXTERNAL_ANALYTICS_COLLECTION, "unity_latest");
        }

        if (!cached) {
            return JSON.stringify({
                success: false,
                error: "No Unity Analytics data cached.",
                hint: "Unity Analytics API only supports event submission, not reading. Export data from Unity Dashboard (cloud.unity.com) → Analytics → Data Export, then use unity_analytics_import RPC to load it.",
                project_id: projectId
            });
        }

        return JSON.stringify({
            success: true,
            source: "unity_analytics",
            from_cache: true,
            project_id: projectId,
            fetched_at: cached.fetched_at || "unknown",
            data: cached
        });

    } catch (err) {
        logger.error("[ExternalAnalytics] Unity error: " + err.message);
        return JSON.stringify({ success: false, error: err.message });
    }
}

/**
 * RPC: unity_analytics_import
 * Import Unity Analytics data (exported from Unity Dashboard).
 * Call this from admin panel or script after exporting data from Unity Cloud.
 * 
 * Payload: { data: {...}, source?: string }
 */
function rpcUnityAnalyticsImport(ctx, logger, nk, payload) {
    try {
        var input = {};
        try { input = JSON.parse(payload || '{}'); } catch (e) {
            return JSON.stringify({ success: false, error: "Invalid JSON payload" });
        }
        
        if (!input.data) {
            return JSON.stringify({ success: false, error: "Missing 'data' field in payload" });
        }
        
        var cacheKey = "unity_quizverse_latest";
        var cacheData = {
            fetched_at: new Date().toISOString(),
            source: input.source || "manual_import",
            data: input.data
        };
        
        storageWrite(nk, EXTERNAL_ANALYTICS_COLLECTION, cacheKey, cacheData);
        storageWrite(nk, EXTERNAL_ANALYTICS_COLLECTION, "unity_latest", cacheData);
        
        logger.info("[ExternalAnalytics] Unity analytics data imported successfully");
        return JSON.stringify({ success: true, message: "Unity analytics data imported", key: cacheKey });
        
    } catch (err) {
        logger.error("[ExternalAnalytics] Unity import error: " + err.message);
        return JSON.stringify({ success: false, error: err.message });
    }
}

// ─── Registration ─────────────────────────────────────────
// postbuild.js scans for initializer.registerRpc() calls

function __ModuleInit_29(ctx, logger, nk, initializer) {
    __rpc_analytics_appodeal = __rpc_analytics_appodeal || (rpcAnalyticsAppodeal);
    __rpc_analytics_apple_appstore = __rpc_analytics_apple_appstore || (rpcAnalyticsAppleAppstore);
    __rpc_apple_appstore_import = __rpc_apple_appstore_import || (rpcAppleImport);
    __rpc_analytics_unity = __rpc_analytics_unity || (rpcAnalyticsUnity);
    __rpc_unity_analytics_import = __rpc_unity_analytics_import || (rpcUnityAnalyticsImport);
    logger.info("[ExternalAnalytics] Module registered: 5 RPCs (appodeal, apple, apple_import, unity, unity_import)");
}


// --- Module: external_pollers\external_pollers.js ---
// external_pollers.js — Phase 2.2 scheduled external-provider pollers.
//
// Solves: Revenue tabs (Appodeal / Apple App Store / Unity Gaming Services)
// currently do live API fetches on every dashboard request. That's slow,
// rate-limits easily, and flaky. This module polls each provider once per
// cadence window and writes canonical docs the dashboard can read cheaply.
//
// Output collections:
//   external_analytics/<provider>/<gameId>/<YYYY-MM-DD>   normalized snapshot
//   external_analytics_last_poll/<provider>                rate-limit meta
//
// Registered RPCs (all admin-gated):
//   external_poll_appodeal    { gameId?, date?, force?, days? }
//   external_poll_appstore    { gameId?, date?, force? }
//   external_poll_ugs         { gameId?, date?, force? }
//   external_poll_all         { force? }                            -> runs all three
//   external_poll_status      {}                                    -> last-poll meta
//
// Auth:
//   Admin session OR payload.dashboard_secret === env.DASHBOARD_SECRET.
//   The cron sidecar uses the shared-secret path.
//
// Feature flag: EXTERNAL_POLLERS_ENABLED=false disables all RPCs (503).
//
// Rate limiting:
//   Default min-interval 1h between polls per provider. Can be bypassed
//   with { force: true } (useful for manual refresh / testing).

var EP_SYSTEM_USER = "00000000-0000-0000-0000-000000000000";
var EP_ADMIN_USERS_COLLECTION = "admin_users";
var EP_COLLECTION = "external_analytics";
var EP_META_COLLECTION = "external_analytics_last_poll";
var EP_DEFAULT_GAME_ID_ENV = "DEFAULT_GAME_ID";
var EP_MIN_POLL_INTERVAL_SECONDS = 3600; // 1 hour

// ─── Helpers ──────────────────────────────────────────────

function epParse(payload) {
    try { return JSON.parse(payload || "{}"); } catch (e) { return {}; }
}

function epOk(data) {
    var out = { success: true };
    if (data) for (var k in data) if (data.hasOwnProperty(k)) out[k] = data[k];
    return JSON.stringify(out);
}

function epErr(msg, code) {
    return JSON.stringify({ success: false, error: msg || "error", code: code || 400 });
}

function epEnv(ctx, key) {
    if (ctx && ctx.env && ctx.env[key] !== undefined && ctx.env[key] !== null) return String(ctx.env[key]);
    return "";
}

function epFeatureEnabled(ctx) {
    var v = epEnv(ctx, "EXTERNAL_POLLERS_ENABLED");
    if (v === "" || v === "true" || v === "1") return true;
    return false;
}

// Mirrors analytics_admin: the admin_users/profile doc is keyed by the
// Nakama UUID (ctx.userId); the "admin:" gate applies to ctx.username.
function epIsAdminUser(nk, userId, username) {
    if (!userId) return false;
    if (!username || username.indexOf("admin:") !== 0) return false;
    try {
        var records = nk.storageRead([{ collection: EP_ADMIN_USERS_COLLECTION, key: "profile", userId: userId }]);
        if (!records || records.length === 0) return false;
        var rec = records[0].value || {};
        if (!rec.isAdmin) return false;
        if (rec.expiresAt && rec.expiresAt < Math.floor(Date.now() / 1000)) return false;
        return true;
    } catch (e) { return false; }
}

function epRequireAdmin(ctx, nk, data) {
    var secret = epEnv(ctx, "DASHBOARD_SECRET");
    if (secret && data && data.dashboard_secret === secret) return { ok: true, bypass: "secret" };
    if (ctx.userId && epIsAdminUser(nk, ctx.userId, ctx.username)) return { ok: true, bypass: "session" };
    return { ok: false, reason: "admin authentication required" };
}

function epReadOne(nk, collection, key, userId) {
    try {
        var r = nk.storageRead([{ collection: collection, key: key, userId: userId || EP_SYSTEM_USER }]);
        if (r && r.length > 0) return r[0].value;
    } catch (e) { /* ignore */ }
    return null;
}

function epWriteOne(nk, collection, key, value) {
    try {
        nk.storageWrite([{
            collection: collection,
            key: key,
            userId: EP_SYSTEM_USER,
            value: value,
            permissionRead: 2,
            permissionWrite: 0
        }]);
        return true;
    } catch (e) { return false; }
}

function epYesterday() {
    var d = new Date();
    d.setUTCDate(d.getUTCDate() - 1);
    return d.toISOString().slice(0, 10);
}

function epDefaultGameId(ctx) {
    var v = epEnv(ctx, EP_DEFAULT_GAME_ID_ENV);
    return v || "126bf539-dae2-4bcf-964d-316c0fa1f92b"; // QuizVerse fallback
}

/**
 * Enforce min-interval between polls per provider. Writes `last_poll`
 * meta-doc after success so subsequent calls within the window skip.
 */
function epCheckRateLimit(nk, provider, force) {
    if (force) return { allowed: true, reason: "force" };
    var meta = epReadOne(nk, EP_META_COLLECTION, provider, EP_SYSTEM_USER) || {};
    if (!meta.lastPollUnix) return { allowed: true, reason: "first-poll" };

    var nowUnix = Math.floor(Date.now() / 1000);
    var elapsed = nowUnix - meta.lastPollUnix;
    if (elapsed < EP_MIN_POLL_INTERVAL_SECONDS) {
        return {
            allowed: false,
            reason: "rate-limited",
            secondsUntilNext: EP_MIN_POLL_INTERVAL_SECONDS - elapsed,
            lastPoll: meta
        };
    }
    return { allowed: true, reason: "interval-ok", lastPoll: meta };
}

function epRecordPoll(nk, provider, success, summary) {
    var nowUnix = Math.floor(Date.now() / 1000);
    epWriteOne(nk, EP_META_COLLECTION, provider, {
        provider: provider,
        lastPollUnix: nowUnix,
        lastPollAt: new Date().toISOString(),
        success: !!success,
        summary: summary || null
    });
}

// ─── Internal: dispatch existing RPCs ─────────────────────
//
// We reuse the existing analytics_appodeal / _apple_appstore / _unity
// handlers rather than re-implementing the API clients. Those handlers
// are exposed via __rpc_<name> globals after postbuild processing.
// To avoid a hard dependency on that global, we try-catch the lookup
// and fall back to a clean error if the legacy RPC isn't present.

function epCallInternalRpc(ctx, logger, nk, rpcName, payload) {
    try {
        // Postbuild exposes every registered RPC as a top-level __rpc_* global.
        var fn;
        try { fn = eval("(typeof __rpc_" + rpcName + " === 'function') ? __rpc_" + rpcName + " : null"); }
        catch (e) { fn = null; }
        if (!fn) return { ok: false, reason: "handler_not_found:" + rpcName };

        var rawPayload = typeof payload === "string" ? payload : JSON.stringify(payload || {});
        var raw = fn(ctx, logger, nk, rawPayload);
        var parsed = typeof raw === "string" ? JSON.parse(raw) : raw;
        return { ok: true, data: parsed };
    } catch (e) {
        return { ok: false, reason: "internal_rpc_error: " + e.message };
    }
}

// ─── RPC: external_poll_appodeal ──────────────────────────

function rpcExternalPollAppodeal(ctx, logger, nk, payload) {
    if (!epFeatureEnabled(ctx)) return epErr("External pollers disabled", 503);

    var data = epParse(payload);
    var gate = epRequireAdmin(ctx, nk, data);
    if (!gate.ok) return epErr(gate.reason, 401);

    var rate = epCheckRateLimit(nk, "appodeal", data.force);
    if (!rate.allowed) {
        return epOk({ skipped: true, reason: rate.reason, seconds_until_next: rate.secondsUntilNext, last_poll: rate.lastPoll });
    }

    if (!epEnv(ctx, "APPODEAL_API_KEY") || !epEnv(ctx, "APPODEAL_USER_ID")) {
        epRecordPoll(nk, "appodeal", false, { error: "APPODEAL credentials missing" });
        return epErr("APPODEAL_API_KEY / APPODEAL_USER_ID not set in runtime env", 503);
    }

    var gameId = data.gameId || epDefaultGameId(ctx);
    var dateStr = data.date || epYesterday();
    var days = parseInt(data.days, 10) || 7;

    // Reuse existing analytics_appodeal handler (admin privilege already checked).
    var call = epCallInternalRpc(ctx, logger, nk, "analytics_appodeal", {
        days: days, date_to: dateStr
    });
    if (!call.ok) {
        epRecordPoll(nk, "appodeal", false, { error: call.reason });
        return epErr("Appodeal poll failed: " + call.reason, 500);
    }
    var fetched = call.data || {};
    if (!fetched.success) {
        epRecordPoll(nk, "appodeal", false, { error: fetched.error || "unknown" });
        return epErr("Appodeal returned error: " + (fetched.error || "unknown"), 502);
    }

    var summary = fetched.summary || {};
    var snapshot = {
        provider: "appodeal",
        gameId: gameId,
        date: dateStr,
        fetchedAt: new Date().toISOString(),
        revenue_usd: summary.total_revenue || 0,
        android_revenue_usd: summary.android_revenue || 0,
        ios_revenue_usd: summary.ios_revenue || 0,
        impressions: summary.total_impressions || 0,
        clicks: summary.total_clicks || 0,
        requests: summary.total_requests || 0,
        avg_ecpm: summary.avg_ecpm || 0,
        avg_fillrate: summary.avg_fillrate || 0,
        raw_rows: fetched.data || []
    };
    epWriteOne(nk, EP_COLLECTION, "appodeal_" + gameId + "_" + dateStr, snapshot);
    epRecordPoll(nk, "appodeal", true, {
        gameId: gameId, date: dateStr, revenue_usd: snapshot.revenue_usd, rows: snapshot.raw_rows.length
    });

    return epOk({ provider: "appodeal", gameId: gameId, date: dateStr, snapshot_keys: ["appodeal_" + gameId + "_" + dateStr], summary: summary });
}

// ─── RPC: external_poll_appstore ──────────────────────────

function rpcExternalPollAppstore(ctx, logger, nk, payload) {
    if (!epFeatureEnabled(ctx)) return epErr("External pollers disabled", 503);

    var data = epParse(payload);
    var gate = epRequireAdmin(ctx, nk, data);
    if (!gate.ok) return epErr(gate.reason, 401);

    var rate = epCheckRateLimit(nk, "appstore", data.force);
    if (!rate.allowed) {
        return epOk({ skipped: true, reason: rate.reason, seconds_until_next: rate.secondsUntilNext, last_poll: rate.lastPoll });
    }

    // App Store Connect requires KEY_ID + ISSUER_ID + PRIVATE_KEY.
    if (!epEnv(ctx, "APPLE_KEY_ID") || !epEnv(ctx, "APPLE_ISSUER_ID") || !epEnv(ctx, "APPLE_PRIVATE_KEY")) {
        epRecordPoll(nk, "appstore", false, { error: "Apple credentials missing" });
        return epErr("APPLE_KEY_ID / APPLE_ISSUER_ID / APPLE_PRIVATE_KEY not set", 503);
    }

    var gameId = data.gameId || epDefaultGameId(ctx);
    var dateStr = data.date || epYesterday();

    var call = epCallInternalRpc(ctx, logger, nk, "analytics_apple_appstore", { date_to: dateStr });
    if (!call.ok) {
        epRecordPoll(nk, "appstore", false, { error: call.reason });
        return epErr("App Store poll failed: " + call.reason, 500);
    }
    var fetched = call.data || {};
    if (!fetched.success) {
        epRecordPoll(nk, "appstore", false, { error: fetched.error || "unknown" });
        return epErr("App Store returned error: " + (fetched.error || "unknown"), 502);
    }

    var snapshot = {
        provider: "appstore",
        gameId: gameId,
        date: dateStr,
        fetchedAt: new Date().toISOString(),
        raw: fetched.data || fetched.summary || fetched
    };
    epWriteOne(nk, EP_COLLECTION, "appstore_" + gameId + "_" + dateStr, snapshot);
    epRecordPoll(nk, "appstore", true, { gameId: gameId, date: dateStr });

    return epOk({ provider: "appstore", gameId: gameId, date: dateStr });
}

// ─── RPC: external_poll_ugs (Unity Gaming Services) ───────

function rpcExternalPollUgs(ctx, logger, nk, payload) {
    if (!epFeatureEnabled(ctx)) return epErr("External pollers disabled", 503);

    var data = epParse(payload);
    var gate = epRequireAdmin(ctx, nk, data);
    if (!gate.ok) return epErr(gate.reason, 401);

    var rate = epCheckRateLimit(nk, "ugs", data.force);
    if (!rate.allowed) {
        return epOk({ skipped: true, reason: rate.reason, seconds_until_next: rate.secondsUntilNext, last_poll: rate.lastPoll });
    }

    if (!epEnv(ctx, "UNITY_KEY_ID") || !epEnv(ctx, "UNITY_SECRET_KEY")) {
        epRecordPoll(nk, "ugs", false, { error: "Unity credentials missing" });
        return epErr("UNITY_KEY_ID / UNITY_SECRET_KEY not set", 503);
    }

    var gameId = data.gameId || epDefaultGameId(ctx);
    var dateStr = data.date || epYesterday();

    var call = epCallInternalRpc(ctx, logger, nk, "analytics_unity", { date_to: dateStr });
    if (!call.ok) {
        epRecordPoll(nk, "ugs", false, { error: call.reason });
        return epErr("UGS poll failed: " + call.reason, 500);
    }
    var fetched = call.data || {};
    if (!fetched.success) {
        epRecordPoll(nk, "ugs", false, { error: fetched.error || "unknown" });
        return epErr("UGS returned error: " + (fetched.error || "unknown"), 502);
    }

    var snapshot = {
        provider: "ugs",
        gameId: gameId,
        date: dateStr,
        fetchedAt: new Date().toISOString(),
        raw: fetched.data || fetched.summary || fetched
    };
    epWriteOne(nk, EP_COLLECTION, "ugs_" + gameId + "_" + dateStr, snapshot);
    epRecordPoll(nk, "ugs", true, { gameId: gameId, date: dateStr });

    return epOk({ provider: "ugs", gameId: gameId, date: dateStr });
}

// ─── RPC: external_poll_all ───────────────────────────────

function rpcExternalPollAll(ctx, logger, nk, payload) {
    if (!epFeatureEnabled(ctx)) return epErr("External pollers disabled", 503);

    var data = epParse(payload);
    var gate = epRequireAdmin(ctx, nk, data);
    if (!gate.ok) return epErr(gate.reason, 401);

    var base = { force: !!data.force, dashboard_secret: data.dashboard_secret, gameId: data.gameId };
    var results = {};

    var rpcs = [
        { key: "appodeal", handler: rpcExternalPollAppodeal },
        { key: "appstore", handler: rpcExternalPollAppstore },
        { key: "ugs",      handler: rpcExternalPollUgs }
    ];

    for (var i = 0; i < rpcs.length; i++) {
        var item = rpcs[i];
        try {
            var raw = item.handler(ctx, logger, nk, JSON.stringify(base));
            results[item.key] = JSON.parse(raw);
        } catch (e) {
            results[item.key] = { success: false, error: e.message };
        }
    }
    return epOk({ results: results, ranAt: new Date().toISOString() });
}

// ─── RPC: external_poll_status ────────────────────────────

function rpcExternalPollStatus(ctx, logger, nk, payload) {
    var data = epParse(payload);
    var gate = epRequireAdmin(ctx, nk, data);
    if (!gate.ok) return epErr(gate.reason, 401);

    var providers = ["appodeal", "appstore", "ugs"];
    var status = {};
    for (var i = 0; i < providers.length; i++) {
        var p = providers[i];
        status[p] = epReadOne(nk, EP_META_COLLECTION, p, EP_SYSTEM_USER) || { provider: p, lastPollUnix: 0 };
    }
    return epOk({ enabled: epFeatureEnabled(ctx), providers: status });
}

// ─── Registration ─────────────────────────────────────────

function __ModuleInit_30(ctx, logger, nk, initializer) {
    __rpc_external_poll_appodeal = __rpc_external_poll_appodeal || (rpcExternalPollAppodeal);
    __rpc_external_poll_appstore = __rpc_external_poll_appstore || (rpcExternalPollAppstore);
    __rpc_external_poll_ugs = __rpc_external_poll_ugs || (rpcExternalPollUgs);
    __rpc_external_poll_all = __rpc_external_poll_all || (rpcExternalPollAll);
    __rpc_external_poll_status = __rpc_external_poll_status || (rpcExternalPollStatus);
    logger.info("[external_pollers] Module registered: 5 RPCs (appodeal/appstore/ugs/all/status)");
}


// --- Module: fortune_wheel\fortune_wheel.js ---
/**
 * fortune_wheel.js — Fortune Wheel Backend V2 (every 3 days)
 * RPCs: fortune_wheel_get_state, fortune_wheel_spin
 * 
 * SERVER-AUTHORITATIVE: Server picks the random reward — client only animates.
 * Storage: fortune_wheel/state per user
 * Rewards: XP, Coins (wallet), AudiobookToken (storage), Shield (storage)
 * 
 * V2 CHANGES:
 *   - fortune_wheel_get_state now returns ad-spin state (organicSpinDone, adSpinsUsed, etc.)
 *   - fortune_wheel_spin now sets organicSpinDone flag in state
 *   - Ad spins are tracked in fortune_wheel_ad_spins collection (managed by fortune-wheel-ad-spin.ts)
 */

var COOLDOWN_DAYS = 3;
var AD_SPINS_MAX = 3;
var AD_COOLDOWN_SECONDS = 10800; // 3 hours between ad spins

// Wheel segments with probability weights — SERVER is source of truth
var SEGMENTS = [
    { type: "XP",             amount: 100,  label: "100 XP",            weight: 20 },
    { type: "Coins",          amount: 50,   label: "50 Coins",          weight: 25 },
    { type: "XP",             amount: 250,  label: "250 XP",            weight: 15 },
    { type: "AudiobookToken", amount: 1,    label: "Audiobook Token",   weight: 8  },
    { type: "Coins",          amount: 150,  label: "150 Coins",         weight: 12 },
    { type: "Shield",         amount: 24,   label: "24h Shield",        weight: 10 },
    { type: "XP",             amount: 500,  label: "500 XP",            weight: 5  },
    { type: "AudiobookToken", amount: 2,    label: "2 Audiobook Tokens",weight: 5  }
];

// ===== RPCs =====

// fortune_wheel_get_state — Get current wheel state + segments + ad-spin info
var fortuneWheelGetState = function(ctx, logger, nk, payload) {
    try {
        var userId = ctx.userId;
        if (!userId) {
            return JSON.stringify({ success: false, error: "Not authenticated" });
        }

        var state = getWheelState(nk, userId);
        var canSpin = canUserSpin(state);

        // --- V2: Read ad-spin cycle record ---
        var adState = getAdSpinState(nk, userId);
        adState = normalizeAdStateForCurrentCycle(nk, userId, state, adState, logger);
        var now = Math.floor(Date.now() / 1000);
        var nextAdSpinTime = 0;
        if (adState.lastSpinAt > 0) {
            nextAdSpinTime = adState.lastSpinAt + AD_COOLDOWN_SECONDS;
        }

        // Determine if organic spin was done in current cycle
        var organicSpinDone = false;
        if (state.organicSpinDone === true) {
            // Check if the cycle is still active (cooldown hasn't expired)
            if (state.nextSpinTime) {
                var nextSpin = new Date(state.nextSpinTime);
                if (new Date() < nextSpin) {
                    organicSpinDone = true;
                }
                // If cooldown expired, organic spin resets
            }
        }

        var effectiveAdSpinsUsed = organicSpinDone ? adState.spinsUsed : 0;
        var effectiveNextAdSpinTime = (organicSpinDone && nextAdSpinTime > now) ? nextAdSpinTime : 0;

        return JSON.stringify({
            success: true,
            canSpin: canSpin,
            nextSpinTime: state.nextSpinTime || null,
            totalSpins: state.totalSpins || 0,
            lastReward: state.lastReward || null,
            cooldownDays: COOLDOWN_DAYS,
            // V2 fields
            organicSpinDone: organicSpinDone,
            adSpinsUsed: effectiveAdSpinsUsed,
            adSpinsMax: AD_SPINS_MAX,
            adCooldownSeconds: AD_COOLDOWN_SECONDS,
            nextAdSpinTime: effectiveNextAdSpinTime,
            cycleEndsAt: state.nextSpinTime || null,
            segments: SEGMENTS.map(function(s) {
                return { type: s.type, amount: s.amount, label: s.label };
            })
        });
    } catch (e) {
        logger.error("fortune_wheel_get_state error: " + e.message);
        return JSON.stringify({ success: false, error: "An internal error occurred" });
    }
};

// fortune_wheel_spin — SERVER picks reward, grants it, returns result
var fortuneWheelSpin = function(ctx, logger, nk, payload) {
    try {
        var userId = ctx.userId;
        if (!userId) {
            return JSON.stringify({ success: false, error: "Not authenticated" });
        }

        var state = getWheelState(nk, userId);

        // Cooldown check — server-authoritative
        if (!canUserSpin(state)) {
            return JSON.stringify({
                success: false,
                error: "On cooldown",
                nextSpinTime: state.nextSpinTime,
                canSpin: false
            });
        }

        // SERVER picks the reward (weighted random) — client has NO say
        var segmentIndex = getWeightedRandomIndex();
        var reward = SEGMENTS[segmentIndex];

        // Update state BEFORE granting reward (atomic claim via version check)
        var now = new Date();
        var nextSpin = new Date(now.getTime() + COOLDOWN_DAYS * 24 * 60 * 60 * 1000);

        state.nextSpinTime = nextSpin.toISOString();
        state.totalSpins = (state.totalSpins || 0) + 1;
        state.organicSpinDone = true; // V2: Mark organic spin as done
        state.lastReward = {
            type: reward.type,
            amount: reward.amount,
            label: reward.label,
            segmentIndex: segmentIndex,
            timestamp: now.toISOString()
        };
        state.history = state.history || [];
        state.history.push(state.lastReward);
        if (state.history.length > 120) state.history = state.history.slice(-120);

        // Save with optimistic concurrency — fails if another spin raced us
        try {
            saveWheelState(nk, userId, state);
        } catch (saveErr) {
            logger.warn("fortune_wheel_spin: concurrent spin detected for " + userId + " — " + saveErr.message);
            return JSON.stringify({ success: false, error: "Spin already in progress. Please try again." });
        }

        // New organic cycle starts here: reset ad-spin counters for this cycle.
        try {
            var currentAdState = getAdSpinState(nk, userId);
            currentAdState.spinsUsed = 0;
            currentAdState.lastSpinAt = 0;
            currentAdState.cycleStart = getCurrentCycleStartIso(state.nextSpinTime);
            saveAdSpinState(nk, userId, currentAdState);
        } catch (adResetErr) {
            logger.warn("fortune_wheel_spin: ad cycle reset failed for " + userId + " — " + adResetErr.message);
        }

        // State claimed successfully — now grant reward (safe: double-grant impossible)
        grantReward(nk, userId, reward.type, reward.amount, logger);

        logger.info("fortune_wheel_spin: " + userId + " won segment " + segmentIndex + " → " + reward.label);

        return JSON.stringify({
            success: true,
            segmentIndex: segmentIndex,
            reward: {
                type: reward.type,
                amount: reward.amount,
                label: reward.label
            },
            nextSpinTime: state.nextSpinTime,
            totalSpins: state.totalSpins
        });
    } catch (e) {
        logger.error("fortune_wheel_spin error: " + e.message);
        return JSON.stringify({ success: false, error: "An internal error occurred" });
    }
};

// ===== HELPERS =====

function getWheelState(nk, userId) {
    try {
        var objects = nk.storageRead([{
            collection: "fortune_wheel",
            key: "state",
            userId: userId
        }]);
        if (objects && objects.length > 0) {
            var result = objects[0].value || {};
            result._version = objects[0].version || "";
            return result;
        }
    } catch(e) { /* first time user */ }
    return {};
}

function saveWheelState(nk, userId, state) {
    var version = state._version || "*";
    delete state._version;
    nk.storageWrite([{
        collection: "fortune_wheel",
        key: "state",
        userId: userId,
        value: state,
        version: version,
        permissionRead: 1,
        permissionWrite: 0
    }]);
}

function canUserSpin(state) {
    if (!state.nextSpinTime) return true;
    var nextSpin = new Date(state.nextSpinTime);
    return new Date() >= nextSpin;
}

/**
 * Returns current cycle start ISO from nextSpinTime.
 * If nextSpinTime is missing/invalid, returns empty string.
 */
function getCurrentCycleStartIso(nextSpinTimeIso) {
    if (!nextSpinTimeIso) return "";
    var nextSpin = new Date(nextSpinTimeIso);
    if (isNaN(nextSpin.getTime())) return "";
    var cycleStart = new Date(nextSpin.getTime() - (COOLDOWN_DAYS * 24 * 60 * 60 * 1000));
    return cycleStart.toISOString();
}

/**
 * V2: Read the ad-spin cycle record with version.
 * Returns { spinsUsed, lastSpinAt, cycleStart, _version }
 */
function getAdSpinState(nk, userId) {
    try {
        var records = nk.storageRead([{
            collection: "fortune_wheel_ad_spins",
            key: "cycle_state",
            userId: userId
        }]);
        if (records && records.length > 0) {
            var val = records[0].value || {};
            return {
                spinsUsed: val.spinsUsed || 0,
                lastSpinAt: val.lastSpinAt || 0,
                cycleStart: val.cycleStart || "",
                _version: records[0].version || ""
            };
        }
    } catch(e) { /* no record yet */ }
    return { spinsUsed: 0, lastSpinAt: 0, cycleStart: "", _version: "*" };
}

/**
 * Persist ad-spin cycle state using optimistic concurrency.
 */
function saveAdSpinState(nk, userId, state) {
    var version = state._version || "*";
    var payload = {
        spinsUsed: state.spinsUsed || 0,
        lastSpinAt: state.lastSpinAt || 0,
        cycleStart: state.cycleStart || ""
    };

    nk.storageWrite([{
        collection: "fortune_wheel_ad_spins",
        key: "cycle_state",
        userId: userId,
        value: payload,
        version: version,
        permissionRead: 1,
        permissionWrite: 0
    }]);
}

/**
 * Ensures ad-state belongs to the current organic cycle.
 * If stale, resets to zero for the active cycle.
 */
function normalizeAdStateForCurrentCycle(nk, userId, wheelState, adState, logger) {
    if (!wheelState || !wheelState.organicSpinDone || !wheelState.nextSpinTime) {
        return { spinsUsed: 0, lastSpinAt: 0, cycleStart: "", _version: adState._version || "*" };
    }

    var expectedCycleStart = getCurrentCycleStartIso(wheelState.nextSpinTime);
    if (!expectedCycleStart) {
        return adState;
    }

    if (adState.cycleStart === expectedCycleStart) {
        return adState;
    }

    var resetState = {
        spinsUsed: 0,
        lastSpinAt: 0,
        cycleStart: expectedCycleStart,
        _version: adState._version || "*"
    };

    try {
        saveAdSpinState(nk, userId, resetState);
        logger.info("fortune_wheel_get_state: reset stale ad cycle for " + userId);
        return resetState;
    } catch (e) {
        logger.warn("fortune_wheel_get_state: failed to reset stale ad cycle for " + userId + " — " + e.message);
        return resetState;
    }
}

/**
 * Server-side weighted random selection.
 * Mirrors client segment order so segmentIndex maps directly to UI slice.
 */
function getWeightedRandomIndex() {
    var totalWeight = 0;
    for (var i = 0; i < SEGMENTS.length; i++) {
        totalWeight += SEGMENTS[i].weight;
    }

    var roll = Math.floor(Math.random() * totalWeight);
    var cumulative = 0;

    for (var i = 0; i < SEGMENTS.length; i++) {
        cumulative += SEGMENTS[i].weight;
        if (roll < cumulative) return i;
    }
    return SEGMENTS.length - 1; // Fallback
}

function grantReward(nk, userId, rewardType, amount, logger) {
    switch (rewardType) {
        case "XP":
            var xpChangeset = {};
            xpChangeset["xp"] = +amount;
            try { nk.walletUpdate(userId, xpChangeset, {}, true); }
            catch(e) { logger.warn("XP grant failed: " + e.message); }
            break;

        case "Coins":
            var coinChangeset = {};
            coinChangeset["coins"] = +amount;
            try { nk.walletUpdate(userId, coinChangeset, {}, true); }
            catch(e) { logger.warn("Coin grant failed: " + e.message); }
            break;

        case "AudiobookToken":
            try {
                var tokenObj = nk.storageRead([{
                    collection: "audiobook",
                    key: "tokens",
                    userId: userId
                }]);
                var tokens = (tokenObj && tokenObj.length > 0) ? (tokenObj[0].value.count || 0) : 0;
                tokens += amount;
                nk.storageWrite([{
                    collection: "audiobook",
                    key: "tokens",
                    userId: userId,
                    value: { count: tokens, lastGranted: new Date().toISOString() },
                    permissionRead: 1,
                    permissionWrite: 0
                }]);
            } catch(e) { logger.warn("Audiobook token grant failed: " + e.message); }
            break;

        case "Shield":
            try {
                nk.storageWrite([{
                    collection: "streak_shield",
                    key: "pending_grant",
                    userId: userId,
                    value: { hours: amount, source: "fortune_wheel", timestamp: new Date().toISOString() },
                    permissionRead: 1,
                    permissionWrite: 0
                }]);
            } catch(e) { logger.warn("Shield grant failed: " + e.message); }
            break;

        default:
            logger.warn("Unknown reward type: " + rewardType);
    }
}


// --- Module: friends\friends.js ---
// ============================================================================
// friends.js — Helper-only module (Phase-4 C2 cleanup)
// ============================================================================
// PRODUCTION-READY | ES5 (Goja runtime)
//
// HISTORY
// -------
// This file used to host SIX RPC handlers and SEVERAL helpers:
//   * RPCs: friends_block, friends_unblock, friends_remove, friends_list,
//          friends_challenge_user, friends_spectate
//   * Helpers: isValidFriendUUID, isUserBlocked, areActualFriends,
//              checkRateLimit, sendChallengePushNotification,
//              sendChallengeChatMessage
//
// All six RPCs were silently shadowed by canonical replacements:
//   * friends_block / friends_unblock / friends_remove → src/legacy/friends.ts
//   * friends_list                                    → src/friends/friends_list.ts (Phase-4 C1)
//   * friends_challenge_user / friends_spectate       → friends/friend_challenges.js (Phase-3a)
//
// Phase-4 C2 strips the dead RPC handlers AND their now-unused helpers
// (isValidFriendUUID, isUserBlocked, areActualFriends, checkRateLimit) so
// nobody can read this file and "fix" the wrong code path. The lone
// `checkRateLimit` deletion also removes a name collision with
// `infrastructure/rate_limiting.js` which defines a totally different
// function with the same name (different signature) — the
// rate_limiting.js version was silently overwriting friends.js's at
// merge time, which is the kind of subtle global-scope bug we never
// want to hit.
//
// What remains
// ------------
// Two helper functions that `friends/friend_challenges.js` still calls
// at runtime (via `typeof X === 'function'` lookups so the module is
// resilient to load-order changes — see line 483-495 of
// friend_challenges.js):
//
//   sendChallengePushNotification(nk, logger, targetUserId, gameId,
//                                 challengerName, quizModeName,
//                                 challengeId, roomCode, isAsync)
//      → fans out a push notification via the PUSH_SEND_URL Lambda
//        endpoint to every push_endpoints row owned by `targetUserId`
//        for the given `gameId`. Used by send_friend_challenge.
//
//   sendChallengeChatMessage(nk, logger, senderId, receiverId,
//                            senderName, challengeData)
//      → inserts a "friend challenge" message into the DM channel
//        between sender and receiver so the challenge appears in their
//        chat thread. Falls back to a `pending_chat_messages` storage
//        row if the channel insert fails.
//
// Both helpers are intentionally kept in the legacy JS module rather
// than ported to TypeScript because (a) the Phase-3a TS challenge
// module already has the canonical RPC handler, (b) these helpers are
// pure side-effect fan-outs the TS handler delegates to via dynamic
// lookup, and (c) the dynamic lookup pattern is the safest way to
// handle "host calls helper if it exists, otherwise no-op" without
// hard-coupling the two files.
//
// If you need to add a NEW friend RPC, ADD IT TO ONE OF:
//   - friends/friend_invites.js     (invite lifecycle)
//   - friends/friend_challenges.js  (challenge lifecycle + spectate)
//   - src/friends/friends_list.ts   (read-only roster RPCs)
//   - src/legacy/friends.ts         (graph mutations)
// NOT to this file. This file should never grow back to handler size.
// ============================================================================


/**
 * Send a push notification for a friend challenge.
 * Calls the push notification Lambda endpoint.
 *
 * @param {object} nk
 * @param {object} logger
 * @param {string} targetUserId   - Recipient userId (the challenged player)
 * @param {string} gameId         - Free-form game/mode id (used to filter push_endpoints)
 * @param {string} challengerName - Display name shown in the push title
 * @param {string} quizModeName   - Display name of the quiz mode for the body
 * @param {string} challengeId    - Server-authoritative challenge id (echoed in data)
 * @param {string} roomCode       - Room/share code (echoed in data)
 * @param {boolean} isAsync       - True for async challenges, false for live
 */
function sendChallengePushNotification(nk, logger, targetUserId, gameId, challengerName, quizModeName, challengeId, roomCode, isAsync) {
    var LAMBDA_PUSH_URL = (typeof process!=="undefined"&&process.env?process.env.PUSH_SEND_URL:undefined) || "https://your-lambda-url.lambda-url.region.on.aws/send-push";

    var endpoints = [];
    try {
        var records = nk.storageList(targetUserId, "push_endpoints", 100);
        for (var i = 0; i < records.length; i++) {
            var value = records[i].value;
            if (value.gameId === gameId) {
                endpoints.push(value);
            }
        }
    } catch (err) {
        utils.logWarn(logger, "Could not list push endpoints: " + err.message);
        return;
    }

    if (endpoints.length === 0) {
        utils.logInfo(logger, "No push endpoints for user " + targetUserId);
        return;
    }

    var challengeType = isAsync ? "Async Challenge" : "Live Challenge";
    var title = "🎮 " + challengerName + " challenged you!";
    var body  = "Accept the " + quizModeName + " " + challengeType + " now!";

    for (var j = 0; j < endpoints.length; j++) {
        var endpoint = endpoints[j];

        var pushPayload = {
            endpointArn: endpoint.endpointArn,
            platform:    endpoint.platform,
            title:       title,
            body:        body,
            data: {
                type:         "friend_challenge",
                challengeId:  challengeId,
                roomCode:     roomCode,
                isAsync:      isAsync,
                click_action: "OPEN_CHALLENGE"
            },
            gameId:    gameId,
            eventType: "friend_challenge"
        };

        try {
            var response = nk.httpRequest(
                LAMBDA_PUSH_URL,
                "post",
                { "Content-Type": "application/json", "Accept": "application/json" },
                JSON.stringify(pushPayload)
            );
            if (response.code === 200 || response.code === 201) {
                utils.logInfo(logger, "Push sent to " + endpoint.platform + " for challenge " + challengeId);
            }
        } catch (pushErr) {
            utils.logWarn(logger, "Push to " + endpoint.platform + " failed: " + pushErr.message);
        }
    }
}

/**
 * Send a friend challenge as a chat message so it appears in the conversation
 * thread between the two users.
 *
 * @param {object} nk
 * @param {object} logger
 * @param {string} senderId      - Challenger userId
 * @param {string} receiverId    - Challenged userId
 * @param {string} senderName    - Challenger display name
 * @param {object} challengeData - { challengeId, roomCode, quizModeName, isAsync,
 *                                   fromUserId, fromDisplayName, expiresAt }
 */
function sendChallengeChatMessage(nk, logger, senderId, receiverId, senderName, challengeData) {
    var channelId = null;
    try {
        // Sort user IDs so both sides resolve to the same DM channel
        var sortedIds = [senderId, receiverId].sort();
        channelId = "dm_" + sortedIds[0] + "_" + sortedIds[1];
    } catch (err) {
        utils.logWarn(logger, "Could not create channel ID: " + err.message);
        return;
    }

    var messageContent = {
        type: "friend_challenge",
        text: "🎮 " + senderName + " challenged you to " + challengeData.quizModeName + "!",
        challenge: {
            challengeId:     challengeData.challengeId,
            roomCode:        challengeData.roomCode,
            shareCode:       challengeData.roomCode,
            quizModeName:    challengeData.quizModeName,
            isAsync:         challengeData.isAsync,
            fromUserId:      challengeData.fromUserId,
            fromDisplayName: challengeData.fromDisplayName,
            expiresAt:       challengeData.expiresAt,
            status:          "pending"
        }
    };

    try {
        nk.channelMessageSend(
            channelId,
            JSON.stringify(messageContent),
            senderId,
            senderName,
            true  // persistent
        );
        utils.logInfo(logger, "Challenge chat message sent to channel " + channelId);
    } catch (chatErr) {
        // Fallback: if the DM channel doesn't exist yet, persist the message
        // so it can be replayed when the channel is later opened.
        utils.logWarn(logger, "Channel message failed, using storage fallback: " + chatErr.message);

        var msgKey = "pending_chat_" + receiverId + "_" + Date.now();
        utils.writeStorage(nk, logger, "pending_chat_messages", msgKey, senderId, {
            senderId:    senderId,
            senderName:  senderName,
            receiverId:  receiverId,
            content:     messageContent,
            timestamp:   utils.getCurrentTimestamp()
        });
    }
}


// --- Module: friends\friends_extras.js ---
// ============================================================================
// friends_extras.js — Social Pressure / Online Count / Battle / Invite-Reward
// ============================================================================
// PRODUCTION-READY | ES5 (Goja runtime)
//
// Houses 4 RPCs that PLAN-ENGAGEMENT_SYSTEM_07_FRIENDS_SOCIAL.md (V11/V17/V20)
// requires the server to expose:
//
//   friends_get_online_count
//       -> count of caller's mutual friends currently online (Nakama presence)
//
//   social_pressure_get_today_summary
//       -> aggregates "friends played today / friends ahead of me / streak at
//          risk" data into a single response so the client doesn't need to
//          stitch 4 separate reads.
//
//   friend_battle_create
//       -> server-mints a battleId/roomCode, persists the lobby record under
//          friend_battles/<battleId>, fans out invitations + push notifications
//          to each invited friend. Atomic: if any non-friend is invited the
//          whole call fails before any side-effect.
//
//   friend_invite_with_reward
//       -> sends a friend invite (Nakama friendsAdd) AND tags it with a
//          reward bundle that's claimable when the recipient accepts. The
//          claim happens in send_friend_invite/accept_friend_invite already;
//          this RPC is a thin wrapper that records the reward intent so the
//          accept-handler can grant it.
//
// SECURITY: every RPC requires an authenticated caller (ctx.userId set), and
// every "target" is verified as a confirmed mutual friend (Nakama state == 0)
// before any side-effect.
// ============================================================================

var FX_BATTLE_COLLECTION = 'friend_battles';
var FX_INVITE_REWARD_COL = 'friend_invite_rewards';
var FX_BATTLE_MAX_INVITES = 8;
var FX_BATTLE_MAX_DATA_BYTES = 4096;

// ─── Tiny self-contained helpers ────────────────────────────────────────────
// Same defensive pattern as friend_challenges.js — no `utils` dependency so
// load-order can't break this module.

function _fxUuidValid(id) {
    if (!id || typeof id !== 'string') return false;
    return /^[0-9a-f]{8}-[0-9a-f]{4}-[0-9a-f]{4}-[0-9a-f]{4}-[0-9a-f]{12}$/i.test(id);
}

function _fxNowIso() { return new Date().toISOString(); }

function _fxOk(extra) {
    var out = { success: true };
    if (extra) {
        for (var k in extra) {
            if (Object.prototype.hasOwnProperty.call(extra, k)) out[k] = extra[k];
        }
    }
    return JSON.stringify(out);
}

function _fxErr(message, errorCode, extra) {
    var out = { success: false, error: message, errorCode: errorCode || 'unknown' };
    if (extra) {
        for (var k in extra) {
            if (Object.prototype.hasOwnProperty.call(extra, k)) out[k] = extra[k];
        }
    }
    return JSON.stringify(out);
}

function _fxParse(payload) {
    if (!payload || payload === '') return { ok: true, data: {} };
    try { return { ok: true, data: JSON.parse(payload) }; }
    catch (e)  { return { ok: false, error: 'Invalid JSON payload: ' + e.message }; }
}

function _fxMintBattleId(nk) {
    try {
        if (nk && typeof nk.uuidv4 === 'function') {
            return 'fbat_' + nk.uuidv4().replace(/-/g, '');
        }
    } catch (_) {}
    var hex = '0123456789abcdef';
    var rand = '';
    for (var i = 0; i < 24; i++) rand += hex.charAt(Math.floor(Math.random() * 16));
    return 'fbat_' + Date.now().toString(36) + '_' + rand;
}

// Returns array of confirmed-friend objects: [{ id, displayName, online }]
// MUST pass the caller's userId — passing null runs under SYSTEM context.
function _fxLoadFriends(nk, userId) {
    if (!userId) return [];
    var out = [];
    try {
        var page = nk.friendsList(userId, 1000, 0, null); // state=0 (FRIEND)
        if (page && page.friends) {
            for (var i = 0; i < page.friends.length; i++) {
                var fr = page.friends[i];
                if (fr && fr.user && fr.user.id) {
                    out.push({
                        id:          fr.user.id,
                        displayName: fr.user.displayName || fr.user.username || 'Friend',
                        online:      !!fr.user.online
                    });
                }
            }
        }
    } catch (_) {}
    return out;
}

// ============================================================================
// RPC: friends_get_online_count
// ============================================================================
//
// Payload: {}  (no inputs)
// Response: {
//   success: true,
//   onlineCount: <int>,
//   totalFriends: <int>,
//   onlineFriendIds: [<UUID>...],   // capped at 50 for response-size sanity
//   timestamp: <iso>
// }
//
// Reads via nk.friendsList(state=0) which already includes the `online` flag
// from Nakama presence — no extra round-trip needed.
function rpcFriendsGetOnlineCount(ctx, logger, nk, payload) {
    if (!ctx.userId) return _fxErr('Authentication required', 'unauthenticated');

    var friends = [];
    try {
        var page = nk.friendsList(ctx.userId, 1000, 0, null);
        if (page && page.friends) friends = page.friends;
    } catch (e) {
        logger.warn('[FriendsExtras] friendsList failed: ' + e.message);
        return _fxErr('Failed to load friends list', 'friends_list_failed');
    }

    var onlineIds = [];
    for (var i = 0; i < friends.length; i++) {
        var fr = friends[i];
        if (fr && fr.user && fr.user.id && fr.user.online === true) {
            if (onlineIds.length < 50) onlineIds.push(fr.user.id);
        }
    }

    return _fxOk({
        onlineCount:     onlineIds.length,
        totalFriends:    friends.length,
        onlineFriendIds: onlineIds,
        timestamp:       _fxNowIso()
    });
}

// ============================================================================
// RPC: social_pressure_get_today_summary
// ============================================================================
//
// Single-shot aggregator for the "Social Pressure" home-screen card. Returns:
//   {
//     friendsPlayedToday:      <int>,    // friends with quiz_complete today
//     friendsPassedMe:         <int>,    // friends whose XP > my XP today
//     friendsAboveMeInLeague:  [{ id, displayName, points, tier }],
//     friendsStreakAtRisk:     [{ id, displayName, streakDays, hoursLeft }],
//     timestamp: <iso>
//   }
//
// Read-only — never mutates state. Best-effort: any sub-source that fails is
// returned as 0 / [] rather than failing the whole call.
function rpcSocialPressureGetTodaySummary(ctx, logger, nk, payload) {
    if (!ctx.userId) return _fxErr('Authentication required', 'unauthenticated');

    var friends = _fxLoadFriends(nk, ctx.userId);
    var todayKey = _fxNowIso().slice(0, 10).replace(/-/g, '');

    // ── friendsPlayedToday + friendsPassedMe ──────────────────────────────
    // Reads friend's `daily_play_log/{userId}_{YYYYMMDD}` if present (set by
    // the existing daily_missions / quiz pipeline). Best-effort.
    var playedToday = 0;
    var passedMe = 0;
    var myXpToday = 0;

    try {
        var myLog = nk.storageRead([{
            collection: 'daily_play_log',
            key: ctx.userId + '_' + todayKey,
            userId: ctx.userId
        }]);
        if (myLog && myLog.length > 0 && myLog[0].value) {
            myXpToday = myLog[0].value.xpToday || 0;
        }
    } catch (_) {}

    for (var i = 0; i < friends.length; i++) {
        var fid = friends[i].id;
        try {
            var rows = nk.storageRead([{
                collection: 'daily_play_log',
                key: fid + '_' + todayKey,
                userId: fid
            }]);
            if (rows && rows.length > 0 && rows[0].value) {
                playedToday++;
                var fxp = rows[0].value.xpToday || 0;
                if (fxp > myXpToday) passedMe++;
            }
        } catch (_) { /* friend may have permission 0 — skip silently */ }
    }

    // ── friendsAboveMeInLeague ────────────────────────────────────────────
    // Reads friend's league record from the legacy leagues collection.
    var aboveInLeague = [];
    var myLeague = null;
    try {
        var myL = nk.storageRead([{
            collection: 'leagues_named',
            key: 'state_quizverse',
            userId: ctx.userId
        }]);
        if (myL && myL.length > 0 && myL[0].value) myLeague = myL[0].value;
    } catch (_) {}

    if (myLeague) {
        for (var j = 0; j < friends.length; j++) {
            var fr = friends[j];
            try {
                var fL = nk.storageRead([{
                    collection: 'leagues_named',
                    key: 'state_quizverse',
                    userId: fr.id
                }]);
                if (fL && fL.length > 0 && fL[0].value) {
                    var lv = fL[0].value;
                    if (lv.tier === myLeague.tier && (lv.points || 0) > (myLeague.points || 0)) {
                        aboveInLeague.push({
                            id:          fr.id,
                            displayName: fr.displayName,
                            points:      lv.points || 0,
                            tier:        lv.tier
                        });
                    }
                }
            } catch (_) {}
        }
        aboveInLeague.sort(function(a, b) { return b.points - a.points; });
        if (aboveInLeague.length > 10) aboveInLeague = aboveInLeague.slice(0, 10);
    }

    // ── friendsStreakAtRisk ───────────────────────────────────────────────
    // Reads MY friend_streaks record (where I am one party of the streak).
    // "At risk" = bilateral streak with <8 hours until break.
    var atRisk = [];
    try {
        var myStreaks = nk.storageRead([{
            collection: 'friend_streaks',
            key: 'streaks_' + ctx.userId,
            userId: ctx.userId
        }]);
        if (myStreaks && myStreaks.length > 0 && myStreaks[0].value &&
            myStreaks[0].value.streaks) {
            var streaks = myStreaks[0].value.streaks;
            var nowMs = Date.now();
            for (var fid2 in streaks) {
                if (!Object.prototype.hasOwnProperty.call(streaks, fid2)) continue;
                var s = streaks[fid2];
                if (!s || !s.lastInteractionAt) continue;
                var hoursSince = (nowMs - new Date(s.lastInteractionAt).getTime()) / 3600000;
                var hoursLeft = 48 - hoursSince;
                if (hoursLeft > 0 && hoursLeft < 8) {
                    atRisk.push({
                        id:          fid2,
                        displayName: s.friendDisplayName || '',
                        streakDays:  s.streakDays || 0,
                        hoursLeft:   Math.max(0, Math.round(hoursLeft))
                    });
                }
            }
            atRisk.sort(function(a, b) { return a.hoursLeft - b.hoursLeft; });
        }
    } catch (e) {
        logger.warn('[FriendsExtras] streak read failed: ' + e.message);
    }

    return _fxOk({
        friendsPlayedToday:     playedToday,
        friendsPassedMe:        passedMe,
        friendsAboveMeInLeague: aboveInLeague,
        friendsStreakAtRisk:    atRisk,
        totalFriends:           friends.length,
        timestamp:              _fxNowIso()
    });
}

// ============================================================================
// RPC: friend_battle_create
// ============================================================================
//
// Server-mints a friend battle / lobby and atomically:
//   1) verifies every invited friend is a confirmed mutual friend
//   2) persists the lobby record (friend_battles/<battleId>)
//   3) sends a Nakama notification to each invitee (code 110)
//
// Photon room creation is owned by the client; this RPC just guarantees the
// invite fan-out is consistent (nobody gets a notification for a battle that
// failed validation).
//
// Payload: {
//   mode:           <string, e.g. 'speed_quiz' | 'classic'>,
//   roomCode:       <string ≤ 64>,
//   invitedFriendIds: [<UUID>...],   // 1..FX_BATTLE_MAX_INVITES
//   metadata?:      <object ≤ 4 KB>
// }
function rpcFriendBattleCreate(ctx, logger, nk, payload) {
    if (!ctx.userId) return _fxErr('Authentication required', 'unauthenticated');

    var p = _fxParse(payload);
    if (!p.ok) return _fxErr(p.error, 'invalid_payload');

    var data = p.data || {};
    var mode = data.mode;
    var roomCode = data.roomCode;
    var invited = data.invitedFriendIds || [];
    var meta = data.metadata || {};

    if (!mode || typeof mode !== 'string' || mode.length > 64) {
        return _fxErr('mode is required (string ≤ 64)', 'invalid_payload');
    }
    if (!roomCode || typeof roomCode !== 'string' || roomCode.length > 64) {
        return _fxErr('roomCode is required (string ≤ 64)', 'invalid_payload');
    }
    if (!Array.isArray(invited) || invited.length === 0) {
        return _fxErr('invitedFriendIds must be non-empty array', 'invalid_payload');
    }
    if (invited.length > FX_BATTLE_MAX_INVITES) {
        return _fxErr('Too many invites (max ' + FX_BATTLE_MAX_INVITES + ')', 'too_many_invites');
    }
    var metaStr;
    try { metaStr = JSON.stringify(meta); }
    catch (e) { return _fxErr('metadata not serialisable: ' + e.message, 'invalid_payload'); }
    if (metaStr.length > FX_BATTLE_MAX_DATA_BYTES) {
        return _fxErr('metadata too large', 'data_too_large');
    }

    // Validate every invitee is a mutual friend BEFORE any side-effect
    var mutualFriends = {};
    var friends = _fxLoadFriends(nk, ctx.userId);
    for (var i = 0; i < friends.length; i++) mutualFriends[friends[i].id] = friends[i];

    var rejected = [];
    for (var j = 0; j < invited.length; j++) {
        var inv = invited[j];
        if (!_fxUuidValid(inv)) {
            rejected.push({ id: inv, reason: 'invalid_uuid' });
        } else if (inv === ctx.userId) {
            rejected.push({ id: inv, reason: 'self_invite' });
        } else if (!mutualFriends[inv]) {
            rejected.push({ id: inv, reason: 'not_mutual_friend' });
        }
    }
    if (rejected.length > 0) {
        return _fxErr('Some invitees are not mutual friends', 'invitees_not_mutual',
                      { rejected: rejected });
    }

    var battleId = _fxMintBattleId(nk);
    var nowIso = _fxNowIso();
    var senderName = ctx.username || ctx.userId;

    var battleRecord = {
        battleId:     battleId,
        creatorId:    ctx.userId,
        creatorName:  senderName,
        mode:         mode,
        roomCode:     roomCode,
        status:       'pending',
        invitedIds:   invited,
        acceptedIds:  [],
        declinedIds:  [],
        metadata:     meta,
        createdAt:    nowIso,
        expiresAt:    new Date(Date.now() + 5 * 60 * 1000).toISOString() // 5 min
    };

    // Persist lobby (owner = creator, owner-readable)
    try {
        nk.storageWrite([{
            collection:      FX_BATTLE_COLLECTION,
            key:             battleId,
            userId:          ctx.userId,
            value:           battleRecord,
            permissionRead:  1,
            permissionWrite: 0
        }]);
    } catch (e) {
        logger.error('[FriendsExtras] battle persist failed: ' + e.message);
        return _fxErr('Failed to persist battle', 'storage_write_failed');
    }

    // Fan out notifications (best-effort — but battle record exists already)
    var notifs = [];
    for (var k = 0; k < invited.length; k++) {
        notifs.push({
            userId:     invited[k],
            subject:    senderName + ' invited you to a battle!',
            content: {
                type:        'friend_battle_invite',
                battleId:    battleId,
                fromUserId:  ctx.userId,
                fromName:    senderName,
                mode:        mode,
                roomCode:    roomCode,
                expiresAt:   battleRecord.expiresAt
            },
            code:       110,
            persistent: true,
            sender:     ctx.userId
        });
    }
    try {
        if (notifs.length > 0) nk.notificationsSend(notifs);
    } catch (e) {
        logger.warn('[FriendsExtras] battle notify failed: ' + e.message);
    }

    return _fxOk({
        battleId:        battleId,
        roomCode:        roomCode,
        mode:            mode,
        invitedIds:      invited,
        invitedCount:    invited.length,
        expiresAt:       battleRecord.expiresAt,
        timestamp:       nowIso
    });
}

// ============================================================================
// RPC: friend_invite_with_reward
// ============================================================================
//
// Sends a friend invite (Nakama friendsAdd) AND records a reward bundle that
// will be granted to BOTH parties on accept. The actual grant happens in
// the existing accept_friend_invite handler — this RPC just stores the intent.
//
// Payload: {
//   targetUserId: <UUID>,
//   rewardBundle?: { coins?: int, gems?: int, xp?: int }   // capped server-side
// }
//
// Caps: coins ≤ 200, gems ≤ 10, xp ≤ 100 per invite (anti-griefing).
var FX_REWARD_CAP = { coins: 200, gems: 10, xp: 100 };

function rpcFriendInviteWithReward(ctx, logger, nk, payload) {
    if (!ctx.userId) return _fxErr('Authentication required', 'unauthenticated');

    var p = _fxParse(payload);
    if (!p.ok) return _fxErr(p.error, 'invalid_payload');

    var data = p.data || {};
    var target = data.targetUserId;
    if (!_fxUuidValid(target)) {
        return _fxErr('Invalid targetUserId (UUID required)', 'invalid_target');
    }
    if (target === ctx.userId) {
        return _fxErr('Cannot invite yourself', 'self_invite');
    }

    var raw = data.rewardBundle || {};
    var bundle = {
        coins: Math.min(FX_REWARD_CAP.coins, Math.max(0, parseInt(raw.coins) || 0)),
        gems:  Math.min(FX_REWARD_CAP.gems,  Math.max(0, parseInt(raw.gems)  || 0)),
        xp:    Math.min(FX_REWARD_CAP.xp,    Math.max(0, parseInt(raw.xp)    || 0))
    };

    // Send the friend request via Nakama's native graph
    try {
        nk.friendsAdd(ctx.userId, ctx.username || '', [target], null);
    } catch (e) {
        return _fxErr('friendsAdd failed: ' + e.message, 'friends_add_failed');
    }

    // Persist the reward intent under both parties so accept_friend_invite
    // (in src/legacy/friends.ts) can find and grant it.
    var nowIso = _fxNowIso();
    var rewardKey = 'invite_reward_' + ctx.userId + '_' + target;
    var rewardRecord = {
        senderId:       ctx.userId,
        recipientId:    target,
        rewardBundle:   bundle,
        status:         'pending',
        createdAt:      nowIso,
        expiresAt:      new Date(Date.now() + 7 * 86400000).toISOString() // 7 days
    };
    try {
        nk.storageWrite([
            {
                collection:      FX_INVITE_REWARD_COL,
                key:             rewardKey,
                userId:          ctx.userId,
                value:           rewardRecord,
                permissionRead:  0,
                permissionWrite: 0
            },
            {
                collection:      FX_INVITE_REWARD_COL,
                key:             rewardKey,
                userId:          target,
                value:           rewardRecord,
                permissionRead:  0,
                permissionWrite: 0
            }
        ]);
    } catch (e) {
        logger.warn('[FriendsExtras] invite-reward persist failed: ' + e.message);
        // Non-fatal — friend invite already went out
    }

    // Notify the recipient
    try {
        nk.notificationsSend([{
            userId:     target,
            subject:    'Friend Invite + Reward',
            content: {
                type:         'friend_invite_with_reward',
                fromUserId:   ctx.userId,
                fromName:     ctx.username || ctx.userId,
                rewardBundle: bundle
            },
            code:       111,
            persistent: true,
            sender:     ctx.userId
        }]);
    } catch (e) {
        logger.warn('[FriendsExtras] invite notify failed: ' + e.message);
    }

    return _fxOk({
        targetUserId:   target,
        rewardBundle:   bundle,
        rewardKey:      rewardKey,
        expiresAt:      rewardRecord.expiresAt,
        timestamp:      nowIso
    });
}

// ============================================================================
// Module Init — register Friends Extras RPCs
// ============================================================================
function __ModuleInit_33(ctx, logger, nk, initializer) {
    __rpc_friends_get_online_count = __rpc_friends_get_online_count || (rpcFriendsGetOnlineCount);
    __rpc_social_pressure_get_today_summary = __rpc_social_pressure_get_today_summary || (rpcSocialPressureGetTodaySummary);
    __rpc_friend_battle_create = __rpc_friend_battle_create || (rpcFriendBattleCreate);
    __rpc_friend_invite_with_reward = __rpc_friend_invite_with_reward || (rpcFriendInviteWithReward);
    if (logger && logger.info) {
        logger.info('[FriendsExtras] Registered 4 RPCs (online_count, social_pressure, battle_create, invite_with_reward)');
    }
}


// --- Module: friends\friend_challenges.js ---
// ============================================================================
// friend_challenges.js - Canonical Friend Challenge Lifecycle RPCs
// ============================================================================
// PRODUCTION-READY | ES5 (Goja runtime) | Single source of truth
//
// Replaces the legacy single-shot `friends_challenge_user` stub (which was
// effectively broken at the network boundary because it required `gameId`
// to be a UUID, but the Unity client sends `async_<guid>` / `sync_<guid>`
// strings).  This module:
//
//  1. SERVER-AUTHORITATIVE challengeId  (`fchg_<32 chars>`, server-minted)
//  2. STRICT mutual-friend gate         (Nakama state == 0 only)
//  3. Bi-directional block check        (sender->target AND target->sender)
//  4. STRICT rate limit                 (1 per (sender,target) per 30 s
//                                        + 20 per sender per minute global,
//                                        sliding window)
//  5. Persists FULL lifecycle           (pending → accepted | declined |
//                                        cancelled | expired)
//  6. Auto-expiry at READ time          (lazy sweep — no scheduled job needed)
//  7. Per-game expiry policy            (async = 24 h, sync = 5 min,
//                                        default = 1 h; client may override
//                                        via challengeData.isAsync)
//  8. challengeData size cap            (4 KB JSON)
//  9. Idempotent state transitions      (double-tap accept/decline/cancel
//                                        returns success without erroring)
// 10. Notifications use canonical       (NotifCode 100/101/102/103 +
//     Subject/Code from notification_codes.js so the Unity
//     `IVXFriendsManager.HandleNotification` filter actually matches)
// 11. Storage layout
//        friend_challenges/<id>          (owner = recipient,  perm 1/0)
//        friend_challenges_outbox/<id>   (owner = sender,     perm 1/0)
//     Two writes per state change, but lets BOTH parties query their own
//     side without cross-user storage reads.
//
// Registered RPCs:
//   send_friend_challenge              ← canonical
//   friends_challenge_user             ← legacy alias (clients may still call this)
//   accept_friend_challenge
//   decline_friend_challenge
//   cancel_friend_challenge
//   list_pending_friend_challenges
//
// SIDE-EFFECTS (re-uses helpers from friends/friends.js when present):
//   sendChallengePushNotification(nk, logger, ...) — push notification fan-out
//   sendChallengeChatMessage(nk, logger, ...)      — DM channel insertion
// Both calls are wrapped in try/catch and `typeof === 'function'` guards
// so this module remains functional even if friends.js is removed.
// ============================================================================

// ─── Tunables ───────────────────────────────────────────────────────────────
var FC_COLLECTION         = 'friend_challenges';        // canonical, owner = recipient
var FC_OUTBOX             = 'friend_challenges_outbox'; // index, owner = sender
var FC_RL_PAIR_KEY        = 'fchg_pair';
var FC_RL_PAIR_MS         = 30000; // 30 s between sends to the same target
var FC_RL_GLOBAL_KEY      = 'fchg_global';
var FC_RL_GLOBAL_WINDOW_MS = 60000; // sliding window
var FC_RL_GLOBAL_MAX      = 20;     // 20 sends / min / sender
var FC_MAX_DATA_BYTES     = 4096;
var FC_MAX_REASON_LEN     = 280;
var FC_MAX_GAMEID_LEN     = 128;

// Status enum
var FC_STATUS_PENDING   = 'pending';
var FC_STATUS_ACCEPTED  = 'accepted';
var FC_STATUS_DECLINED  = 'declined';
var FC_STATUS_CANCELLED = 'cancelled';
var FC_STATUS_EXPIRED   = 'expired';

// Nakama friend states (from runtime API)
var FCF_STATE_FRIEND  = 0;
var FCF_STATE_BLOCKED = 3;

// ─── Tiny self-contained helpers (no external `utils` dependency) ──────────
// Same philosophy as friend_invites.js: bullet-proof regardless of merge order.

function _fcUuidValid(id) {
    if (!id || typeof id !== 'string') return false;
    return /^[0-9a-f]{8}-[0-9a-f]{4}-[0-9a-f]{4}-[0-9a-f]{4}-[0-9a-f]{12}$/i.test(id);
}

function _fcNowIso() { return new Date().toISOString(); }
function _fcNowMs()  { return Date.now(); }

function _fcOk(extra) {
    var out = { success: true };
    if (extra) {
        for (var k in extra) {
            if (Object.prototype.hasOwnProperty.call(extra, k)) out[k] = extra[k];
        }
    }
    return JSON.stringify(out);
}

// Standardised error envelope. `errorCode` is a stable machine code so the
// client can switch on it without parsing English strings.
function _fcErr(message, errorCode, extra) {
    var out = { success: false, error: message, errorCode: errorCode || 'unknown' };
    if (extra) {
        for (var k in extra) {
            if (Object.prototype.hasOwnProperty.call(extra, k)) out[k] = extra[k];
        }
    }
    return JSON.stringify(out);
}

function _fcParsePayload(payload) {
    if (!payload || payload === '') return { ok: true, data: {} };
    try { return { ok: true, data: JSON.parse(payload) }; }
    catch (e)  { return { ok: false, error: 'Invalid JSON payload: ' + e.message }; }
}

// Mint a server-authoritative challengeId.
//
// Prefers `nk.uuidv4()` (cryptographically random, available in Nakama JS
// runtime) and falls back to a timestamp + 24 random hex chars composite
// for environments where the API may have moved/renamed in a future runtime.
function _fcMintChallengeId(nk) {
    try {
        if (nk && typeof nk.uuidv4 === 'function') {
            return 'fchg_' + nk.uuidv4().replace(/-/g, '');
        }
    } catch (_) { /* fall through */ }
    var hex = '0123456789abcdef';
    var rand = '';
    for (var i = 0; i < 24; i++) {
        rand += hex.charAt(Math.floor(Math.random() * 16));
    }
    return 'fchg_' + Date.now().toString(36) + '_' + rand;
}

// Per-game expiry policy.  Returns seconds.
//   isAsync == true  → 24 h
//   isAsync == false → 5  min
//   gameId contains 'async' → 24 h
//   gameId contains 'sync'  → 5  min
//   default                  → 1  h
function _fcExpirySecondsForGame(gameId, isAsync) {
    if (isAsync === true)  return 24 * 3600;
    if (isAsync === false) return 5 * 60;
    if (typeof gameId === 'string') {
        var g = gameId.toLowerCase();
        if (g.indexOf('async') !== -1) return 24 * 3600;
        if (g.indexOf('sync')  !== -1) return 5 * 60;
    }
    return 3600;
}

// STRICT mutual-friend check using Nakama's native friend graph.
// Returns true ONLY for state == 0 (FRIEND).  Pending invites do NOT count.
function _fcAreFriends(nk, callerId, targetId) {
    try {
        // friendsList(userId, limit, state, cursor) — state == 0 limits the page
        // to confirmed friends only, which is materially cheaper than fetching
        // every relationship and filtering.
        var page = nk.friendsList(callerId, 1000, FCF_STATE_FRIEND, null);
        if (page && page.friends) {
            for (var i = 0; i < page.friends.length; i++) {
                var fr = page.friends[i];
                if (fr && fr.user && fr.user.id === targetId) return true;
            }
        }
    } catch (_) { /* fail-closed (deny on lookup error) */ }
    return false;
}

// One-direction block check via the legacy `user_blocks` storage collection
// that friends/friends.js populates.  Caller passes the BLOCKER first.
function _fcIsBlockedBy(nk, blockerUserId, blockedUserId) {
    try {
        var rows = nk.storageRead([{
            collection: 'user_blocks',
            key:        'blocked_' + blockerUserId + '_' + blockedUserId,
            userId:     blockerUserId
        }]);
        return !!(rows && rows.length > 0 && rows[0] && rows[0].value);
    } catch (_) { return false; /* fail-open on lookup error */ }
}

// Pair-level rate limit: at most 1 challenge from sender→target per 30 s.
// Also serves as natural double-submit protection.
function _fcCheckPairRateLimit(nk, senderId, targetId) {
    var key = FC_RL_PAIR_KEY + '_' + senderId + '_' + targetId;
    var now = _fcNowMs();
    try {
        var rows = nk.storageRead([{ collection: 'rate_limits', key: key, userId: senderId }]);
        if (rows && rows.length > 0 && rows[0].value && rows[0].value.timestamp) {
            var elapsed = now - rows[0].value.timestamp;
            if (elapsed < FC_RL_PAIR_MS) {
                return { allowed: false, retryAfterMs: FC_RL_PAIR_MS - elapsed };
            }
        }
    } catch (_) { /* fail-open */ }
    try {
        nk.storageWrite([{
            collection:      'rate_limits',
            key:             key,
            userId:          senderId,
            value:           { timestamp: now },
            permissionRead:  0, // server-only
            permissionWrite: 0
        }]);
    } catch (_) { /* non-critical */ }
    return { allowed: true };
}

// Global rate limit: at most 20 challenges per sender per 60 s window.
// Implemented as a sliding-window timestamp ring stored under the user.
function _fcCheckGlobalRateLimit(nk, senderId) {
    var key = FC_RL_GLOBAL_KEY + '_' + senderId;
    var now = _fcNowMs();
    var stamps = [];
    try {
        var rows = nk.storageRead([{ collection: 'rate_limits', key: key, userId: senderId }]);
        if (rows && rows.length > 0 && rows[0].value && rows[0].value.stamps) {
            stamps = rows[0].value.stamps;
        }
    } catch (_) { /* fail-open */ }
    var fresh = [];
    for (var i = 0; i < stamps.length; i++) {
        if ((now - stamps[i]) < FC_RL_GLOBAL_WINDOW_MS) fresh.push(stamps[i]);
    }
    if (fresh.length >= FC_RL_GLOBAL_MAX) {
        // Oldest stamp determines when the next slot frees up
        return { allowed: false, retryAfterMs: FC_RL_GLOBAL_WINDOW_MS - (now - fresh[0]) };
    }
    fresh.push(now);
    try {
        nk.storageWrite([{
            collection:      'rate_limits',
            key:             key,
            userId:          senderId,
            value:           { stamps: fresh },
            permissionRead:  0,
            permissionWrite: 0
        }]);
    } catch (_) { /* non-critical */ }
    return { allowed: true };
}

function _fcDisplayName(nk, userId, fallback) {
    try {
        var users = nk.usersGetId([userId]);
        if (users && users.length > 0 && users[0]) {
            return users[0].displayName || users[0].username || fallback || userId;
        }
    } catch (_) {}
    return fallback || userId;
}

function _fcReadChallenge(nk, challengeId, recipientId) {
    try {
        var rows = nk.storageRead([{
            collection: FC_COLLECTION, key: challengeId, userId: recipientId
        }]);
        if (rows && rows.length > 0 && rows[0].value) {
            return { value: rows[0].value, version: rows[0].version };
        }
    } catch (_) {}
    return null;
}

function _fcReadOutbox(nk, challengeId, senderId) {
    try {
        var rows = nk.storageRead([{
            collection: FC_OUTBOX, key: challengeId, userId: senderId
        }]);
        if (rows && rows.length > 0 && rows[0].value) {
            return { value: rows[0].value, version: rows[0].version };
        }
    } catch (_) {}
    return null;
}

function _fcWriteChallenge(nk, challenge, recipientId, version) {
    var rec = {
        collection:      FC_COLLECTION,
        key:             challenge.challengeId,
        userId:          recipientId,
        value:           challenge,
        permissionRead:  1,  // owner-readable
        permissionWrite: 0   // server-only
    };
    if (version) rec.version = version;
    nk.storageWrite([rec]);
}

function _fcWriteOutbox(nk, challenge, senderId, version) {
    // Mini index — keeps the sender's outbox small even if challengeData is big.
    var quizMode = '';
    if (challenge.challengeData) {
        quizMode = challenge.challengeData.modeName ||
                   challenge.challengeData.quizModeName || '';
    }
    var index = {
        challengeId:       challenge.challengeId,
        targetUserId:      challenge.toUserId,
        targetDisplayName: challenge.toDisplayName || '',
        gameId:            challenge.gameId,
        quizModeName:      quizMode,
        roomCode:          challenge.roomCode || '',
        shareCode:         challenge.shareCode || '',
        isAsync:           !!challenge.isAsync,
        status:            challenge.status,
        createdAt:         challenge.createdAt,
        expiresAt:         challenge.expiresAt,
        statusUpdatedAt:   challenge.updatedAt
    };
    var rec = {
        collection:      FC_OUTBOX,
        key:             challenge.challengeId,
        userId:          senderId,
        value:           index,
        permissionRead:  1,
        permissionWrite: 0
    };
    if (version) rec.version = version;
    nk.storageWrite([rec]);
}

// ============================================================================
// RPC: send_friend_challenge
// ============================================================================
// Replaces friends_challenge_user.  Both names are registered (legacy alias).
//
// Payload:
//   {
//     friendUserId: <UUID>,             // recipient
//     gameId:       <string, ≤128 chars>, // ANY string — we no longer require UUID
//     challengeData: {                   // ≤ 4 KB JSON
//       isAsync?:   boolean,
//       roomCode?:  string,
//       shareCode?: string,
//       modeName?:  string,
//       ...
//     },
//     correlationId?: <string>           // optimistic-UI hint, echoed back
//   }
//
// Response (success):
//   {
//     success: true,
//     challengeId, fromUserId, toUserId, gameId, status, roomCode, shareCode,
//     isAsync, expiresAt, timestamp, correlationId
//   }
//
// Response (failure): { success: false, error, errorCode, ... }
function rpcSendFriendChallenge(ctx, logger, nk, payload) {
    var senderId = ctx.userId;
    if (!senderId) return _fcErr('Authentication required', 'unauthenticated');

    var p = _fcParsePayload(payload);
    if (!p.ok) return _fcErr(p.error, 'invalid_payload');

    var data                = p.data || {};
    var targetUserId        = data.friendUserId || data.targetUserId;
    var gameId              = data.gameId;
    var rawData             = data.challengeData || {};
    var clientCorrelationId = data.correlationId || null;

    // ── Input validation ───────────────────────────────────────────────────
    if (!_fcUuidValid(targetUserId)) {
        return _fcErr('Invalid friendUserId (must be a UUID)', 'invalid_target');
    }
    if (targetUserId === senderId) {
        return _fcErr('Cannot challenge yourself', 'self_challenge');
    }
    if (!gameId || typeof gameId !== 'string') {
        return _fcErr('gameId is required (string)', 'invalid_payload');
    }
    if (gameId.length > FC_MAX_GAMEID_LEN) {
        return _fcErr('gameId is too long (max ' + FC_MAX_GAMEID_LEN + ')', 'invalid_payload');
    }
    if (typeof rawData !== 'object' || rawData === null || Array.isArray(rawData)) {
        return _fcErr('challengeData must be an object', 'invalid_payload');
    }
    var dataStr;
    try { dataStr = JSON.stringify(rawData); }
    catch (e) { return _fcErr('challengeData not serialisable: ' + e.message, 'invalid_payload'); }
    if (dataStr.length > FC_MAX_DATA_BYTES) {
        return _fcErr('challengeData too large (max ' + FC_MAX_DATA_BYTES + ' bytes)',
                      'data_too_large');
    }
    if (clientCorrelationId !== null &&
        (typeof clientCorrelationId !== 'string' || clientCorrelationId.length > 128)) {
        return _fcErr('correlationId must be a string ≤ 128 chars', 'invalid_payload');
    }

    // ── Mutual-friend gate (STRICT) ────────────────────────────────────────
    if (!_fcAreFriends(nk, senderId, targetUserId)) {
        return _fcErr('You can only challenge mutual friends', 'not_mutual_friends');
    }

    // ── Block checks (both directions) ─────────────────────────────────────
    if (_fcIsBlockedBy(nk, senderId, targetUserId)) {
        return _fcErr('You have blocked this user. Unblock them first.',
                      'caller_blocked_target');
    }
    if (_fcIsBlockedBy(nk, targetUserId, senderId)) {
        // Don't reveal — generic error
        return _fcErr('Unable to send challenge at this time', 'send_blocked');
    }

    // ── Rate limits (STRICT — pair AND global) ─────────────────────────────
    var pairRl = _fcCheckPairRateLimit(nk, senderId, targetUserId);
    if (!pairRl.allowed) {
        return _fcErr('Slow down — you challenged this friend recently',
                      'pair_rate_limited', { retryAfterMs: pairRl.retryAfterMs });
    }
    var globRl = _fcCheckGlobalRateLimit(nk, senderId);
    if (!globRl.allowed) {
        return _fcErr('Too many challenges in a short time',
                      'global_rate_limited', { retryAfterMs: globRl.retryAfterMs });
    }

    // ── Build canonical challenge record ───────────────────────────────────
    var nowMs    = _fcNowMs();
    var nowIso   = _fcNowIso();
    var isAsync  = (rawData.isAsync === true);
    var expirySec  = _fcExpirySecondsForGame(gameId, rawData.isAsync);
    var expiresMs  = nowMs + (expirySec * 1000);

    var challengeId  = _fcMintChallengeId(nk);
    var senderName   = _fcDisplayName(nk, senderId, ctx.username);
    var targetName   = _fcDisplayName(nk, targetUserId, '');

    var challenge = {
        challengeId:      challengeId,
        fromUserId:       senderId,
        fromUsername:     ctx.username || senderId,
        fromDisplayName:  senderName,
        toUserId:         targetUserId,
        toDisplayName:    targetName,
        gameId:           gameId,
        challengeData:    rawData,
        roomCode:         rawData.roomCode || rawData.shareCode || '',
        shareCode:        rawData.shareCode || rawData.roomCode || '',
        isAsync:          isAsync,
        status:           FC_STATUS_PENDING,
        createdAt:        nowIso,
        updatedAt:        nowIso,
        expiresAt:        new Date(expiresMs).toISOString(),
        expiresAtMs:      expiresMs,
        correlationId:    clientCorrelationId
    };

    // Canonical persist (under recipient — owner-readable for accept/decline)
    try {
        _fcWriteChallenge(nk, challenge, targetUserId, null);
    } catch (e) {
        logger.error('[FriendChallenges] storageWrite recipient failed: ' + e.message);
        return _fcErr('Failed to persist challenge', 'storage_write_failed');
    }

    // Outbox index persist (under sender — owner-readable for cancel/list)
    try {
        _fcWriteOutbox(nk, challenge, senderId, null);
    } catch (e) {
        // Non-fatal — sender just won't see this in their outgoing list until
        // the next successful write.  Canonical row is still authoritative.
        logger.warn('[FriendChallenges] outbox write failed (non-fatal): ' + e.message);
    }

    // ── Notify recipient (canonical Subject/Code contract) ─────────────────
    try {
        sendFriendsNotification(nk, logger, 'FRIEND_CHALLENGE_RECEIVED', targetUserId, {
            challengeId:     challengeId,
            fromUserId:      senderId,
            fromUsername:    ctx.username || senderId,
            fromDisplayName: senderName,
            gameId:          gameId,
            roomCode:        challenge.roomCode,
            shareCode:       challenge.shareCode,
            quizModeName:    (rawData.modeName || rawData.quizModeName || ''),
            isAsync:         isAsync,
            expiresAt:       challenge.expiresAt
        }, senderId);
    } catch (e) {
        logger.warn('[FriendChallenges] notify recipient failed: ' + e.message);
    }

    // ── Push notification (best-effort; helper lives in friends.js) ────────
    try {
        if (typeof sendChallengePushNotification === 'function') {
            sendChallengePushNotification(nk, logger, targetUserId, gameId, senderName,
                (rawData.modeName || rawData.quizModeName || 'Quiz'), challengeId,
                challenge.roomCode, isAsync);
        }
    } catch (e) {
        logger.warn('[FriendChallenges] push notification failed: ' + e.message);
    }

    // ── DM chat message (best-effort; helper lives in friends.js) ──────────
    try {
        if (typeof sendChallengeChatMessage === 'function') {
            sendChallengeChatMessage(nk, logger, senderId, targetUserId, senderName, {
                type:            'friend_challenge',
                challengeId:     challengeId,
                fromUserId:      senderId,
                fromDisplayName: senderName,
                gameId:          gameId,
                roomCode:        challenge.roomCode,
                shareCode:       challenge.shareCode,
                quizModeName:    (rawData.modeName || rawData.quizModeName || 'Quiz'),
                isAsync:         isAsync,
                expiresAt:       challenge.expiresAt
            });
        }
    } catch (e) {
        logger.warn('[FriendChallenges] chat insert failed: ' + e.message);
    }

    return _fcOk({
        challengeId:    challengeId,
        fromUserId:     senderId,
        toUserId:       targetUserId,
        gameId:         gameId,
        status:         FC_STATUS_PENDING,
        roomCode:       challenge.roomCode,
        shareCode:      challenge.shareCode,
        isAsync:        isAsync,
        expiresAt:      challenge.expiresAt,
        timestamp:      nowIso,
        correlationId:  clientCorrelationId
    });
}

// ============================================================================
// RPC: accept_friend_challenge
// ============================================================================
// Payload: { challengeId: <string> }
// Idempotent — second-tap accept returns success.
function rpcAcceptFriendChallenge(ctx, logger, nk, payload) {
    var userId = ctx.userId;
    if (!userId) return _fcErr('Authentication required', 'unauthenticated');

    var p = _fcParsePayload(payload);
    if (!p.ok) return _fcErr(p.error, 'invalid_payload');

    var challengeId = (p.data || {}).challengeId;
    if (!challengeId || typeof challengeId !== 'string') {
        return _fcErr('challengeId is required', 'invalid_payload');
    }

    var read = _fcReadChallenge(nk, challengeId, userId);
    if (!read) return _fcErr('Challenge not found', 'challenge_not_found');

    var challenge = read.value;
    if (challenge.toUserId !== userId) {
        return _fcErr('This challenge is not for you', 'challenge_not_for_caller');
    }

    // Idempotent — second-tap "Accept" must not throw
    if (challenge.status === FC_STATUS_ACCEPTED) {
        return _fcOk({
            challengeId:     challengeId,
            alreadyAccepted: true,
            fromUserId:      challenge.fromUserId,
            fromDisplayName: challenge.fromDisplayName,
            gameId:          challenge.gameId,
            roomCode:        challenge.roomCode,
            shareCode:       challenge.shareCode,
            isAsync:         challenge.isAsync
        });
    }
    if (challenge.status !== FC_STATUS_PENDING) {
        return _fcErr('This challenge has already been ' + challenge.status,
                      'challenge_not_pending', { currentStatus: challenge.status });
    }

    // Lazy expiry sweep
    if (challenge.expiresAtMs && challenge.expiresAtMs < _fcNowMs()) {
        challenge.status    = FC_STATUS_EXPIRED;
        challenge.updatedAt = _fcNowIso();
        try { _fcWriteChallenge(nk, challenge, userId, read.version); } catch (_) {}
        return _fcErr('This challenge has expired', 'challenge_expired',
                      { currentStatus: FC_STATUS_EXPIRED });
    }

    // ── Transition to ACCEPTED with optimistic concurrency ─────────────────
    challenge.status     = FC_STATUS_ACCEPTED;
    challenge.acceptedAt = _fcNowIso();
    challenge.updatedAt  = _fcNowIso();

    try {
        _fcWriteChallenge(nk, challenge, userId, read.version);
    } catch (e) {
        return _fcErr('Failed to persist accept: ' + e.message, 'storage_write_failed');
    }

    // Sync sender's outbox index so their UI reflects the new status
    try {
        _fcWriteOutbox(nk, challenge, challenge.fromUserId, null);
    } catch (e) {
        logger.warn('[FriendChallenges] accept outbox sync failed: ' + e.message);
    }

    // Notify the sender
    try {
        sendFriendsNotification(nk, logger, 'FRIEND_CHALLENGE_ACCEPTED', challenge.fromUserId, {
            challengeId:           challengeId,
            acceptedBy:            userId,
            acceptedByDisplayName: _fcDisplayName(nk, userId, ctx.username),
            gameId:                challenge.gameId,
            roomCode:              challenge.roomCode,
            shareCode:             challenge.shareCode,
            isAsync:               challenge.isAsync
        }, userId);
    } catch (e) {
        logger.warn('[FriendChallenges] notify accept failed: ' + e.message);
    }

    return _fcOk({
        challengeId:     challengeId,
        status:          FC_STATUS_ACCEPTED,
        fromUserId:      challenge.fromUserId,
        fromDisplayName: challenge.fromDisplayName,
        gameId:          challenge.gameId,
        roomCode:        challenge.roomCode,
        shareCode:       challenge.shareCode,
        isAsync:         challenge.isAsync,
        acceptedAt:      challenge.acceptedAt
    });
}

// ============================================================================
// RPC: decline_friend_challenge
// ============================================================================
// Payload: { challengeId: <string>, reason?: <string ≤ 280> }
// Idempotent.
function rpcDeclineFriendChallenge(ctx, logger, nk, payload) {
    var userId = ctx.userId;
    if (!userId) return _fcErr('Authentication required', 'unauthenticated');

    var p = _fcParsePayload(payload);
    if (!p.ok) return _fcErr(p.error, 'invalid_payload');

    var data        = p.data || {};
    var challengeId = data.challengeId;
    var reason      = data.reason || '';
    if (!challengeId || typeof challengeId !== 'string') {
        return _fcErr('challengeId is required', 'invalid_payload');
    }
    if (typeof reason !== 'string') reason = '';
    if (reason.length > FC_MAX_REASON_LEN) {
        reason = reason.substring(0, FC_MAX_REASON_LEN);
    }

    var read = _fcReadChallenge(nk, challengeId, userId);
    if (!read) return _fcErr('Challenge not found', 'challenge_not_found');

    var challenge = read.value;
    if (challenge.toUserId !== userId) {
        return _fcErr('This challenge is not for you', 'challenge_not_for_caller');
    }
    if (challenge.status === FC_STATUS_DECLINED) {
        return _fcOk({ challengeId: challengeId, alreadyDeclined: true });
    }
    if (challenge.status !== FC_STATUS_PENDING) {
        return _fcErr('This challenge has already been ' + challenge.status,
                      'challenge_not_pending', { currentStatus: challenge.status });
    }

    challenge.status        = FC_STATUS_DECLINED;
    challenge.declinedAt    = _fcNowIso();
    challenge.updatedAt     = _fcNowIso();
    if (reason) challenge.declineReason = reason;

    try {
        _fcWriteChallenge(nk, challenge, userId, read.version);
    } catch (e) {
        return _fcErr('Failed to persist decline: ' + e.message, 'storage_write_failed');
    }

    try {
        _fcWriteOutbox(nk, challenge, challenge.fromUserId, null);
    } catch (e) {
        logger.warn('[FriendChallenges] decline outbox sync failed: ' + e.message);
    }

    try {
        sendFriendsNotification(nk, logger, 'FRIEND_CHALLENGE_DECLINED', challenge.fromUserId, {
            challengeId: challengeId,
            declinedBy:  userId,
            reason:      reason
        }, userId);
    } catch (e) {
        logger.warn('[FriendChallenges] notify decline failed: ' + e.message);
    }

    return _fcOk({
        challengeId: challengeId,
        status:      FC_STATUS_DECLINED,
        declinedAt:  challenge.declinedAt
    });
}

// ============================================================================
// RPC: cancel_friend_challenge  (sender rescinds their own outgoing challenge)
// ============================================================================
// Payload: { challengeId: <string> }
// Idempotent.
function rpcCancelFriendChallenge(ctx, logger, nk, payload) {
    var userId = ctx.userId;
    if (!userId) return _fcErr('Authentication required', 'unauthenticated');

    var p = _fcParsePayload(payload);
    if (!p.ok) return _fcErr(p.error, 'invalid_payload');

    var challengeId = (p.data || {}).challengeId;
    if (!challengeId || typeof challengeId !== 'string') {
        return _fcErr('challengeId is required', 'invalid_payload');
    }

    // Outbox under the sender is the only thing the caller can read directly.
    var outbox = _fcReadOutbox(nk, challengeId, userId);
    if (!outbox) {
        return _fcErr('Challenge not found in your outbox', 'challenge_not_found');
    }

    var indexRec    = outbox.value;
    var recipientId = indexRec.targetUserId;
    if (!recipientId) {
        return _fcErr('Outbox record corrupt (missing targetUserId)', 'outbox_invalid');
    }

    var read = _fcReadChallenge(nk, challengeId, recipientId);
    if (!read) {
        // Canonical record gone — clean up outbox and return idempotent success.
        try {
            nk.storageDelete([{
                collection: FC_OUTBOX, key: challengeId, userId: userId
            }]);
        } catch (_) {}
        return _fcOk({ challengeId: challengeId, status: FC_STATUS_CANCELLED,
                       alreadyGone: true });
    }

    var challenge = read.value;
    if (challenge.fromUserId !== userId) {
        return _fcErr('You can only cancel challenges you sent', 'challenge_not_owned');
    }
    if (challenge.status === FC_STATUS_CANCELLED) {
        return _fcOk({ challengeId: challengeId, alreadyCancelled: true });
    }
    if (challenge.status !== FC_STATUS_PENDING) {
        return _fcErr('Cannot cancel a ' + challenge.status + ' challenge',
                      'challenge_not_pending', { currentStatus: challenge.status });
    }

    challenge.status      = FC_STATUS_CANCELLED;
    challenge.cancelledAt = _fcNowIso();
    challenge.updatedAt   = _fcNowIso();

    try {
        _fcWriteChallenge(nk, challenge, recipientId, read.version);
    } catch (e) {
        return _fcErr('Failed to persist cancel: ' + e.message, 'storage_write_failed');
    }

    try {
        _fcWriteOutbox(nk, challenge, userId, outbox.version);
    } catch (e) {
        logger.warn('[FriendChallenges] cancel outbox sync failed: ' + e.message);
    }

    try {
        sendFriendsNotification(nk, logger, 'FRIEND_CHALLENGE_CANCELLED', recipientId, {
            challengeId: challengeId,
            cancelledBy: userId
        }, userId);
    } catch (e) {
        logger.warn('[FriendChallenges] notify cancel failed: ' + e.message);
    }

    return _fcOk({
        challengeId: challengeId,
        status:      FC_STATUS_CANCELLED,
        cancelledAt: challenge.cancelledAt
    });
}

// ============================================================================
// RPC: list_pending_friend_challenges
// ============================================================================
// Payload: { limit?: int (1..100, default 50), includeExpired?: bool }
// Returns BOTH incoming and outgoing pending challenges for the caller.
//
// As a side effect, performs LAZY expiry sweep: any pending row whose
// expiresAtMs < now is transitioned to `expired` (and persisted) before
// being returned.  This eliminates the need for a scheduled sweeper job.
function rpcListPendingFriendChallenges(ctx, logger, nk, payload) {
    var userId = ctx.userId;
    if (!userId) return _fcErr('Authentication required', 'unauthenticated');

    var p = _fcParsePayload(payload);
    if (!p.ok) return _fcErr(p.error, 'invalid_payload');

    var data           = p.data || {};
    var limit          = parseInt(data.limit) || 50;
    var includeExpired = data.includeExpired === true;
    if (limit < 1)   limit = 1;
    if (limit > 100) limit = 100;

    var nowMs = _fcNowMs();

    // ── Incoming: scan friend_challenges owned by caller ───────────────────
    var incoming = [];
    try {
        var page = nk.storageList(userId, FC_COLLECTION, limit, null);
        var objects = (page && page.objects) ? page.objects : (page || []);
        for (var i = 0; i < objects.length; i++) {
            var o = objects[i];
            if (!o || !o.value) continue;
            var c = o.value;
            if (c.toUserId !== userId) continue; // safety

            // Lazy expiry sweep
            if (c.status === FC_STATUS_PENDING && c.expiresAtMs && c.expiresAtMs < nowMs) {
                c.status    = FC_STATUS_EXPIRED;
                c.updatedAt = _fcNowIso();
                try { _fcWriteChallenge(nk, c, userId, o.version); } catch (_) {}
                // Also fire an EXPIRED notification to the SENDER so their
                // outbox UI clears without polling.
                try {
                    sendFriendsNotification(nk, logger, 'FRIEND_CHALLENGE_EXPIRED',
                        c.fromUserId, {
                            challengeId: c.challengeId,
                            expiredFor:  userId
                        }, userId);
                } catch (_) {}
            }

            if (c.status !== FC_STATUS_PENDING && !includeExpired) continue;

            incoming.push({
                challengeId:     c.challengeId,
                fromUserId:      c.fromUserId,
                fromUsername:    c.fromUsername,
                fromDisplayName: c.fromDisplayName,
                gameId:          c.gameId,
                roomCode:        c.roomCode || '',
                shareCode:       c.shareCode || '',
                isAsync:         !!c.isAsync,
                quizModeName:    (c.challengeData &&
                                  (c.challengeData.modeName || c.challengeData.quizModeName)) || '',
                status:          c.status,
                createdAt:       c.createdAt,
                expiresAt:       c.expiresAt
            });
        }
    } catch (e) {
        logger.warn('[FriendChallenges] list incoming failed: ' + e.message);
    }

    // ── Outgoing: scan caller's outbox index ───────────────────────────────
    var outgoing = [];
    try {
        var page2 = nk.storageList(userId, FC_OUTBOX, limit, null);
        var objects2 = (page2 && page2.objects) ? page2.objects : (page2 || []);
        for (var j = 0; j < objects2.length; j++) {
            var o2 = objects2[j];
            if (!o2 || !o2.value) continue;
            var ix = o2.value;

            // Refresh from canonical (recipient may have accepted/declined since
            // our index was last written).
            var canonical = _fcReadChallenge(nk, ix.challengeId, ix.targetUserId);
            var status      = ix.status;
            var expiresAtMs = ix.expiresAt ? new Date(ix.expiresAt).getTime() : 0;
            if (canonical) {
                status      = canonical.value.status;
                expiresAtMs = canonical.value.expiresAtMs || expiresAtMs;
                // Heal index if drifted (cheap write)
                if (status !== ix.status) {
                    ix.status          = status;
                    ix.statusUpdatedAt = canonical.value.updatedAt;
                    try {
                        nk.storageWrite([{
                            collection:      FC_OUTBOX,
                            key:             ix.challengeId,
                            userId:          userId,
                            value:           ix,
                            version:         o2.version,
                            permissionRead:  1,
                            permissionWrite: 0
                        }]);
                    } catch (_) {}
                }
            }
            if (status === FC_STATUS_PENDING && expiresAtMs && expiresAtMs < nowMs) {
                status = FC_STATUS_EXPIRED;
            }
            if (status !== FC_STATUS_PENDING && !includeExpired) continue;

            outgoing.push({
                challengeId:       ix.challengeId,
                targetUserId:      ix.targetUserId,
                targetDisplayName: ix.targetDisplayName,
                gameId:            ix.gameId,
                quizModeName:      ix.quizModeName || '',
                roomCode:          ix.roomCode || '',
                shareCode:         ix.shareCode || '',
                isAsync:           !!ix.isAsync,
                status:            status,
                createdAt:         ix.createdAt,
                expiresAt:         ix.expiresAt
            });
        }
    } catch (e) {
        logger.warn('[FriendChallenges] list outgoing failed: ' + e.message);
    }

    return _fcOk({
        incoming:      incoming,
        outgoing:      outgoing,
        incomingCount: incoming.length,
        outgoingCount: outgoing.length
    });
}

// ============================================================================
// RPC: friends_spectate  (hardened in-place; replaces legacy stub)
// ============================================================================
// Payload: { friendUserId: <UUID> }
//
// Responds with the friend's active matchId (if any) AND fires a
// FRIEND_SPECTATE_REQUEST notification (code 105) to the friend so their
// client can confirm/deny via the spectate-popup UI.  This is the hardened
// replacement for the legacy `rpcFriendsSpectate` in friends/friends.js
// (which is no longer registered — see legacy_runtime.js for the removal).
//
// What changed vs legacy:
//   - Strict mutual-friend gate (state == 0) [was: same]
//   - Explicit reverse-direction block check (target-blocked-caller)
//   - Per-pair rate limit (1 request per 30 s) — same key-space as challenge
//   - Notifies the FRIEND with canonical code/subject (was: silent)
//   - Idempotent — no storage write, just a read + notify
function rpcFriendsSpectate(ctx, logger, nk, payload) {
    var userId = ctx.userId;
    if (!userId) return _fcErr('Authentication required', 'unauthenticated');

    var p = _fcParsePayload(payload);
    if (!p.ok) return _fcErr(p.error, 'invalid_payload');

    var data         = p.data || {};
    var friendUserId = data.friendUserId || data.targetUserId;

    if (!_fcUuidValid(friendUserId)) {
        return _fcErr('Invalid friendUserId (must be a UUID)', 'invalid_target');
    }
    if (friendUserId === userId) {
        return _fcErr('Cannot spectate yourself', 'self_spectate');
    }

    // Mutual-friend gate
    if (!_fcAreFriends(nk, userId, friendUserId)) {
        return _fcErr('You can only spectate mutual friends', 'not_mutual_friends');
    }

    // Block checks (both directions)
    if (_fcIsBlockedBy(nk, userId, friendUserId)) {
        return _fcErr('You have blocked this user', 'caller_blocked_target');
    }
    if (_fcIsBlockedBy(nk, friendUserId, userId)) {
        return _fcErr('Unable to spectate this friend', 'spectate_blocked');
    }

    // Per-pair rate limit (re-uses the same 30 s key-space as challenges so
    // that a sender can't bypass the challenge cooldown by spamming spectate
    // requests).
    var pairRl = _fcCheckPairRateLimit(nk, userId, friendUserId);
    if (!pairRl.allowed) {
        return _fcErr('Slow down — you spectated this friend recently',
                      'pair_rate_limited', { retryAfterMs: pairRl.retryAfterMs });
    }

    // Look up friend's active match (best-effort)
    var matchId = null;
    var online  = false;
    try {
        var accounts = nk.usersGetId([friendUserId]);
        if (accounts && accounts.length > 0 && accounts[0]) {
            online = !!accounts[0].online;
        }
    } catch (e) {
        logger.warn('[FriendChallenges] usersGetId failed in spectate: ' + e.message);
    }

    try {
        var matchRows = nk.storageRead([{
            collection: 'active_matches',
            key:        'current_match',
            userId:     friendUserId
        }]);
        if (matchRows && matchRows.length > 0 && matchRows[0].value &&
            matchRows[0].value.matchId) {
            matchId = matchRows[0].value.matchId;
        }
    } catch (e) {
        logger.warn('[FriendChallenges] active_matches read failed: ' + e.message);
    }

    // Notify the friend that someone wants to spectate (canonical code 105)
    try {
        var requesterName = _fcDisplayName(nk, userId, ctx.username);
        sendFriendsNotification(nk, logger, 'FRIEND_SPECTATE_REQUEST', friendUserId, {
            fromUserId:      userId,
            fromUsername:    ctx.username || userId,
            fromDisplayName: requesterName,
            matchId:         matchId || ''
        }, userId);
    } catch (e) {
        logger.warn('[FriendChallenges] notify spectate request failed: ' + e.message);
    }

    return _fcOk({
        userId:        userId,
        friendUserId:  friendUserId,
        matchId:       matchId || '',
        online:        online,
        spectateReady: !!matchId,
        timestamp:     _fcNowIso()
    });
}

// ============================================================================
// Module Init — register all friend-challenge RPCs (+ legacy alias)
// ============================================================================
// postbuild.js renames this `InitModule` to `__ModuleInit_N` (only one
// InitModule allowed in the merged output) and rewrites every
// `__rpc_id = __rpc_id || (handler)` into
// `__rpc_id = __rpc_id || handler` (guarded — first declaration wins) which
// is then replayed at global scope on every Goja VM.
//
// IMPORTANT: legacy_runtime.js's `friends_challenge_user` registration must
// stay removed / commented so it doesn't compete with our handler.
function __ModuleInit_34(ctx, logger, nk, initializer) {
    __rpc_send_friend_challenge = __rpc_send_friend_challenge || (rpcSendFriendChallenge);
    __rpc_friends_challenge_user = __rpc_friends_challenge_user || (rpcSendFriendChallenge); // legacy alias
    __rpc_accept_friend_challenge = __rpc_accept_friend_challenge || (rpcAcceptFriendChallenge);
    __rpc_decline_friend_challenge = __rpc_decline_friend_challenge || (rpcDeclineFriendChallenge);
    __rpc_cancel_friend_challenge = __rpc_cancel_friend_challenge || (rpcCancelFriendChallenge);
    __rpc_list_pending_friend_challenges = __rpc_list_pending_friend_challenges || (rpcListPendingFriendChallenges);
    __rpc_friends_spectate = __rpc_friends_spectate || (rpcFriendsSpectate); // hardened replacement

    if (logger && logger.info) {
        logger.info('[FriendChallenges] Registered 7 RPCs (send + alias + 4 lifecycle + spectate)');
    }
}


// --- Module: friends\friend_invites.js ---
// ============================================================================
// friend_invites.js - Canonical Friend Invite RPCs (Split-Brain Fix)
// ============================================================================
// PRODUCTION-READY | ES5 (Goja runtime) | Single source of truth
//
// Replaces three legacy implementations that were causing the "split-brain"
// friend graph problem:
//   - legacy_runtime.js  : sendFriendInvite / acceptFriendInvite / declineFriendInvite
//   - copilot/social_features.js (orphaned, never registered)
//
// THE SPLIT-BRAIN BUG (and why this file fixes it)
// ------------------------------------------------
// Old send_friend_invite wrote a row to the `friend_invites` storage
// collection but NEVER touched Nakama's native friend graph (nk.friendsAdd).
// When accept_friend_invite later called nk.friendsAdd(acceptorId,
// [senderId]) it created a NEW invite from the *acceptor* in the wrong
// direction, leaving Nakama's `user_friends` table with one-sided
// INVITE_SENT / INVITE_RECEIVED relationships. Every other system that
// reads nk.friendsList (friend quests, friend streaks, friends_list,
// challenge mutual-friend check, find-friends relationship enrichment)
// then saw an inconsistent picture.
//
// The fix is one line in send: nk.friendsAdd(senderId, [targetUserId]) —
// this creates the proper INVITE_SENT relation immediately, then the
// existing accept-side nk.friendsAdd transitions BOTH users to FRIEND state
// atomically, exactly like Nakama's built-in addFriend flow does.
//
// What's new vs the old impl
// --------------------------
//  1. nk.friendsAdd called inside send (the actual split-brain fix)
//  2. Idempotent invite IDs derived from a sorted user-pair, so re-sending
//     the same invite returns the same row instead of creating duplicates
//  3. Self-invite check
//  4. Block check in BOTH directions (sender->target and target->sender)
//  5. Already-friends short-circuit (returns success without re-creating)
//  6. Existing-pending-invite short-circuit (returns success with same id)
//  7. Per-user rate limit (1 invite send / 5 seconds; 1 accept-or-decline
//     per invite is intrinsic via storage status check)
//  8. Cancel-invite RPC (sender can rescind an outgoing invite, also
//     cleans up the Nakama INVITE_SENT relation)
//  9. List-pending-invites RPC (returns BOTH incoming and outgoing custom
//     invites with enriched user data — what the QuizVerse UI actually needs)
// 10. Notifications use canonical notification_codes constants so client
//     filters always match (kills the "subject mismatch" bug too)
// 11. Optimistic concurrency on storage writes (storageWrite version field)
//     to prevent two simultaneous accepts/declines clobbering each other
// 12. Decline cleans up the INVITE_SENT relation (nk.friendsDelete) so the
//     sender no longer sees a phantom outgoing request
//
// Migration of existing data: NONE (per product decision). Old pending
// rows in friend_invites simply remain as data; they will fail the
// already-friends check the next time the sender retries (which now adds
// to the Nakama graph properly).
//
// All registered RPCs:
//   send_friend_invite
//   accept_friend_invite
//   decline_friend_invite
//   cancel_friend_invite              (NEW)
//   list_pending_friend_invites       (NEW)
// ============================================================================

// ─── Tunables ───────────────────────────────────────────────────────────────
var FRIEND_INVITES_COLLECTION  = 'friend_invites';
var FRIEND_INV_RATELIMIT_KEY   = 'fr_invite_send';
var FRIEND_INV_RATELIMIT_MS    = 5000; // 5s between sends per user
var FRIEND_INV_MAX_MESSAGE_LEN = 280;  // tweet-length

var INVITE_STATUS_PENDING   = 'pending';
var INVITE_STATUS_ACCEPTED  = 'accepted';
var INVITE_STATUS_DECLINED  = 'declined';
var INVITE_STATUS_CANCELLED = 'cancelled';

// Nakama friend states (from runtime API)
var FR_STATE_FRIEND          = 0;
var FR_STATE_INVITE_SENT     = 1;
var FR_STATE_INVITE_RECEIVED = 2;
var FR_STATE_BLOCKED         = 3;

// ─── Tiny self-contained helpers (no external `utils` dependency) ──────────
// We deliberately do NOT depend on the global `utils` namespace because it
// is a minimal subset (validatePayload/handleError/log*) defined in
// copilot/utils.js — and missing fields like safeJsonParse/getCurrentTimestamp
// have caused production crashes in other modules. Keeping these inline
// makes this module bullet-proof even if the merge order changes.

function _fiUuidValid(id) {
    if (!id || typeof id !== 'string') return false;
    return /^[0-9a-f]{8}-[0-9a-f]{4}-[0-9a-f]{4}-[0-9a-f]{4}-[0-9a-f]{12}$/i.test(id);
}

function _fiNowIso()  { return new Date().toISOString(); }
function _fiNowMs()   { return Date.now(); }

function _fiOk(extra) {
    var out = { success: true };
    if (extra) {
        for (var k in extra) {
            if (Object.prototype.hasOwnProperty.call(extra, k)) out[k] = extra[k];
        }
    }
    return JSON.stringify(out);
}

// Standardised error envelope. `errorCode` is a stable machine code so the
// client can switch on it without parsing English strings.
function _fiErr(message, errorCode, extra) {
    var out = { success: false, error: message, errorCode: errorCode || 'unknown' };
    if (extra) {
        for (var k in extra) {
            if (Object.prototype.hasOwnProperty.call(extra, k)) out[k] = extra[k];
        }
    }
    return JSON.stringify(out);
}

function _fiParsePayload(payload) {
    if (!payload || payload === '') return { ok: true, data: {} };
    try { return { ok: true, data: JSON.parse(payload) }; }
    catch (e)  { return { ok: false, error: 'Invalid JSON payload: ' + e.message }; }
}

// Build the deterministic invite ID for a sender→target pair.
// We include a timestamp suffix so that an invite that was previously
// accepted/declined can be re-sent later (with a fresh row), but two
// concurrent sends within 1ms of each other would still produce the
// same id (acceptable; the storage version check will deduplicate).
function _fiInviteId(senderId, targetId) {
    return 'inv_' + senderId + '_' + targetId;
}

/**
 * Look up the Nakama friend-graph relationship between caller and target.
 * Returns the integer state (0=FRIEND, 1=INVITE_SENT, 2=INVITE_RECEIVED,
 * 3=BLOCKED) or -1 if there is no relationship.
 */
function _fiNakamaRelation(nk, callerId, targetId) {
    try {
        // friendsList returns up to `limit` friends in any state — we ask
        // for all and scan. With a hard cap of 1000 this is O(1) for
        // typical players; for power users we still terminate on first match.
        var page = nk.friendsList(callerId, 1000, null, null);
        if (page && page.friends) {
            for (var i = 0; i < page.friends.length; i++) {
                var f = page.friends[i];
                if (f && f.user && f.user.id === targetId) {
                    var s = (f.state && typeof f.state === 'object' && 'value' in f.state)
                        ? f.state.value : f.state;
                    return (typeof s === 'number') ? s : -1;
                }
            }
        }
    } catch (_) { /* fall through */ }
    return -1;
}

/**
 * Per-user simple cooldown for invite sends. Returns
 *   { allowed: true } or
 *   { allowed: false, retryAfterMs: <number> }
 */
function _fiCheckRateLimit(nk, userId, action, cooldownMs) {
    var key = 'rl_' + action + '_' + userId;
    var now = _fiNowMs();
    try {
        var rows = nk.storageRead([{ collection: 'rate_limits', key: key, userId: userId }]);
        if (rows && rows.length > 0 && rows[0].value && rows[0].value.timestamp) {
            var elapsed = now - rows[0].value.timestamp;
            if (elapsed < cooldownMs) {
                return { allowed: false, retryAfterMs: cooldownMs - elapsed };
            }
        }
    } catch (_) { /* fail-open */ }
    try {
        nk.storageWrite([{
            collection: 'rate_limits',
            key: key,
            userId: userId,
            value: { timestamp: now },
            permissionRead: 0,
            permissionWrite: 0
        }]);
    } catch (_) { /* non-critical */ }
    return { allowed: true };
}

function _fiUserDisplayName(nk, userId, fallback) {
    try {
        var users = nk.usersGetId([userId]);
        if (users && users.length > 0 && users[0]) {
            return users[0].displayName || users[0].username || fallback || userId;
        }
    } catch (_) {}
    return fallback || userId;
}

/**
 * Fetch a user's username by ID. Returns userId as fallback so the result
 * is never empty (nk.friendsAdd/Delete require a non-empty username string).
 */
function _fiUserUsername(nk, userId) {
    try {
        var users = nk.usersGetId([userId]);
        if (users && users.length > 0 && users[0]) {
            return users[0].username || userId;
        }
    } catch (_) {}
    return userId;
}

/**
 * Read an existing invite row stored under either user. We always store
 * the row under the TARGET user (so they can read their own inbox), but
 * during a re-send the caller is the SENDER and may not have read access.
 * We try both userIds.
 */
function _fiReadInviteEither(nk, inviteId, userIdA, userIdB) {
    var keys = [
        { collection: FRIEND_INVITES_COLLECTION, key: inviteId, userId: userIdA },
        { collection: FRIEND_INVITES_COLLECTION, key: inviteId, userId: userIdB }
    ];
    try {
        var rows = nk.storageRead(keys);
        if (rows && rows.length > 0) {
            // Pick the latest by updatedAt
            var best = null;
            for (var i = 0; i < rows.length; i++) {
                var r = rows[i];
                if (!r || !r.value) continue;
                if (best == null || (r.value.updatedAt || '') > (best.value.updatedAt || '')) {
                    best = r;
                }
            }
            return best;
        }
    } catch (_) {}
    return null;
}

// ============================================================================
// RPC: send_friend_invite
// ============================================================================
function rpcFriendsSendInvite(ctx, logger, nk, payload) {
    var fromUserId = ctx.userId;
    if (!fromUserId) return _fiErr('Authentication required', 'unauthenticated');

    var p = _fiParsePayload(payload);
    if (!p.ok) return _fiErr(p.error, 'invalid_payload');

    var data = p.data || {};
    var targetUserId = data.targetUserId;
    var rawMessage   = data.message;

    if (!_fiUuidValid(targetUserId)) {
        return _fiErr('Invalid targetUserId (must be a UUID)', 'invalid_target');
    }
    if (targetUserId === fromUserId) {
        return _fiErr('Cannot send a friend invite to yourself', 'self_invite');
    }

    var message = '';
    if (rawMessage) {
        if (typeof rawMessage !== 'string') {
            return _fiErr('message must be a string', 'invalid_payload');
        }
        message = rawMessage.length > FRIEND_INV_MAX_MESSAGE_LEN
            ? rawMessage.substring(0, FRIEND_INV_MAX_MESSAGE_LEN)
            : rawMessage;
    }

    // Rate limit early
    var rl = _fiCheckRateLimit(nk, fromUserId, FRIEND_INV_RATELIMIT_KEY, FRIEND_INV_RATELIMIT_MS);
    if (!rl.allowed) {
        return _fiErr('Please wait before sending another invite', 'rate_limited',
            { retryAfterMs: rl.retryAfterMs });
    }

    // Verify target exists (cheap usersGetId — also gives us their username
    // to feed into nk.friendsAdd as the second arg, which Nakama uses when
    // the target is identified by username rather than id).
    var targetUser = null;
    try {
        var users = nk.usersGetId([targetUserId]);
        if (users && users.length > 0) targetUser = users[0];
    } catch (e) {
        logger.warn('[FriendInvites] usersGetId failed: ' + e.message);
    }
    if (!targetUser) {
        return _fiErr('Target user not found', 'target_not_found');
    }

    // ── Block checks (both directions) ─────────────────────────────────────
    // 1. Caller's own block list (from Nakama state=3)
    var callerRel = _fiNakamaRelation(nk, fromUserId, targetUserId);
    if (callerRel === FR_STATE_BLOCKED) {
        return _fiErr('You have blocked this user. Unblock them first.', 'caller_blocked_target');
    }
    // 2. Target's view (does target have caller blocked?). We cannot read
    //    target's friendsList (insufficient perms), so we use the custom
    //    user_blocks storage that friends/friends.js writes.
    try {
        var blockRows = nk.storageRead([{
            collection: 'user_blocks',
            key: 'blocked_' + targetUserId + '_' + fromUserId,
            userId: targetUserId
        }]);
        if (blockRows && blockRows.length > 0) {
            // Don't reveal — generic error
            return _fiErr('Unable to send invite at this time', 'send_blocked');
        }
    } catch (_) { /* fail-open on block lookup */ }

    // ── Already-friends / already-pending short-circuits ───────────────────
    if (callerRel === FR_STATE_FRIEND) {
        return _fiOk({ status: INVITE_STATUS_ACCEPTED, alreadyFriends: true,
                       targetUserId: targetUserId });
    }
    if (callerRel === FR_STATE_INVITE_SENT) {
        // Idempotent: there is already an outstanding invite from caller→target
        var existingId = _fiInviteId(fromUserId, targetUserId);
        return _fiOk({ status: INVITE_STATUS_PENDING, inviteId: existingId,
                       targetUserId: targetUserId, alreadySent: true });
    }
    if (callerRel === FR_STATE_INVITE_RECEIVED) {
        // Target already invited caller. Auto-accept.
        try { nk.friendsAdd(fromUserId, ctx.username || fromUserId, [targetUserId], null, {}); }
        catch (e) {
            return _fiErr('Failed to auto-accept reciprocal invite: ' + e.message,
                          'autoaccept_failed');
        }
        return _fiOk({ status: INVITE_STATUS_ACCEPTED, autoAccepted: true,
                       targetUserId: targetUserId });
    }

    // ── Build the canonical invite row ─────────────────────────────────────
    var inviteId   = _fiInviteId(fromUserId, targetUserId);
    var fromName   = _fiUserDisplayName(nk, fromUserId, ctx.username);
    var inviteData = {
        inviteId:        inviteId,
        fromUserId:      fromUserId,
        fromUsername:    ctx.username || fromUserId,
        fromDisplayName: fromName,
        targetUserId:    targetUserId,
        targetUsername:  targetUser.username || '',
        message:         message,
        status:          INVITE_STATUS_PENDING,
        createdAt:       _fiNowIso(),
        updatedAt:       _fiNowIso()
    };

    // Store under the TARGET (so they can read their inbox via permissionRead=1).
    try {
        nk.storageWrite([{
            collection:      FRIEND_INVITES_COLLECTION,
            key:             inviteId,
            userId:          targetUserId,
            value:           inviteData,
            permissionRead:  1, // owner-read
            permissionWrite: 0  // server-only
        }]);
    } catch (e) {
        logger.error('[FriendInvites] storageWrite failed: ' + e.message);
        return _fiErr('Failed to persist friend invite', 'storage_write_failed');
    }

    // ── THE SPLIT-BRAIN FIX ────────────────────────────────────────────────
    // Without this line, Nakama's user_friends graph stays empty and every
    // downstream system (friends_list, friend_quests, friend_streaks,
    // friends_challenge_user mutual-friend check, find_friends relationship
    // enrichment) sees the wrong picture.
    try {
        nk.friendsAdd(fromUserId, ctx.username || fromUserId, [targetUserId], null, {});
    } catch (e) {
        // If Nakama refuses (e.g. target re-blocked between our check and
        // the call) we MUST roll back the storage write to keep the two
        // sides consistent.
        try {
            nk.storageDelete([{ collection: FRIEND_INVITES_COLLECTION,
                                key: inviteId, userId: targetUserId }]);
        } catch (_) { /* best-effort */ }
        logger.warn('[FriendInvites] nk.friendsAdd rejected: ' + e.message);
        return _fiErr('Unable to send invite (target may have blocked you)',
                      'friends_add_rejected');
    }

    // ── Notify the target with canonical Subject/Code/type contract ────────
    try {
        sendFriendsNotification(nk, logger, 'FRIEND_REQUEST', targetUserId, {
            inviteId:        inviteId,
            fromUserId:      fromUserId,
            fromUsername:    inviteData.fromUsername,
            fromDisplayName: inviteData.fromDisplayName,
            message:         message
        }, fromUserId);
    } catch (e) {
        // Notification failure must NEVER fail the parent RPC — the invite
        // is already on the server and the client can refresh manually.
        logger.warn('[FriendInvites] notify target failed: ' + e.message);
    }

    return _fiOk({
        inviteId:     inviteId,
        targetUserId: targetUserId,
        status:       INVITE_STATUS_PENDING,
        sentAt:       inviteData.createdAt
    });
}

// ============================================================================
// RPC: accept_friend_invite
// ============================================================================
function rpcFriendsAcceptInvite(ctx, logger, nk, payload) {
    var userId = ctx.userId;
    if (!userId) return _fiErr('Authentication required', 'unauthenticated');

    var p = _fiParsePayload(payload);
    if (!p.ok) return _fiErr(p.error, 'invalid_payload');

    var inviteId = (p.data || {}).inviteId;
    if (!inviteId || typeof inviteId !== 'string') {
        return _fiErr('inviteId is required', 'invalid_payload');
    }

    // Read invite (it is stored under the target = the caller).
    var rows;
    try {
        rows = nk.storageRead([{
            collection: FRIEND_INVITES_COLLECTION,
            key:        inviteId,
            userId:     userId
        }]);
    } catch (e) {
        return _fiErr('Failed to read invite: ' + e.message, 'storage_read_failed');
    }

    if (!rows || rows.length === 0 || !rows[0].value) {
        return _fiErr('Friend invite not found', 'invite_not_found');
    }

    var invite     = rows[0].value;
    var rowVersion = rows[0].version; // for optimistic concurrency

    if (invite.targetUserId !== userId) {
        return _fiErr('This invite is not for you', 'invite_not_for_caller');
    }

    if (invite.status === INVITE_STATUS_ACCEPTED) {
        // Idempotent — second click on the same accept button must not error.
        return _fiOk({ inviteId: inviteId, alreadyAccepted: true,
                       friendUserId: invite.fromUserId,
                       friendDisplayName: invite.fromDisplayName });
    }
    if (invite.status !== INVITE_STATUS_PENDING) {
        return _fiErr('This invite has already been ' + invite.status,
                      'invite_not_pending', { currentStatus: invite.status });
    }

    // Add the reciprocal friend edge. Combined with the INVITE_SENT
    // edge created at send-time this transitions BOTH users to FRIEND.
    try {
        nk.friendsAdd(userId, ctx.username || userId, [invite.fromUserId], null, {});
    } catch (e) {
        logger.error('[FriendInvites] accept nk.friendsAdd failed: ' + e.message);
        return _fiErr('Failed to add friend: ' + e.message, 'friends_add_failed');
    }

    // Update invite row with optimistic concurrency control. Goja's
    // storageWrite supports a `version` field — passing the previously-read
    // version makes the write atomic w.r.t. concurrent accepts/declines.
    invite.status     = INVITE_STATUS_ACCEPTED;
    invite.acceptedAt = _fiNowIso();
    invite.updatedAt  = _fiNowIso();

    try {
        nk.storageWrite([{
            collection:      FRIEND_INVITES_COLLECTION,
            key:             inviteId,
            userId:          userId,
            value:           invite,
            version:         rowVersion || undefined, // OCC; undefined = no check
            permissionRead:  1,
            permissionWrite: 0
        }]);
    } catch (e) {
        // Friend was added to Nakama already — log and continue. The graph
        // is the source of truth; the storage row is just a UI hint.
        logger.warn('[FriendInvites] accept storageWrite failed (non-fatal): ' + e.message);
    }

    // Notify the original sender that their request was accepted.
    try {
        var acceptorName = _fiUserDisplayName(nk, userId, ctx.username);
        sendFriendsNotification(nk, logger, 'FRIEND_REQUEST_ACCEPTED', invite.fromUserId, {
            inviteId:               inviteId,
            acceptedBy:             userId,
            acceptedByUsername:     ctx.username || userId,
            acceptedByDisplayName:  acceptorName
        }, userId);
    } catch (e) {
        logger.warn('[FriendInvites] notify sender of accept failed: ' + e.message);
    }

    return _fiOk({
        inviteId:           inviteId,
        friendUserId:       invite.fromUserId,
        friendUsername:     invite.fromUsername,
        friendDisplayName:  invite.fromDisplayName,
        acceptedAt:         invite.acceptedAt
    });
}

// ============================================================================
// RPC: decline_friend_invite
// ============================================================================
function rpcFriendsDeclineInvite(ctx, logger, nk, payload) {
    var userId = ctx.userId;
    if (!userId) return _fiErr('Authentication required', 'unauthenticated');

    var p = _fiParsePayload(payload);
    if (!p.ok) return _fiErr(p.error, 'invalid_payload');

    var inviteId = (p.data || {}).inviteId;
    if (!inviteId || typeof inviteId !== 'string') {
        return _fiErr('inviteId is required', 'invalid_payload');
    }

    var rows;
    try {
        rows = nk.storageRead([{
            collection: FRIEND_INVITES_COLLECTION,
            key:        inviteId,
            userId:     userId
        }]);
    } catch (e) {
        return _fiErr('Failed to read invite: ' + e.message, 'storage_read_failed');
    }

    if (!rows || rows.length === 0 || !rows[0].value) {
        return _fiErr('Friend invite not found', 'invite_not_found');
    }

    var invite     = rows[0].value;
    var rowVersion = rows[0].version;

    if (invite.targetUserId !== userId) {
        return _fiErr('This invite is not for you', 'invite_not_for_caller');
    }

    if (invite.status === INVITE_STATUS_DECLINED) {
        return _fiOk({ inviteId: inviteId, alreadyDeclined: true });
    }
    if (invite.status !== INVITE_STATUS_PENDING) {
        return _fiErr('This invite has already been ' + invite.status,
                      'invite_not_pending', { currentStatus: invite.status });
    }

    // Remove the sender's INVITE_SENT relation from Nakama's graph so it
    // doesn't sit there forever as a phantom outgoing request. We delete
    // from the SENDER's list (decline = "they no longer have a sent
    // invite to me"). nk.friendsDelete is idempotent.
    try {
        nk.friendsDelete(invite.fromUserId, invite.fromUsername || _fiUserUsername(nk, invite.fromUserId), [userId], null);
    } catch (e) {
        logger.warn('[FriendInvites] decline nk.friendsDelete failed (non-fatal): ' + e.message);
    }

    invite.status     = INVITE_STATUS_DECLINED;
    invite.declinedAt = _fiNowIso();
    invite.updatedAt  = _fiNowIso();

    try {
        nk.storageWrite([{
            collection:      FRIEND_INVITES_COLLECTION,
            key:             inviteId,
            userId:          userId,
            value:           invite,
            version:         rowVersion || undefined,
            permissionRead:  1,
            permissionWrite: 0
        }]);
    } catch (e) {
        return _fiErr('Failed to persist decline: ' + e.message, 'storage_write_failed');
    }

    // Notify the sender that their request was declined. We send a
    // notification (rather than silently dropping) so the sender's UI
    // can move the row out of "pending sent" without polling.
    try {
        sendFriendsNotification(nk, logger, 'FRIEND_REQUEST_DECLINED', invite.fromUserId, {
            inviteId:   inviteId,
            declinedBy: userId
        }, userId);
    } catch (e) {
        logger.warn('[FriendInvites] notify sender of decline failed: ' + e.message);
    }

    return _fiOk({ inviteId: inviteId, status: INVITE_STATUS_DECLINED });
}

// ============================================================================
// RPC: cancel_friend_invite  (NEW — sender rescinds their own outgoing invite)
// ============================================================================
function rpcFriendsCancelInvite(ctx, logger, nk, payload) {
    var userId = ctx.userId;
    if (!userId) return _fiErr('Authentication required', 'unauthenticated');

    var p = _fiParsePayload(payload);
    if (!p.ok) return _fiErr(p.error, 'invalid_payload');

    var data         = p.data || {};
    var inviteId     = data.inviteId;
    var targetUserId = data.targetUserId;

    if (!targetUserId && inviteId) {
        // Derive target from inviteId pattern "inv_<sender>_<target>"
        var m = /^inv_([0-9a-f-]{36})_([0-9a-f-]{36})$/i.exec(inviteId);
        if (m && m[1] === userId) targetUserId = m[2];
    }

    if (!_fiUuidValid(targetUserId)) {
        return _fiErr('targetUserId (or a valid inviteId you own) is required',
                      'invalid_payload');
    }

    if (!inviteId) inviteId = _fiInviteId(userId, targetUserId);

    // Invite row is stored under the TARGET (the caller is the sender).
    var rows = null;
    try {
        rows = nk.storageRead([{
            collection: FRIEND_INVITES_COLLECTION,
            key:        inviteId,
            userId:     targetUserId
        }]);
    } catch (e) {
        // Don't fail — fall through to graph cleanup
        logger.warn('[FriendInvites] cancel storageRead failed: ' + e.message);
    }

    var invite = (rows && rows.length > 0 && rows[0].value) ? rows[0].value : null;

    if (invite) {
        if (invite.fromUserId !== userId) {
            return _fiErr('You can only cancel invites you sent', 'invite_not_owned');
        }
        if (invite.status !== INVITE_STATUS_PENDING &&
            invite.status !== INVITE_STATUS_CANCELLED) {
            return _fiErr('This invite cannot be cancelled (status=' + invite.status + ')',
                          'invite_not_pending', { currentStatus: invite.status });
        }
    }

    // Delete the INVITE_SENT relation in Nakama's graph regardless.
    try {
        nk.friendsDelete(userId, ctx.username || _fiUserUsername(nk, userId), [targetUserId], null);
    } catch (e) {
        logger.warn('[FriendInvites] cancel nk.friendsDelete failed: ' + e.message);
    }

    if (invite && invite.status === INVITE_STATUS_PENDING) {
        invite.status      = INVITE_STATUS_CANCELLED;
        invite.cancelledAt = _fiNowIso();
        invite.updatedAt   = _fiNowIso();
        try {
            nk.storageWrite([{
                collection:      FRIEND_INVITES_COLLECTION,
                key:             inviteId,
                userId:          targetUserId,
                value:           invite,
                version:         rows[0].version || undefined,
                permissionRead:  1,
                permissionWrite: 0
            }]);
        } catch (e) {
            logger.warn('[FriendInvites] cancel storageWrite failed: ' + e.message);
        }
    }

    // Optional: tell the target their pending request disappeared so their
    // UI can update without a refresh. Code is FRIEND_REQUEST_CANCELLED.
    try {
        sendFriendsNotification(nk, logger, 'FRIEND_REQUEST_CANCELLED', targetUserId, {
            inviteId:    inviteId,
            cancelledBy: userId
        }, userId);
    } catch (e) {
        logger.warn('[FriendInvites] notify cancel failed: ' + e.message);
    }

    return _fiOk({ inviteId: inviteId, targetUserId: targetUserId,
                   status: INVITE_STATUS_CANCELLED });
}

// ============================================================================
// RPC: list_pending_friend_invites  (NEW)
// ============================================================================
// Returns BOTH incoming pending invites (rows stored under the caller, the
// caller is target) AND outgoing pending invites (rows where caller is the
// sender). Single round-trip — replaces ad-hoc client polling of multiple
// endpoints.
function rpcFriendsListPendingInvites(ctx, logger, nk, payload) {
    var userId = ctx.userId;
    if (!userId) return _fiErr('Authentication required', 'unauthenticated');

    var p = _fiParsePayload(payload);
    if (!p.ok) return _fiErr(p.error, 'invalid_payload');

    var limit = parseInt((p.data || {}).limit) || 100;
    if (limit < 1)   limit = 1;
    if (limit > 200) limit = 200;

    // Incoming: scan the caller's own friend_invites collection.
    var incoming = [];
    try {
        var page = nk.storageList(userId, FRIEND_INVITES_COLLECTION, limit, null);
        var objects = (page && page.objects) ? page.objects : (page || []);
        for (var i = 0; i < objects.length; i++) {
            var o = objects[i];
            if (!o || !o.value) continue;
            if (o.value.status !== INVITE_STATUS_PENDING) continue;
            if (o.value.targetUserId !== userId) continue; // safety
            incoming.push({
                inviteId:        o.value.inviteId,
                fromUserId:      o.value.fromUserId,
                fromUsername:    o.value.fromUsername,
                fromDisplayName: o.value.fromDisplayName,
                message:         o.value.message || '',
                createdAt:       o.value.createdAt
            });
        }
    } catch (e) {
        logger.warn('[FriendInvites] list incoming failed: ' + e.message);
    }

    // Outgoing: derive from Nakama's friend graph (state=1 INVITE_SENT)
    // — this is more reliable than scanning storage, because the storage
    // row lives under the TARGET (we'd need cross-user reads). Friend
    // graph is authoritative.
    var outgoing = [];
    try {
        var page2 = nk.friendsList(userId, 1000, FR_STATE_INVITE_SENT, null);
        if (page2 && page2.friends) {
            for (var j = 0; j < page2.friends.length && outgoing.length < limit; j++) {
                var fr = page2.friends[j];
                if (!fr || !fr.user) continue;
                outgoing.push({
                    inviteId:        _fiInviteId(userId, fr.user.id),
                    targetUserId:    fr.user.id,
                    targetUsername:  fr.user.username || '',
                    targetDisplayName: fr.user.displayName || fr.user.username || '',
                    avatarUrl:       fr.user.avatarUrl || '',
                    online:          fr.user.online || false
                });
            }
        }
    } catch (e) {
        logger.warn('[FriendInvites] list outgoing failed: ' + e.message);
    }

    return _fiOk({
        incoming:      incoming,
        outgoing:      outgoing,
        incomingCount: incoming.length,
        outgoingCount: outgoing.length
    });
}

// ============================================================================
// Module Init — register all friend-invite RPCs
// ============================================================================
// Postbuild renames this `InitModule` to `__ModuleInit_N` (since there can
// only be one InitModule in the merged output) and rewrites every
// `__rpc_id = __rpc_id || (handler)` into a guarded global stub
// assignment, then replays it at module-load time. The legacy
// registrations for these same RPC ids in legacy_runtime.js have been
// commented out so this module wins the "first to set the stub" race.
function __ModuleInit_35(ctx, logger, nk, initializer) {
    __rpc_send_friend_invite = __rpc_send_friend_invite || (rpcFriendsSendInvite);
    __rpc_accept_friend_invite = __rpc_accept_friend_invite || (rpcFriendsAcceptInvite);
    __rpc_decline_friend_invite = __rpc_decline_friend_invite || (rpcFriendsDeclineInvite);
    __rpc_cancel_friend_invite = __rpc_cancel_friend_invite || (rpcFriendsCancelInvite);
    __rpc_list_pending_friend_invites = __rpc_list_pending_friend_invites || (rpcFriendsListPendingInvites);

    if (logger && logger.info) {
        logger.info('[FriendInvites] Registered 5 canonical friend-invite RPCs');
    }
}


// --- Module: friends\notification_codes.js ---
// ============================================================================
// notification_codes.js - Canonical Friends Notification Constants
// ============================================================================
// PRODUCTION-READY | ES5 (Goja runtime) | Single source of truth
//
// Why this file exists
// --------------------
// Before this file the server sent notifications with arbitrary `Subject`
// strings (e.g. "Friend Request") and ad-hoc numeric `Code` values, while the
// Unity client filtered with a different machine-id convention
// (e.g. subject == "friend_request"). The two never matched, so real-time
// invite / accept / decline popups were silently dropped.
//
// Going forward, EVERY friend-related notification MUST be sent using these
// constants and EVERY client listener MUST filter primarily by `Code`
// (cheapest, most stable) and fall back to `Subject` (machine id) for
// compatibility with notifications already sitting in inboxes.
//
// Contract
// --------
//   notification.Subject  = NotifSubject.<X>   ← stable machine id, lower_snake_case
//   notification.Code     = NotifCode.<X>      ← canonical numeric filter
//   notification.Content  = JSON-serialised object including a "type" field
//                           equal to NotifSubject.<X>  (backup filter)
//
// Numeric ranges (do NOT reuse — collisions break client filtering):
//   1   – 99   reserved for ORIGINAL friend invite/decline (legacy compat)
//   100 – 104  friend challenge lifecycle (request/accept/decline/cancel/expire)
//   105 – 199  reserved for additional friend social actions (spectate=105 first)
//   200 – 299  reserved for future friend social events
//   300 – 399  reserved for friend quests
//   400 – 499  reserved for friend streaks
//
// IMPORTANT: codes 1 and 2 are kept identical to the legacy values so that
// any notification already persisted in user inboxes still matches the
// new client filter. NEVER change those two without a coordinated client
// release that handles both old and new values.
// ============================================================================

var NotifCode = {
    // Friend invite lifecycle (1-9 reserved, codes 1-3 are legacy-compatible)
    FRIEND_REQUEST:           1,   // Was used by old send_friend_invite
    FRIEND_REQUEST_ACCEPTED:  2,   // Was used by old accept_friend_invite
    FRIEND_REQUEST_DECLINED:  3,
    FRIEND_REQUEST_CANCELLED: 4,
    FRIEND_REMOVED:           5,
    FRIEND_BLOCKED:           6,

    // Friend challenges (100-199)
    FRIEND_CHALLENGE_RECEIVED: 100, // Was used by friends_challenge_user
    FRIEND_CHALLENGE_ACCEPTED: 101,
    FRIEND_CHALLENGE_DECLINED: 102,
    FRIEND_CHALLENGE_CANCELLED: 103,
    FRIEND_CHALLENGE_EXPIRED:  104,

    // Friend spectate (105) - hardened friends_spectate RPC
    FRIEND_SPECTATE_REQUEST:   105
};

// Subject strings are STABLE MACHINE IDs (lower_snake_case). They are
// intentionally NOT human-readable display strings — display titles must
// be built on the client (so they can be localised) or read from
// notification.Content.title.
var NotifSubject = {
    FRIEND_REQUEST:           'friend_request',
    FRIEND_REQUEST_ACCEPTED:  'friend_request_accepted',
    FRIEND_REQUEST_DECLINED:  'friend_request_declined',
    FRIEND_REQUEST_CANCELLED: 'friend_request_cancelled',
    FRIEND_REMOVED:           'friend_removed',
    FRIEND_BLOCKED:           'friend_blocked',

    FRIEND_CHALLENGE_RECEIVED:  'friend_challenge',
    FRIEND_CHALLENGE_ACCEPTED:  'friend_challenge_accepted',
    FRIEND_CHALLENGE_DECLINED:  'friend_challenge_declined',
    FRIEND_CHALLENGE_CANCELLED: 'friend_challenge_cancelled',
    FRIEND_CHALLENGE_EXPIRED:   'friend_challenge_expired',

    FRIEND_SPECTATE_REQUEST:    'friend_spectate_request'
};

// Default human-readable titles. Clients SHOULD build their own localised
// titles, but if they do not, the server can fall back to these strings
// in notification.Content.title.
var NotifTitle = {
    FRIEND_REQUEST:           'Friend Request',
    FRIEND_REQUEST_ACCEPTED:  'Friend Request Accepted',
    FRIEND_REQUEST_DECLINED:  'Friend Request Declined',
    FRIEND_REQUEST_CANCELLED: 'Friend Request Cancelled',
    FRIEND_REMOVED:           'Friend Removed',
    FRIEND_BLOCKED:           'You Were Blocked',

    FRIEND_CHALLENGE_RECEIVED:  'Friend Challenge',
    FRIEND_CHALLENGE_ACCEPTED:  'Challenge Accepted',
    FRIEND_CHALLENGE_DECLINED:  'Challenge Declined',
    FRIEND_CHALLENGE_CANCELLED: 'Challenge Cancelled',
    FRIEND_CHALLENGE_EXPIRED:   'Challenge Expired',

    FRIEND_SPECTATE_REQUEST:    'Spectate Request'
};

/**
 * Build a fully-formed notification record with the canonical contract.
 * @param {string} subjectKey - One of NotifSubject keys (e.g. "FRIEND_REQUEST")
 * @param {string} userId - Recipient userId
 * @param {object} payload - Caller-supplied payload merged into Content
 * @param {string|null} senderId - Optional sender userId (Nakama notification field)
 * @returns {object} A record suitable for nk.notificationsSend([...])
 */
function buildFriendsNotification(subjectKey, userId, payload, senderId) {
    if (!NotifSubject.hasOwnProperty(subjectKey)) {
        throw new Error('buildFriendsNotification: unknown subjectKey "' + subjectKey + '"');
    }

    var subject = NotifSubject[subjectKey];
    var code    = NotifCode[subjectKey];
    var title   = NotifTitle[subjectKey];

    var content = payload || {};
    // Always inject "type" as a machine-id backup filter for older clients
    // that still look at notification.Content.type instead of Code.
    content.type  = subject;
    content.title = content.title || title;
    content.code  = code;

    return {
        userId:     userId,
        subject:    subject,
        content:    content,
        code:       code,
        sender:     senderId || null,
        persistent: true
    };
}

/**
 * Convenience wrapper that sends a single friends-system notification.
 * Catches and logs failure (notifications must never break the parent RPC).
 */
function sendFriendsNotification(nk, logger, subjectKey, userId, payload, senderId) {
    try {
        var rec = buildFriendsNotification(subjectKey, userId, payload, senderId);
        nk.notificationsSend([rec]);
        return true;
    } catch (err) {
        if (logger && logger.warn) {
            logger.warn('[FriendsNotif] Failed to send ' + subjectKey + ' to ' + userId + ': ' + err.message);
        }
        return false;
    }
}


// --- Module: friend_quests\friend_quests.js ---
// friend_quests.js - Friend Quest System for QuizVerse v4.1
// RPCs: friend_quest_get_state, friend_quest_complete, friend_quest_record_progress
// Spec: MRS §31 — 10 friend quest types + 3 solo quest types, server-authoritative generation
// v4.1: Solo/starter quests when user has no friends — ensures every user always sees quests

/**
 * Friend Quest System — Server-Authoritative
 *
 * 10 friend quest types generated from user's real friends list.
 * 3 solo/starter quest types for users with no friends.
 * Server is the source of truth — client only renders.
 * Tracks progress, grants rewards (wallet + notification), duplicate protection.
 *
 * Storage: collection="friend_quests", key="quest_state_{userId}"
 */

// ─── CONSTANTS ──────────────────────────────────────────────────────────────

var FQ_COLLECTION = 'friend_quests';
var FQ_MAX_ACTIVE = 3;
var FQ_REFRESH_HOURS = 8;

// 10 friend quest types matching client-side QuestType enum
var FQ_QUEST_TYPES = [
    'PlayTogether',
    'ChallengeFriend',
    'StudyBuddy',
    'GroupStreak',
    'BeatInSpeedQuiz',
    'DailyQuizDuo',
    'PerfectRound',
    'ExploreTogether',
    'ShareScore',
    'WinThreeQuizzes'
];

// 3 solo/starter quest types for users with no friends
var FQ_SOLO_QUEST_TYPES = [
    'CompleteQuiz',
    'DailyChallenge',
    'ScoreTarget'
];

// Solo quest templates — no friend required
var FQ_SOLO_TEMPLATES = {
    CompleteQuiz: {
        title: 'Complete a Quiz',
        desc: 'Finish any quiz to earn your first quest reward!',
        target: 1, coins: 30, xp: 15
    },
    DailyChallenge: {
        title: 'Daily Challenge',
        desc: 'Complete the Daily Quiz today',
        target: 1, coins: 50, xp: 25
    },
    ScoreTarget: {
        title: 'Score Champion',
        desc: 'Score 80% or higher in any quiz',
        target: 1, coins: 60, xp: 30
    }
};

// Quest templates: { title format, description format, targetProgress, coinReward, xpReward }
var FQ_TEMPLATES = {
    PlayTogether: {
        title: 'Play with {0}',
        desc: 'Complete a quiz while {0} is online',
        target: 1, coins: 50, xp: 25
    },
    ChallengeFriend: {
        title: 'Challenge {0}',
        desc: 'Send a challenge to {0} and have them accept',
        target: 1, coins: 75, xp: 40
    },
    StudyBuddy: {
        title: 'Study with {0}',
        desc: 'Both you and {0} complete a review session today',
        target: 1, coins: 100, xp: 50
    },
    GroupStreak: {
        title: '7-Day Streak with {0}',
        desc: 'Maintain your friend streak with {0} for 7 days',
        target: 7, coins: 200, xp: 100
    },
    BeatInSpeedQuiz: {
        title: 'Beat {0} in Speed Quiz',
        desc: 'Score higher than {0} in a Speed Quiz',
        target: 1, coins: 75, xp: 40
    },
    DailyQuizDuo: {
        title: 'Daily Quiz Duo with {0}',
        desc: 'Both you and {0} complete the Daily Quiz today',
        target: 1, coins: 60, xp: 30
    },
    PerfectRound: {
        title: 'Perfect Round with {0}',
        desc: 'Both answer 5 questions correctly in same session',
        target: 5, coins: 100, xp: 50
    },
    ExploreTogether: {
        title: 'Explore Together with {0}',
        desc: 'Both play GeoExplore mode on the same day',
        target: 1, coins: 75, xp: 40
    },
    ShareScore: {
        title: 'Share a Score with {0}',
        desc: 'Share your quiz result with {0}',
        target: 1, coins: 50, xp: 25
    },
    WinThreeQuizzes: {
        title: 'Win 3 Quizzes with {0}',
        desc: 'Win 3 quizzes while {0} is online',
        target: 3, coins: 150, xp: 75
    }
};

// ─── HELPERS ────────────────────────────────────────────────────────────────

function fqStorageKey(userId) {
    return 'quest_state_' + userId;
}

function fqReadData(nk, logger, userId) {
    try {
        var records = nk.storageRead([{
            collection: FQ_COLLECTION,
            key: fqStorageKey(userId),
            userId: userId
        }]);
        if (records && records.length > 0 && records[0].value) {
            return records[0].value;
        }
    } catch (err) {
        logger.warn('[FriendQuests] Storage read failed: ' + err.message);
    }
    return null;
}

function fqWriteData(nk, logger, userId, data) {
    try {
        nk.storageWrite([{
            collection: FQ_COLLECTION,
            key: fqStorageKey(userId),
            userId: userId,
            value: data,
            permissionRead: 1,
            permissionWrite: 0
        }]);
        return true;
    } catch (err) {
        logger.error('[FriendQuests] Storage write failed: ' + err.message);
        return false;
    }
}

function fqInitData() {
    return {
        quests: [],
        completedIds: [],
        lastRefresh: null,
        createdAt: new Date().toISOString(),
        updatedAt: new Date().toISOString()
    };
}

function fqError(msg) {
    return JSON.stringify({ success: false, error: msg });
}

function fqGenerateId() {
    // 8-char hex ID
    var chars = '0123456789abcdef';
    var id = '';
    for (var i = 0; i < 8; i++) {
        id += chars.charAt(Math.floor(Math.random() * chars.length));
    }
    return id;
}

function fqFormatString(template, friendName) {
    return template.replace(/\{0\}/g, friendName);
}

// ─── SERVER-SIDE QUEST GENERATION ───────────────────────────────────────────

/**
 * Generate quests from user's Nakama friends list.
 * Called by friend_quest_get_state when no active quests exist or they've expired.
 */
function fqGenerateQuests(nk, logger, userId, existingData) {
    // Get user's friends list
    var friends = [];
    try {
        var friendsResult = nk.friendsList(userId, null, null, null);
        if (friendsResult && friendsResult.friends) {
            for (var i = 0; i < friendsResult.friends.length; i++) {
                var f = friendsResult.friends[i];
                if (f && f.user && f.user.id) {
                    var displayName = f.user.displayName || f.user.username || 'Friend';
                    friends.push({ id: f.user.id, name: displayName });
                }
            }
        }
    } catch (err) {
        logger.warn('[FriendQuests] Could not fetch friends list: ' + err.message);
    }

    if (friends.length === 0) {
        logger.info('[FriendQuests] No friends found for user ' + userId + ' — generating solo starter quests');
        return fqGenerateSoloQuests(nk, logger, userId, existingData);
    }

    // Determine how many quests to generate
    var activeCount = 0;
    var now = new Date();
    if (existingData && existingData.quests) {
        for (var j = 0; j < existingData.quests.length; j++) {
            var q = existingData.quests[j];
            if (!q.isCompleted && q.expiresAt && new Date(q.expiresAt) > now) {
                activeCount++;
            }
        }
    }

    var toGenerate = FQ_MAX_ACTIVE - activeCount;
    if (toGenerate <= 0) return existingData ? existingData.quests : [];

    // Shuffle quest types to get random selection
    var shuffledTypes = FQ_QUEST_TYPES.slice();
    for (var s = shuffledTypes.length - 1; s > 0; s--) {
        var r = Math.floor(Math.random() * (s + 1));
        var tmp = shuffledTypes[s];
        shuffledTypes[s] = shuffledTypes[r];
        shuffledTypes[r] = tmp;
    }

    var newQuests = [];
    var expiresAt = new Date(now.getTime() + FQ_REFRESH_HOURS * 60 * 60 * 1000).toISOString();
    var createdAt = now.toISOString();

    for (var k = 0; k < toGenerate; k++) {
        var friend = friends[k % friends.length];
        var questType = shuffledTypes[k % shuffledTypes.length];
        var template = FQ_TEMPLATES[questType];

        if (!template) continue;

        newQuests.push({
            questId: fqGenerateId(),
            type: questType,
            friendId: friend.id,
            friendDisplayName: friend.name,
            title: fqFormatString(template.title, friend.name),
            description: fqFormatString(template.desc, friend.name),
            currentProgress: 0,
            targetProgress: template.target,
            isCompleted: false,
            coinReward: template.coins,
            xpReward: template.xp,
            createdAt: createdAt,
            expiresAt: expiresAt
        });
    }

    logger.info('[FriendQuests] Generated ' + newQuests.length + ' quests from ' +
                friends.length + ' friends for user ' + userId);
    return newQuests;
}

/**
 * Generate solo/starter quests for users with no friends.
 * Keeps the feature visible and actionable even without a social graph.
 */
function fqGenerateSoloQuests(nk, logger, userId, existingData) {
    var activeCount = 0;
    var now = new Date();
    if (existingData && existingData.quests) {
        for (var j = 0; j < existingData.quests.length; j++) {
            var q = existingData.quests[j];
            if (!q.isCompleted && q.expiresAt && new Date(q.expiresAt) > now) {
                activeCount++;
            }
        }
    }

    var toGenerate = FQ_MAX_ACTIVE - activeCount;
    if (toGenerate <= 0) return existingData ? existingData.quests : [];

    var newQuests = [];
    var expiresAt = new Date(now.getTime() + FQ_REFRESH_HOURS * 60 * 60 * 1000).toISOString();
    var createdAt = now.toISOString();

    for (var k = 0; k < toGenerate; k++) {
        var questType = FQ_SOLO_QUEST_TYPES[k % FQ_SOLO_QUEST_TYPES.length];
        var template = FQ_SOLO_TEMPLATES[questType];
        if (!template) continue;

        newQuests.push({
            questId: fqGenerateId(),
            type: questType,
            friendId: '',
            friendDisplayName: '',
            title: template.title,
            description: template.desc,
            currentProgress: 0,
            targetProgress: template.target,
            isCompleted: false,
            coinReward: template.coins,
            xpReward: template.xp,
            createdAt: createdAt,
            expiresAt: expiresAt
        });
    }

    logger.info('[FriendQuests] Generated ' + newQuests.length + ' solo starter quests for user ' + userId);
    return newQuests;
}

// ─── RPC: friend_quest_get_state ────────────────────────────────────────────

function rpcFriendQuestGetState(ctx, logger, nk, payload) {
    if (!ctx.userId) return fqError('User not authenticated');

    var data = fqReadData(nk, logger, ctx.userId);
    if (!data) data = fqInitData();

    // Check if we need to generate new quests
    var now = new Date();
    var needsRefresh = false;

    // Filter active non-expired quests
    var activeQuests = [];
    var expiredOrCompleted = [];
    if (data.quests && data.quests.length > 0) {
        for (var i = 0; i < data.quests.length; i++) {
            var q = data.quests[i];
            if (q.isCompleted) {
                expiredOrCompleted.push(q);
            } else if (q.expiresAt && new Date(q.expiresAt) <= now) {
                // Expired — don't include
                expiredOrCompleted.push(q);
            } else {
                activeQuests.push(q);
            }
        }
    }

    // Check refresh timer
    if (data.lastRefresh) {
        var lastRefreshDate = new Date(data.lastRefresh);
        var hoursSince = (now.getTime() - lastRefreshDate.getTime()) / (1000 * 60 * 60);
        if (hoursSince >= FQ_REFRESH_HOURS) {
            needsRefresh = true;
        }
    } else {
        needsRefresh = true;
    }

    // Generate new quests if needed
    if (activeQuests.length < FQ_MAX_ACTIVE && needsRefresh) {
        // Keep completed quests for history, replace active with fresh
        data.quests = activeQuests; // Keep valid active ones
        var newQuests = fqGenerateQuests(nk, logger, ctx.userId, data);

        // Merge new quests
        for (var j = 0; j < newQuests.length; j++) {
            data.quests.push(newQuests[j]);
        }

        data.lastRefresh = now.toISOString();
        data.updatedAt = now.toISOString();
        fqWriteData(nk, logger, ctx.userId, data);

        activeQuests = [];
        for (var k = 0; k < data.quests.length; k++) {
            if (!data.quests[k].isCompleted) {
                activeQuests.push(data.quests[k]);
            }
        }
    }

    return JSON.stringify({
        success: true,
        quests: activeQuests,
        completedIds: data.completedIds || [],
        lastRefresh: data.lastRefresh || null,
        timestamp: now.toISOString()
    });
}

// ─── RPC: friend_quest_complete ─────────────────────────────────────────────

function rpcFriendQuestComplete(ctx, logger, nk, payload) {
    if (!ctx.userId) return fqError('User not authenticated');

    var input;
    try { input = JSON.parse(payload); } catch (e) { return fqError('Invalid JSON'); }

    var questId = input.questId;
    var questType = input.questType;
    var friendId = input.friendId;
    var coinReward = input.coinReward || 50;
    var xpReward = input.xpReward || 25;

    if (!questId || !questType) return fqError('Missing questId or questType');

    var data = fqReadData(nk, logger, ctx.userId) || fqInitData();

    // Duplicate protection
    if (!data.completedIds) data.completedIds = [];
    for (var i = 0; i < data.completedIds.length; i++) {
        if (data.completedIds[i] === questId) {
            return JSON.stringify({
                success: false,
                error: 'Quest already completed',
                already_completed: true
            });
        }
    }

    // Mark completed
    data.completedIds.push(questId);

    // Update quest record if exists — use server-stored rewards for authority
    if (data.quests) {
        for (var j = 0; j < data.quests.length; j++) {
            if (data.quests[j].questId === questId) {
                data.quests[j].isCompleted = true;
                // Use server-stored reward values (authoritative)
                if (data.quests[j].coinReward) coinReward = data.quests[j].coinReward;
                if (data.quests[j].xpReward) xpReward = data.quests[j].xpReward;
                break;
            }
        }
    }

    // Grant rewards via wallet — coins + XP
    try {
        var changeset = {};
        changeset['coins'] = coinReward;
        changeset['xp'] = xpReward;
        nk.walletUpdate(ctx.userId, changeset, {
            source: 'friend_quest_' + questType
        }, true);
    } catch (walletErr) {
        logger.warn('[FriendQuests] Wallet update failed: ' + walletErr.message);
    }

    // Save state
    data.updatedAt = new Date().toISOString();
    fqWriteData(nk, logger, ctx.userId, data);

    // Notify friend about completion
    if (friendId) {
        try {
            nk.notificationsSend([{
                userId: friendId,
                subject: 'Friend Quest Completed!',
                content: {
                    type: 'friend_quest_complete',
                    quest_type: questType,
                    friend_id: ctx.userId
                },
                code: 102,
                persistent: true
            }]);
        } catch (notifErr) {
            logger.warn('[FriendQuests] Friend notification failed: ' + notifErr.message);
        }
    }

    logger.info('[FriendQuests] Quest completed: ' + questId + ' type=' + questType +
                ' coins=' + coinReward + ' xp=' + xpReward +
                ' user=' + ctx.userId);

    return JSON.stringify({
        success: true,
        questId: questId,
        coinReward: coinReward,
        xpReward: xpReward,
        timestamp: new Date().toISOString()
    });
}

// ─── RPC: friend_quest_record_progress ──────────────────────────────────────
//
// Server-authoritative progress increment. Closes the
// "client-trusted friend_quest_complete" exploit (PLAN-07 §V4) by making the
// server the owner of `quest.currentProgress`. Client only reports the
// interaction event; server validates type ↔ event compatibility and bumps.
//
// Payload: {
//   questId: <string>,
//   eventType: 'quiz_win' | 'quiz_complete' | 'review_session' | 'speed_quiz_win' |
//              'daily_quiz_complete' | 'perfect_round' | 'geo_explore_play' |
//              'share_score' | 'challenge_accepted' | 'play_with_friend',
//   amount?: <number, default 1>
// }
//
// Returns the updated quest record (or completion notification if it just
// crossed the targetProgress threshold). NEVER auto-grants rewards — caller
// must follow up with friend_quest_complete (which now also re-validates).
//
// Validation rules: each questType has an allow-list of compatible eventTypes;
// foreign event types are silently ignored (return success:true, applied:0).
var FQ_EVENT_RULES = {
    PlayTogether:    { events: ['quiz_complete','play_with_friend'] },
    ChallengeFriend: { events: ['challenge_accepted'] },
    StudyBuddy:      { events: ['review_session'] },
    GroupStreak:     { events: ['streak_advanced'] },
    BeatInSpeedQuiz: { events: ['speed_quiz_win'] },
    DailyQuizDuo:    { events: ['daily_quiz_complete'] },
    PerfectRound:    { events: ['perfect_round','quiz_complete'] },
    ExploreTogether: { events: ['geo_explore_play'] },
    ShareScore:      { events: ['share_score'] },
    WinThreeQuizzes: { events: ['quiz_win'] },
    // Solo quest event rules
    CompleteQuiz:    { events: ['quiz_complete'] },
    DailyChallenge:  { events: ['daily_quiz_complete'] },
    ScoreTarget:     { events: ['quiz_complete','quiz_win'] }
};

function rpcFriendQuestRecordProgress(ctx, logger, nk, payload) {
    if (!ctx.userId) return fqError('User not authenticated');

    var input;
    try { input = JSON.parse(payload || '{}'); } catch (e) { return fqError('Invalid JSON'); }

    var questId   = input.questId;
    var eventType = input.eventType;
    var amount    = parseInt(input.amount) || 1;
    if (!questId || !eventType) return fqError('Missing questId or eventType');
    if (amount < 1 || amount > 100) return fqError('Invalid amount (1..100)');

    var data = fqReadData(nk, logger, ctx.userId);
    if (!data || !data.quests) return fqError('No quest state — call friend_quest_get_state first');

    var found = null;
    for (var i = 0; i < data.quests.length; i++) {
        if (data.quests[i].questId === questId) { found = data.quests[i]; break; }
    }
    if (!found) return fqError('Quest not found: ' + questId);

    // Refuse to mutate completed/expired quests
    if (found.isCompleted) {
        return JSON.stringify({
            success: true,
            applied: 0,
            quest: found,
            message: 'Quest already completed',
            timestamp: new Date().toISOString()
        });
    }
    if (found.expiresAt && new Date(found.expiresAt) <= new Date()) {
        return JSON.stringify({
            success: true,
            applied: 0,
            quest: found,
            message: 'Quest expired',
            timestamp: new Date().toISOString()
        });
    }

    // Event-type ↔ quest-type compatibility check
    var rule = FQ_EVENT_RULES[found.type];
    if (!rule) return fqError('Unknown quest type: ' + found.type);
    var allowed = false;
    for (var e = 0; e < rule.events.length; e++) {
        if (rule.events[e] === eventType) { allowed = true; break; }
    }
    if (!allowed) {
        return JSON.stringify({
            success: true,
            applied: 0,
            quest: found,
            message: 'Event type ' + eventType + ' not applicable to quest type ' + found.type,
            timestamp: new Date().toISOString()
        });
    }

    // Apply progress (clamped at target)
    var prevProgress = found.currentProgress || 0;
    var target       = found.targetProgress || 1;
    var newProgress  = Math.min(target, prevProgress + amount);
    var applied      = newProgress - prevProgress;
    found.currentProgress = newProgress;

    // Auto-complete server-side when threshold reached
    var justCompleted = false;
    if (newProgress >= target && !found.isCompleted) {
        found.isCompleted = true;
        justCompleted = true;
        if (!data.completedIds) data.completedIds = [];
        // De-dup completedIds
        var alreadyCompleted = false;
        for (var c = 0; c < data.completedIds.length; c++) {
            if (data.completedIds[c] === questId) { alreadyCompleted = true; break; }
        }
        if (!alreadyCompleted) data.completedIds.push(questId);
    }

    data.updatedAt = new Date().toISOString();
    if (!fqWriteData(nk, logger, ctx.userId, data)) {
        return fqError('Failed to save quest progress');
    }

    logger.info('[FriendQuests] record_progress questId=' + questId +
                ' type=' + found.type + ' eventType=' + eventType +
                ' applied=' + applied + ' newProgress=' + newProgress + '/' + target +
                (justCompleted ? ' COMPLETED' : ''));

    return JSON.stringify({
        success: true,
        questId: questId,
        applied: applied,
        currentProgress: newProgress,
        targetProgress: target,
        isCompleted: found.isCompleted,
        justCompleted: justCompleted,
        // When justCompleted, the client should call friend_quest_complete to
        // claim the reward — but server already marks isCompleted so the
        // claim is purely a wallet transaction at that point.
        coinReward: justCompleted ? (found.coinReward || 0) : undefined,
        xpReward:   justCompleted ? (found.xpReward || 0)   : undefined,
        timestamp: new Date().toISOString()
    });
}

