// --- Module: friend_streaks\friend_streaks.js ---
// friend_streaks.js - Bilateral Friend Streak System for QuizVerse v3.0
// RPCs: friend_streak_get_state, friend_streak_record_contribution, friend_streak_send_nudge
// Spec: MRS §29-§31 — Snapchat-style bilateral daily streaks

/**
 * Friend Streak System — Production-Ready
 *
 * Tracks bilateral daily streaks between friends (both must play each day).
 * Max 5 concurrent streaks per player. Unlocks at Day 14.
 * Nudge system: 3 nudges/day with 4h cooldown per friend.
 *
 * Storage: collection="friend_streaks", key="streaks_{userId}"
 */

// ─── CONSTANTS ──────────────────────────────────────────────────────────────

var FS_COLLECTION = 'friend_streaks';
var FS_MAX_CONCURRENT = 5;
var FS_NUDGES_PER_DAY = 3;
var FS_NUDGE_COOLDOWN_HOURS = 4;
var FS_STREAK_BREAK_HOURS = 48; // 2 days without bilateral contribution = broken

// ─── HELPERS ────────────────────────────────────────────────────────────────

function fsStorageKey(userId) {
    return 'streaks_' + userId;
}

function fsReadData(nk, logger, userId) {
    try {
        var records = nk.storageRead([{
            collection: FS_COLLECTION,
            key: fsStorageKey(userId),
            userId: userId
        }]);
        if (records && records.length > 0 && records[0].value) {
            return records[0].value;
        }
    } catch (err) {
        logger.warn('[FriendStreaks] Storage read failed: ' + err.message);
    }
    return null;
}

function fsWriteData(nk, logger, userId, data) {
    try {
        nk.storageWrite([{
            collection: FS_COLLECTION,
            key: fsStorageKey(userId),
            userId: userId,
            value: data,
            permissionRead: 1,
            permissionWrite: 0
        }]);
        return true;
    } catch (err) {
        logger.error('[FriendStreaks] Storage write failed: ' + err.message);
        return false;
    }
}

function fsInitData() {
    return {
        streaks: {},
        nudgesSentToday: 0,
        nudgeDateKey: '',
        lastNudgeTimes: {},
        createdAt: new Date().toISOString(),
        updatedAt: new Date().toISOString()
    };
}

function fsError(msg) {
    return JSON.stringify({ success: false, error: msg });
}

function fsTodayKey() {
    return new Date().toISOString().slice(0, 10).replace(/-/g, '');
}

function fsHoursSince(isoDate) {
    if (!isoDate) return 9999;
    return (Date.now() - new Date(isoDate).getTime()) / 3600000;
}

// Clean up broken streaks. When a streak is broken we also persist a
// rolling "broken log" entry under collection=friend_streaks key=broken_log_{userId}
// so the player's UI can later surface "you lost a 30-day streak with X" even
// if they weren't online when the prune happened (V23 in PLAN-07).
var FS_BROKEN_LOG_MAX = 50;

function fsAppendBrokenLog(nk, logger, userId, brokenList) {
    if (!brokenList || brokenList.length === 0) return;
    try {
        var existing = [];
        try {
            var rows = nk.storageRead([{
                collection: FS_COLLECTION,
                key: 'broken_log_' + userId,
                userId: userId
            }]);
            if (rows && rows.length > 0 && rows[0].value && rows[0].value.entries) {
                existing = rows[0].value.entries;
            }
        } catch (_) {}

        var now = new Date().toISOString();
        for (var i = 0; i < brokenList.length; i++) {
            var b = brokenList[i];
            existing.unshift({
                friendId:  b.friendId,
                streakDays: b.days || 0,
                brokenAt:  now,
                repaired:  false
            });
        }
        if (existing.length > FS_BROKEN_LOG_MAX) {
            existing = existing.slice(0, FS_BROKEN_LOG_MAX);
        }

        nk.storageWrite([{
            collection: FS_COLLECTION,
            key: 'broken_log_' + userId,
            userId: userId,
            value: { entries: existing, updatedAt: now },
            permissionRead: 1,
            permissionWrite: 0
        }]);
    } catch (err) {
        if (logger && logger.warn) logger.warn('[FriendStreaks] broken-log persist failed: ' + err.message);
    }
}

function fsPruneStreaks(data) {
    var pruned = [];
    for (var fid in data.streaks) {
        var s = data.streaks[fid];
        if (fsHoursSince(s.lastInteractionAt) > FS_STREAK_BREAK_HOURS) {
            pruned.push({ friendId: fid, days: s.streakDays, friendDisplayName: s.friendDisplayName || '' });
            delete data.streaks[fid];
        }
    }
    return pruned;
}

// Reset daily nudge counter if new day
function fsRefreshNudges(data) {
    var today = fsTodayKey();
    if (data.nudgeDateKey !== today) {
        data.nudgesSentToday = 0;
        data.nudgeDateKey = today;
        data.lastNudgeTimes = {};
    }
}

// ─── RPC: friend_streak_get_state ───────────────────────────────────────────

function rpcFriendStreakGetState(ctx, logger, nk, payload) {
    if (!ctx.userId) return fsError('User not authenticated');

    var data = fsReadData(nk, logger, ctx.userId);
    if (!data) data = fsInitData();

    // Prune broken streaks
    var broken = fsPruneStreaks(data);
    fsRefreshNudges(data);

    if (broken.length > 0) {
        fsWriteData(nk, logger, ctx.userId, data);
        fsAppendBrokenLog(nk, logger, ctx.userId, broken);
    }

    // Build response
    var streakList = [];
    for (var fid in data.streaks) {
        var s = data.streaks[fid];
        var hoursLeft = FS_STREAK_BREAK_HOURS - fsHoursSince(s.lastInteractionAt);
        streakList.push({
            friendId: fid,
            friendDisplayName: s.friendDisplayName || '',
            streakDays: s.streakDays || 0,
            myContributionToday: s.myContributionToday || false,
            friendContributionToday: s.friendContributionToday || false,
            isAtRisk: hoursLeft < 4 && hoursLeft > 0,
            hoursUntilBreak: Math.max(0, Math.round(hoursLeft)),
            startedAt: s.startedAt || null
        });
    }

    return JSON.stringify({
        success: true,
        streaks: streakList,
        totalActive: streakList.length,
        maxStreaks: FS_MAX_CONCURRENT,
        nudgesRemaining: Math.max(0, FS_NUDGES_PER_DAY - (data.nudgesSentToday || 0)),
        brokenStreaks: broken,
        timestamp: new Date().toISOString()
    });
}

// ─── RPC: friend_streak_record_contribution ─────────────────────────────────

function rpcFriendStreakRecordContribution(ctx, logger, nk, payload) {
    if (!ctx.userId) return fsError('User not authenticated');

    var input;
    try { input = JSON.parse(payload); } catch (e) { return fsError('Invalid JSON'); }

    var friendId = input.friendId;
    if (!friendId) return fsError('Missing friendId');

    // --- My data ---
    var myData = fsReadData(nk, logger, ctx.userId) || fsInitData();
    fsPruneStreaks(myData);

    // Auto-create streak if not exists (within limits)
    if (!myData.streaks[friendId]) {
        if (Object.keys(myData.streaks).length >= FS_MAX_CONCURRENT) {
            return fsError('Max concurrent streaks reached (' + FS_MAX_CONCURRENT + ')');
        }
        myData.streaks[friendId] = {
            friendDisplayName: input.friendDisplayName || '',
            streakDays: 0,
            myContributionToday: false,
            friendContributionToday: false,
            lastInteractionAt: new Date().toISOString(),
            startedAt: new Date().toISOString()
        };
    }

    var myStreak = myData.streaks[friendId];
    myStreak.myContributionToday = true;
    myStreak.lastInteractionAt = new Date().toISOString();

    // --- Friend's data (mirror the contribution) ---
    var friendData = fsReadData(nk, logger, friendId) || fsInitData();
    fsPruneStreaks(friendData);

    if (!friendData.streaks[ctx.userId]) {
        if (Object.keys(friendData.streaks).length >= FS_MAX_CONCURRENT) {
            logger.warn('[FriendStreaks] Friend ' + friendId + ' at max streaks, cannot mirror');
        } else {
            friendData.streaks[ctx.userId] = {
                friendDisplayName: input.myDisplayName || '',
                streakDays: 0,
                myContributionToday: false,
                friendContributionToday: false,
                lastInteractionAt: new Date().toISOString(),
                startedAt: new Date().toISOString()
            };
        }
    }

    if (friendData.streaks[ctx.userId]) {
        friendData.streaks[ctx.userId].friendContributionToday = true;
        friendData.streaks[ctx.userId].lastInteractionAt = new Date().toISOString();

        // Check bilateral completion on friend side
        if (friendData.streaks[ctx.userId].myContributionToday &&
            friendData.streaks[ctx.userId].friendContributionToday) {
            friendData.streaks[ctx.userId].streakDays =
                (friendData.streaks[ctx.userId].streakDays || 0) + 1;
            friendData.streaks[ctx.userId].myContributionToday = false;
            friendData.streaks[ctx.userId].friendContributionToday = false;
        }
        friendData.updatedAt = new Date().toISOString();
        fsWriteData(nk, logger, friendId, friendData);
    }

    // Check bilateral completion on my side
    var advanced = false;
    if (myStreak.myContributionToday && myStreak.friendContributionToday) {
        myStreak.streakDays = (myStreak.streakDays || 0) + 1;
        myStreak.myContributionToday = false;
        myStreak.friendContributionToday = false;
        advanced = true;
    }

    myData.updatedAt = new Date().toISOString();
    if (!fsWriteData(nk, logger, ctx.userId, myData)) {
        return fsError('Failed to save streak data');
    }

    logger.info('[FriendStreaks] ' + ctx.userId + ' contributed to streak with ' +
                friendId + (advanced ? ' — ADVANCED to day ' + myStreak.streakDays : ''));

    return JSON.stringify({
        success: true,
        friendId: friendId,
        streakDays: myStreak.streakDays,
        advanced: advanced,
        myContributionToday: myStreak.myContributionToday,
        friendContributionToday: myStreak.friendContributionToday,
        timestamp: new Date().toISOString()
    });
}

// ─── RPC: friend_streak_send_nudge ──────────────────────────────────────────

function rpcFriendStreakSendNudge(ctx, logger, nk, payload) {
    if (!ctx.userId) return fsError('User not authenticated');

    var input;
    try { input = JSON.parse(payload); } catch (e) { return fsError('Invalid JSON'); }

    var friendId = input.friendId;
    if (!friendId) return fsError('Missing friendId');

    var data = fsReadData(nk, logger, ctx.userId) || fsInitData();
    fsRefreshNudges(data);

    // Check daily limit
    if ((data.nudgesSentToday || 0) >= FS_NUDGES_PER_DAY) {
        return fsError('Daily nudge limit reached (' + FS_NUDGES_PER_DAY + ')');
    }

    // Check cooldown per friend
    var lastNudge = data.lastNudgeTimes ? data.lastNudgeTimes[friendId] : null;
    if (lastNudge && fsHoursSince(lastNudge) < FS_NUDGE_COOLDOWN_HOURS) {
        var remaining = Math.ceil(FS_NUDGE_COOLDOWN_HOURS - fsHoursSince(lastNudge));
        return fsError('Nudge cooldown: ' + remaining + 'h remaining');
    }

    // Send notification to friend
    try {
        nk.notificationsSend([{
            userId: friendId,
            subject: 'Streak Nudge! 🔥',
            content: {
                type: 'friend_streak_nudge',
                senderId: ctx.userId,
                senderName: input.myDisplayName || 'A friend'
            },
            code: 101, // Custom notification code for streak nudges
            persistent: true
        }]);
    } catch (err) {
        logger.warn('[FriendStreaks] Failed to send nudge notification: ' + err.message);
        // Continue anyway — nudge is counted even if notification fails
    }

    // Update nudge state
    data.nudgesSentToday = (data.nudgesSentToday || 0) + 1;
    if (!data.lastNudgeTimes) data.lastNudgeTimes = {};
    data.lastNudgeTimes[friendId] = new Date().toISOString();
    data.updatedAt = new Date().toISOString();

    fsWriteData(nk, logger, ctx.userId, data);

    var remaining = FS_NUDGES_PER_DAY - data.nudgesSentToday;
    logger.info('[FriendStreaks] Nudge sent from ' + ctx.userId + ' to ' + friendId +
                '. Remaining: ' + remaining);

    return JSON.stringify({
        success: true,
        friendId: friendId,
        nudgesRemaining: remaining,
        cooldownHours: FS_NUDGE_COOLDOWN_HOURS,
        timestamp: new Date().toISOString()
    });
}

// ─── RPC: friend_streak_get_broken_log ──────────────────────────────────────
//
// Returns the rolling log of streaks that broke while the player was offline,
// so the client can show a "you lost a 30-day streak with X" banner. Also
// runs a fresh prune so the log is always up to date at read time.

function rpcFriendStreakGetBrokenLog(ctx, logger, nk, payload) {
    if (!ctx.userId) return fsError('User not authenticated');

    var input = {};
    if (payload && payload !== '') {
        try { input = JSON.parse(payload); } catch (e) { /* ignore — empty filter */ }
    }
    var limit = parseInt(input.limit) || 20;
    if (limit < 1)  limit = 1;
    if (limit > FS_BROKEN_LOG_MAX) limit = FS_BROKEN_LOG_MAX;
    var includeRepaired = input.includeRepaired === true;

    // Fresh prune so the log is always current at read time
    var data = fsReadData(nk, logger, ctx.userId) || fsInitData();
    var fresh = fsPruneStreaks(data);
    if (fresh.length > 0) {
        fsWriteData(nk, logger, ctx.userId, data);
        fsAppendBrokenLog(nk, logger, ctx.userId, fresh);
    }

    var entries = [];
    try {
        var rows = nk.storageRead([{
            collection: FS_COLLECTION,
            key: 'broken_log_' + ctx.userId,
            userId: ctx.userId
        }]);
        if (rows && rows.length > 0 && rows[0].value && rows[0].value.entries) {
            entries = rows[0].value.entries;
        }
    } catch (err) {
        logger.warn('[FriendStreaks] broken-log read failed: ' + err.message);
    }

    if (!includeRepaired) {
        var filtered = [];
        for (var i = 0; i < entries.length; i++) {
            if (!entries[i].repaired) filtered.push(entries[i]);
        }
        entries = filtered;
    }
    if (entries.length > limit) entries = entries.slice(0, limit);

    return JSON.stringify({
        success: true,
        entries: entries,
        totalEntries: entries.length,
        timestamp: new Date().toISOString()
    });
}

// ─── RPC: friend_streak_repair ──────────────────────────────────────────────
//
// Spend a "Streak Saver" (gem cost) to restore a broken bilateral streak.
// Server-authoritative: validates the broken-log entry exists, debits the
// wallet, restores the streak with its previous day count, marks the entry
// repaired, and notifies the friend so their state can mirror.
//
// Schema: { friendId: <UUID>, idempotencyKey?: <string> }

var FS_REPAIR_GEM_COST = 50;

function rpcFriendStreakRepair(ctx, logger, nk, payload) {
    if (!ctx.userId) return fsError('User not authenticated');

    var input;
    try { input = JSON.parse(payload || '{}'); } catch (e) { return fsError('Invalid JSON'); }

    var friendId = input.friendId;
    if (!friendId) return fsError('Missing friendId');
    var idempotencyKey = input.idempotencyKey || ('fs_repair_' + friendId + '_' + Date.now());

    // Idempotency check — refuse double-spend on the same key
    try {
        var idemRows = nk.storageRead([{
            collection: FS_COLLECTION,
            key: 'repair_idem_' + ctx.userId + '_' + idempotencyKey,
            userId: ctx.userId
        }]);
        if (idemRows && idemRows.length > 0 && idemRows[0].value) {
            return JSON.stringify({
                success: true,
                idempotent: true,
                friendId: friendId,
                streakDays: idemRows[0].value.restoredDays || 0,
                timestamp: new Date().toISOString()
            });
        }
    } catch (_) { /* fall-through */ }

    // Find the broken-log entry for this friend (most recent unrepaired)
    var brokenEntry = null;
    var brokenLog = null;
    try {
        var rows = nk.storageRead([{
            collection: FS_COLLECTION,
            key: 'broken_log_' + ctx.userId,
            userId: ctx.userId
        }]);
        if (rows && rows.length > 0 && rows[0].value && rows[0].value.entries) {
            brokenLog = rows[0].value;
            for (var i = 0; i < brokenLog.entries.length; i++) {
                if (brokenLog.entries[i].friendId === friendId && !brokenLog.entries[i].repaired) {
                    brokenEntry = brokenLog.entries[i];
                    break;
                }
            }
        }
    } catch (err) {
        logger.warn('[FriendStreaks] repair read broken-log failed: ' + err.message);
    }

    if (!brokenEntry) {
        return fsError('No broken streak found for friend ' + friendId);
    }

    // Repair window: only repair if the streak broke within last 7 days
    var brokenAtMs = new Date(brokenEntry.brokenAt).getTime();
    if ((Date.now() - brokenAtMs) > (7 * 86400000)) {
        return fsError('Streak broken more than 7 days ago — too late to repair');
    }

    // Debit gems
    try {
        nk.walletUpdate(ctx.userId, { gems: -FS_REPAIR_GEM_COST }, {
            source: 'friend_streak_repair',
            friendId: friendId,
            idempotencyKey: idempotencyKey
        }, true);
    } catch (walletErr) {
        return fsError('Insufficient gems: ' + walletErr.message);
    }

    // Restore the streak on caller's side
    var data = fsReadData(nk, logger, ctx.userId) || fsInitData();
    if (Object.keys(data.streaks).length >= FS_MAX_CONCURRENT) {
        // Refund gems
        try {
            nk.walletUpdate(ctx.userId, { gems: FS_REPAIR_GEM_COST }, {
                source: 'friend_streak_repair_refund',
                friendId: friendId
            }, true);
        } catch (_) {}
        return fsError('Max concurrent streaks reached — cannot restore');
    }
    data.streaks[friendId] = {
        friendDisplayName: brokenEntry.friendDisplayName || '',
        streakDays: brokenEntry.streakDays || 0,
        myContributionToday: false,
        friendContributionToday: false,
        lastInteractionAt: new Date().toISOString(),
        startedAt: new Date().toISOString(),
        repairedAt: new Date().toISOString()
    };
    data.updatedAt = new Date().toISOString();
    fsWriteData(nk, logger, ctx.userId, data);

    // Mark broken-log entry as repaired
    try {
        if (brokenLog && brokenLog.entries) {
            for (var j = 0; j < brokenLog.entries.length; j++) {
                if (brokenLog.entries[j] === brokenEntry) {
                    brokenLog.entries[j].repaired = true;
                    brokenLog.entries[j].repairedAt = new Date().toISOString();
                    break;
                }
            }
            nk.storageWrite([{
                collection: FS_COLLECTION,
                key: 'broken_log_' + ctx.userId,
                userId: ctx.userId,
                value: brokenLog,
                permissionRead: 1,
                permissionWrite: 0
            }]);
        }
    } catch (err) {
        logger.warn('[FriendStreaks] repair mark-log failed: ' + err.message);
    }

    // Persist idempotency record (24h TTL via Nakama isn't supported in JS
    // runtime, so we just persist forever — keys are scoped per-user and small)
    try {
        nk.storageWrite([{
            collection: FS_COLLECTION,
            key: 'repair_idem_' + ctx.userId + '_' + idempotencyKey,
            userId: ctx.userId,
            value: {
                friendId: friendId,
                restoredDays: brokenEntry.streakDays || 0,
                gemCost: FS_REPAIR_GEM_COST,
                repairedAt: new Date().toISOString()
            },
            permissionRead: 0,
            permissionWrite: 0
        }]);
    } catch (_) {}

    // Notify the friend
    try {
        nk.notificationsSend([{
            userId: friendId,
            subject: 'Streak Restored! 🔥',
            content: {
                type: 'friend_streak_repaired',
                fromUserId: ctx.userId,
                streakDays: brokenEntry.streakDays || 0
            },
            code: 102,
            persistent: true
        }]);
    } catch (err) {
        logger.warn('[FriendStreaks] repair notify failed: ' + err.message);
    }

    logger.info('[FriendStreaks] Repaired streak ' + ctx.userId + ' ↔ ' + friendId +
                ' restoredDays=' + (brokenEntry.streakDays || 0) + ' gemCost=' + FS_REPAIR_GEM_COST);

    return JSON.stringify({
        success: true,
        friendId: friendId,
        streakDays: brokenEntry.streakDays || 0,
        gemCost: FS_REPAIR_GEM_COST,
        idempotencyKey: idempotencyKey,
        timestamp: new Date().toISOString()
    });
}

// ============================================================================
// Module Init — register Friend Streak RPCs
// ============================================================================
// Registers all 5 friend-streak RPCs. Existing 3 (get_state, record_contribution,
// send_nudge) are also registered by legacy_runtime.js; postbuild's `||` guard
// + module-first concat order means our handler wins.
function __ModuleInit_38(ctx, logger, nk, initializer) {
    __rpc_friend_streak_get_state = __rpc_friend_streak_get_state || (rpcFriendStreakGetState);
    __rpc_friend_streak_record_contribution = __rpc_friend_streak_record_contribution || (rpcFriendStreakRecordContribution);
    __rpc_friend_streak_send_nudge = __rpc_friend_streak_send_nudge || (rpcFriendStreakSendNudge);
    __rpc_friend_streak_get_broken_log = __rpc_friend_streak_get_broken_log || (rpcFriendStreakGetBrokenLog);
    __rpc_friend_streak_repair = __rpc_friend_streak_repair || (rpcFriendStreakRepair);
    if (logger && logger.info) {
        logger.info('[FriendStreaks] Registered 5 RPCs (get_state, record_contribution, send_nudge, get_broken_log, repair)');
    }
}


// --- Module: game_metrics\game_metrics.js ---
// game_metrics.js — Universal game metrics capture, query, and aggregation
//
// Collections:
//   game_metrics_{gameId}  — per-user match/session results (user-owned)
//   game_metrics_index     — game-wide metric summaries (system-owned)
//
// Works for ANY game (cricket, quiz, survival, etc.) with a flexible schema.

var SYSTEM_USER = "00000000-0000-0000-0000-000000000000";

// ============================================================================
// HELPERS
// ============================================================================

function gmDateStr() {
    return new Date().toISOString().slice(0, 10);
}

function gmNow() {
    return new Date().toISOString();
}

function gmUnix() {
    return Math.floor(Date.now() / 1000);
}

function gmSafeRead(nk, collection, key, userId) {
    try {
        var r = nk.storageRead([{ collection: collection, key: key, userId: userId }]);
        if (r && r.length > 0 && r[0].value) return r[0].value;
    } catch (e) { /* ignore */ }
    return null;
}

function gmSafeWrite(nk, collection, key, userId, value) {
    try {
        nk.storageWrite([{
            collection: collection,
            key: key,
            userId: userId,
            value: value,
            permissionRead: 1,
            permissionWrite: 0
        }]);
        return true;
    } catch (e) {
        return false;
    }
}

function gmSafeList(nk, userId, collection, limit, cursor) {
    try {
        return nk.storageList(userId, collection, limit, cursor);
    } catch (e) {
        return { objects: [], cursor: "" };
    }
}

function gmMedian(arr) {
    if (!arr.length) return 0;
    var s = arr.slice().sort(function (a, b) { return a - b; });
    var mid = Math.floor(s.length / 2);
    return s.length % 2 === 0 ? (s[mid - 1] + s[mid]) / 2 : s[mid];
}

function gmPercentile(arr, p) {
    if (!arr.length) return 0;
    var s = arr.slice().sort(function (a, b) { return a - b; });
    var idx = Math.ceil((p / 100) * s.length) - 1;
    return s[Math.max(0, idx)];
}

function gmRound(n, d) {
    var f = Math.pow(10, d || 2);
    return Math.round(n * f) / f;
}

// ============================================================================
// RPC: game_metrics_submit
// ============================================================================

function rpcGameMetricsSubmit(ctx, logger, nk, payload) {
    logger.info("[GameMetrics] RPC game_metrics_submit called");

    try {
        var data = JSON.parse(payload || "{}");
    } catch (e) {
        return JSON.stringify({ success: false, error: "Invalid JSON payload" });
    }

    var gameId = data.game_id;
    if (!gameId) {
        return JSON.stringify({ success: false, error: "Missing required field: game_id" });
    }

    var userId = ctx.userId;
    if (!userId) {
        return JSON.stringify({ success: false, error: "User not authenticated" });
    }

    var metricType = data.metric_type || "match_result";
    var metrics = data.metrics || {};
    var tags = data.tags || {};
    var ts = gmNow();
    var unix = gmUnix();

    // Build the record
    var record = {
        game_id: gameId,
        user_id: userId,
        metric_type: metricType,
        metrics: metrics,
        tags: tags,
        date: gmDateStr(),
        timestamp: ts,
        unix_ts: unix
    };

    // Store with unique key
    var collection = "game_metrics_" + gameId;
    var key = metricType + "_" + userId + "_" + unix;
    gmSafeWrite(nk, collection, key, userId, record);

    // Update the per-game summary index for aggregation
    try {
        var indexKey = "summary_" + gameId;
        var summary = gmSafeRead(nk, "game_metrics_index", indexKey, SYSTEM_USER) || {
            game_id: gameId,
            total_submissions: 0,
            unique_users: [],
            metric_types: {},
            last_updated: ts
        };

        summary.total_submissions += 1;
        if (summary.unique_users.indexOf(userId) === -1) {
            summary.unique_users.push(userId);
        }

        if (!summary.metric_types[metricType]) {
            summary.metric_types[metricType] = { count: 0, last_seen: ts };
        }
        summary.metric_types[metricType].count += 1;
        summary.metric_types[metricType].last_seen = ts;
        summary.last_updated = ts;

        // Keep running stats for numeric metric fields
        if (!summary.numeric_stats) summary.numeric_stats = {};
        for (var field in metrics) {
            if (typeof metrics[field] === "number") {
                if (!summary.numeric_stats[field]) {
                    summary.numeric_stats[field] = {
                        count: 0, sum: 0, min: metrics[field], max: metrics[field]
                    };
                }
                var stat = summary.numeric_stats[field];
                stat.count += 1;
                stat.sum += metrics[field];
                if (metrics[field] < stat.min) stat.min = metrics[field];
                if (metrics[field] > stat.max) stat.max = metrics[field];
                stat.avg = gmRound(stat.sum / stat.count);
            }
        }

        gmSafeWrite(nk, "game_metrics_index", indexKey, SYSTEM_USER, summary);
    } catch (indexErr) {
        logger.warn("[GameMetrics] Failed to update index: " + indexErr.message);
    }

    logger.info("[GameMetrics] Submitted " + metricType + " for user " + userId + " in game " + gameId);

    return JSON.stringify({
        success: true,
        game_id: gameId,
        metric_type: metricType,
        record_key: key,
        timestamp: ts
    });
}

// ============================================================================
// RPC: game_metrics_query
// ============================================================================

function rpcGameMetricsQuery(ctx, logger, nk, payload) {
    logger.info("[GameMetrics] RPC game_metrics_query called");

    try {
        var data = JSON.parse(payload || "{}");
    } catch (e) {
        return JSON.stringify({ success: false, error: "Invalid JSON payload" });
    }

    var gameId = data.game_id;
    if (!gameId) {
        return JSON.stringify({ success: false, error: "Missing required field: game_id" });
    }

    var userId = data.user_id || (ctx.userId || null);
    if (!userId) {
        return JSON.stringify({ success: false, error: "Missing user_id (or authenticate)" });
    }

    var metricType = data.metric_type || null;
    var limit = data.limit || 50;
    var cursor = data.cursor || null;

    if (limit < 1) limit = 1;
    if (limit > 100) limit = 100;

    var collection = "game_metrics_" + gameId;
    var result = gmSafeList(nk, userId, collection, limit, cursor);

    var records = [];
    if (result && result.objects) {
        for (var i = 0; i < result.objects.length; i++) {
            var obj = result.objects[i];
            var val = obj.value || {};

            // Filter by metric_type if specified
            if (metricType && val.metric_type !== metricType) {
                continue;
            }

            records.push({
                key: obj.key,
                metric_type: val.metric_type,
                metrics: val.metrics,
                tags: val.tags,
                date: val.date,
                timestamp: val.timestamp
            });
        }
    }

    return JSON.stringify({
        success: true,
        game_id: gameId,
        user_id: userId,
        records: records,
        count: records.length,
        cursor: (result && result.cursor) ? result.cursor : null,
        filter: metricType ? { metric_type: metricType } : null
    });
}

// ============================================================================
// RPC: game_metrics_aggregate
// ============================================================================

function rpcGameMetricsAggregate(ctx, logger, nk, payload) {
    logger.info("[GameMetrics] RPC game_metrics_aggregate called");

    try {
        var data = JSON.parse(payload || "{}");
    } catch (e) {
        return JSON.stringify({ success: false, error: "Invalid JSON payload" });
    }

    var gameId = data.game_id;
    if (!gameId) {
        return JSON.stringify({ success: false, error: "Missing required field: game_id" });
    }

    var metricType = data.metric_type || null;
    var fields = data.fields || [];
    var sampleSize = data.sample_size || 50;
    if (sampleSize > 200) sampleSize = 200;

    // Read the game summary index for quick stats
    var indexKey = "summary_" + gameId;
    var summary = gmSafeRead(nk, "game_metrics_index", indexKey, SYSTEM_USER);

    if (!summary) {
        return JSON.stringify({
            success: true,
            game_id: gameId,
            message: "No metrics data found for this game",
            summary: null,
            field_stats: {},
            sample_size: 0
        });
    }

    // If fields are requested, sample actual records for detailed aggregation
    var fieldStats = {};
    var sampled = 0;

    if (fields.length > 0 && summary.unique_users && summary.unique_users.length > 0) {
        var fieldValues = {};
        for (var fi = 0; fi < fields.length; fi++) {
            fieldValues[fields[fi]] = [];
        }

        var collection = "game_metrics_" + gameId;
        var usersToSample = summary.unique_users.slice(0, Math.min(20, summary.unique_users.length));

        for (var ui = 0; ui < usersToSample.length && sampled < sampleSize; ui++) {
            var userRecords = gmSafeList(nk, usersToSample[ui], collection, 20, null);
            if (userRecords && userRecords.objects) {
                for (var ri = 0; ri < userRecords.objects.length && sampled < sampleSize; ri++) {
                    var rec = userRecords.objects[ri].value;
                    if (!rec || !rec.metrics) continue;
                    if (metricType && rec.metric_type !== metricType) continue;

                    for (var fj = 0; fj < fields.length; fj++) {
                        var fname = fields[fj];
                        if (rec.metrics[fname] !== undefined && typeof rec.metrics[fname] === "number") {
                            fieldValues[fname].push(rec.metrics[fname]);
                        }
                    }
                    sampled++;
                }
            }
        }

        // Compute stats per field
        for (var fk = 0; fk < fields.length; fk++) {
            var fname2 = fields[fk];
            var vals = fieldValues[fname2];
            if (vals.length > 0) {
                var sum = 0;
                var min = vals[0];
                var max = vals[0];
                for (var vi = 0; vi < vals.length; vi++) {
                    sum += vals[vi];
                    if (vals[vi] < min) min = vals[vi];
                    if (vals[vi] > max) max = vals[vi];
                }
                fieldStats[fname2] = {
                    count: vals.length,
                    sum: gmRound(sum),
                    avg: gmRound(sum / vals.length),
                    min: gmRound(min),
                    max: gmRound(max),
                    median: gmRound(gmMedian(vals)),
                    p95: gmRound(gmPercentile(vals, 95)),
                    distribution: {
                        below_avg: vals.filter(function (v) { return v < (sum / vals.length); }).length,
                        above_avg: vals.filter(function (v) { return v >= (sum / vals.length); }).length
                    }
                };
            } else {
                fieldStats[fname2] = { count: 0, message: "No data for this field" };
            }
        }
    } else if (summary.numeric_stats) {
        // Use the running stats from the index
        fieldStats = summary.numeric_stats;
    }

    // Build metric type breakdown
    var typeBreakdown = [];
    if (summary.metric_types) {
        for (var mt in summary.metric_types) {
            typeBreakdown.push({
                metric_type: mt,
                count: summary.metric_types[mt].count,
                last_seen: summary.metric_types[mt].last_seen
            });
        }
        typeBreakdown.sort(function (a, b) { return b.count - a.count; });
    }

    return JSON.stringify({
        success: true,
        game_id: gameId,
        summary: {
            total_submissions: summary.total_submissions,
            unique_players: summary.unique_users ? summary.unique_users.length : 0,
            metric_types: typeBreakdown,
            last_updated: summary.last_updated
        },
        field_stats: fieldStats,
        sample_size: sampled,
        filter: metricType ? { metric_type: metricType } : null
    });
}


// --- Module: groups\groups.js ---
// groups.js - Groups/Clans/Guilds system for multi-game backend
// Provides comprehensive group management with roles, shared wallets, and group challenges

/**
 * Groups/Clans/Guilds System
 * 
 * Features:
 * - Create and manage groups with roles (Owner, Admin, Member)
 * - Group leaderboards and shared wallets
 * - Group XP and quest challenges
 * - Group chat channels (via Nakama built-in)
 * - Per-game group support
 */

// Group role hierarchy
var GROUP_ROLES = {
    OWNER: 0,      // Creator, full control
    ADMIN: 1,      // Can manage members, not delete group
    MEMBER: 2      // Regular member
};

// Group metadata structure
function createGroupMetadata(gameId, groupType, customData) {
    return {
        gameId: gameId,
        groupType: groupType || "guild",
        createdAt: new Date().toISOString(),
        level: 1,
        xp: 0,
        totalMembers: 1,
        customData: customData || {}
    };
}

/**
 * RPC: create_game_group
 * Create a group/clan/guild for a specific game
 */
function rpcCreateGameGroup(ctx, logger, nk, payload) {
    try {
        if (!ctx.userId) {
            return JSON.stringify({
                success: false,
                error: "Authentication required"
            });
        }

        var data;
        try {
            data = JSON.parse(payload);
        } catch (err) {
            return JSON.stringify({
                success: false,
                error: "Invalid JSON payload"
            });
        }

        // Validate required fields
        if (!data.gameId || !data.name) {
            return JSON.stringify({
                success: false,
                error: "Missing required fields: gameId, name"
            });
        }

        var gameId = data.gameId;
        var name = data.name;
        var description = data.description || "";
        var avatarUrl = data.avatarUrl || "";
        var langTag = data.langTag || "en";
        var open = data.open !== undefined ? data.open : false;
        var maxCount = data.maxCount || 100;
        var groupType = data.groupType || "guild";

        // Create group metadata
        var metadata = createGroupMetadata(gameId, groupType, data.customData);

        // Create group using Nakama's built-in Groups API
        var group;
        try {
            group = nk.groupCreate(
                ctx.userId,
                name,
                description,
                avatarUrl,
                langTag,
                JSON.stringify(metadata),
                open,
                maxCount
            );
        } catch (err) {
            logger.error("[Groups] Failed to create group: " + err.message);
            return JSON.stringify({
                success: false,
                error: "Failed to create group: " + err.message
            });
        }

        // Initialize group wallet
        try {
            var walletKey = "group_wallet_" + group.id;
            nk.storageWrite([{
                collection: "group_wallets",
                key: walletKey,
                userId: "00000000-0000-0000-0000-000000000000",
                value: {
                    groupId: group.id,
                    gameId: gameId,
                    currencies: {
                        tokens: 0,
                        xp: 0
                    },
                    createdAt: new Date().toISOString()
                },
                permissionRead: 1,
                permissionWrite: 0
            }]);
        } catch (err) {
            logger.warn("[Groups] Failed to create group wallet: " + err.message);
        }

        logger.info("[Groups] Created group: " + group.id + " for game: " + gameId);

        return JSON.stringify({
            success: true,
            group: {
                id: group.id,
                creatorId: group.creatorId,
                name: group.name,
                description: group.description,
                avatarUrl: group.avatarUrl,
                langTag: group.langTag,
                open: group.open,
                edgeCount: group.edgeCount,
                maxCount: group.maxCount,
                createTime: group.createTime,
                updateTime: group.updateTime,
                metadata: metadata
            },
            timestamp: new Date().toISOString()
        });

    } catch (err) {
        logger.error("[Groups] Unexpected error in rpcCreateGameGroup: " + err.message);
        return JSON.stringify({
            success: false,
            error: "An unexpected error occurred"
        });
    }
}

/**
 * RPC: update_group_xp
 * Update group XP (for challenges/quests)
 */
function rpcUpdateGroupXP(ctx, logger, nk, payload) {
    try {
        if (!ctx.userId) {
            return JSON.stringify({
                success: false,
                error: "Authentication required"
            });
        }

        var data;
        try {
            data = JSON.parse(payload);
        } catch (err) {
            return JSON.stringify({
                success: false,
                error: "Invalid JSON payload"
            });
        }

        if (!data.groupId || data.xp === undefined) {
            return JSON.stringify({
                success: false,
                error: "Missing required fields: groupId, xp"
            });
        }

        var groupId = data.groupId;
        var xpToAdd = parseInt(data.xp);

        // Get group to verify it exists and get metadata
        var groups;
        try {
            groups = nk.groupsGetId([groupId]);
        } catch (err) {
            return JSON.stringify({
                success: false,
                error: "Group not found"
            });
        }

        if (!groups || groups.length === 0) {
            return JSON.stringify({
                success: false,
                error: "Group not found"
            });
        }

        var group = groups[0];
        var metadata = JSON.parse(group.metadata || "{}");
        
        // Update XP
        metadata.xp = (metadata.xp || 0) + xpToAdd;
        
        // Calculate level (100 XP per level)
        var newLevel = Math.floor(metadata.xp / 100) + 1;
        var leveledUp = newLevel > (metadata.level || 1);
        metadata.level = newLevel;

        // Update group metadata
        try {
            nk.groupUpdate(
                groupId,
                ctx.userId,
                group.name,
                group.description,
                group.avatarUrl,
                group.langTag,
                JSON.stringify(metadata),
                group.open,
                group.maxCount
            );
        } catch (err) {
            logger.error("[Groups] Failed to update group: " + err.message);
            return JSON.stringify({
                success: false,
                error: "Failed to update group XP"
            });
        }

        logger.info("[Groups] Updated group XP: " + groupId + " +" + xpToAdd + " XP");

        return JSON.stringify({
            success: true,
            groupId: groupId,
            xpAdded: xpToAdd,
            totalXP: metadata.xp,
            level: metadata.level,
            leveledUp: leveledUp,
            timestamp: new Date().toISOString()
        });

    } catch (err) {
        logger.error("[Groups] Unexpected error in rpcUpdateGroupXP: " + err.message);
        return JSON.stringify({
            success: false,
            error: "An unexpected error occurred"
        });
    }
}

/**
 * RPC: get_group_wallet
 * Get group's shared wallet
 */
function rpcGetGroupWallet(ctx, logger, nk, payload) {
    try {
        if (!ctx.userId) {
            return JSON.stringify({
                success: false,
                error: "Authentication required"
            });
        }

        var data;
        try {
            data = JSON.parse(payload);
        } catch (err) {
            return JSON.stringify({
                success: false,
                error: "Invalid JSON payload"
            });
        }

        if (!data.groupId) {
            return JSON.stringify({
                success: false,
                error: "Missing required field: groupId"
            });
        }

        var groupId = data.groupId;
        var walletKey = "group_wallet_" + groupId;

        // Read wallet from storage
        var records;
        try {
            records = nk.storageRead([{
                collection: "group_wallets",
                key: walletKey,
                userId: "00000000-0000-0000-0000-000000000000"
            }]);
        } catch (err) {
            return JSON.stringify({
                success: false,
                error: "Failed to read group wallet"
            });
        }

        if (!records || records.length === 0) {
            // Initialize wallet if it doesn't exist
            var wallet = {
                groupId: groupId,
                gameId: data.gameId || "",
                currencies: {
                    tokens: 0,
                    xp: 0
                },
                createdAt: new Date().toISOString()
            };

            try {
                nk.storageWrite([{
                    collection: "group_wallets",
                    key: walletKey,
                    userId: "00000000-0000-0000-0000-000000000000",
                    value: wallet,
                    permissionRead: 1,
                    permissionWrite: 0
                }]);
            } catch (err) {
                logger.warn("[Groups] Failed to create group wallet: " + err.message);
            }

            return JSON.stringify({
                success: true,
                wallet: wallet,
                timestamp: new Date().toISOString()
            });
        }

        return JSON.stringify({
            success: true,
            wallet: records[0].value,
            timestamp: new Date().toISOString()
        });

    } catch (err) {
        logger.error("[Groups] Unexpected error in rpcGetGroupWallet: " + err.message);
        return JSON.stringify({
            success: false,
            error: "An unexpected error occurred"
        });
    }
}

/**
 * RPC: update_group_wallet
 * Update group's shared wallet (admins only)
 */
function rpcUpdateGroupWallet(ctx, logger, nk, payload) {
    try {
        if (!ctx.userId) {
            return JSON.stringify({
                success: false,
                error: "Authentication required"
            });
        }

        var data;
        try {
            data = JSON.parse(payload);
        } catch (err) {
            return JSON.stringify({
                success: false,
                error: "Invalid JSON payload"
            });
        }

        if (!data.groupId || !data.currency || data.amount === undefined || !data.operation) {
            return JSON.stringify({
                success: false,
                error: "Missing required fields: groupId, currency, amount, operation"
            });
        }

        var groupId = data.groupId;
        var currency = data.currency;
        var amount = parseInt(data.amount);
        var operation = data.operation; // "add" or "subtract"

        // Verify user is admin of the group
        var userGroups;
        try {
            userGroups = nk.userGroupsList(ctx.userId);
        } catch (err) {
            return JSON.stringify({
                success: false,
                error: "Failed to verify group membership"
            });
        }

        var isAdmin = false;
        if (userGroups && userGroups.userGroups) {
            for (var i = 0; i < userGroups.userGroups.length; i++) {
                var ug = userGroups.userGroups[i];
                if (ug.group.id === groupId && (ug.state <= GROUP_ROLES.ADMIN)) {
                    isAdmin = true;
                    break;
                }
            }
        }

        if (!isAdmin) {
            return JSON.stringify({
                success: false,
                error: "Only group admins can update group wallet"
            });
        }

        // Get current wallet
        var walletKey = "group_wallet_" + groupId;
        var records;
        try {
            records = nk.storageRead([{
                collection: "group_wallets",
                key: walletKey,
                userId: "00000000-0000-0000-0000-000000000000"
            }]);
        } catch (err) {
            return JSON.stringify({
                success: false,
                error: "Failed to read group wallet"
            });
        }

        if (!records || records.length === 0) {
            return JSON.stringify({
                success: false,
                error: "Group wallet not found"
            });
        }

        var wallet = records[0].value;
        var currentBalance = wallet.currencies[currency] || 0;
        var newBalance;

        if (operation === "add") {
            newBalance = currentBalance + amount;
        } else if (operation === "subtract") {
            newBalance = currentBalance - amount;
            if (newBalance < 0) {
                return JSON.stringify({
                    success: false,
                    error: "Insufficient balance"
                });
            }
        } else {
            return JSON.stringify({
                success: false,
                error: "Invalid operation. Use 'add' or 'subtract'"
            });
        }

        wallet.currencies[currency] = newBalance;

        // Update wallet
        try {
            nk.storageWrite([{
                collection: "group_wallets",
                key: walletKey,
                userId: "00000000-0000-0000-0000-000000000000",
                value: wallet,
                permissionRead: 1,
                permissionWrite: 0
            }]);
        } catch (err) {
            return JSON.stringify({
                success: false,
                error: "Failed to update group wallet"
            });
        }

        logger.info("[Groups] Updated group wallet: " + groupId + " " + operation + " " + amount + " " + currency);

        return JSON.stringify({
            success: true,
            groupId: groupId,
            currency: currency,
            operation: operation,
            amount: amount,
            newBalance: newBalance,
            timestamp: new Date().toISOString()
        });

    } catch (err) {
        logger.error("[Groups] Unexpected error in rpcUpdateGroupWallet: " + err.message);
        return JSON.stringify({
            success: false,
            error: "An unexpected error occurred"
        });
    }
}

/**
 * RPC: get_user_groups
 * Get all groups for a user (filtered by gameId if provided)
 */
function rpcGetUserGroups(ctx, logger, nk, payload) {
    try {
        if (!ctx.userId) {
            return JSON.stringify({
                success: false,
                error: "Authentication required"
            });
        }

        var data;
        try {
            data = JSON.parse(payload || "{}");
        } catch (err) {
            return JSON.stringify({
                success: false,
                error: "Invalid JSON payload"
            });
        }

        var gameId = data.gameId || null;

        // Get user groups
        var userGroups;
        try {
            userGroups = nk.userGroupsList(ctx.userId);
        } catch (err) {
            return JSON.stringify({
                success: false,
                error: "Failed to retrieve user groups"
            });
        }

        var groups = [];
        if (userGroups && userGroups.userGroups) {
            for (var i = 0; i < userGroups.userGroups.length; i++) {
                var ug = userGroups.userGroups[i];
                var group = ug.group;
                var metadata = JSON.parse(group.metadata || "{}");

                // Filter by gameId if provided
                if (gameId && metadata.gameId !== gameId) {
                    continue;
                }

                groups.push({
                    id: group.id,
                    name: group.name,
                    description: group.description,
                    avatarUrl: group.avatarUrl,
                    langTag: group.langTag,
                    open: group.open,
                    edgeCount: group.edgeCount,
                    maxCount: group.maxCount,
                    createTime: group.createTime,
                    updateTime: group.updateTime,
                    metadata: metadata,
                    userRole: ug.state,
                    userRoleName: getRoleName(ug.state)
                });
            }
        }

        return JSON.stringify({
            success: true,
            userId: ctx.userId,
            gameId: gameId,
            groups: groups,
            count: groups.length,
            timestamp: new Date().toISOString()
        });

    } catch (err) {
        logger.error("[Groups] Unexpected error in rpcGetUserGroups: " + err.message);
        return JSON.stringify({
            success: false,
            error: "An unexpected error occurred"
        });
    }
}

function getRoleName(state) {
    if (state === GROUP_ROLES.OWNER) return "Owner";
    if (state === GROUP_ROLES.ADMIN) return "Admin";
    if (state === GROUP_ROLES.MEMBER) return "Member";
    return "Unknown";
}


// --- Module: identity.js ---
// identity.js - Device-based identity management per game
// Compatible with Nakama JavaScript runtime (no ES modules)

/**
 * Get or create identity for a device + game combination
 * @param {object} nk - Nakama runtime
 * @param {object} logger - Logger instance
 * @param {string} deviceId - Device identifier
 * @param {string} gameId - Game UUID
 * @param {string} username - Username to assign
 * @param {string} userId - Optional authenticated user ID from context
 * @returns {object} Identity object with wallet_id and global_wallet_id
 */
function getOrCreateIdentity(nk, logger, deviceId, gameId, username, userId) {
    var collection = "quizverse";
    var key = "identity:" + deviceId + ":" + gameId;
    
    // Use provided userId or fallback to system userId for device-based lookups
    var storageUserId = userId || "00000000-0000-0000-0000-000000000000";
    
    logger.info("[NAKAMA] Looking for identity: " + key + " (userId: " + storageUserId + ")");
    
    // Try to read existing identity - first try with actual userId, then fallback to system userId for backward compatibility
    try {
        var records = nk.storageRead([{
            collection: collection,
            key: key,
            userId: storageUserId
        }]);
        
        if (records && records.length > 0 && records[0].value) {
            logger.info("[NAKAMA] Found existing identity for device " + deviceId + " game " + gameId);
            return {
                exists: true,
                identity: records[0].value,
                userId: storageUserId
            };
        }
        
        // If not found with userId, try with system userId for backward compatibility
        if (userId && storageUserId !== "00000000-0000-0000-0000-000000000000") {
            records = nk.storageRead([{
                collection: collection,
                key: key,
                userId: "00000000-0000-0000-0000-000000000000"
            }]);
            
            if (records && records.length > 0 && records[0].value) {
                logger.info("[NAKAMA] Found existing identity with system userId, migrating to user-scoped storage");
                var existingIdentity = records[0].value;
                
                // Migrate to user-scoped storage
                nk.storageWrite([{
                    collection: collection,
                    key: key,
                    userId: userId,
                    value: existingIdentity,
                    permissionRead: 1,
                    permissionWrite: 0,
                    version: "*"
                }]);
                
                return {
                    exists: true,
                    identity: existingIdentity,
                    userId: userId,
                    migrated: true
                };
            }
        }
    } catch (err) {
        logger.warn("[NAKAMA] Failed to read identity: " + err.message);
    }
    
    // Create new identity
    logger.info("[NAKAMA] Creating new identity for device " + deviceId + " game " + gameId);
    
    // Generate wallet IDs
    var walletId = generateUUID();
    var globalWalletId = "global:" + deviceId;
    
    var identity = {
        username: username,
        device_id: deviceId,
        game_id: gameId,
        wallet_id: walletId,
        global_wallet_id: globalWalletId,
        user_id: userId || null,
        created_at: new Date().toISOString(),
        updated_at: new Date().toISOString()
    };
    
    // Write identity to storage with proper userId
    try {
        nk.storageWrite([{
            collection: collection,
            key: key,
            userId: storageUserId,
            value: identity,
            permissionRead: 1,
            permissionWrite: 0,
            version: "*"
        }]);
        
        logger.info("[NAKAMA] Created identity with wallet_id " + walletId + " for userId " + storageUserId);
    } catch (err) {
        logger.error("[NAKAMA] Failed to write identity: " + err.message);
        throw err;
    }
    
    return {
        exists: false,
        identity: identity,
        userId: storageUserId
    };
}

/**
 * Simple UUID v4 generator
 * @returns {string} UUID
 */
function generateUUID() {
    var d = new Date().getTime();
    var d2 = (typeof performance !== 'undefined' && performance.now && (performance.now() * 1000)) || 0;
    return 'xxxxxxxx-xxxx-4xxx-yxxx-xxxxxxxxxxxx'.replace(/[xy]/g, function(c) {
        var r = Math.random() * 16;
        if (d > 0) {
            r = (d + r) % 16 | 0;
            d = Math.floor(d / 16);
        } else {
            r = (d2 + r) % 16 | 0;
            d2 = Math.floor(d2 / 16);
        }
        return (c === 'x' ? r : (r & 0x3 | 0x8)).toString(16);
    });
}

/**
 * Update Nakama username for user
 * @param {object} nk - Nakama runtime
 * @param {object} logger - Logger instance
 * @param {string} userId - User ID
 * @param {string} username - New username
 */
function updateNakamaUsername(nk, logger, userId, username) {
    try {
        nk.accountUpdateId(userId, username, null, null, null, null, null);
        logger.info("[NAKAMA] Updated username to " + username + " for user " + userId);
    } catch (err) {
        logger.warn("[NAKAMA] Failed to update username: " + err.message);
    }
}


// --- Module: infrastructure\batch_operations.js ---
/**
 * Batch Operations for Multi-Game Platform
 * Execute multiple RPCs in a single call for improved performance
 */

/**
 * RPC: batch_execute
 * Execute multiple RPCs in one call
 */
var rpcBatchExecute = function(ctx, logger, nk, payload) {
    try {
        var data = JSON.parse(payload || '{}');
        
        if (!data.operations || !Array.isArray(data.operations)) {
            throw Error("operations array is required");
        }
        
        var operations = data.operations;
        var atomic = data.atomic || false; // All or nothing
        
        logger.info("[Batch] Executing " + operations.length + " operations, atomic: " + atomic);
        
        var results = [];
        var allSuccessful = true;
        
        for (var i = 0; i < operations.length; i++) {
            var op = operations[i];
            
            try {
                if (!op.rpc_id || !op.payload) {
                    throw Error("Each operation must have rpc_id and payload");
                }
                
                var result = nk.rpcHttp(ctx, op.rpc_id, JSON.stringify(op.payload));
                var parsedResult = JSON.parse(result);
                
                results.push({
                    success: true,
                    operation_index: i,
                    rpc_id: op.rpc_id,
                    data: parsedResult
                });
                
            } catch (err) {
                allSuccessful = false;
                
                results.push({
                    success: false,
                    operation_index: i,
                    rpc_id: op.rpc_id,
                    error: err.message
                });
                
                // If atomic, stop on first error
                if (atomic) {
                    logger.error("[Batch] Atomic batch failed at operation " + i);
                    break;
                }
            }
        }
        
        return JSON.stringify({
            success: !atomic || allSuccessful,
            atomic: atomic,
            total_operations: operations.length,
            successful_operations: results.filter(function(r) { return r.success; }).length,
            failed_operations: results.filter(function(r) { return !r.success; }).length,
            results: results
        });
        
    } catch (err) {
        logger.error("[Batch] Execute error: " + err.message);
        return JSON.stringify({
            success: false,
            error: err.message
        });
    }
};

/**
 * RPC: batch_wallet_operations
 * Optimized batch operations for wallet transactions
 */
var rpcBatchWalletOperations = function(ctx, logger, nk, payload) {
    try {
        var data = JSON.parse(payload || '{}');
        
        if (!data.game_id || !data.operations || !Array.isArray(data.operations)) {
            throw Error("game_id and operations array are required");
        }
        
        var userId = ctx.userId;
        var gameId = data.game_id;
        var operations = data.operations;
        
        logger.info("[Batch] Processing " + operations.length + " wallet operations");
        
        // Get wallet once
        var walletKey = "wallet_" + userId + "_" + gameId;
        var wallet = { balance: 0 };
        
        try {
            var walletRecords = nk.storageRead([{
                collection: gameId + "_wallets",
                key: walletKey,
                userId: userId
            }]);
            
            if (walletRecords && walletRecords.length > 0 && walletRecords[0].value) {
                wallet = walletRecords[0].value;
            }
        } catch (err) {
            logger.debug("[Batch] Creating new wallet");
        }
        
        var initialBalance = wallet.balance;
        var results = [];
        
        // Apply all operations
        for (var i = 0; i < operations.length; i++) {
            var op = operations[i];
            
            try {
                if (!op.operation || !op.amount) {
                    throw Error("Each operation must have operation and amount");
                }
                
                if (op.operation === "add") {
                    wallet.balance += op.amount;
                } else if (op.operation === "subtract") {
                    if (wallet.balance < op.amount) {
                        throw Error("Insufficient balance for operation " + i);
                    }
                    wallet.balance -= op.amount;
                } else {
                    throw Error("Invalid operation: " + op.operation);
                }
                
                results.push({
                    success: true,
                    operation_index: i,
                    operation: op.operation,
                    amount: op.amount,
                    balance_after: wallet.balance
                });
                
            } catch (err) {
                results.push({
                    success: false,
                    operation_index: i,
                    error: err.message
                });
                
                // Rollback
                wallet.balance = initialBalance;
                throw Error("Batch wallet operation failed at index " + i + ": " + err.message);
            }
        }
        
        // Save wallet
        wallet.updated_at = new Date().toISOString();
        
        nk.storageWrite([{
            collection: gameId + "_wallets",
            key: walletKey,
            userId: userId,
            value: wallet,
            permissionRead: 1,
            permissionWrite: 0
        }]);
        
        return JSON.stringify({
            success: true,
            initial_balance: initialBalance,
            final_balance: wallet.balance,
            operations_completed: results.length,
            results: results
        });
        
    } catch (err) {
        logger.error("[Batch] Wallet operations error: " + err.message);
        return JSON.stringify({
            success: false,
            error: err.message
        });
    }
};

/**
 * RPC: batch_achievement_progress
 * Update progress for multiple achievements in one call
 */
var rpcBatchAchievementProgress = function(ctx, logger, nk, payload) {
    try {
        var data = JSON.parse(payload || '{}');
        
        if (!data.game_id || !data.achievements || !Array.isArray(data.achievements)) {
            throw Error("game_id and achievements array are required");
        }
        
        var userId = ctx.userId;
        var gameId = data.game_id;
        var achievements = data.achievements;
        
        logger.info("[Batch] Updating " + achievements.length + " achievement progress");
        
        var results = [];
        var unlocked = [];
        
        for (var i = 0; i < achievements.length; i++) {
            var ach = achievements[i];
            
            try {
                // Call individual achievement update RPC
                var updatePayload = {
                    game_id: gameId,
                    achievement_id: ach.achievement_id,
                    progress: ach.progress,
                    increment: ach.increment || false
                };
                
                var result = nk.rpcHttp(ctx, "achievements_update_progress", JSON.stringify(updatePayload));
                var parsedResult = JSON.parse(result);
                
                results.push({
                    success: parsedResult.success,
                    achievement_id: ach.achievement_id,
                    data: parsedResult
                });
                
                if (parsedResult.achievement && parsedResult.achievement.just_unlocked) {
                    unlocked.push(ach.achievement_id);
                }
                
            } catch (err) {
                results.push({
                    success: false,
                    achievement_id: ach.achievement_id,
                    error: err.message
                });
            }
        }
        
        return JSON.stringify({
            success: true,
            total_updated: results.filter(function(r) { return r.success; }).length,
            total_unlocked: unlocked.length,
            unlocked_achievements: unlocked,
            results: results
        });
        
    } catch (err) {
        logger.error("[Batch] Achievement progress error: " + err.message);
        return JSON.stringify({
            success: false,
            error: err.message
        });
    }
};


// --- Module: infrastructure\caching.js ---
/**
 * Caching Layer for Multi-Game Platform
 * Improve performance for frequently accessed data
 */

// In-memory cache (use Redis in production)
var cache = {};

/**
 * Cache configuration
 */
var CacheConfig = {
    // TTL in seconds for different data types
    LEADERBOARD: 60,           // 1 minute
    PROFILE: 300,              // 5 minutes
    ACHIEVEMENT_DEFINITIONS: 600, // 10 minutes
    WALLET: 30,                // 30 seconds
    TOURNAMENT_LIST: 120,      // 2 minutes
    DAILY_REWARDS: 300         // 5 minutes
};

/**
 * Set cache value with TTL
 */
var cacheSet = function(key, value, ttlSeconds) {
    var now = Math.floor(Date.now() / 1000);
    
    cache[key] = {
        value: value,
        expires_at: now + ttlSeconds,
        created_at: now
    };
};

/**
 * Get cache value if not expired
 */
var cacheGet = function(key) {
    var now = Math.floor(Date.now() / 1000);
    
    if (!cache[key]) {
        return null;
    }
    
    var entry = cache[key];
    
    // Check if expired
    if (entry.expires_at < now) {
        delete cache[key];
        return null;
    }
    
    return entry.value;
};

/**
 * Delete cache entry
 */
var cacheDelete = function(key) {
    delete cache[key];
};

/**
 * Clear cache by pattern
 */
var cacheClearByPattern = function(pattern) {
    var regex = new RegExp(pattern);
    var keys = Object.keys(cache);
    
    for (var i = 0; i < keys.length; i++) {
        if (regex.test(keys[i])) {
            delete cache[keys[i]];
        }
    }
};

/**
 * Clear all expired entries (cleanup)
 */
var cacheCleanup = function() {
    var now = Math.floor(Date.now() / 1000);
    var keys = Object.keys(cache);
    var cleaned = 0;
    
    for (var i = 0; i < keys.length; i++) {
        if (cache[keys[i]].expires_at < now) {
            delete cache[keys[i]];
            cleaned++;
        }
    }
    
    return cleaned;
};

/**
 * Wrapper to add caching to any RPC
 */
var withCache = function(rpcFunction, rpcName, ttlSeconds, cacheKeyGenerator) {
    return function(ctx, logger, nk, payload) {
        // Generate cache key
        var cacheKey = cacheKeyGenerator(ctx, payload);
        
        // Check cache
        var cached = cacheGet(cacheKey);
        
        if (cached !== null) {
            logger.debug("[Cache] Hit for " + rpcName + ": " + cacheKey);
            return JSON.stringify({
                success: true,
                cached: true,
                data: cached
            });
        }
        
        logger.debug("[Cache] Miss for " + rpcName + ": " + cacheKey);
        
        // Call original function
        var response = rpcFunction(ctx, logger, nk, payload);
        var parsed = JSON.parse(response);
        
        // Cache successful responses
        if (parsed.success) {
            cacheSet(cacheKey, parsed, ttlSeconds);
        }
        
        return response;
    };
};

/**
 * Example cache key generators
 */
var CacheKeyGenerators = {
    // User-specific data
    userGameKey: function(ctx, payload) {
        var data = JSON.parse(payload || '{}');
        return ctx.userId + "_" + data.game_id;
    },
    
    // Leaderboard data
    leaderboardKey: function(ctx, payload) {
        var data = JSON.parse(payload || '{}');
        return "leaderboard_" + data.game_id + "_" + data.period;
    },
    
    // Achievement definitions (game-wide)
    achievementDefsKey: function(ctx, payload) {
        var data = JSON.parse(payload || '{}');
        return "achievements_" + data.game_id;
    },
    
    // Tournament list
    tournamentListKey: function(ctx, payload) {
        var data = JSON.parse(payload || '{}');
        return "tournaments_" + data.game_id;
    }
};

/**
 * RPC: cache_stats
 * Get cache statistics
 */
var rpcCacheStats = function(ctx, logger, nk, payload) {
    try {
        var now = Math.floor(Date.now() / 1000);
        var keys = Object.keys(cache);
        
        var totalEntries = keys.length;
        var expiredEntries = 0;
        var totalSize = 0;
        
        for (var i = 0; i < keys.length; i++) {
            var entry = cache[keys[i]];
            
            if (entry.expires_at < now) {
                expiredEntries++;
            }
            
            // Rough size estimate
            totalSize += JSON.stringify(entry.value).length;
        }
        
        return JSON.stringify({
            success: true,
            cache_stats: {
                total_entries: totalEntries,
                expired_entries: expiredEntries,
                active_entries: totalEntries - expiredEntries,
                estimated_size_bytes: totalSize
            }
        });
        
    } catch (err) {
        logger.error("[Cache] Stats error: " + err.message);
        return JSON.stringify({
            success: false,
            error: err.message
        });
    }
};

/**
 * RPC: cache_clear (Admin only)
 * Clear cache entries
 */
var rpcCacheClear = function(ctx, logger, nk, payload) {
    try {
        var data = JSON.parse(payload || '{}');
        var pattern = data.pattern;
        
        if (pattern) {
            cacheClearByPattern(pattern);
            logger.info("[Cache] Cleared entries matching pattern: " + pattern);
        } else {
            cache = {};
            logger.info("[Cache] Cleared all entries");
        }
        
        return JSON.stringify({
            success: true,
            message: pattern ? "Cleared entries matching pattern" : "Cleared all cache"
        });
        
    } catch (err) {
        logger.error("[Cache] Clear error: " + err.message);
        return JSON.stringify({
            success: false,
            error: err.message
        });
    }
};

