    var apiKeyName = sdResolve(ctx, "SATORI_API_KEY_NAME", SD_API_KEY_NAME);
    var signingKey = sdResolve(ctx, "SATORI_SIGNING_KEY", SD_SIGNING_KEY);
    var now = Math.floor(Date.now() / 1000);
