/**
 * Smart Review System — Production-Ready SM-2 Algorithm
 *
 * Tracks wrong answers from quizzes and creates flashcard review decks.
 * Uses the SM-2 (SuperMemo 2) algorithm for optimal spaced repetition:
 * - EaseFactor: How easy the card is (starts at 2.5)
 * - Interval: Days between reviews
 * - Repetitions: Consecutive correct reviews
 *
 * Storage: collection="smart_review", key="cards_{userId}_{gameId}"
 */

// ─── CONSTANTS ──────────────────────────────────────────────────────────────

var SR_STORAGE_COLLECTION = 'smart_review';
var SR_DEFAULT_EASE = 2.5;
var SR_MIN_EASE = 1.3;
var SR_MAX_CARDS_PER_SESSION = 20;
var SR_MAX_STORED_CARDS = 500;

// ─── SM-2 ALGORITHM ─────────────────────────────────────────────────────────

/**
 * SM-2 Algorithm Implementation
 * rating: 0=blackout, 1=wrong, 2=hard, 3=okay, 4=easy, 5=perfect
 */
function sm2Calculate(card, rating) {
    var easeFactor = card.easeFactor || SR_DEFAULT_EASE;
    var interval = card.interval || 1;
    var repetitions = card.repetitions || 0;

    if (rating < 3) {
        // Failed: reset repetitions, keep ease factor
        repetitions = 0;
        interval = 1;
    } else {
        // Passed: increase interval
        if (repetitions === 0) {
            interval = 1;
        } else if (repetitions === 1) {
            interval = 6;
        } else {
            interval = Math.round(interval * easeFactor);
        }
        repetitions += 1;
    }

    // Update ease factor
    easeFactor = easeFactor + (0.1 - (5 - rating) * (0.08 + (5 - rating) * 0.02));
    if (easeFactor < SR_MIN_EASE) easeFactor = SR_MIN_EASE;

    // Cap interval at 365 days
    if (interval > 365) interval = 365;

    return {
        interval: interval,
        easeFactor: Math.round(easeFactor * 100) / 100,
        repetitions: repetitions
    };
}

// ─── HELPERS ────────────────────────────────────────────────────────────────

function srStorageKey(userId, gameId) {
    return 'cards_' + userId + '_' + gameId;
}

function readSmartReviewData(nk, logger, userId, gameId) {
    try {
        var records = nk.storageRead([{
            collection: SR_STORAGE_COLLECTION,
            key: srStorageKey(userId, gameId),
            userId: userId
        }]);
        if (records && records.length > 0 && records[0].value) {
            return records[0].value;
        }
    } catch (err) {
        logger.warn('[SmartReview] Storage read failed: ' + err.message);
    }
    return null;
}

function writeSmartReviewData(nk, logger, userId, gameId, data) {
    try {
        nk.storageWrite([{
            collection: SR_STORAGE_COLLECTION,
            key: srStorageKey(userId, gameId),
            userId: userId,
            value: data,
            permissionRead: 1,
            permissionWrite: 0
        }]);
        return true;
    } catch (err) {
        logger.error('[SmartReview] Storage write failed: ' + err.message);
        return false;
    }
}

function initSmartReviewData() {
    var now = new Date().toISOString();
    return {
        cards: {},
        totalCardsAdded: 0,
        totalReviews: 0,
        totalCorrect: 0,
        lastReviewAt: null,
        createdAt: now,
        updatedAt: now
    };
}

function srErrorResponse(msg) {
    return JSON.stringify({ success: false, error: msg });
}

function srValidatePayload(payload) {
    if (!payload || payload === '') return {};
    try {
        return JSON.parse(payload);
    } catch (err) {
        return null;
    }
}

// ─── RPC: smart_review_get_cards ────────────────────────────────────────────

function rpcSmartReviewGetCards(ctx, logger, nk, payload) {
    if (!ctx.userId) return srErrorResponse('User not authenticated');

    var data = srValidatePayload(payload);
    if (data === null) return srErrorResponse('Invalid JSON payload');

    var gameId = data.gameId || 'quizverse';
    var limit = Math.min(parseInt(data.limit) || 5, SR_MAX_CARDS_PER_SESSION);
    var mode = data.mode || 'due';  // "due" = SM-2 scheduled, "recent_wrong" = latest misses

    var reviewData = readSmartReviewData(nk, logger, ctx.userId, gameId);
    if (!reviewData || !reviewData.cards || Object.keys(reviewData.cards).length === 0) {
        return JSON.stringify({
            success: true,
            cards: [],
            totalCards: 0,
            mode: mode,
            message: 'No review cards available. Complete a quiz to generate cards.',
            timestamp: new Date().toISOString()
        });
    }

    var now = new Date();
    var candidates = [];

    for (var qId in reviewData.cards) {
        var card = reviewData.cards[qId];

        if (mode === 'due') {
            // SM-2 mode: return cards that are due for review
            var nextReview = card.nextReviewAt ? new Date(card.nextReviewAt) : new Date(0);
            if (nextReview.getTime() <= now.getTime()) {
                candidates.push({
                    questionId: qId,
                    card: card,
                    overdueDays: Math.max(0, Math.floor((now.getTime() - nextReview.getTime()) / 86400000)),
                    sortKey: nextReview.getTime()
                });
            }
        } else if (mode === 'recent_wrong') {
            // Recent wrong mode: return latest wrong answers regardless of SM-2 schedule
            candidates.push({
                questionId: qId,
                card: card,
                overdueDays: 0,
                sortKey: card.lastAttemptAt ? new Date(card.lastAttemptAt).getTime() : 0
            });
        }
    }

    // Sort: due mode → oldest first, recent_wrong → newest first
    if (mode === 'due') {
        candidates.sort(function(a, b) { return a.sortKey - b.sortKey; });
    } else {
        candidates.sort(function(a, b) { return b.sortKey - a.sortKey; });
    }

    // Take top N
    var selectedCards = candidates.slice(0, limit);
    var resultCards = [];

    for (var i = 0; i < selectedCards.length; i++) {
        var c = selectedCards[i].card;
        resultCards.push({
            questionId: selectedCards[i].questionId,
            question: c.question || '',
            correctAnswer: c.correctAnswer || '',
            userAnswer: c.userAnswer || '',
            category: c.category || '',
            topic: c.topic || '',
            attempts: c.attempts || 1,
            lastAttemptAt: c.lastAttemptAt || null,
            overdueDays: selectedCards[i].overdueDays,
            sm2: {
                interval: c.interval || 1,
                easeFactor: c.easeFactor || SR_DEFAULT_EASE,
                repetitions: c.repetitions || 0
            }
        });
    }

    return JSON.stringify({
        success: true,
        cards: resultCards,
        totalCards: Object.keys(reviewData.cards).length,
        totalDue: mode === 'due' ? candidates.length : undefined,
        mode: mode,
        reviewStats: {
            totalReviews: reviewData.totalReviews || 0,
            totalCorrect: reviewData.totalCorrect || 0,
            accuracy: reviewData.totalReviews > 0 ?
                Math.round((reviewData.totalCorrect / reviewData.totalReviews) * 100) : 0,
            lastReviewAt: reviewData.lastReviewAt
        },
        timestamp: now.toISOString()
    });
}

// ─── RPC: smart_review_rate_card ────────────────────────────────────────────

function rpcSmartReviewRateCard(ctx, logger, nk, payload) {
    if (!ctx.userId) return srErrorResponse('User not authenticated');

    var data = srValidatePayload(payload);
    if (data === null) return srErrorResponse('Invalid JSON payload');

    var gameId = data.gameId || 'quizverse';
    var questionId = data.questionId;
    var rating = parseInt(data.rating);

    if (!questionId) return srErrorResponse('Missing required field: questionId');
    if (isNaN(rating) || rating < 0 || rating > 5) {
        return srErrorResponse('Invalid rating. Must be 0-5.');
    }

    var reviewData = readSmartReviewData(nk, logger, ctx.userId, gameId);
    if (!reviewData) {
        return srErrorResponse('No review data found');
    }

    var card = reviewData.cards[questionId];
    if (!card) {
        return srErrorResponse('Card not found: ' + questionId);
    }

    // Apply SM-2 algorithm
    var sm2Result = sm2Calculate(card, rating);

    // Update card
    card.interval = sm2Result.interval;
    card.easeFactor = sm2Result.easeFactor;
    card.repetitions = sm2Result.repetitions;
    card.lastReviewedAt = new Date().toISOString();

    // Calculate next review date
    var nextReview = new Date();
    nextReview.setDate(nextReview.getDate() + sm2Result.interval);
    card.nextReviewAt = nextReview.toISOString();

    card.reviewCount = (card.reviewCount || 0) + 1;

    // Update stats
    reviewData.totalReviews = (reviewData.totalReviews || 0) + 1;
    if (rating >= 3) reviewData.totalCorrect = (reviewData.totalCorrect || 0) + 1;
    reviewData.lastReviewAt = new Date().toISOString();
    reviewData.updatedAt = new Date().toISOString();

    // If card has been answered correctly 5+ times in a row with high ease, consider mastered
    var isMastered = card.repetitions >= 5 && card.easeFactor >= 2.5;

    if (!writeSmartReviewData(nk, logger, ctx.userId, gameId, reviewData)) {
        return srErrorResponse('Failed to save review data');
    }

    logger.info('[SmartReview] Card ' + questionId + ' rated ' + rating +
                ' → interval=' + sm2Result.interval + 'd, ease=' + sm2Result.easeFactor);

    return JSON.stringify({
        success: true,
        questionId: questionId,
        rating: rating,
        newInterval: sm2Result.interval,
        newEaseFactor: sm2Result.easeFactor,
        newRepetitions: sm2Result.repetitions,
        nextReviewAt: card.nextReviewAt,
        isMastered: isMastered,
        reviewCount: card.reviewCount,
        reviewStats: {
            totalReviews: reviewData.totalReviews,
            totalCorrect: reviewData.totalCorrect,
            accuracy: reviewData.totalReviews > 0 ?
                Math.round((reviewData.totalCorrect / reviewData.totalReviews) * 100) : 0
        },
        timestamp: new Date().toISOString()
    });
}

// ─── RPC: smart_review_add_card ─────────────────────────────────────────────
//
// Schema: {
//   gameId?, questionId, question, correctAnswer, userAnswer?,
//   distractors?: string[], category?, topic?, subtopic?, sourceQuizId?
// }
// Idempotent on questionId — re-adding an existing card is a no-op (returns
// existing SM-2 state). When the deck would exceed SR_MAX_STORED_CARDS we LRU-
// evict the lowest-priority cards (mastered first → oldest lastReviewedAt next).

function rpcSmartReviewAddCard(ctx, logger, nk, payload) {
    if (!ctx.userId) return srErrorResponse('User not authenticated');

    var data = srValidatePayload(payload);
    if (data === null) return srErrorResponse('Invalid JSON payload');

    var gameId = data.gameId || 'quizverse';
    var questionId = data.questionId;
    if (!questionId || typeof questionId !== 'string') {
        return srErrorResponse('Missing required field: questionId');
    }
    if (!data.question || !data.correctAnswer) {
        return srErrorResponse('Missing required fields: question, correctAnswer');
    }

    var reviewData = readSmartReviewData(nk, logger, ctx.userId, gameId) || initSmartReviewData();
    if (!reviewData.cards) reviewData.cards = {};

    var nowIso = new Date().toISOString();

    // Idempotent re-add: if the card already exists, just refresh metadata
    // (question text / distractors may have been corrected).
    if (reviewData.cards[questionId]) {
        var existing = reviewData.cards[questionId];
        existing.question      = data.question;
        existing.correctAnswer = data.correctAnswer;
        if (data.userAnswer)   existing.userAnswer  = data.userAnswer;
        if (data.distractors)  existing.distractors = data.distractors;
        if (data.category)     existing.category    = data.category;
        if (data.topic)        existing.topic       = data.topic;
        if (data.subtopic)     existing.subtopic    = data.subtopic;
        existing.attempts      = (existing.attempts || 1) + 1;
        existing.lastAttemptAt = nowIso;
        reviewData.updatedAt   = nowIso;
        writeSmartReviewData(nk, logger, ctx.userId, gameId, reviewData);
        return JSON.stringify({
            success: true,
            questionId: questionId,
            alreadyExisted: true,
            attempts: existing.attempts,
            totalCards: Object.keys(reviewData.cards).length,
            timestamp: nowIso
        });
    }

    // ── LRU eviction when at cap ──────────────────────────────────────────
    var cardIds = Object.keys(reviewData.cards);
    if (cardIds.length >= SR_MAX_STORED_CARDS) {
        var entries = [];
        for (var ei = 0; ei < cardIds.length; ei++) {
            var id = cardIds[ei];
            var c = reviewData.cards[id];
            // Mastered cards (rep>=5, ease>=2.5) get lowest priority; then
            // ascending lastReviewedAt (oldest first).
            var mastered = (c.repetitions >= 5 && c.easeFactor >= 2.5) ? 1 : 0;
            var ts = c.lastReviewedAt ? new Date(c.lastReviewedAt).getTime() : 0;
            entries.push({ id: id, mastered: mastered, ts: ts });
        }
        entries.sort(function(a, b) {
            if (b.mastered !== a.mastered) return b.mastered - a.mastered; // mastered first
            return a.ts - b.ts; // oldest first
        });
        // Evict enough to make room for one new card
        var toEvict = (cardIds.length - SR_MAX_STORED_CARDS) + 1;
        for (var ev = 0; ev < toEvict; ev++) {
            delete reviewData.cards[entries[ev].id];
        }
    }

    // ── Create card with SM-2 defaults ─────────────────────────────────────
    reviewData.cards[questionId] = {
        question:       data.question,
        correctAnswer:  data.correctAnswer,
        userAnswer:     data.userAnswer || '',
        distractors:    data.distractors || [],
        category:       data.category || '',
        topic:          data.topic || '',
        subtopic:       data.subtopic || '',
        sourceQuizId:   data.sourceQuizId || '',
        attempts:       1,
        easeFactor:     SR_DEFAULT_EASE,
        interval:       1,
        repetitions:    0,
        reviewCount:    0,
        lastAttemptAt:  nowIso,
        lastReviewedAt: null,
        nextReviewAt:   nowIso, // immediately due
        addedAt:        nowIso
    };

    reviewData.totalCardsAdded = (reviewData.totalCardsAdded || 0) + 1;
    reviewData.updatedAt = nowIso;
    if (!writeSmartReviewData(nk, logger, ctx.userId, gameId, reviewData)) {
        return srErrorResponse('Failed to save review data');
    }

    return JSON.stringify({
        success: true,
        questionId: questionId,
        alreadyExisted: false,
        totalCards: Object.keys(reviewData.cards).length,
        totalCardsAdded: reviewData.totalCardsAdded,
        timestamp: nowIso
    });
}

// ─── RPC: smart_review_bulk_rate ────────────────────────────────────────────
//
// Schema: { gameId?, ratings: [{ questionId, rating (0..5), reviewedAt? }] }
// Atomic: all SM-2 updates are applied in one storage write. Skips any
// rating that targets an unknown card and reports it back in `skipped`.

function rpcSmartReviewBulkRate(ctx, logger, nk, payload) {
    if (!ctx.userId) return srErrorResponse('User not authenticated');

    var data = srValidatePayload(payload);
    if (data === null) return srErrorResponse('Invalid JSON payload');

    var gameId = data.gameId || 'quizverse';
    var ratings = data.ratings;
    if (!ratings || !Array.isArray(ratings) || ratings.length === 0) {
        return srErrorResponse('ratings must be a non-empty array');
    }
    if (ratings.length > 100) {
        return srErrorResponse('Cannot rate more than 100 cards per call');
    }

    var reviewData = readSmartReviewData(nk, logger, ctx.userId, gameId);
    if (!reviewData || !reviewData.cards) {
        return srErrorResponse('No review data found');
    }

    var nowIso = new Date().toISOString();
    var applied = [];
    var skipped = [];

    for (var i = 0; i < ratings.length; i++) {
        var r = ratings[i];
        var qId = r.questionId;
        var rating = parseInt(r.rating);
        if (!qId || isNaN(rating) || rating < 0 || rating > 5) {
            skipped.push({ questionId: qId || null, reason: 'invalid_rating' });
            continue;
        }
        var card = reviewData.cards[qId];
        if (!card) {
            skipped.push({ questionId: qId, reason: 'card_not_found' });
            continue;
        }

        var sm2Result = sm2Calculate(card, rating);
        card.interval       = sm2Result.interval;
        card.easeFactor     = sm2Result.easeFactor;
        card.repetitions    = sm2Result.repetitions;
        card.lastReviewedAt = r.reviewedAt || nowIso;
        var nextReview = new Date();
        nextReview.setDate(nextReview.getDate() + sm2Result.interval);
        card.nextReviewAt = nextReview.toISOString();
        card.reviewCount  = (card.reviewCount || 0) + 1;

        reviewData.totalReviews = (reviewData.totalReviews || 0) + 1;
        if (rating >= 3) reviewData.totalCorrect = (reviewData.totalCorrect || 0) + 1;

        applied.push({
            questionId:    qId,
            rating:        rating,
            newInterval:   sm2Result.interval,
            newEaseFactor: sm2Result.easeFactor,
            nextReviewAt:  card.nextReviewAt
        });
    }

    reviewData.lastReviewAt = nowIso;
    reviewData.updatedAt    = nowIso;

    if (!writeSmartReviewData(nk, logger, ctx.userId, gameId, reviewData)) {
        return srErrorResponse('Failed to save review data');
    }

    return JSON.stringify({
        success: true,
        appliedCount: applied.length,
        skippedCount: skipped.length,
        applied:      applied,
        skipped:      skipped,
        reviewStats: {
            totalReviews: reviewData.totalReviews,
            totalCorrect: reviewData.totalCorrect,
            accuracy: reviewData.totalReviews > 0 ?
                Math.round((reviewData.totalCorrect / reviewData.totalReviews) * 100) : 0
        },
        timestamp: nowIso
    });
}

// ─── RPC: smart_review_get_state ────────────────────────────────────────────
//
// Returns the entire deck snapshot (for client hydration / cross-device sync).
// `get_cards` only returns the due-or-recent slice. This is the heavyweight
// read — clients should call sparingly (cache locally + invalidate by version).

function rpcSmartReviewGetState(ctx, logger, nk, payload) {
    if (!ctx.userId) return srErrorResponse('User not authenticated');

    var data = srValidatePayload(payload);
    if (data === null) return srErrorResponse('Invalid JSON payload');

    var gameId = data.gameId || 'quizverse';
    var reviewData = readSmartReviewData(nk, logger, ctx.userId, gameId);
    if (!reviewData || !reviewData.cards) {
        return JSON.stringify({
            success: true,
            cards: [],
            totalCards: 0,
            totalDue: 0,
            totalMastered: 0,
            stats: { totalReviews: 0, totalCorrect: 0, accuracy: 0 },
            timestamp: new Date().toISOString()
        });
    }

    var nowMs = Date.now();
    var allCards = [];
    var due = 0, mastered = 0;
    for (var qId in reviewData.cards) {
        if (!Object.prototype.hasOwnProperty.call(reviewData.cards, qId)) continue;
        var c = reviewData.cards[qId];
        var nextMs = c.nextReviewAt ? new Date(c.nextReviewAt).getTime() : 0;
        var isDue = nextMs <= nowMs;
        var isMastered = (c.repetitions || 0) >= 5 && (c.easeFactor || 0) >= 2.5;
        if (isDue) due++;
        if (isMastered) mastered++;
        allCards.push({
            questionId:     qId,
            question:       c.question || '',
            correctAnswer:  c.correctAnswer || '',
            userAnswer:     c.userAnswer || '',
            distractors:    c.distractors || [],
            category:       c.category || '',
            topic:          c.topic || '',
            subtopic:       c.subtopic || '',
            attempts:       c.attempts || 1,
            reviewCount:    c.reviewCount || 0,
            lastAttemptAt:  c.lastAttemptAt || null,
            lastReviewedAt: c.lastReviewedAt || null,
            nextReviewAt:   c.nextReviewAt || null,
            addedAt:        c.addedAt || null,
            isDue:          isDue,
            isMastered:     isMastered,
            sm2: {
                interval:    c.interval || 1,
                easeFactor:  c.easeFactor || SR_DEFAULT_EASE,
                repetitions: c.repetitions || 0
            }
        });
    }

    return JSON.stringify({
        success: true,
        cards: allCards,
        totalCards:    allCards.length,
        totalDue:      due,
        totalMastered: mastered,
        totalCardsAdded: reviewData.totalCardsAdded || allCards.length,
        stats: {
            totalReviews: reviewData.totalReviews || 0,
            totalCorrect: reviewData.totalCorrect || 0,
            accuracy: reviewData.totalReviews > 0 ?
                Math.round((reviewData.totalCorrect / reviewData.totalReviews) * 100) : 0,
            lastReviewAt: reviewData.lastReviewAt || null
        },
        version: reviewData.updatedAt || reviewData.createdAt || null,
        timestamp: new Date().toISOString()
    });
}

// ─── RPC: smart_review_get_weakness_map ─────────────────────────────────────
//
// Aggregates SM-2 stats by category/topic so the client can render a heatmap
// of "where the player is weakest". Higher attemptsPerCard / lower easeFactor
// → weaker. Returns a list sorted by weakness descending.

function rpcSmartReviewGetWeaknessMap(ctx, logger, nk, payload) {
    if (!ctx.userId) return srErrorResponse('User not authenticated');

    var data = srValidatePayload(payload);
    if (data === null) return srErrorResponse('Invalid JSON payload');

    var gameId = data.gameId || 'quizverse';
    var reviewData = readSmartReviewData(nk, logger, ctx.userId, gameId);
    if (!reviewData || !reviewData.cards) {
        return JSON.stringify({
            success: true,
            weakness: [],
            timestamp: new Date().toISOString()
        });
    }

    var byCategory = {};
    var byTopic = {};
    for (var qId in reviewData.cards) {
        if (!Object.prototype.hasOwnProperty.call(reviewData.cards, qId)) continue;
        var c = reviewData.cards[qId];
        var cat = c.category || 'Uncategorized';
        var top = c.topic || 'General';

        if (!byCategory[cat]) byCategory[cat] = { cardCount: 0, totalAttempts: 0, totalEase: 0, totalReps: 0, mastered: 0 };
        byCategory[cat].cardCount++;
        byCategory[cat].totalAttempts += (c.attempts || 1);
        byCategory[cat].totalEase     += (c.easeFactor || SR_DEFAULT_EASE);
        byCategory[cat].totalReps     += (c.repetitions || 0);
        if ((c.repetitions || 0) >= 5 && (c.easeFactor || 0) >= 2.5) byCategory[cat].mastered++;

        var topKey = cat + '::' + top;
        if (!byTopic[topKey]) byTopic[topKey] = { category: cat, topic: top, cardCount: 0, totalAttempts: 0, totalEase: 0, mastered: 0 };
        byTopic[topKey].cardCount++;
        byTopic[topKey].totalAttempts += (c.attempts || 1);
        byTopic[topKey].totalEase     += (c.easeFactor || SR_DEFAULT_EASE);
        if ((c.repetitions || 0) >= 5 && (c.easeFactor || 0) >= 2.5) byTopic[topKey].mastered++;
    }

    var categories = [];
    for (var cKey in byCategory) {
        if (!Object.prototype.hasOwnProperty.call(byCategory, cKey)) continue;
        var cv = byCategory[cKey];
        var avgEase = cv.cardCount > 0 ? (cv.totalEase / cv.cardCount) : SR_DEFAULT_EASE;
        var attemptsPerCard = cv.cardCount > 0 ? (cv.totalAttempts / cv.cardCount) : 0;
        // Weakness: 0..1 — higher = weaker. (3.0 - easeFactor) / 1.7 normalizes to roughly [0,1]
        var weakness = Math.max(0, Math.min(1, (3.0 - avgEase) / 1.7));
        categories.push({
            category:        cKey,
            cardCount:       cv.cardCount,
            mastered:        cv.mastered,
            attemptsPerCard: Math.round(attemptsPerCard * 100) / 100,
            avgEaseFactor:   Math.round(avgEase * 100) / 100,
            weaknessScore:   Math.round(weakness * 100) / 100
        });
    }
    categories.sort(function(a, b) { return b.weaknessScore - a.weaknessScore; });

    var topics = [];
    for (var tKey in byTopic) {
        if (!Object.prototype.hasOwnProperty.call(byTopic, tKey)) continue;
        var tv = byTopic[tKey];
        var avgEase2 = tv.cardCount > 0 ? (tv.totalEase / tv.cardCount) : SR_DEFAULT_EASE;
        var attemptsPerCard2 = tv.cardCount > 0 ? (tv.totalAttempts / tv.cardCount) : 0;
        var weakness2 = Math.max(0, Math.min(1, (3.0 - avgEase2) / 1.7));
        topics.push({
            category:        tv.category,
            topic:           tv.topic,
            cardCount:       tv.cardCount,
            mastered:        tv.mastered,
            attemptsPerCard: Math.round(attemptsPerCard2 * 100) / 100,
            avgEaseFactor:   Math.round(avgEase2 * 100) / 100,
            weaknessScore:   Math.round(weakness2 * 100) / 100
        });
    }
    topics.sort(function(a, b) { return b.weaknessScore - a.weaknessScore; });

    return JSON.stringify({
        success: true,
        categories: categories,
        topics:     topics,
        timestamp:  new Date().toISOString()
    });
}

// ─── RPC: smart_review_get_forecast ─────────────────────────────────────────
//
// Returns "cards due per day" for the next N days (default 7, max 30) so the
// client can render a workload calendar / "you'll review X cards tomorrow"
// preview. Counts cards by their nextReviewAt bucket.

function rpcSmartReviewGetForecast(ctx, logger, nk, payload) {
    if (!ctx.userId) return srErrorResponse('User not authenticated');

    var data = srValidatePayload(payload);
    if (data === null) return srErrorResponse('Invalid JSON payload');

    var gameId = data.gameId || 'quizverse';
    var days = parseInt(data.days) || 7;
    if (days < 1)  days = 1;
    if (days > 30) days = 30;

    var reviewData = readSmartReviewData(nk, logger, ctx.userId, gameId);
    if (!reviewData || !reviewData.cards) {
        var emptyForecast = [];
        var startMidnight = new Date(); startMidnight.setHours(0,0,0,0);
        for (var ed = 0; ed < days; ed++) {
            var ed2 = new Date(startMidnight.getTime() + ed * 86400000);
            emptyForecast.push({ date: ed2.toISOString().slice(0,10), cardsDue: 0 });
        }
        return JSON.stringify({
            success: true,
            forecast: emptyForecast,
            totalCards: 0,
            overdueCount: 0,
            timestamp: new Date().toISOString()
        });
    }

    var now = new Date();
    var todayMidnight = new Date(now); todayMidnight.setHours(0,0,0,0);
    var horizonMs = todayMidnight.getTime() + days * 86400000;

    var buckets = {};
    for (var d = 0; d < days; d++) {
        var dDate = new Date(todayMidnight.getTime() + d * 86400000);
        buckets[dDate.toISOString().slice(0,10)] = 0;
    }

    var overdueCount = 0;
    var totalCards = 0;
    for (var qId in reviewData.cards) {
        if (!Object.prototype.hasOwnProperty.call(reviewData.cards, qId)) continue;
        totalCards++;
        var c = reviewData.cards[qId];
        var nextMs = c.nextReviewAt ? new Date(c.nextReviewAt).getTime() : 0;

        if (nextMs <= now.getTime()) {
            overdueCount++;
            // Overdue cards are counted in today's bucket
            var todayKey = todayMidnight.toISOString().slice(0,10);
            buckets[todayKey] = (buckets[todayKey] || 0) + 1;
        } else if (nextMs < horizonMs) {
            var b = new Date(nextMs); b.setHours(0,0,0,0);
            var bk = b.toISOString().slice(0,10);
            if (Object.prototype.hasOwnProperty.call(buckets, bk)) {
                buckets[bk]++;
            }
        }
    }

    var forecast = [];
    for (var d2 = 0; d2 < days; d2++) {
        var dd = new Date(todayMidnight.getTime() + d2 * 86400000);
        var key = dd.toISOString().slice(0,10);
        forecast.push({ date: key, cardsDue: buckets[key] || 0 });
    }

    return JSON.stringify({
        success: true,
        forecast: forecast,
        totalCards: totalCards,
        overdueCount: overdueCount,
        days: days,
        timestamp: new Date().toISOString()
    });
}

// ============================================================================
// Module Init — register Smart Review RPCs
// ============================================================================
// postbuild.js renames `InitModule` to `__ModuleInit_N` and rewrites every
// `__rpc_id = __rpc_id || (handler)` into a guarded
// `__rpc_id = __rpc_id || handler` assignment that gets replayed at global
// scope on every Goja VM. Because the modules section is concatenated BEFORE
// legacy_runtime.js, the module-level handler wins — even if legacy still
// has its own registration for `smart_review_get_cards` /
// `smart_review_rate_card`, our handler is what actually fires.
function __ModuleInit_81(ctx, logger, nk, initializer) {
    __rpc_smart_review_get_cards = __rpc_smart_review_get_cards || (rpcSmartReviewGetCards);
    __rpc_smart_review_rate_card = __rpc_smart_review_rate_card || (rpcSmartReviewRateCard);
    __rpc_smart_review_add_card = __rpc_smart_review_add_card || (rpcSmartReviewAddCard);
    __rpc_smart_review_bulk_rate = __rpc_smart_review_bulk_rate || (rpcSmartReviewBulkRate);
    __rpc_smart_review_get_state = __rpc_smart_review_get_state || (rpcSmartReviewGetState);
    __rpc_smart_review_get_weakness_map = __rpc_smart_review_get_weakness_map || (rpcSmartReviewGetWeaknessMap);
    __rpc_smart_review_get_forecast = __rpc_smart_review_get_forecast || (rpcSmartReviewGetForecast);
    if (logger && logger.info) {
        logger.info('[SmartReview] Registered 7 RPCs (get_cards, rate_card, add_card, bulk_rate, get_state, get_weakness_map, get_forecast)');
    }
}


// --- Module: social_v2\social_v2.js ---
// social_v2.js - Social features: challenges, rivalries, teams, duos, group quests
// Compatible with Nakama JavaScript runtime (no ES modules)

var SYSTEM_USER_ID = "00000000-0000-0000-0000-000000000000";

// Notification codes (arbitrary ints, must be > 0)
var NOTIFY_CHALLENGE_ACCEPTED = 100;
var NOTIFY_CHALLENGE_DECLINED = 101;
var NOTIFY_CHALLENGE_RECEIVED = 102;
var NOTIFY_DUO_INVITE = 110;

// ---------------------------------------------------------------------------
// Helpers
// ---------------------------------------------------------------------------

function generateUUID() {
    var d = new Date().getTime();
    var d2 = (typeof performance !== 'undefined' && performance.now && (performance.now() * 1000)) || 0;
    return 'xxxxxxxx-xxxx-4xxx-yxxx-xxxxxxxxxxxx'.replace(/[xy]/g, function (c) {
        var r = Math.random() * 16;
        if (d > 0) {
            r = (d + r) % 16 | 0;
            d = Math.floor(d / 16);
        } else {
            r = (d2 + r) % 16 | 0;
            d2 = Math.floor(d2 / 16);
        }
        return (c === 'x' ? r : (r & 0x3 | 0x8)).toString(16);
    });
}

function nowISO() {
    return new Date().toISOString();
}

function safeRead(nk, collection, key, userId) {
    try {
        var recs = nk.storageRead([{ collection: collection, key: key, userId: userId }]);
        if (recs && recs.length > 0) return recs[0].value;
    } catch (_) { /* swallow */ }
    return null;
}

function safeWrite(nk, collection, key, userId, value) {
    nk.storageWrite([{
        collection: collection,
        key: key,
        userId: userId,
        value: value,
        permissionRead: 1,
        permissionWrite: 0
    }]);
}

function generateJoinCode() {
    // 6-digit numeric (100000–999999) — unified room-code format across QuizVerse
    // so the 6-box numeric input field on the join-code page accepts every char.
    return String(100000 + Math.floor(Math.random() * 900000));
}

// Local wrapper around the global resolveGameIdAlias helper exposed by
// analytics.js (via postbuild bundling). Falls back to identity if the helper
// has not been bundled yet so this module remains loadable in isolation.
function svResolveGameId(gameId) {
    if (!gameId) return gameId;
    try {
        if (typeof resolveGameIdAlias === 'function') {
            return resolveGameIdAlias(gameId);
        }
    } catch (e) { /* helper not bundled — keep raw value */ }
    return gameId;
}

// ---------------------------------------------------------------------------
// 1. rpcChallengeAccept
// ---------------------------------------------------------------------------

function rpcChallengeAccept(ctx, logger, nk, payload) {
    logger.info("[social_v2] rpcChallengeAccept called");
    try {
        var data = JSON.parse(payload || '{}');
        if (!data.challenge_id) {
            return JSON.stringify({ success: false, error: "challenge_id is required" });
        }

        var userId = ctx.userId || SYSTEM_USER_ID;
        var challenge = safeRead(nk, "challenges", data.challenge_id, SYSTEM_USER_ID);
        if (!challenge) {
            return JSON.stringify({ success: false, error: "Challenge not found" });
        }
        if (challenge.status !== "pending") {
            return JSON.stringify({ success: false, error: "Challenge is not pending" });
        }

        challenge.status = "accepted";
        challenge.accepted_by = userId;
        challenge.accepted_at = nowISO();
        safeWrite(nk, "challenges", data.challenge_id, SYSTEM_USER_ID, challenge);

        try {
            nk.notificationSend(
                challenge.challenger_id,
                "Challenge accepted",
                NOTIFY_CHALLENGE_ACCEPTED,
                { challenge_id: data.challenge_id, accepted_by: userId },
                userId
            );
        } catch (e) {
            logger.warn("[social_v2] notification send failed: " + e.message);
        }

        return JSON.stringify({ success: true, challenge: challenge });
    } catch (err) {
        logger.error("[social_v2] rpcChallengeAccept error: " + err.message);
        return JSON.stringify({ success: false, error: err.message });
    }
}

// ---------------------------------------------------------------------------
// 2. rpcChallengeDecline
// ---------------------------------------------------------------------------

function rpcChallengeDecline(ctx, logger, nk, payload) {
    logger.info("[social_v2] rpcChallengeDecline called");
    try {
        var data = JSON.parse(payload || '{}');
        if (!data.challenge_id) {
            return JSON.stringify({ success: false, error: "challenge_id is required" });
        }

        var userId = ctx.userId || SYSTEM_USER_ID;
        var challenge = safeRead(nk, "challenges", data.challenge_id, SYSTEM_USER_ID);
        if (!challenge) {
            return JSON.stringify({ success: false, error: "Challenge not found" });
        }

        challenge.status = "declined";
        challenge.declined_by = userId;
        challenge.declined_at = nowISO();
        safeWrite(nk, "challenges", data.challenge_id, SYSTEM_USER_ID, challenge);

        try {
            nk.notificationSend(
                challenge.challenger_id,
                "Challenge declined",
                NOTIFY_CHALLENGE_DECLINED,
                { challenge_id: data.challenge_id, declined_by: userId },
                userId
            );
        } catch (e) {
            logger.warn("[social_v2] notification send failed: " + e.message);
        }

        return JSON.stringify({ success: true, challenge: challenge });
    } catch (err) {
        logger.error("[social_v2] rpcChallengeDecline error: " + err.message);
        return JSON.stringify({ success: false, error: err.message });
    }
}

// ---------------------------------------------------------------------------
// 3. rpcChallengeList
// ---------------------------------------------------------------------------

function rpcChallengeList(ctx, logger, nk, payload) {
    logger.info("[social_v2] rpcChallengeList called");
    try {
        var data = JSON.parse(payload || '{}');
        var userId = ctx.userId || SYSTEM_USER_ID;
        var gameId = svResolveGameId(data.game_id) || "";
        var statusFilter = data.status || "";

        var records = [];
        try {
            var result = nk.storageList(userId, "challenges_v2", 100, "");
            if (result && result.length) {
                records = result;
            } else if (result && result.objects) {
                records = result.objects;
            }
        } catch (e) {
            logger.warn("[social_v2] storageList failed: " + e.message);
        }

        var filtered = [];
        for (var i = 0; i < records.length; i++) {
            var val = records[i].value || records[i];
            if (gameId && val.game_id && val.game_id !== gameId) continue;
            if (statusFilter && val.status && val.status !== statusFilter) continue;
            filtered.push(val);
        }

        return JSON.stringify({ success: true, challenges: filtered, count: filtered.length });
    } catch (err) {
        logger.error("[social_v2] rpcChallengeList error: " + err.message);
        return JSON.stringify({ success: false, error: err.message });
    }
}

// ---------------------------------------------------------------------------
// 4. rpcGetRivalry
// ---------------------------------------------------------------------------

function rpcGetRivalry(ctx, logger, nk, payload) {
    logger.info("[social_v2] rpcGetRivalry called");
    try {
        var data = JSON.parse(payload || '{}');
        if (!data.target_user_id) {
            return JSON.stringify({ success: false, error: "target_user_id is required" });
        }

        var userId = ctx.userId || SYSTEM_USER_ID;
        var gameId = svResolveGameId(data.game_id) || "";
        var pairKey = [userId, data.target_user_id].sort().join(":");
        var key = "rivalry:" + gameId + ":" + pairKey;

        var rivalry = safeRead(nk, "rivalries", key, SYSTEM_USER_ID);
        if (!rivalry) {
            return JSON.stringify({
                success: true,
                rivalry: { wins: 0, losses: 0, draws: 0, last_match: null, streak: 0 },
                exists: false
            });
        }

        var perspective = {
            wins: (rivalry.player_a === userId) ? rivalry.a_wins : rivalry.b_wins,
            losses: (rivalry.player_a === userId) ? rivalry.b_wins : rivalry.a_wins,
            draws: rivalry.draws || 0,
            last_match: rivalry.last_match || null,
            streak: rivalry.streak || 0
        };

        return JSON.stringify({ success: true, rivalry: perspective, exists: true });
    } catch (err) {
        logger.error("[social_v2] rpcGetRivalry error: " + err.message);
        return JSON.stringify({ success: false, error: err.message });
    }
}

// ---------------------------------------------------------------------------
// 5. rpcFriendScoreAlert
// ---------------------------------------------------------------------------

function rpcFriendScoreAlert(ctx, logger, nk, payload) {
    logger.info("[social_v2] rpcFriendScoreAlert called");
    try {
        var data = JSON.parse(payload || '{}');
        var userId = ctx.userId || SYSTEM_USER_ID;
        var gameId = svResolveGameId(data.game_id) || "";

        var friends = [];
        try {
            var friendsResult = nk.friendsList(userId, 100, 0, "");
            if (friendsResult && friendsResult.friends) {
                friends = friendsResult.friends;
            } else if (friendsResult && friendsResult.length) {
                friends = friendsResult;
            }
        } catch (e) {
            logger.warn("[social_v2] friendsList failed: " + e.message);
            return JSON.stringify({ success: true, alerts: [], message: "Could not retrieve friends" });
        }

        var leaderboardId = "leaderboard_" + gameId;
        var userRecord = null;
        try {
            var ownerRecords = nk.leaderboardRecordsList(leaderboardId, [userId], 1, "", 0);
            if (ownerRecords && ownerRecords.ownerRecords && ownerRecords.ownerRecords.length > 0) {
                userRecord = ownerRecords.ownerRecords[0];
            } else if (ownerRecords && ownerRecords.records && ownerRecords.records.length > 0) {
                userRecord = ownerRecords.records[0];
            }
        } catch (e) {
            logger.warn("[social_v2] leaderboard lookup failed: " + e.message);
        }

        var userScore = userRecord ? (userRecord.score || 0) : 0;
        var alerts = [];

        for (var i = 0; i < friends.length; i++) {
            var friend = friends[i];
            var friendId = friend.user ? friend.user.userId : (friend.userId || friend.id);
            if (!friendId) continue;

            try {
                var friendRecords = nk.leaderboardRecordsList(leaderboardId, [friendId], 1, "", 0);
                var friendRec = null;
                if (friendRecords && friendRecords.ownerRecords && friendRecords.ownerRecords.length > 0) {
                    friendRec = friendRecords.ownerRecords[0];
                } else if (friendRecords && friendRecords.records && friendRecords.records.length > 0) {
                    friendRec = friendRecords.records[0];
                }
                if (friendRec && (friendRec.score || 0) > userScore) {
                    var friendUsername = friend.user ? friend.user.username : (friend.username || "Friend");
                    alerts.push({
                        friend_id: friendId,
                        friend_username: friendUsername,
                        friend_score: friendRec.score,
                        your_score: userScore,
                        difference: friendRec.score - userScore
                    });
                }
            } catch (_) { /* skip friend */ }
        }

        alerts.sort(function (a, b) { return b.difference - a.difference; });

        return JSON.stringify({ success: true, alerts: alerts, count: alerts.length });
    } catch (err) {
        logger.error("[social_v2] rpcFriendScoreAlert error: " + err.message);
        return JSON.stringify({ success: false, error: err.message });
    }
}

// ---------------------------------------------------------------------------
// 6. rpcTeamQuizCreate
// ---------------------------------------------------------------------------

function rpcTeamQuizCreate(ctx, logger, nk, payload) {
    logger.info("[social_v2] rpcTeamQuizCreate called");
    try {
        var data = JSON.parse(payload || '{}');
        // Canonicalize game_id (slug -> UUID) once so persisted records and
        // downstream filters always see the canonical UUID.
        var gameId = svResolveGameId(data.game_id);
        if (!gameId || !data.team_name) {
            return JSON.stringify({ success: false, error: "game_id and team_name are required" });
        }

        var userId = ctx.userId || SYSTEM_USER_ID;
        var quizId = generateUUID();
        var joinCode = generateJoinCode();
        var maxMembers = data.max_members || 4;

        var teamQuiz = {
            quiz_id: quizId,
            game_id: gameId,
            team_name: data.team_name,
            join_code: joinCode,
            max_members: maxMembers,
            creator_id: userId,
            members: [userId],
            status: "waiting",
            created_at: nowISO()
        };

        safeWrite(nk, "team_quizzes", quizId, SYSTEM_USER_ID, teamQuiz);

        // Also index by join_code for quick lookup
        safeWrite(nk, "team_quiz_codes", joinCode, SYSTEM_USER_ID, { quiz_id: quizId });

        return JSON.stringify({ success: true, quiz_id: quizId, join_code: joinCode, team_quiz: teamQuiz });
    } catch (err) {
        logger.error("[social_v2] rpcTeamQuizCreate error: " + err.message);
        return JSON.stringify({ success: false, error: err.message });
    }
}

// ---------------------------------------------------------------------------
// 7. rpcTeamQuizJoin
// ---------------------------------------------------------------------------

function rpcTeamQuizJoin(ctx, logger, nk, payload) {
    logger.info("[social_v2] rpcTeamQuizJoin called");
    try {
        var data = JSON.parse(payload || '{}');
        if (!data.join_code) {
            return JSON.stringify({ success: false, error: "join_code is required" });
        }

        var userId = ctx.userId || SYSTEM_USER_ID;
        var codeEntry = safeRead(nk, "team_quiz_codes", data.join_code, SYSTEM_USER_ID);
        if (!codeEntry || !codeEntry.quiz_id) {
            return JSON.stringify({ success: false, error: "Invalid join code" });
        }

        var quiz = safeRead(nk, "team_quizzes", codeEntry.quiz_id, SYSTEM_USER_ID);
        if (!quiz) {
            return JSON.stringify({ success: false, error: "Team quiz not found" });
        }
        if (quiz.status !== "waiting") {
            return JSON.stringify({ success: false, error: "Team quiz is no longer accepting members" });
        }
        if (quiz.members.length >= quiz.max_members) {
            return JSON.stringify({ success: false, error: "Team quiz is full" });
        }

        for (var i = 0; i < quiz.members.length; i++) {
            if (quiz.members[i] === userId) {
                return JSON.stringify({ success: false, error: "Already a member of this team quiz" });
            }
        }

        quiz.members.push(userId);
        quiz.updated_at = nowISO();
        safeWrite(nk, "team_quizzes", codeEntry.quiz_id, SYSTEM_USER_ID, quiz);

        return JSON.stringify({ success: true, quiz_id: codeEntry.quiz_id, team_quiz: quiz });
    } catch (err) {
        logger.error("[social_v2] rpcTeamQuizJoin error: " + err.message);
        return JSON.stringify({ success: false, error: err.message });
    }
}

// ---------------------------------------------------------------------------
// 8. rpcDailyDuoCreate
// ---------------------------------------------------------------------------

function rpcDailyDuoCreate(ctx, logger, nk, payload) {
    logger.info("[social_v2] rpcDailyDuoCreate called");
    try {
        var data = JSON.parse(payload || '{}');
        // Canonicalize game_id (slug -> UUID) once at entry so duo records and
        // notifications carry the canonical UUID for downstream filtering.
        var gameId = svResolveGameId(data.game_id);
        if (!gameId || !data.partner_user_id) {
            return JSON.stringify({ success: false, error: "game_id and partner_user_id are required" });
        }

        var userId = ctx.userId || SYSTEM_USER_ID;
        var duoId = generateUUID();
        var today = nowISO().substring(0, 10);

        var duo = {
            duo_id: duoId,
            game_id: gameId,
            creator_id: userId,
            partner_id: data.partner_user_id,
            date: today,
            creator_completed: false,
            partner_completed: false,
            status: "active",
            created_at: nowISO()
        };

        safeWrite(nk, "daily_duos", duoId, SYSTEM_USER_ID, duo);

        try {
            nk.notificationSend(
                data.partner_user_id,
                "You've been invited to a Daily Duo!",
                NOTIFY_DUO_INVITE,
                { duo_id: duoId, game_id: gameId, from: userId },
                userId
            );
        } catch (e) {
            logger.warn("[social_v2] duo notification failed: " + e.message);
        }

        return JSON.stringify({ success: true, duo_id: duoId, duo: duo });
    } catch (err) {
        logger.error("[social_v2] rpcDailyDuoCreate error: " + err.message);
        return JSON.stringify({ success: false, error: err.message });
    }
}

// ---------------------------------------------------------------------------
// 9. rpcDailyDuoStatus
// ---------------------------------------------------------------------------

function rpcDailyDuoStatus(ctx, logger, nk, payload) {
    logger.info("[social_v2] rpcDailyDuoStatus called");
    try {
        var data = JSON.parse(payload || '{}');
        if (!data.duo_id) {
            return JSON.stringify({ success: false, error: "duo_id is required" });
        }

        var duo = safeRead(nk, "daily_duos", data.duo_id, SYSTEM_USER_ID);
        if (!duo) {
            return JSON.stringify({ success: false, error: "Daily duo not found" });
        }

        var bothDone = duo.creator_completed && duo.partner_completed;

        return JSON.stringify({
            success: true,
            duo: duo,
            both_completed: bothDone,
            status: bothDone ? "completed" : "in_progress"
        });
    } catch (err) {
        logger.error("[social_v2] rpcDailyDuoStatus error: " + err.message);
        return JSON.stringify({ success: false, error: err.message });
    }
}

// ---------------------------------------------------------------------------
// 10. rpcGroupQuestCreate
// ---------------------------------------------------------------------------

function rpcGroupQuestCreate(ctx, logger, nk, payload) {
    logger.info("[social_v2] rpcGroupQuestCreate called");
    try {
        var data = JSON.parse(payload || '{}');
        if (!data.group_id || !data.quest_name || !data.target_type || !data.target_value) {
            return JSON.stringify({ success: false, error: "group_id, quest_name, target_type, and target_value are required" });
        }

        var userId = ctx.userId || SYSTEM_USER_ID;
        var questId = generateUUID();
        var durationHours = data.duration_hours || 24;
        var expiresAt = new Date(Date.now() + durationHours * 3600000).toISOString();

        var quest = {
            quest_id: questId,
            group_id: data.group_id,
            quest_name: data.quest_name,
            target_type: data.target_type,
            target_value: Number(data.target_value),
            current_value: 0,
            duration_hours: durationHours,
            expires_at: expiresAt,
            creator_id: userId,
            contributors: {},
            status: "active",
            created_at: nowISO()
        };

        safeWrite(nk, "group_quests", questId, SYSTEM_USER_ID, quest);

        return JSON.stringify({ success: true, quest_id: questId, quest: quest });
    } catch (err) {
        logger.error("[social_v2] rpcGroupQuestCreate error: " + err.message);
        return JSON.stringify({ success: false, error: err.message });
    }
}

// ---------------------------------------------------------------------------
// 11. rpcGroupQuestProgress
// ---------------------------------------------------------------------------

function rpcGroupQuestProgress(ctx, logger, nk, payload) {
    logger.info("[social_v2] rpcGroupQuestProgress called");
    try {
        var data = JSON.parse(payload || '{}');
        if (!data.quest_id) {
            return JSON.stringify({ success: false, error: "quest_id is required" });
        }

        var userId = ctx.userId || SYSTEM_USER_ID;
        var increment = Number(data.increment) || 1;

        var quest = safeRead(nk, "group_quests", data.quest_id, SYSTEM_USER_ID);
        if (!quest) {
            return JSON.stringify({ success: false, error: "Quest not found" });
        }
        if (quest.status !== "active") {
            return JSON.stringify({ success: false, error: "Quest is no longer active" });
        }

        if (new Date(quest.expires_at) < new Date()) {
            quest.status = "expired";
            safeWrite(nk, "group_quests", data.quest_id, SYSTEM_USER_ID, quest);
            return JSON.stringify({ success: false, error: "Quest has expired" });
        }

        quest.current_value += increment;
        quest.contributors[userId] = (quest.contributors[userId] || 0) + increment;
        quest.updated_at = nowISO();

        var justCompleted = false;
        if (quest.current_value >= quest.target_value && quest.status === "active") {
            quest.status = "completed";
            quest.completed_at = nowISO();
            justCompleted = true;
        }

        safeWrite(nk, "group_quests", data.quest_id, SYSTEM_USER_ID, quest);

        // Log activity
        try {
            var activityId = generateUUID();
            safeWrite(nk, "group_activity", activityId, SYSTEM_USER_ID, {
                group_id: quest.group_id,
                user_id: userId,
                action: justCompleted ? "quest_completed" : "quest_progress",
                quest_id: data.quest_id,
                quest_name: quest.quest_name,
                increment: increment,
                new_total: quest.current_value,
                timestamp: nowISO()
            });
        } catch (_) { /* best effort */ }

        return JSON.stringify({
            success: true,
            quest: quest,
            just_completed: justCompleted,
            progress_percent: Math.min(100, Math.floor((quest.current_value / quest.target_value) * 100))
        });
    } catch (err) {
        logger.error("[social_v2] rpcGroupQuestProgress error: " + err.message);
        return JSON.stringify({ success: false, error: err.message });
    }
}

// ---------------------------------------------------------------------------
// 12. rpcGroupActivityFeed
// ---------------------------------------------------------------------------

function rpcGroupActivityFeed(ctx, logger, nk, payload) {
    logger.info("[social_v2] rpcGroupActivityFeed called");
    try {
        var data = JSON.parse(payload || '{}');
        if (!data.group_id) {
            return JSON.stringify({ success: false, error: "group_id is required" });
        }

        var limit = data.limit || 20;
        if (limit > 100) limit = 100;

        var allRecords = [];
        try {
            var result = nk.storageList(SYSTEM_USER_ID, "group_activity", limit, "");
            if (result && result.objects) {
                allRecords = result.objects;
            } else if (result && result.length) {
                allRecords = result;
            }
        } catch (e) {
            logger.warn("[social_v2] storageList failed: " + e.message);
        }

        var events = [];
        for (var i = 0; i < allRecords.length; i++) {
            var val = allRecords[i].value || allRecords[i];
            if (val.group_id === data.group_id) {
                events.push(val);
            }
        }

        events.sort(function (a, b) {
            return (b.timestamp || "").localeCompare(a.timestamp || "");
        });

        if (events.length > limit) {
            events = events.slice(0, limit);
        }

        return JSON.stringify({ success: true, events: events, count: events.length });
    } catch (err) {
        logger.error("[social_v2] rpcGroupActivityFeed error: " + err.message);
        return JSON.stringify({ success: false, error: err.message });
    }
}


// --- Module: tournaments\tournaments.js ---
/**
 * Tournament System for Multi-Game Platform
 * Supports scheduled tournaments with brackets and prizes
 * 
 * Collections:
 * - tournaments: Stores tournament definitions (system-owned)
 * - tournament_entries: Stores player registrations
 */

var TOURNAMENT_COLLECTION = "tournaments";
var TOURNAMENT_ENTRIES_COLLECTION = "tournament_entries";

/**
 * RPC: tournament_create (Admin only)
 * Create a new tournament
 */
var rpcTournamentCreate = function(ctx, logger, nk, payload) {
    try {
        var data = JSON.parse(payload || '{}');
        
        if (!data.game_id || !data.title || !data.start_time || !data.end_time) {
            throw Error("game_id, title, start_time, and end_time are required");
        }
        
        var gameId = data.game_id;
        var tournamentId = "tournament_" + gameId + "_" + Date.now();
        
        // Create tournament leaderboard
        var metadata = {
            title: data.title,
            description: data.description || "",
            start_time: data.start_time,
            end_time: data.end_time,
            entry_fee: data.entry_fee || 0,
            max_players: data.max_players || 100,
            prize_pool: data.prize_pool || {},
            format: data.format || "leaderboard",
            game_id: gameId
        };
        
        nk.leaderboardCreate(
            tournamentId,
            false,
            "desc",
            "reset",
            JSON.stringify(metadata)
        );
        
        // Store tournament info
        var tournament = {
            tournament_id: tournamentId,
            game_id: gameId,
            title: data.title,
            description: data.description || "",
            start_time: data.start_time,
            end_time: data.end_time,
            entry_fee: data.entry_fee || 0,
            max_players: data.max_players || 100,
            prize_pool: data.prize_pool || {
                1: { coins: 5000, items: ["legendary_trophy"] },
                2: { coins: 3000, items: ["epic_trophy"] },
                3: { coins: 2000, items: ["rare_trophy"] }
            },
            format: data.format || "leaderboard",
            status: "upcoming",
            players_joined: 0,
            created_at: new Date().toISOString()
        };
        
        nk.storageWrite([{
            collection: TOURNAMENT_COLLECTION,
            key: tournamentId,
            userId: "00000000-0000-0000-0000-000000000000",
            value: tournament,
            permissionRead: 2,
            permissionWrite: 0
        }]);
        
        logger.info("[Tournament] Created: " + tournamentId);
        
        return JSON.stringify({
            success: true,
            tournament: tournament
        });
        
    } catch (err) {
        logger.error("[Tournament] Create error: " + err.message);
        return JSON.stringify({
            success: false,
            error: err.message
        });
    }
};

/**
 * RPC: tournament_join
 * Join a tournament
 */
var rpcTournamentJoin = function(ctx, logger, nk, payload) {
    try {
        var data = JSON.parse(payload || '{}');
        
        if (!data.tournament_id) {
            throw Error("tournament_id is required");
        }
        
        var userId = ctx.userId;
        var tournamentId = data.tournament_id;
        
        logger.info("[Tournament] User " + userId + " joining tournament: " + tournamentId);
        
        // Get tournament info
        var records = nk.storageRead([{
            collection: TOURNAMENT_COLLECTION,
            key: tournamentId,
            userId: "00000000-0000-0000-0000-000000000000"
        }]);
        
        if (!records || records.length === 0 || !records[0].value) {
            throw Error("Tournament not found");
        }
        
        var tournament = records[0].value;
        
        // Check if tournament is open for registration
        var now = new Date();
        var startTime = new Date(tournament.start_time);
        
        if (now >= startTime) {
            throw Error("Tournament has already started");
        }
        
        // Check if tournament is full
        if (tournament.players_joined >= tournament.max_players) {
            throw Error("Tournament is full");
        }
        
        // Check if already joined
        var entryKey = "entry_" + userId + "_" + tournamentId;
        
        try {
            var entryRecords = nk.storageRead([{
                collection: TOURNAMENT_ENTRIES_COLLECTION,
                key: entryKey,
                userId: userId
            }]);
            
            if (entryRecords && entryRecords.length > 0 && entryRecords[0].value) {
                throw Error("Already joined this tournament");
            }
        } catch (err) {
            // Not joined yet, continue
        }
        
        // Check and deduct entry fee
        if (tournament.entry_fee > 0) {
            var walletKey = "wallet_" + userId + "_" + tournament.game_id;
            var wallet = null;
            
            var walletRecords = nk.storageRead([{
                collection: tournament.game_id + "_wallets",
                key: walletKey,
                userId: userId
            }]);
            
            if (walletRecords && walletRecords.length > 0 && walletRecords[0].value) {
                wallet = walletRecords[0].value;
            }
            
            if (!wallet || wallet.balance < tournament.entry_fee) {
                throw Error("Insufficient balance for entry fee");
            }
            
            // Deduct entry fee
            wallet.balance -= tournament.entry_fee;
            wallet.updated_at = new Date().toISOString();
            
            nk.storageWrite([{
                collection: tournament.game_id + "_wallets",
                key: walletKey,
                userId: userId,
                value: wallet,
                permissionRead: 1,
                permissionWrite: 0
            }]);
        }
        
        // Create entry
        var entry = {
            user_id: userId,
            tournament_id: tournamentId,
            joined_at: new Date().toISOString(),
            entry_fee_paid: tournament.entry_fee
        };
        
        nk.storageWrite([{
            collection: TOURNAMENT_ENTRIES_COLLECTION,
            key: entryKey,
            userId: userId,
            value: entry,
            permissionRead: 1,
            permissionWrite: 0
        }]);
        
        // Update tournament player count
        tournament.players_joined += 1;
        
        nk.storageWrite([{
            collection: TOURNAMENT_COLLECTION,
            key: tournamentId,
            userId: "00000000-0000-0000-0000-000000000000",
            value: tournament,
            permissionRead: 2,
            permissionWrite: 0
        }]);
        
        logger.info("[Tournament] User joined: " + userId);
        
        return JSON.stringify({
            success: true,
            tournament_id: tournamentId,
            players_joined: tournament.players_joined,
            max_players: tournament.max_players
        });
        
    } catch (err) {
        logger.error("[Tournament] Join error: " + err.message);
        return JSON.stringify({
            success: false,
            error: err.message
        });
    }
};

/**
 * RPC: tournament_list_active
 * Get all active tournaments for a game
 */
var rpcTournamentListActive = function(ctx, logger, nk, payload) {
    try {
        var data = JSON.parse(payload || '{}');
        
        if (!data.game_id) {
            throw Error("game_id is required");
        }
        
        var gameId = data.game_id;
        
        // List all tournaments
        var records = nk.storageList("00000000-0000-0000-0000-000000000000", TOURNAMENT_COLLECTION, 100);
        
        var tournaments = [];
        var now = new Date();
        
        if (records && records.objects) {
            for (var i = 0; i < records.objects.length; i++) {
                var tournament = records.objects[i].value;
                
                if (tournament.game_id !== gameId) {
                    continue;
                }
                
                var endTime = new Date(tournament.end_time);
                
                if (now <= endTime) {
                    tournaments.push({
                        tournament_id: tournament.tournament_id,
                        title: tournament.title,
                        description: tournament.description,
                        start_time: tournament.start_time,
                        end_time: tournament.end_time,
                        entry_fee: tournament.entry_fee,
                        players_joined: tournament.players_joined,
                        max_players: tournament.max_players,
                        prize_pool: tournament.prize_pool,
                        format: tournament.format,
                        status: now < new Date(tournament.start_time) ? "upcoming" : "active"
                    });
                }
            }
        }
        
        return JSON.stringify({
            success: true,
            tournaments: tournaments
        });
        
    } catch (err) {
        logger.error("[Tournament] List active error: " + err.message);
        return JSON.stringify({
            success: false,
            error: err.message
        });
    }
};

/**
 * RPC: tournament_submit_score
 * Submit score to tournament
 */
var rpcTournamentSubmitScore = function(ctx, logger, nk, payload) {
    try {
        var data = JSON.parse(payload || '{}');
        
        if (!data.tournament_id || data.score === undefined) {
            throw Error("tournament_id and score are required");
        }
        
        var userId = ctx.userId;
        var username = ctx.username || "Player";
        var tournamentId = data.tournament_id;
        var score = data.score;
        var metadata = data.metadata || {};
        
        // Verify user joined tournament
        var entryKey = "entry_" + userId + "_" + tournamentId;
        
        var entryRecords = nk.storageRead([{
            collection: TOURNAMENT_ENTRIES_COLLECTION,
            key: entryKey,
            userId: userId
        }]);
        
        if (!entryRecords || entryRecords.length === 0 || !entryRecords[0].value) {
            throw Error("You must join the tournament first");
        }
        
        // Submit score to tournament leaderboard
        nk.leaderboardRecordWrite(
            tournamentId,
            userId,
            username,
            score,
            0,
            metadata
        );
        
        // Get rank
        var leaderboard = nk.leaderboardRecordsList(tournamentId, [userId], 1);
        var rank = 999;
        
        if (leaderboard && leaderboard.records && leaderboard.records.length > 0) {
            rank = leaderboard.records[0].rank;
        }
        
        logger.info("[Tournament] Score submitted: " + score + ", rank: " + rank);
        
        return JSON.stringify({
            success: true,
            tournament_id: tournamentId,
            score: score,
            rank: rank
        });
        
    } catch (err) {
        logger.error("[Tournament] Submit score error: " + err.message);
        return JSON.stringify({
            success: false,
            error: err.message
        });
    }
};

/**
 * RPC: tournament_get_leaderboard
 * Get tournament leaderboard
 */
var rpcTournamentGetLeaderboard = function(ctx, logger, nk, payload) {
    try {
        var data = JSON.parse(payload || '{}');
        
        if (!data.tournament_id) {
            throw Error("tournament_id is required");
        }
        
        var tournamentId = data.tournament_id;
        var limit = data.limit || 100;
        
        // Get leaderboard records
        var leaderboard = nk.leaderboardRecordsList(tournamentId, null, limit);
        
        var records = [];
        
        if (leaderboard && leaderboard.records) {
            for (var i = 0; i < leaderboard.records.length; i++) {
                var record = leaderboard.records[i];
                records.push({
                    rank: record.rank,
                    user_id: record.ownerId,
                    username: record.username || "Player",
                    score: record.score,
                    metadata: record.metadata
                });
            }
        }
        
        return JSON.stringify({
            success: true,
            tournament_id: tournamentId,
            leaderboard: records,
            total_entries: records.length
        });
        
    } catch (err) {
        logger.error("[Tournament] Get leaderboard error: " + err.message);
        return JSON.stringify({
            success: false,
            error: err.message
        });
    }
};

/**
 * RPC: tournament_claim_rewards (Called after tournament ends)
 * Distribute rewards to winners
 */
var rpcTournamentClaimRewards = function(ctx, logger, nk, payload) {
    try {
        var data = JSON.parse(payload || '{}');
        
        if (!data.tournament_id) {
            throw Error("tournament_id is required");
        }
        
        var userId = ctx.userId;
        var tournamentId = data.tournament_id;
        
        // Get tournament info
        var records = nk.storageRead([{
            collection: TOURNAMENT_COLLECTION,
            key: tournamentId,
            userId: "00000000-0000-0000-0000-000000000000"
        }]);
        
        if (!records || records.length === 0 || !records[0].value) {
            throw Error("Tournament not found");
        }
        
        var tournament = records[0].value;
        
        // Check if tournament has ended
        var now = new Date();
        var endTime = new Date(tournament.end_time);
        
        if (now < endTime) {
            throw Error("Tournament has not ended yet");
        }
        
        // Get user's rank
        var leaderboard = nk.leaderboardRecordsList(tournamentId, [userId], 1);
        
        if (!leaderboard || !leaderboard.records || leaderboard.records.length === 0) {
            throw Error("No tournament entry found for user");
        }
        
        var rank = leaderboard.records[0].rank;
        
        // Check if user has rewards
        var rewards = tournament.prize_pool[rank];
        
        if (!rewards) {
            return JSON.stringify({
                success: true,
                rank: rank,
                rewards: null,
                message: "No rewards for this rank"
            });
        }
        
        // Check if already claimed
        var claimKey = "claim_" + userId + "_" + tournamentId;
        
        try {
            var claimRecords = nk.storageRead([{
                collection: "tournament_claims",
                key: claimKey,
                userId: userId
            }]);
            
            if (claimRecords && claimRecords.length > 0 && claimRecords[0].value) {
                throw Error("Rewards already claimed");
            }
        } catch (err) {
            // Not claimed yet, continue
        }
        
        // Grant rewards
        if (rewards.coins && rewards.coins > 0) {
            var walletKey = "wallet_" + userId + "_" + tournament.game_id;
            var wallet = { balance: 0 };
            
            try {
                var walletRecords = nk.storageRead([{
                    collection: tournament.game_id + "_wallets",
                    key: walletKey,
                    userId: userId
                }]);
                
                if (walletRecords && walletRecords.length > 0 && walletRecords[0].value) {
                    wallet = walletRecords[0].value;
                }
            } catch (err) {
                logger.debug("[Tournament] Creating new wallet");
            }
            
            wallet.balance = (wallet.balance || 0) + rewards.coins;
            wallet.updated_at = new Date().toISOString();
            
            nk.storageWrite([{
                collection: tournament.game_id + "_wallets",
                key: walletKey,
                userId: userId,
                value: wallet,
                permissionRead: 1,
                permissionWrite: 0
            }]);
        }
        
        // Mark as claimed
        nk.storageWrite([{
            collection: "tournament_claims",
            key: claimKey,
            userId: userId,
            value: {
                tournament_id: tournamentId,
                rank: rank,
                rewards: rewards,
                claimed_at: new Date().toISOString()
            },
            permissionRead: 1,
            permissionWrite: 0
        }]);
        
        logger.info("[Tournament] Rewards claimed by user " + userId + " for rank " + rank);
        
        return JSON.stringify({
            success: true,
            rank: rank,
            rewards: rewards,
            message: "Rewards claimed successfully"
        });
        
    } catch (err) {
        logger.error("[Tournament] Claim rewards error: " + err.message);
        return JSON.stringify({
            success: false,
            error: err.message
        });
    }
};


// --- Module: visual_path\visual_path.js ---
// ============================================================================
// visual_path.js — Visual Path / Milestone System
// ============================================================================
// PRODUCTION-READY | ES5 (Goja runtime)
//
// Implements the server side of PLAN-ENGAGEMENT_SYSTEM_02_VISUAL_PATH:
//
//   visual_path_get_state
//       -> per-user progress: currentDay, currentMilestoneId, completedMilestoneIds,
//          lastVisitDay, totalPlayDays
//
//   visual_path_get_schedule
//       -> the milestone catalog. Reads from system storage
//          (collection=visual_path_config, key=schedule_v1, userId=00000…).
//          If no record exists yet, returns the seeded default schedule so
//          the client never sees an empty list. Includes a `version` field
//          for client cache invalidation.
//
//   visual_path_skip_day_with_ad
//       -> rewarded-ad path: caller spends a watched ad (client claims they
//          watched; trust boundary = SDK-level ad token, validated upstream)
//          to advance currentDay by 1. Rate-limited: max 1 per day, max 5
//          per 30-day window.
//
// Storage:
//   visual_path/state_<userId>            — per-user state (perm 1/0)
//   visual_path_config/schedule_v1        — system-level schedule (perm 2/0)
//   visual_path/skip_log_<userId>         — rate-limit ledger (perm 0/0)
//
// SECURITY: every mutation is authenticated. The schedule write path is NOT
// exposed as an RPC — admin must seed the row directly via the Nakama
// console / a separate admin-guarded endpoint.
// ============================================================================

var VP_STATE_COLLECTION  = 'visual_path';
var VP_CONFIG_COLLECTION = 'visual_path_config';
var VP_CONFIG_KEY        = 'schedule_v1';
var VP_SYSTEM_USER_ID    = '00000000-0000-0000-0000-000000000000';
var VP_SKIP_LOG_KEY_PFX  = 'skip_log_';
var VP_SKIPS_PER_30D     = 5;

// Default schedule — used when no admin-seeded row exists yet so the client
// always has a milestone list to render. Mirrors the client-side hardcoded
// list (PLAN-02 §V1) but lets us roll new milestones server-side without a
// client deploy.
var VP_DEFAULT_SCHEDULE = {
    version: '1.0.0',
    milestones: [
        { id: 'first_steps',    name: 'First Steps',     description: 'Complete your first quiz',                          dayRequired: 1,  iconCdnPath: 'milestones/first_steps.png' },
        { id: 'three_day',      name: '3-Day Streak',    description: 'Play 3 days in a row',                              dayRequired: 3,  iconCdnPath: 'milestones/three_day.png' },
        { id: 'week_warrior',   name: 'Week Warrior',    description: 'Play 7 days in a row',                              dayRequired: 7,  iconCdnPath: 'milestones/week_warrior.png' },
        { id: 'two_weeks',      name: 'Two Weeks Strong',description: 'Play 14 days in a row',                             dayRequired: 14, iconCdnPath: 'milestones/two_weeks.png' },
        { id: 'monthly',        name: 'Monthly Master',  description: 'Play 30 days in a row',
          dayRequired: 30, iconCdnPath: 'milestones/monthly.png' },
        { id: 'sixty_days',     name: 'Two Months',      description: 'Play 60 days in a row',                             dayRequired: 60, iconCdnPath: 'milestones/sixty_days.png' },
        { id: 'hundred_days',   name: 'Centurion',       description: 'Play 100 days in a row',                            dayRequired: 100,iconCdnPath: 'milestones/hundred_days.png' },
        { id: 'half_year',      name: 'Half Year Hero',  description: 'Play 180 days in a row',                            dayRequired: 180,iconCdnPath: 'milestones/half_year.png' },
        { id: 'year',           name: 'Year-Long Legend',description: 'Play 365 days in a row',                            dayRequired: 365,iconCdnPath: 'milestones/year.png' }
    ]
};

// ─── Tiny helpers ───────────────────────────────────────────────────────────

function _vpNowIso() { return new Date().toISOString(); }
function _vpTodayKey() { return _vpNowIso().slice(0, 10); }

function _vpOk(extra) {
    var out = { success: true };
    if (extra) {
        for (var k in extra) {
            if (Object.prototype.hasOwnProperty.call(extra, k)) out[k] = extra[k];
        }
    }
    return JSON.stringify(out);
}

function _vpErr(message, errorCode) {
    return JSON.stringify({
        success: false,
        error: message,
        errorCode: errorCode || 'unknown'
    });
}

function _vpParse(payload) {
    if (!payload || payload === '') return { ok: true, data: {} };
    try { return { ok: true, data: JSON.parse(payload) }; }
    catch (e) { return { ok: false, error: 'Invalid JSON: ' + e.message }; }
}

function _vpReadState(nk, logger, userId) {
    try {
        var rows = nk.storageRead([{
            collection: VP_STATE_COLLECTION,
            key: 'state_' + userId,
            userId: userId
        }]);
        if (rows && rows.length > 0 && rows[0].value) return rows[0].value;
    } catch (err) {
        if (logger && logger.warn) logger.warn('[VisualPath] state read failed: ' + err.message);
    }
    return null;
}

function _vpWriteState(nk, logger, userId, state) {
    try {
        nk.storageWrite([{
            collection: VP_STATE_COLLECTION,
            key: 'state_' + userId,
            userId: userId,
            value: state,
            permissionRead: 1,
            permissionWrite: 0
        }]);
        return true;
    } catch (err) {
        if (logger && logger.error) logger.error('[VisualPath] state write failed: ' + err.message);
        return false;
    }
}

function _vpInitState() {
    var now = _vpNowIso();
    return {
        currentDay:            1,
        totalPlayDays:         1,
        lastVisitDay:          _vpTodayKey(),
        currentMilestoneId:    'first_steps',
        completedMilestoneIds: [],
        skipsUsed:             [],
        createdAt:             now,
        updatedAt:             now
    };
}

function _vpReadSchedule(nk, logger) {
    try {
        var rows = nk.storageRead([{
            collection: VP_CONFIG_COLLECTION,
            key:        VP_CONFIG_KEY,
            userId:     VP_SYSTEM_USER_ID
        }]);
        if (rows && rows.length > 0 && rows[0].value && rows[0].value.milestones) {
            return rows[0].value;
        }
    } catch (err) {
        if (logger && logger.warn) logger.warn('[VisualPath] schedule read failed: ' + err.message);
    }
    return VP_DEFAULT_SCHEDULE;
}

// Given currentDay + schedule, recomputes currentMilestoneId and the list of
// completedMilestoneIds. Pure function — no side-effects.
function _vpRecomputeMilestone(state, schedule) {
    var done = [];
    var current = null;
    for (var i = 0; i < schedule.milestones.length; i++) {
        var m = schedule.milestones[i];
        if ((state.currentDay || 1) >= (m.dayRequired || 1)) {
            done.push(m.id);
            current = m.id;
        } else {
            if (!current) current = m.id; // first not-yet-reached
            break;
        }
    }
    state.completedMilestoneIds = done;
    state.currentMilestoneId    = current || (schedule.milestones.length > 0 ? schedule.milestones[0].id : null);
    return state;
}

// ============================================================================
// RPC: visual_path_get_state
// ============================================================================
function rpcVisualPathGetState(ctx, logger, nk, payload) {
    if (!ctx.userId) return _vpErr('Authentication required', 'unauthenticated');

    var schedule = _vpReadSchedule(nk, logger);
    var state    = _vpReadState(nk, logger, ctx.userId);
    var isNew    = false;

    if (!state) {
        state = _vpInitState();
        isNew = true;
    } else {
        // Increment day-counter when a new calendar day is detected
        var today = _vpTodayKey();
        if (state.lastVisitDay !== today) {
            // If the visit was yesterday, advance currentDay by 1 (streak continues).
            // If the gap is >1 day, currentDay still advances by 1 — calendar-day
            // count, not "consecutive" — to align with client semantics in
            // PLAN-02 §V1 which uses totalPlayDays as the milestone driver.
            state.currentDay   = (state.currentDay || 1) + 1;
            state.totalPlayDays = (state.totalPlayDays || 1) + 1;
            state.lastVisitDay = today;
        }
    }

    state = _vpRecomputeMilestone(state, schedule);
    state.updatedAt = _vpNowIso();
    _vpWriteState(nk, logger, ctx.userId, state);

    // Find the next-milestone object for the client to render the "X days
    // until next milestone" UI.
    var nextMilestone = null;
    for (var i = 0; i < schedule.milestones.length; i++) {
        var m = schedule.milestones[i];
        if ((m.dayRequired || 1) > (state.currentDay || 1)) { nextMilestone = m; break; }
    }

    return _vpOk({
        currentDay:            state.currentDay,
        totalPlayDays:         state.totalPlayDays,
        lastVisitDay:          state.lastVisitDay,
        currentMilestoneId:    state.currentMilestoneId,
        completedMilestoneIds: state.completedMilestoneIds,
        nextMilestone:         nextMilestone,
        scheduleVersion:       schedule.version || '1.0.0',
        isNewUser:             isNew,
        timestamp:             _vpNowIso()
    });
}

// ============================================================================
// RPC: visual_path_get_schedule
// ============================================================================
//
// Payload: { knownVersion?: <string> }
//
// If `knownVersion` matches the server schedule version, returns
// `{ success: true, unchanged: true, version }` so the client can skip the
// full milestone list (cheap cache-validation round-trip).
function rpcVisualPathGetSchedule(ctx, logger, nk, payload) {
    var p = _vpParse(payload);
    if (!p.ok) return _vpErr(p.error, 'invalid_payload');
    var knownVersion = (p.data || {}).knownVersion;

    var schedule = _vpReadSchedule(nk, logger);

    if (knownVersion && schedule.version && knownVersion === schedule.version) {
        return _vpOk({
            unchanged: true,
            version:   schedule.version,
            timestamp: _vpNowIso()
        });
    }

    return _vpOk({
        version:    schedule.version || '1.0.0',
        milestones: schedule.milestones || [],
        unchanged:  false,
        timestamp:  _vpNowIso()
    });
}

// ============================================================================
// RPC: visual_path_skip_day_with_ad
// ============================================================================
//
// Lets a player advance currentDay by 1 in exchange for a watched rewarded
// ad. Rate-limited:
//   - max 1 skip per calendar day
//   - max VP_SKIPS_PER_30D (5) skips in any rolling 30-day window
//
// Payload: { adImpressionId?: <string> }   // SDK-level token; logged for audit
//
// We trust the client's "ad watched" claim because the upstream ad-SDK uses
// signed callbacks; storing the impressionId lets us correlate with the
// ad-network reconciliation pipeline if abuse is suspected later.
function rpcVisualPathSkipDayWithAd(ctx, logger, nk, payload) {
    if (!ctx.userId) return _vpErr('Authentication required', 'unauthenticated');

    var p = _vpParse(payload);
    if (!p.ok) return _vpErr(p.error, 'invalid_payload');
    var data = p.data || {};
    var impressionId = data.adImpressionId || '';

    var schedule = _vpReadSchedule(nk, logger);
    var state    = _vpReadState(nk, logger, ctx.userId) || _vpInitState();
    var today    = _vpTodayKey();

    if (!state.skipsUsed) state.skipsUsed = [];

    // Daily cap: refuse if already skipped today
    for (var i = 0; i < state.skipsUsed.length; i++) {
        if (state.skipsUsed[i].day === today) {
            return _vpErr('Already used your daily skip', 'daily_skip_used',
                          { skippedAt: state.skipsUsed[i].at });
        }
    }

    // 30-day cap: count skips in trailing 30 days
    var nowMs = Date.now();
    var freshSkips = [];
    for (var j = 0; j < state.skipsUsed.length; j++) {
        var sk = state.skipsUsed[j];
        var ms = new Date(sk.at).getTime();
        if ((nowMs - ms) < (30 * 86400000)) freshSkips.push(sk);
    }
    if (freshSkips.length >= VP_SKIPS_PER_30D) {
        return _vpErr('30-day skip limit reached (' + VP_SKIPS_PER_30D + ')',
                      'monthly_skip_limit', { freshSkipsCount: freshSkips.length });
    }

    // Apply skip
    state.currentDay    = (state.currentDay || 1) + 1;
    state.totalPlayDays = (state.totalPlayDays || 1) + 1;
    state.lastVisitDay  = today;
    state.skipsUsed     = freshSkips.concat([{
        day: today,
        at: _vpNowIso(),
        impressionId: impressionId
    }]);

    state = _vpRecomputeMilestone(state, schedule);
    state.updatedAt = _vpNowIso();
    if (!_vpWriteState(nk, logger, ctx.userId, state)) {
        return _vpErr('Failed to persist skip', 'storage_write_failed');
    }

    if (logger && logger.info) {
        logger.info('[VisualPath] skip_day_with_ad user=' + ctx.userId +
                    ' day=' + state.currentDay +
                    ' impressionId=' + impressionId);
    }

    return _vpOk({
        currentDay:            state.currentDay,
        totalPlayDays:         state.totalPlayDays,
        currentMilestoneId:    state.currentMilestoneId,
        completedMilestoneIds: state.completedMilestoneIds,
        skipsUsedThisMonth:    state.skipsUsed.length,
        skipsRemainingThisMonth: Math.max(0, VP_SKIPS_PER_30D - state.skipsUsed.length),
        timestamp:             _vpNowIso()
    });
}

// ============================================================================
// Module Init — register Visual Path RPCs
// ============================================================================
function __ModuleInit_84(ctx, logger, nk, initializer) {
    __rpc_visual_path_get_state = __rpc_visual_path_get_state || (rpcVisualPathGetState);
    __rpc_visual_path_get_schedule = __rpc_visual_path_get_schedule || (rpcVisualPathGetSchedule);
    __rpc_visual_path_skip_day_with_ad = __rpc_visual_path_skip_day_with_ad || (rpcVisualPathSkipDayWithAd);
    if (logger && logger.info) {
        logger.info('[VisualPath] Registered 3 RPCs (get_state, get_schedule, skip_day_with_ad)');
    }
}


// --- Module: wallet\wallet.js ---
// wallet.js - Enhanced Wallet System (Global + Per-Game Sub-Wallets)

/**
 * Get or create global wallet for user
 * @param {object} nk - Nakama runtime
 * @param {object} logger - Logger instance
 * @param {string} userId - User ID
 * @returns {object} Global wallet data
 */
function getGlobalWallet(nk, logger, userId) {
    var collection = "wallets";
    var key = utils.makeGlobalStorageKey("global_wallet", userId);
    
    var wallet = utils.readStorage(nk, logger, collection, key, userId);
    
    if (!wallet) {
        // Initialize new global wallet
        wallet = {
            userId: userId,
            currencies: {
                xut: 0,
                xp: 0
            },
            items: {},
            nfts: [],
            createdAt: utils.getCurrentTimestamp()
        };
    }
    
    return wallet;
}

/**
 * Get or create game-specific wallet for user
 * @param {object} nk - Nakama runtime
 * @param {object} logger - Logger instance
 * @param {string} userId - User ID
 * @param {string} gameId - Game ID (UUID)
 * @returns {object} Game wallet data
 */
function getGameWallet(nk, logger, userId, gameId) {
    var collection = "wallets";
    var key = utils.makeGameStorageKey("wallet", userId, gameId);
    
    var wallet = utils.readStorage(nk, logger, collection, key, userId);
    
    if (!wallet) {
        // Initialize new game wallet
        wallet = {
            userId: userId,
            gameId: gameId,
            currencies: {
                tokens: 0,
                xp: 0
            },
            items: {},
            consumables: {},
            cosmetics: {},
            createdAt: utils.getCurrentTimestamp()
        };
    }
    
    return wallet;
}

/**
 * Save global wallet
 * @param {object} nk - Nakama runtime
 * @param {object} logger - Logger instance
 * @param {string} userId - User ID
 * @param {object} wallet - Wallet data
 * @returns {boolean} Success status
 */
function saveGlobalWallet(nk, logger, userId, wallet) {
    var collection = "wallets";
    var key = utils.makeGlobalStorageKey("global_wallet", userId);
    wallet.updatedAt = utils.getCurrentTimestamp();
    return utils.writeStorage(nk, logger, collection, key, userId, wallet);
}

/**
 * Save game wallet
 * @param {object} nk - Nakama runtime
 * @param {object} logger - Logger instance
 * @param {string} userId - User ID
 * @param {string} gameId - Game ID (UUID)
 * @param {object} wallet - Wallet data
 * @returns {boolean} Success status
 */
function saveGameWallet(nk, logger, userId, gameId, wallet) {
    var collection = "wallets";
    var key = utils.makeGameStorageKey("wallet", userId, gameId);
    wallet.updatedAt = utils.getCurrentTimestamp();
    return utils.writeStorage(nk, logger, collection, key, userId, wallet);
}

/**
 * Log transaction
 * @param {object} nk - Nakama runtime
 * @param {object} logger - Logger instance
 * @param {string} userId - User ID
 * @param {object} transaction - Transaction data
 */
function logTransaction(nk, logger, userId, transaction) {
    var key = "transaction_log_" + userId + "_" + utils.getUnixTimestamp();
    transaction.timestamp = utils.getCurrentTimestamp();
    utils.writeStorage(nk, logger, "transaction_logs", key, userId, transaction);
}

/**
 * RPC: Get all wallets (global + all game wallets)
 * @param {object} ctx - Request context
 * @param {object} logger - Logger instance
 * @param {object} nk - Nakama runtime
 * @param {string} payload - JSON payload (empty)
 * @returns {string} JSON response
 */
function rpcWalletGetAll(ctx, logger, nk, payload) {
    utils.logInfo(logger, "RPC wallet_get_all called");
    
    var userId = ctx.userId;
    if (!userId) {
        return utils.handleError(ctx, null, "User not authenticated");
    }
    
    // Get global wallet
    var globalWallet = getGlobalWallet(nk, logger, userId);
    
    // Get all game wallets
    var gameWallets = [];
    try {
        var records = nk.storageList(userId, "wallets", 100);
        for (var i = 0; i < records.length; i++) {
            if (records[i].key.indexOf("wallet_" + userId + "_") === 0) {
                gameWallets.push(records[i].value);
            }
        }
    } catch (err) {
        utils.logWarn(logger, "Failed to list game wallets: " + err.message);
    }
    
    return JSON.stringify({
        success: true,
        userId: userId,
        globalWallet: globalWallet,
        gameWallets: gameWallets,
        timestamp: utils.getCurrentTimestamp()
    });
}

/**
 * RPC: Update global wallet
 * @param {object} ctx - Request context
 * @param {object} logger - Logger instance
 * @param {object} nk - Nakama runtime
 * @param {string} payload - JSON payload with { currency: "xut", amount: 100, operation: "add" }
 * @returns {string} JSON response
 */
function rpcWalletUpdateGlobal(ctx, logger, nk, payload) {
    utils.logInfo(logger, "RPC wallet_update_global called");
    
    var parsed = utils.safeJsonParse(payload);
    if (!parsed.success) {
        return utils.handleError(ctx, null, "Invalid JSON payload");
    }
    
    var data = parsed.data;
    var validation = utils.validatePayload(data, ['currency', 'amount', 'operation']);
    if (!validation.valid) {
        return utils.handleError(ctx, null, "Missing required fields: " + validation.missing.join(", "));
    }
    
    var userId = ctx.userId;
    if (!userId) {
        return utils.handleError(ctx, null, "User not authenticated");
    }
    
    var currency = data.currency;
    var amount = Number(data.amount);
    var operation = data.operation; // "add" or "subtract"

    if (!isFinite(amount) || amount < 0) {
        return utils.handleError(ctx, null, "Invalid amount: must be a non-negative finite number");
    }
    
    // Get global wallet
    var wallet = getGlobalWallet(nk, logger, userId);
    
    // Initialize currency if not exists
    if (!wallet.currencies[currency]) {
        wallet.currencies[currency] = 0;
    }
    
    // Update currency
    if (operation === "add") {
        wallet.currencies[currency] += amount;
    } else if (operation === "subtract") {
        wallet.currencies[currency] -= amount;
        if (wallet.currencies[currency] < 0) {
            wallet.currencies[currency] = 0;
        }
    } else {
        return utils.handleError(ctx, null, "Invalid operation: " + operation);
    }
    
    // Save wallet
    if (!saveGlobalWallet(nk, logger, userId, wallet)) {
        return utils.handleError(ctx, null, "Failed to save global wallet");
    }
    
    // Log transaction
    logTransaction(nk, logger, userId, {
        type: "global_wallet_update",
        currency: currency,
        amount: amount,
        operation: operation,
        newBalance: wallet.currencies[currency]
    });
    
    return JSON.stringify({
        success: true,
        userId: userId,
        currency: currency,
        newBalance: wallet.currencies[currency],
        timestamp: utils.getCurrentTimestamp()
    });
}

function rpcWalletUpdateGameWallet(ctx, logger, nk, payload) {
    utils.logInfo(logger, "RPC wallet_update_game_wallet called");
    
    var parsed = utils.safeJsonParse(payload);
    if (!parsed.success) {
        return utils.handleError(ctx, null, "Invalid JSON payload");
    }
    
    var data = parsed. data;
    var validation = utils.validatePayload(data, ['gameId', 'currency', 'amount', 'operation']);
    if (! validation.valid) {
        return utils. handleError(ctx, null, "Missing required fields: " + validation.missing.join(", "));
    }
    
    var gameId = data.gameId;
    if (!utils. isValidUUID(gameId)) {
        return utils.handleError(ctx, null, "Invalid gameId UUID format");
    }
    
    var userId = ctx. userId;
    if (!userId) {
        return utils.handleError(ctx, null, "User not authenticated");
    }
    
    var currency = data.currency;
    var amount = Number(data.amount);
    var operation = data.operation;

    if (!isFinite(amount) || amount < 0) {
        return utils.handleError(ctx, null, "Invalid amount: must be a non-negative finite number");
    }
    
    //  NORMALIZE CURRENCY KEY - Map client aliases to storage keys
    var storageCurrency = currency;
    if (currency === "game") {
        storageCurrency = "game";  // Keep as "game" for consistency
    } else if (currency === "global") {
        storageCurrency = "global";
    }
    
    // Get game wallet
    var wallet = getGameWallet(nk, logger, userId, gameId);
    
    // Initialize currency if not exists
    if (wallet.currencies[storageCurrency] === undefined || wallet.currencies[storageCurrency] === null) {
        wallet.currencies[storageCurrency] = 0;
    }
    
    // Update currency
    if (operation === "add") {
        wallet.currencies[storageCurrency] += amount;
    } else if (operation === "subtract") {
        wallet.currencies[storageCurrency] -= amount;
        if (wallet.currencies[storageCurrency] < 0) {
            wallet. currencies[storageCurrency] = 0;
        }
    } else {
        return utils.handleError(ctx, null, "Invalid operation: " + operation);
    }
    
    //  CRITICAL: Save wallet - ensure this succeeds
    var saveResult = saveGameWallet(nk, logger, userId, gameId, wallet);
    if (!saveResult) {
        utils.logError(logger, "Failed to save game wallet for user: " + userId + ", game: " + gameId);
        return utils.handleError(ctx, null, "Failed to save game wallet");
    }
    
    utils.logInfo(logger, "Successfully saved wallet.  New balance for " + storageCurrency + ": " + wallet. currencies[storageCurrency]);
    
    // Log transaction
    logTransaction(nk, logger, userId, {
        type: "game_wallet_update",
        gameId: gameId,
        currency: storageCurrency,
        amount: amount,
        operation: operation,
        newBalance: wallet.currencies[storageCurrency]
    });
    
    // Return both the specific currency AND the common aliases
    return JSON.stringify({
        success: true,
        userId: userId,
        gameId: gameId,
        currency: storageCurrency,
        newBalance: wallet.currencies[storageCurrency],
        // Also return as game_balance/global_balance for Unity compatibility
        game_balance: wallet. currencies["game"] || wallet.currencies["tokens"] || 0,
        global_balance: wallet.currencies["global"] || wallet.currencies["xut"] || 0,
        currencies: wallet.currencies,
        timestamp: utils.getCurrentTimestamp()
    });
}

/**
 * RPC: Transfer between game wallets
 * @param {object} ctx - Request context
 * @param {object} logger - Logger instance
 * @param {object} nk - Nakama runtime
 * @param {string} payload - JSON with { fromGameId: "uuid", toGameId: "uuid", currency: "tokens", amount: 100 }
 * @returns {string} JSON response
 */
function rpcWalletTransferBetweenGameWallets(ctx, logger, nk, payload) {
    utils.logInfo(logger, "RPC wallet_transfer_between_game_wallets called");
    
    var parsed = utils.safeJsonParse(payload);
    if (!parsed.success) {
        return utils.handleError(ctx, null, "Invalid JSON payload");
    }
    
    var data = parsed.data;
    var validation = utils.validatePayload(data, ['fromGameId', 'toGameId', 'currency', 'amount']);
    if (!validation.valid) {
        return utils.handleError(ctx, null, "Missing required fields: " + validation.missing.join(", "));
    }
    
    var fromGameId = data.fromGameId;
    var toGameId = data.toGameId;
    
    if (!utils.isValidUUID(fromGameId) || !utils.isValidUUID(toGameId)) {
        return utils.handleError(ctx, null, "Invalid gameId UUID format");
    }
    
    var userId = ctx.userId;
    if (!userId) {
        return utils.handleError(ctx, null, "User not authenticated");
    }
    
    var currency = data.currency;
    var amount = Number(data.amount);

    if (!isFinite(amount) || amount <= 0) {
        return utils.handleError(ctx, null, "Invalid amount: must be a positive finite number");
    }
    
    // Get both wallets
    var fromWallet = getGameWallet(nk, logger, userId, fromGameId);
    var toWallet = getGameWallet(nk, logger, userId, toGameId);
    
    // Check if source wallet has enough
    if (!fromWallet.currencies[currency] || fromWallet.currencies[currency] < amount) {
        return JSON.stringify({
            success: false,
            error: "Insufficient balance in source wallet"
        });
    }
    
    // Transfer
    fromWallet.currencies[currency] -= amount;
    if (!toWallet.currencies[currency]) {
        toWallet.currencies[currency] = 0;
    }
    toWallet.currencies[currency] += amount;
    
    // Save both wallets
    if (!saveGameWallet(nk, logger, userId, fromGameId, fromWallet)) {
        return utils.handleError(ctx, null, "Failed to save source wallet");
    }
    if (!saveGameWallet(nk, logger, userId, toGameId, toWallet)) {
        return utils.handleError(ctx, null, "Failed to save destination wallet");
    }
    
    // Log transaction
    logTransaction(nk, logger, userId, {
        type: "wallet_transfer",
        fromGameId: fromGameId,
        toGameId: toGameId,
        currency: currency,
        amount: amount
    });
    
    return JSON.stringify({
        success: true,
        userId: userId,
        fromGameId: fromGameId,
        toGameId: toGameId,
        currency: currency,
        amount: amount,
        fromBalance: fromWallet.currencies[currency],
        toBalance: toWallet.currencies[currency],
        timestamp: utils.getCurrentTimestamp()
    });
}
// At top, make sure you have access to utils and getGameWallet
// (these are already used in other functions in this file)

// RPC: Get balances for a specific game wallet
// Payload: { gameId: "uuid" }
// Response: { success, game_balance, global_balance, currencies }
function rpcWalletGetBalances(ctx, logger, nk, payload) {
    utils.logInfo(logger, "RPC wallet_get_balances called");

    var parsed = utils.safeJsonParse(payload);
    if (!parsed.success) {
        return utils.handleError(ctx, null, "Invalid JSON payload");
    }

    var data = parsed.data;
    var validation = utils.validatePayload(data, ['gameId']);
    if (!validation.valid) {
        return utils.handleError(ctx, null, "Missing required fields: " + validation.missing.join(", "));
    }

    var gameId = data.gameId;
    if (!utils.isValidUUID(gameId)) {
        return utils.handleError(ctx, null, "Invalid gameId UUID format");
    }

    var userId = ctx.userId;
    if (!userId) {
        return utils.handleError(ctx, null, "User not authenticated");
    }

    // Reuse existing helper – this is how wallet_update_game_wallet works
    var wallet = getGameWallet(nk, logger, userId, gameId);

    var currencies = wallet.currencies || {};

    // Convention: treat "game" and "global" as main ones, if present
    var gameBalance   = currencies["game"]   || 0;
    var globalBalance = currencies["global"] || 0;

    return JSON.stringify({
        success:        true,
        userId:         userId,
        gameId:         gameId,
        game_balance:   gameBalance,
        global_balance: globalBalance,
        currencies:     currencies,
        timestamp:      utils.getCurrentTimestamp()
    });
}


// --- Module: wallet.js ---
// wallet.js - DEPRECATED: Wrapper for backward compatibility
// All wallet operations now go through data/modules/wallet/wallet.js
// 
// This file provides backward-compatible functions that map old storage
// patterns to the new unified wallet system. 

/**
 * MIGRATION NOTES:
 * - Old system used deviceId-based keys: "wallet:{deviceId}:{gameId}"
 * - Old system used collections: "game_wallets", "global_wallets", "quizverse"
 * - Old system used single "balance" field
 * 
 * New system uses:
 * - userId-based keys: "wallet_{userId}_{gameId}"
 * - Collection: "wallets"  
 * - currencies object: { game: 0, global: 0, tokens: 0, xut: 0 }
 */

/**
 * Get or create a per-game wallet (backward compatible wrapper)
 * Maps old deviceId-based lookups to new userId-based system
 */
function getOrCreateGameWallet(nk, logger, deviceId, gameId, walletId, userId) {
    // Use the new wallet system's collection and key format
    var collection = "wallets";
    var actualUserId = userId || deviceId; // Fallback to deviceId for legacy clients
    var key = "wallet_" + actualUserId + "_" + gameId;
    
    logger.info("[Wallet-Compat] Looking for game wallet with key: " + key);
    
    // Try to read from new system first
    var wallet = null;
    try {
        var records = nk.storageRead([{
            collection: collection,
            key: key,
            userId: actualUserId
        }]);
        
        if (records && records.length > 0 && records[0].value) {
            wallet = records[0].value;
            logger.info("[Wallet-Compat] Found wallet in new system");
            
            // Convert new format to old format for backward compatibility
            return {
                wallet_id: walletId || wallet.userId,
                device_id: deviceId,
                game_id: gameId,
                user_id: actualUserId,
                balance: (wallet.currencies && wallet.currencies.game) || 
                         (wallet.currencies && wallet.currencies.tokens) || 0,
                currency: "coins",
                currencies: wallet.currencies || { game: 0, tokens: 0 },
                created_at: wallet.createdAt || new Date().toISOString(),
                updated_at: wallet.updatedAt || new Date().toISOString()
            };
        }
    } catch (err) {
        logger.warn("[Wallet-Compat] Error reading from new system: " + err.message);
    }
    
    // Try legacy locations for migration
    var legacyCollections = ["game_wallets", "quizverse"];
    var legacyKey = "wallet:" + deviceId + ":" + gameId;
    
    for (var i = 0; i < legacyCollections.length; i++) {
        try {
            var legacyRecords = nk.storageRead([{
                collection: legacyCollections[i],
                key: legacyKey,
                userId: "00000000-0000-0000-0000-000000000000"
            }]);
            
            if (legacyRecords && legacyRecords.length > 0 && legacyRecords[0].value) {
                var legacyWallet = legacyRecords[0].value;
                logger.info("[Wallet-Compat] Found legacy wallet in " + legacyCollections[i] + ", migrating...");
                
                // Migrate to new system
                var newWallet = {
                    userId: actualUserId,
                    gameId: gameId,
                    currencies: {
                        game: legacyWallet.balance || 0,
                        tokens: legacyWallet.balance || 0,
                        xp: 0
                    },
                    items: {},
                    createdAt: legacyWallet.created_at || new Date().toISOString(),
                    updatedAt: new Date().toISOString()
                };
                
                // Write to new system
                nk.storageWrite([{
                    collection: collection,
                    key: key,
                    userId: actualUserId,
                    value: newWallet,
                    permissionRead: 1,
                    permissionWrite: 0,
                    version: "*"
                }]);
                
                logger.info("[Wallet-Compat] Migrated wallet to new system");
                
                return {
                    wallet_id: walletId || actualUserId,
                    device_id: deviceId,
                    game_id: gameId,
                    user_id: actualUserId,
                    balance: newWallet.currencies.game,
                    currency: "coins",
                    currencies: newWallet.currencies,
                    created_at: newWallet.createdAt,
                    updated_at: newWallet.updatedAt
                };
            }
        } catch (err) {
            logger.debug("[Wallet-Compat] Not found in " + legacyCollections[i]);
        }
    }
    
    // Create new wallet in the new system
    logger.info("[Wallet-Compat] Creating new wallet in unified system");
    
    var newWallet = {
        userId: actualUserId,
        gameId: gameId,
        currencies: {
            game: 0,
            tokens: 0,
            xp: 0
        },
        items: {},
        consumables: {},
        cosmetics: {},
        createdAt: new Date().toISOString(),
        updatedAt: new Date().toISOString()
    };
    
    try {
        nk.storageWrite([{
            collection: collection,
            key: key,
            userId: actualUserId,
            value: newWallet,
            permissionRead: 1,
            permissionWrite: 0,
            version: "*"
        }]);
        
        logger.info("[Wallet-Compat] Created new wallet for user: " + actualUserId);
    } catch (err) {
        logger.error("[Wallet-Compat] Failed to create wallet: " + err.message);
        throw err;
    }
    
    return {
        wallet_id: walletId || actualUserId,
        device_id: deviceId,
        game_id: gameId,
        user_id: actualUserId,
        balance: 0,
        currency: "coins",
        currencies: newWallet.currencies,
        created_at: newWallet.createdAt,
        updated_at: newWallet.updatedAt
    };
}

/**
 * Get or create a global wallet (backward compatible wrapper)
 */
function getOrCreateGlobalWallet(nk, logger, deviceId, globalWalletId, userId) {
    var collection = "wallets";
    var actualUserId = userId || deviceId;
    var key = "global_wallet_" + actualUserId;
    
    logger.info("[Wallet-Compat] Looking for global wallet with key: " + key);
    
    // Try to read from new system
    try {
        var records = nk.storageRead([{
            collection: collection,
            key: key,
            userId: actualUserId
        }]);
        
        if (records && records.length > 0 && records[0].value) {
            var wallet = records[0].value;
            logger.info("[Wallet-Compat] Found global wallet in new system");
            
            return {
                wallet_id: globalWalletId || wallet.userId,
                device_id: deviceId,
                game_id: "global",
                user_id: actualUserId,
                balance: (wallet.currencies && wallet.currencies.global) ||
                         (wallet.currencies && wallet.currencies.xut) || 0,
                currency: "global_coins",
                currencies: wallet.currencies || { global: 0, xut: 0 },
                created_at: wallet.createdAt || new Date().toISOString(),
                updated_at: wallet.updatedAt || new Date().toISOString()
            };
        }
    } catch (err) {
        logger.warn("[Wallet-Compat] Error reading global wallet: " + err.message);
    }
    
    // Create new global wallet
    logger.info("[Wallet-Compat] Creating new global wallet");
    
    var newWallet = {
        userId: actualUserId,
        currencies: {
            global: 0,
            xut: 0,
            xp: 0
        },
        items: {},
        nfts: [],
        createdAt: new Date().toISOString(),
        updatedAt: new Date().toISOString()
    };
    
    try {
        nk.storageWrite([{
            collection: collection,
            key: key,
            userId: actualUserId,
            value: newWallet,
            permissionRead: 1,
            permissionWrite: 0,
            version: "*"
        }]);
        
        logger.info("[Wallet-Compat] Created new global wallet for user: " + actualUserId);
    } catch (err) {
        logger.error("[Wallet-Compat] Failed to create global wallet: " + err.message);
        throw err;
    }
    
    return {
        wallet_id: globalWalletId || actualUserId,
        device_id: deviceId,
        game_id: "global",
        user_id: actualUserId,
        balance: 0,
        currency: "global_coins",
        currencies: newWallet.currencies,
        created_at: newWallet.createdAt,
        updated_at: newWallet.updatedAt
    };
}

/**
 * Update game wallet balance (backward compatible wrapper)
 * CRITICAL: This now increments the balance, not sets it
 */
function updateGameWalletBalance(nk, logger, deviceId, gameId, amountToAdd, userId) {
    var collection = "wallets";
    var actualUserId = userId || deviceId;
    var key = "wallet_" + actualUserId + "_" + gameId;
    
    logger.info("[Wallet-Compat] Incrementing wallet balance by " + amountToAdd);
    
    // Read current wallet
    var wallet = null;
    try {
        var records = nk.storageRead([{
            collection: collection,
            key: key,
            userId: actualUserId
        }]);
        
        if (records && records.length > 0 && records[0].value) {
            wallet = records[0].value;
        }
    } catch (err) {
        logger.warn("[Wallet-Compat] Error reading wallet: " + err.message);
    }
    
    if (!wallet) {
        // Get or create wallet first
        var compatWallet = getOrCreateGameWallet(nk, logger, deviceId, gameId, null, userId);
        wallet = {
            userId: actualUserId,
            gameId: gameId,
            currencies: compatWallet.currencies || { game: 0, tokens: 0 },
            createdAt: compatWallet.created_at,
            updatedAt: new Date().toISOString()
        };
    }
    
    // Ensure currencies object exists
    if (!wallet.currencies) {
        wallet.currencies = { game: 0, tokens: 0, xp: 0 };
    }
    
    // INCREMENT both game and tokens (keep them in sync)
    var oldBalance = wallet.currencies.game || wallet.currencies.tokens || 0;
    var newBalance = oldBalance + amountToAdd;
    
    wallet.currencies.game = newBalance;
    wallet.currencies.tokens = newBalance;
    wallet.updatedAt = new Date().toISOString();
    
    // Save updated wallet
    try {
        nk.storageWrite([{
            collection: collection,
            key: key,
            userId: actualUserId,
            value: wallet,
            permissionRead: 1,
            permissionWrite: 0,
            version: "*"
        }]);
        
        logger.info("[Wallet-Compat] Updated wallet: " + oldBalance + " + " + amountToAdd + " = " + newBalance);
    } catch (err) {
        logger.error("[Wallet-Compat] Failed to update wallet: " + err.message);
        throw err;
    }
    
    return {
        wallet_id: actualUserId,
        device_id: deviceId,
        game_id: gameId,
        user_id: actualUserId,
        balance: newBalance,
        currency: "coins",
        currencies: wallet.currencies,
        updated_at: wallet.updatedAt
    };
}


