/**
 * RPC: quizverse_load_player_data
 * Load player data from storage
 */
function __legacy_quizverseLoadPlayerData(context, logger, nk, payload) {
    try {
        var data = __legacy_parseAndValidateGamePayload(payload, ["gameID", "key"]);
        var userId = __legacy_getUserId(data, context);

        var collection = __legacy_getCollection(data.gameID, "player_data");
        var storageKey = data.key;

        // Read player data
        var playerData = null;
        try {
            var records = nk.storageRead([{
                collection: collection,
                key: storageKey,
                userId: userId
            }]);
            if (records && records.length > 0 && records[0].value) {
                playerData = records[0].value;
            }
        } catch (err) {
            logger.debug("No player data found for key: " + storageKey);
        }

        if (!playerData) {
            return JSON.stringify({
                success: false,
                error: "Player data not found"
            });
        }

        return JSON.stringify({
            success: true,
            data: {
                key: storageKey,
                value: playerData.value,
                updatedAt: playerData.updatedAt
            }
        });

    } catch (err) {
        logger.error("quizverse_load_player_data error: " + err.message);
        return JSON.stringify({
            success: false,
            error: err.message
        });
    }
}

