/**
 * RPC: quizverse_get_server_config
 * Get server configuration
 */
function quizverseGetServerConfig(context, logger, nk, payload) {
    try {
        var data = __legacy_parseAndValidateGamePayload(payload, ["gameID"]);

        var collection = __legacy_getCollection(data.gameID, "config");
        var key = "server_config";

        var config = {};
        try {
            var records = nk.storageRead([{
                collection: collection,
                key: key,
                userId: "00000000-0000-0000-0000-000000000000"
            }]);
            if (records && records.length > 0 && records[0].value) {
                config = records[0].value;
            }
        } catch (err) {
            // Return default config
            config = {
                maxPlayersPerMatch: 10,
                matchDuration: 300,
                enableChat: true
            };
        }

        logger.info("[" + data.gameID + "] Server config retrieved");

        return JSON.stringify({
            success: true,
            data: { config: config }
        });

    } catch (err) {
        logger.error("quizverse_get_server_config error: " + err.message);
        throw {
            code: 400,
            message: err.message,
            data: {}
        };
    }
}

